import React, { Suspense, lazy, useEffect } from "react";
import { PersistQueryClientProvider } from "@tanstack/react-query-persist-client";
import { BrowserRouter as Router, Routes, Route, useNavigate } from "react-router-dom";
import { Toaster } from "@/components/ui/toaster";
import { AuthProvider } from "@/contexts/AuthContext";
import { ProtectedRoute } from "@/components/auth/ProtectedRoute";
import { Layout } from "@/components/layout/Layout";
import { ErrorBoundary } from "@/components/ErrorBoundary";
import { LoadingSpinner } from "@/components/ui/loading-spinner";
import { LandingRoute } from "@/pages/LandingRoute";
import { queryClient, persister } from "@/lib/react-query/queryClient";
import { prefetchCriticalRoutes } from "@/utils/route-prefetch";

// Lazy load pages for better performance
const LoginPage = lazy(() => import("@/pages/LoginPage").then((m) => ({ default: m.LoginPage })));
const DashboardPage = lazy(() =>
  import("@/pages/DashboardPage").then((m) => ({ default: m.DashboardPage })),
);
const PatientsPage = lazy(() =>
  import("@/pages/PatientsPage").then((m) => ({ default: m.PatientsPage })),
);
const PatientDetailPage = lazy(() =>
  import("@/pages/PatientDetailPage").then((m) => ({ default: m.PatientDetailPage })),
);
const MessagesPage = lazy(() =>
  import("@/pages/MessagesPage").then((m) => ({ default: m.MessagesPage })),
);
const QuizPage = lazy(() => import("@/pages/QuizPage").then((m) => ({ default: m.QuizPage })));
const MonthlyQuizDashboard = lazy(() =>
  import("@/pages/MonthlyQuizDashboard").then((m) => ({ default: m.MonthlyQuizDashboard })),
);
const ReportsPage = lazy(() =>
  import("@/pages/ReportsPage").then((m) => ({ default: m.ReportsPage })),
);
const AlertsPage = lazy(() =>
  import("@/pages/AlertsPage").then((m) => ({ default: m.AlertsPage })),
);
const AnalyticsPage = lazy(() =>
  import("@/pages/AnalyticsPage").then((m) => ({ default: m.AnalyticsPage })),
);
const SettingsPage = lazy(() =>
  import("@/pages/SettingsPage").then((m) => ({ default: m.SettingsPage })),
);
const FlowsPage = lazy(() => import("@/pages/FlowsPage").then((m) => ({ default: m.FlowsPage })));
const QuestionariosPage = lazy(() =>
  import("@/pages/QuestionariosPage").then((m) => ({ default: m.QuestionariosPage })),
);
// Physician dashboard
const PhysicianDashboard = lazy(() =>
  import("@/pages/PhysicianDashboard").then((m) => ({ default: m.default })),
);
// Admin system import
const AdminApp = lazy(() => import("@/AdminApp"));
const WhatsAppPage = lazy(() =>
  import("@/pages/WhatsAppPage").then((m) => ({ default: m.WhatsAppPage })),
);
const DLQDashboard = lazy(() =>
  import("@/pages/DLQDashboard").then((m) => ({ default: m.DLQDashboard })),
);
const UnauthorizedPage = lazy(() =>
  import("@/pages/UnauthorizedPage").then((m) => ({ default: m.default })),
);

// Loading component for Suspense
const PageLoader = () => (
  <div className="min-h-screen flex items-center justify-center">
    <LoadingSpinner size="lg" color="primary" />
  </div>
);

// 404 Not Found component with React Router navigation
const NotFoundPage = () => {
  const navigate = useNavigate();

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50">
      <div className="text-center">
        <h1 className="text-4xl font-bold text-gray-900 mb-4">404</h1>
        <p className="text-lg text-gray-600 mb-8">P├ígina n├úo encontrada</p>
        <button
          onClick={() => navigate("/dashboard")}
          className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded"
        >
          Voltar ao Dashboard
        </button>
      </div>
    </div>
  );
};

/**
 * React Query Configuration - Phase 2.2 Enhanced with IndexedDB Persistence
 *
 * Configuration is now imported from @/lib/react-query/queryClient
 * for better modularity and testability.
 *
 * Phase 2.2 Performance improvements:
 * 1. IndexedDB persistence: 7-day offline cache with automatic expiration
 * 2. Enhanced deduplication: 30s window (up from 5s) = 40-60% fewer API calls
 * 3. Optimized cache time: 5min memory cache (down from 15min) for better memory management
 * 4. Query batching: Reduces network overhead
 * 5. Smart retries: Exponential backoff for better error handling
 *
 * Expected Phase 2.2 impact:
 * - 40-60% reduction in API calls (deduplication)
 * - 30-50% reduction in component re-renders (React.memo)
 * - Offline-first data access (IndexedDB)
 * - Faster perceived performance (persistent cache)
 * - Lower bandwidth usage (~50% reduction)
 * - Better memory management (optimized gcTime)
 */

function App() {
  // Prefetch critical routes after initial load for better performance
  useEffect(() => {
    // Only prefetch in production or when explicitly enabled
    if (import.meta.env.PROD || import.meta.env['VITE_ENABLE_PREFETCH'] === "true") {
      console.warn("[App] Initializing critical route prefetch");
      prefetchCriticalRoutes();
    }
  }, []);

  return (
    <ErrorBoundary>
      {/* Phase 2.2: PersistQueryClientProvider for IndexedDB persistence */}
      <PersistQueryClientProvider client={queryClient} persistOptions={{ persister }}>
        <AuthProvider>
          <Router>
            <div className="min-h-screen bg-background">
              <Suspense fallback={<PageLoader />}>
                <Routes>
                  <Route path="/login" element={<LoginPage />} />
                  {/* Smart routing: shows loading spinner, then redirects based on auth state and role */}
                  <Route path="/" element={<LandingRoute />} />

                  {/* Protected Routes with Suspense */}
                  <Route
                    path="/dashboard"
                    element={
                      <ProtectedRoute>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <DashboardPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/patients"
                    element={
                      <ProtectedRoute>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <PatientsPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/patients/:id"
                    element={
                      <ProtectedRoute>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <PatientDetailPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/messages"
                    element={
                      <ProtectedRoute>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <MessagesPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/quiz"
                    element={
                      <ProtectedRoute>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <QuizPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/monthly-quiz"
                    element={
                      <ProtectedRoute>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <MonthlyQuizDashboard />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/reports"
                    element={
                      <ProtectedRoute>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <ReportsPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/alerts"
                    element={
                      <ProtectedRoute>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <AlertsPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/analytics"
                    element={
                      <ProtectedRoute>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <AnalyticsPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/settings"
                    element={
                      <ProtectedRoute requiredPermission="canManageSettings">
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <SettingsPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/flows"
                    element={
                      <ProtectedRoute requiredPermission="canManageFlows">
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <FlowsPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/questionarios"
                    element={
                      <ProtectedRoute>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <QuestionariosPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/dlq"
                    element={
                      <ProtectedRoute>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <DLQDashboard />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/admin/*"
                    element={
                      <ProtectedRoute requiredPermission="canAccessAdmin">
                        <Suspense fallback={<PageLoader />}>
                          <AdminApp />
                        </Suspense>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/whatsapp"
                    element={
                      <ProtectedRoute>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <WhatsAppPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />

                  {/* Physician Dashboard Routes */}
                  <Route
                    path="/physician/dashboard"
                    element={
                      <ProtectedRoute requiredRoles={["PHYSICIAN", "DOCTOR", "ADMIN"]}>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <PhysicianDashboard />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/physician/patients/:id"
                    element={
                      <ProtectedRoute requiredRoles={["PHYSICIAN", "DOCTOR", "ADMIN"]}>
                        <Layout>
                          <Suspense fallback={<PageLoader />}>
                            <PatientDetailPage />
                          </Suspense>
                        </Layout>
                      </ProtectedRoute>
                    }
                  />

                  {/* Unauthorized Access Page */}
                  <Route
                    path="/unauthorized"
                    element={
                      <Suspense fallback={<PageLoader />}>
                        <UnauthorizedPage />
                      </Suspense>
                    }
                  />

                  {/* 404 Catch-all Route */}
                  <Route path="*" element={<NotFoundPage />} />
                </Routes>
              </Suspense>
            </div>
            <Toaster />
          </Router>
        </AuthProvider>
      </PersistQueryClientProvider>
    </ErrorBoundary>
  );
}

export default App;

import React from "react";
import ReactDOM from "react-dom/client";
import App from "./App"; // App completo com autentica├º├úo
import { ConfigProvider } from "@/lib/config-initializer";
import "./index.css";

// Debug: Log environment variables
if (import.meta.env.DEV) {
  console.warn('[Dev] Environment:', import.meta.env.MODE);
  console.warn('[Dev] API URL:', import.meta.env.VITE_API_BASE_URL);
  console.warn('[Dev] Firebase project:', import.meta.env['VITE_FIREBASE_PROJECT_ID']);
}

// Global error handling for unhandled promise rejections
window.addEventListener('unhandledrejection', (event) => {
  console.error('Unhandled promise rejection:', event.reason);
  
  // Prevent the default behavior (error overlay)
  event.preventDefault();
  
  // Check if it's a WebSocket or network error (non-critical)
  if (event.reason?.message?.includes('WebSocket') || 
      event.reason?.message?.includes('ws://') ||
      event.reason?.message?.includes('wss://') ||
      event.reason?.message?.includes('Failed to fetch') ||
      event.reason?.message?.includes('NetworkError')) {
    console.warn('Non-critical error handled gracefully:', event.reason.message);
    return;
  }
  
  // For other errors, log but don't show overlay
  console.error('Promise rejection handled:', event.reason);
});

const rootElement = document.getElementById("root");

if (!rootElement) {
  document.body.innerHTML = `
    <div style="display: flex; align-items: center; justify-content: center; height: 100vh; font-family: system-ui;">
      <div style="text-align: center;">
        <h1 style="color: red;">Erro: Elemento root n├úo encontrado</h1>
        <p>Por favor, verifique o arquivo index.html</p>
      </div>
    </div>
  `;
} else {
  ReactDOM.createRoot(rootElement).render( 
    <React.StrictMode>
      <ConfigProvider>
        <App />
      </ConfigProvider>
    </React.StrictMode>
  );
}

// Simple client types export to avoid import errors
export interface ApiResponse<T = any> {
  data: T
  status: number
  statusText: string
}

export interface ApiError {
  message: string
  status: number
  details?: any
}

// Placeholder for client types that may be needed
export type ClientResponse<T = any> = ApiResponse<T>
export type ClientError = ApiError

import React, { Component, ErrorInfo, ReactNode } from 'react'
import { AlertTriangle, RefreshCw } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { createLogger } from '../lib/logger'

const logger = createLogger('ErrorBoundary')

interface Props {
  children: ReactNode
  fallback?: React.ComponentType<{ error: Error; resetError: () => void }>
}

interface State {
  hasError: boolean
  error: Error | null
}

class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props)
    this.state = { hasError: false, error: null }
  }

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error }
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    logger.error('Error caught by boundary:', error, errorInfo)

    // Here you could send error to monitoring service
    // Example: Sentry.captureException(error, { contexts: { errorInfo } })
  }

  resetError = () => {
    this.setState({ hasError: false, error: null })
  }

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
        const FallbackComponent = this.props.fallback
        return <FallbackComponent error={this.state.error!} resetError={this.resetError} />
      }

      return <DefaultErrorFallback error={this.state.error!} resetError={this.resetError} />
    }

    return this.props.children
  }
}

interface DefaultErrorFallbackProps {
  error: Error
  resetError: () => void
}

function DefaultErrorFallback({ error, resetError }: DefaultErrorFallbackProps) {
  return (
    <div className="flex items-center justify-center min-h-screen p-4">
      <Card className="w-full max-w-md">
        <CardHeader className="text-center">
          <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-red-100">
            <AlertTriangle className="h-6 w-6 text-red-600" />
          </div>
          <CardTitle className="text-xl">Algo deu errado</CardTitle>
          <CardDescription>
            Ocorreu um erro inesperado. Nossa equipe foi notificada e est├í trabalhando para resolver.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <details className="text-sm">
            <summary className="cursor-pointer font-medium text-gray-700 hover:text-gray-900">
              Detalhes t├®cnicos
            </summary>
            <pre className="mt-2 whitespace-pre-wrap rounded bg-gray-100 p-2 text-xs">
              {error.message}
            </pre>
          </details>
          <div className="flex space-x-2">
            <Button onClick={resetError} className="flex-1">
              <RefreshCw className="mr-2 h-4 w-4" />
              Tentar novamente
            </Button>
            <Button 
              variant="outline" 
              onClick={() => window.location.reload()}
              className="flex-1"
            >
              Recarregar p├ígina
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}

// Export both named and default
export { ErrorBoundary }
export default ErrorBoundary

import React, { useState, useCallback } from 'react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import { Eye, EyeOff, Shield, AlertCircle, CheckCircle, Clock } from 'lucide-react'
import { Button } from '../ui/button'
import { Input } from '../ui/input'
import { Label } from '../ui/label'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card'
import { Alert, AlertDescription } from '../ui/alert'
import { Progress } from '../ui/progress'
import { Checkbox } from '../ui/checkbox'
import {
  AdminLoginCredentials,
  PasswordStrength,
  AdminLoginResponse,
  AdminAuthError
} from '../../types/admin'
import { createLogger } from '../../lib/logger'

const logger = createLogger('AdminLoginForm')

// Password strength validation
const calculatePasswordStrength = (password: string): PasswordStrength => {
  const score = (() => {
    if (password.length < 6) return 0

    let strength = 0

    // Length checks
    if (password.length >= 8) strength += 1
    if (password.length >= 12) strength += 1

    // Character type checks
    if (/[a-z]/.test(password)) strength += 1
    if (/[A-Z]/.test(password)) strength += 1
    if (/[0-9]/.test(password)) strength += 1
    if (/[^A-Za-z0-9]/.test(password)) strength += 1

    // Bonus for very long passwords
    if (password.length >= 16) strength += 1

    return Math.min(4, Math.max(0, strength - 1))
  })() as 0 | 1 | 2 | 3 | 4

  const feedback: string[] = []
  const suggestions: string[] = []

  if (password.length < 8) {
    feedback.push('Senha muito curta')
    suggestions.push('Use pelo menos 8 caracteres')
  }

  if (!/[a-z]/.test(password)) {
    feedback.push('Faltam letras min├║sculas')
    suggestions.push('Adicione letras min├║sculas')
  }

  if (!/[A-Z]/.test(password)) {
    feedback.push('Faltam letras mai├║sculas')
    suggestions.push('Adicione letras mai├║sculas')
  }

  if (!/[0-9]/.test(password)) {
    feedback.push('Faltam n├║meros')
    suggestions.push('Adicione n├║meros')
  }

  if (!/[^A-Za-z0-9]/.test(password)) {
    feedback.push('Faltam caracteres especiais')
    suggestions.push('Adicione caracteres especiais (!@#$%^&*)')
  }

  const isValid = score >= 3 && password.length >= 8

  return { score, feedback, suggestions, isValid }
}

// Validation schema
const adminLoginSchema = z.object({
  email: z
    .string()
    .min(1, 'Email ├® obrigat├│rio')
    .email('Formato de email inv├ílido'),
  password: z
    .string()
    .min(1, 'Senha ├® obrigat├│ria')
    .min(8, 'Senha deve ter pelo menos 8 caracteres'),
  twoFactorCode: z
    .string()
    .optional()
    .refine((code) => !code || /^\d{6}$/.test(code), {
      message: 'C├│digo 2FA deve ter 6 d├¡gitos'
    }),
  rememberMe: z.boolean().optional()
})

type AdminLoginFormData = z.infer<typeof adminLoginSchema>

interface AdminLoginFormProps {
  onLogin: (credentials: AdminLoginCredentials) => Promise<AdminLoginResponse>
  onForgotPassword?: (email: string) => void
  isLoading?: boolean
  requiresTwoFactor?: boolean
  lockoutTime?: number
  maxAttempts?: number
  currentAttempts?: number
}

export const AdminLoginForm: React.FC<AdminLoginFormProps> = ({
  onLogin,
  onForgotPassword,
  isLoading = false,
  requiresTwoFactor = false,
  lockoutTime = 0,
  maxAttempts = 5,
  currentAttempts = 0
}) => {
  const [showPassword, setShowPassword] = useState(false)
  const [passwordStrength, setPasswordStrength] = useState<PasswordStrength | null>(null)
  const [loginError, setLoginError] = useState<string | null>(null)
  const [isLocked, setIsLocked] = useState(lockoutTime > 0)
  const [timeRemaining, setTimeRemaining] = useState(lockoutTime)

  const {
    register,
    handleSubmit,
    watch,
    formState: { errors, isSubmitting },
    setValue,
    clearErrors
  } = useForm<AdminLoginFormData>({
    resolver: zodResolver(adminLoginSchema),
    defaultValues: {
      email: '',
      password: '',
      twoFactorCode: '',
      rememberMe: false
    }
  })

  const watchedPassword = watch('password')
  const watchedEmail = watch('email')

  // Update password strength when password changes
  React.useEffect(() => {
    if (watchedPassword) {
      setPasswordStrength(calculatePasswordStrength(watchedPassword))
    } else {
      setPasswordStrength(null)
    }
  }, [watchedPassword])

  // Lockout timer
  React.useEffect(() => {
    if (timeRemaining > 0) {
      const timer = setTimeout(() => {
        setTimeRemaining(time => {
          const newTime = time - 1
          if (newTime <= 0) {
            setIsLocked(false)
            return 0
          }
          return newTime
        })
      }, 1000)

      return () => clearTimeout(timer)
    }
    // Return undefined when timeRemaining <= 0
    return undefined
  }, [timeRemaining])

  const formatLockoutTime = (seconds: number): string => {
    const minutes = Math.floor(seconds / 60)
    const remainingSeconds = seconds % 60
    return `${minutes}:${remainingSeconds.toString().padStart(2, '0')}`
  }

  const getPasswordStrengthColor = (score: number): string => {
    switch (score) {
      case 0:
      case 1:
        return 'bg-red-500'
      case 2:
        return 'bg-yellow-500'
      case 3:
        return 'bg-blue-500'
      case 4:
        return 'bg-green-500'
      default:
        return 'bg-gray-300'
    }
  }

  const getPasswordStrengthText = (score: number): string => {
    switch (score) {
      case 0:
        return 'Muito Fraca'
      case 1:
        return 'Fraca'
      case 2:
        return 'Razo├ível'
      case 3:
        return 'Boa'
      case 4:
        return 'Forte'
      default:
        return 'Desconhecida'
    }
  }

  const onSubmit = useCallback(async (data: AdminLoginFormData) => {
    if (isLocked) return

    try {
      setLoginError(null)
      clearErrors()

      const response = await onLogin({
        email: data['email'],
        password: data['password'],
        ...(data.twoFactorCode ? { twoFactorCode: data.twoFactorCode } : {}),
        ...(data.rememberMe !== undefined ? { rememberMe: data.rememberMe } : {})
      })

      if (!response.success) {
        throw new AdminAuthError(response.error || 'Falha no login')
      }
    } catch (error) {
      logger.error('Login error', { error })

      if (error instanceof AdminAuthError) {
        setLoginError(error.message)

        // Handle account lockout
        if (error.code === 'ACCOUNT_LOCKED') {
          setIsLocked(true)
          setTimeRemaining(lockoutTime)
        }
      } else {
        setLoginError('Ocorreu um erro inesperado. Tente novamente.')
      }
    }
  }, [onLogin, isLocked, clearErrors, lockoutTime])

  const handleForgotPassword = useCallback(() => {
    if (onForgotPassword && watchedEmail) {
      onForgotPassword(watchedEmail)
    }
  }, [onForgotPassword, watchedEmail])

  const remainingAttempts = maxAttempts - currentAttempts

  return (
    <div className="flex min-h-screen items-center justify-center bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
      <Card className="w-full max-w-md">
        <CardHeader className="space-y-1">
          <div className="flex items-center justify-center mb-4">
            <Shield className="h-12 w-12 text-blue-600" />
          </div>
          <CardTitle className="text-2xl text-center">Portal Administrativo</CardTitle>
          <CardDescription className="text-center">
            Entre para acessar o painel administrativo
          </CardDescription>
        </CardHeader>

        <CardContent className="space-y-4">
          {/* Account Lockout Warning */}
          {isLocked && (
            <Alert className="border-red-200 bg-red-50">
              <Clock className="h-4 w-4 text-red-600" />
              <AlertDescription className="text-red-800">
                Conta temporariamente bloqueada devido a m├║ltiplas tentativas de login falhadas.
                <br />
                Tente novamente em: {formatLockoutTime(timeRemaining)}
              </AlertDescription>
            </Alert>
          )}

          {/* Login Error */}
          {loginError && (
            <Alert className="border-red-200 bg-red-50">
              <AlertCircle className="h-4 w-4 text-red-600" />
              <AlertDescription className="text-red-800">
                {loginError}
              </AlertDescription>
            </Alert>
          )}

          {/* Remaining Attempts Warning */}
          {!isLocked && remainingAttempts <= 2 && remainingAttempts > 0 && (
            <Alert className="border-yellow-200 bg-yellow-50">
              <AlertCircle className="h-4 w-4 text-yellow-600" />
              <AlertDescription className="text-yellow-800">
                Aviso: {remainingAttempts} {remainingAttempts !== 1 ? 'tentativas de login restantes' : 'tentativa de login restante'}
              </AlertDescription>
            </Alert>
          )}

          <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
            {/* Email Field */}
            <div className="space-y-2">
              <Label htmlFor="email">Endere├ºo de Email</Label>
              <Input
                id="email"
                type="email"
                autoComplete="email"
                disabled={isLocked || isLoading || isSubmitting}
                {...register('email')}
                className={errors['email'] ? 'border-red-500' : ''}
              />
              {errors['email'] && (
                <p className="text-sm text-red-600">{errors['email'].message}</p>
              )}
            </div>

            {/* Password Field */}
            <div className="space-y-2">
              <Label htmlFor="password">Senha</Label>
              <div className="relative">
                <Input
                  id="password"
                  type={showPassword ? 'text' : 'password'}
                  autoComplete="current-password"
                  disabled={isLocked || isLoading || isSubmitting}
                  {...register('password')}
                  className={errors['password'] ? 'border-red-500 pr-10' : 'pr-10'}
                />
                <button
                  type="button"
                  className="absolute inset-y-0 right-0 pr-3 flex items-center"
                  onClick={() => setShowPassword(!showPassword)}
                  disabled={isLocked || isLoading || isSubmitting}
                >
                  {showPassword ? (
                    <EyeOff className="h-4 w-4 text-gray-400" />
                  ) : (
                    <Eye className="h-4 w-4 text-gray-400" />
                  )}
                </button>
              </div>
              {errors['password'] && (
                <p className="text-sm text-red-600">{errors['password'].message}</p>
              )}

              {/* Password Strength Indicator */}
              {passwordStrength && watchedPassword && (
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <span className="text-xs text-gray-600">For├ºa da Senha:</span>
                    <span className={`text-xs font-medium ${
                      passwordStrength.score >= 3 ? 'text-green-600' :
                      passwordStrength.score >= 2 ? 'text-yellow-600' : 'text-red-600'
                    }`}>
                      {getPasswordStrengthText(passwordStrength.score)}
                    </span>
                  </div>
                  <Progress
                    value={(passwordStrength.score / 4) * 100}
                    className={`h-2 ${getPasswordStrengthColor(passwordStrength.score)}`}
                  />
                  {passwordStrength.feedback.length > 0 && (
                    <div className="text-xs text-gray-600">
                      {passwordStrength.suggestions.join(', ')}
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* Two-Factor Authentication Code */}
            {requiresTwoFactor && (
              <div className="space-y-2">
                <Label htmlFor="twoFactorCode">C├│digo 2FA</Label>
                <Input
                  id="twoFactorCode"
                  type="text"
                  placeholder="000000"
                  maxLength={6}
                  autoComplete="one-time-code"
                  disabled={isLocked || isLoading || isSubmitting}
                  {...register('twoFactorCode')}
                  className={errors.twoFactorCode ? 'border-red-500' : ''}
                />
                {errors.twoFactorCode && (
                  <p className="text-sm text-red-600">{errors.twoFactorCode.message}</p>
                )}
              </div>
            )}

            {/* Remember Me */}
            <div className="flex items-center space-x-2">
              <Checkbox
                id="rememberMe"
                disabled={isLocked || isLoading || isSubmitting}
                onCheckedChange={(checked) => setValue('rememberMe', !!checked)}
              />
              <Label htmlFor="rememberMe" className="text-sm text-gray-600">
                Lembrar-me por 30 dias
              </Label>
            </div>

            {/* Submit Button */}
            <Button
              type="submit"
              className="w-full"
              disabled={isLocked || isLoading || isSubmitting}
            >
              {isSubmitting ? (
                <div className="flex items-center space-x-2">
                  <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
                  <span>Entrando...</span>
                </div>
              ) : (
                'Entrar'
              )}
            </Button>

            {/* Forgot Password */}
            {onForgotPassword && (
              <div className="text-center">
                <button
                  type="button"
                  onClick={handleForgotPassword}
                  disabled={!watchedEmail || isLocked || isLoading}
                  className="text-sm text-blue-600 hover:text-blue-500 disabled:text-gray-400 disabled:cursor-not-allowed"
                >
                  Esqueceu sua senha?
                </button>
              </div>
            )}
          </form>

          {/* Security Notice */}
          <div className="mt-6 p-3 bg-gray-50 rounded-md">
            <div className="flex items-start space-x-2">
              <CheckCircle className="h-4 w-4 text-green-600 mt-0.5 flex-shrink-0" />
              <div className="text-xs text-gray-600">
                <p className="font-medium">Login Seguro</p>
                <ul className="mt-1 space-y-1">
                  <li>ÔÇó Criptografia ponta a ponta</li>
                  <li>ÔÇó Monitoramento de sess├úo</li>
                  <li>ÔÇó Prote├º├úo contra tentativas falhadas</li>
                </ul>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}

