                {...(dateRange.to ? { to: dateRange.to } : {})}
                onSelect={(range) => {
                  if (range) {
                    const newRange: { from?: Date; to?: Date } = {}
                    if (range.from) newRange.from = range.from
                    if (range.to) newRange.to = range.to
                    setDateRange(newRange)
                  } else {
