                <TableHead>User</TableHead>
                <TableHead>Resource</TableHead>
                <TableHead>Location</TableHead>
                <TableHead>Risk</TableHead>
                <TableHead>Timestamp</TableHead>
                <TableHead className="w-[50px]"></TableHead>
