export function RoleAssignmentModal({ open, onOpenChange, user }: RoleAssignmentModalProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [selectedRole, setSelectedRole] = useState<string>("doctor");
  const [selectedPermissions, setSelectedPermissions] = useState<string[]>([]);
  const [hasChanges, setHasChanges] = useState(false);

  // Load user data when user changes
  useEffect(() => {
    if (user) {
      setSelectedRole(user["role"]);
      setSelectedPermissions(user.permissions);
      setHasChanges(false);
    }
  }, [user]);

  // Track changes
  useEffect(() => {
    if (!user) return;

    const roleChanged = selectedRole !== user["role"];
    const permissionsChanged =
      selectedPermissions.length !== user.permissions.length ||
      selectedPermissions.some((p) => !user.permissions.includes(p)) ||
      user.permissions.some((p) => !selectedPermissions.includes(p));

    setHasChanges(roleChanged || permissionsChanged);
  }, [selectedRole, selectedPermissions, user]);

  const updateRoleMutation = useMutation({
    mutationFn: async ({ id, role }: { id: string; role: string }) => {
      return apiClient.adminUsers.updateRole(id, role);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-users"] });
      queryClient.invalidateQueries({ queryKey: ["admin-user", user?.id] });
      toast({
        title: "Fun├º├úo atualizada com sucesso",
        description: "A fun├º├úo do usu├írio foi alterada.",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Erro ao atualizar fun├º├úo",
        description: error.data?.message || "Ocorreu um erro inesperado.",
        variant: "destructive",
      });
    },
  });

  const updatePermissionsMutation = useMutation({
    mutationFn: async ({ id, permissions }: { id: string; permissions: string[] }) => {
      // WARNING: Backend endpoint is currently a placeholder and doesn't persist permissions
      // TODO: Implement actual permissions storage in backend (see backend-hormonia/app/api/v2/admin/users.py:830-885)
      return apiClient.adminUsers.updatePermissions(id, permissions);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-users"] });
      queryClient.invalidateQueries({ queryKey: ["admin-user", user?.id] });
      toast({
        title: "ÔÜá´©Å Permiss├Áes atualizadas (tempor├írio)",
        description: "Nota: Backend ainda n├úo persiste permiss├Áes. Implementa├º├úo pendente.",
        variant: "default",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Erro ao atualizar permiss├Áes",
        description: error.data?.message || "Ocorreu um erro inesperado.",
        variant: "destructive",
      });
    },
  });

  const handleRoleChange = (role: string) => {
    setSelectedRole(role);
    const roleTemplate = ROLE_TEMPLATES[role as RoleKey];
    if (roleTemplate) {
      setSelectedPermissions(roleTemplate.permissions);
    }
  };

  const togglePermission = (permissionId: string) => {
    setSelectedPermissions((prev) =>
      prev.includes(permissionId)
        ? prev.filter((p) => p !== permissionId)
        : [...prev, permissionId],
    );
  };

  const toggleGroupPermissions = (group: PermissionGroup, enable: boolean) => {
    const groupPermissionIds = group.permissions.map((p) => p.id);

    if (enable) {
      setSelectedPermissions((prev) => [
        ...prev.filter((p) => !groupPermissionIds.includes(p)),
        ...groupPermissionIds,
      ]);
    } else {
      setSelectedPermissions((prev) => prev.filter((p) => !groupPermissionIds.includes(p)));
    }
  };

  const handleSave = async () => {
    if (!user) return;

    try {
      // Update role if changed
      if (selectedRole !== user["role"]) {
        await updateRoleMutation.mutateAsync({ id: user["id"], role: selectedRole });
      }

      // Update permissions if changed
      const permissionsChanged =
        selectedPermissions.length !== user.permissions.length ||
        selectedPermissions.some((p) => !user.permissions.includes(p)) ||
        user.permissions.some((p) => !selectedPermissions.includes(p));

      if (permissionsChanged) {
        await updatePermissionsMutation.mutateAsync({
          id: user["id"],
          permissions: selectedPermissions,
        });
      }

      onOpenChange(false);
    } catch (error) {
      // Errors are handled by the mutations
    }
  };

  const getPermissionLevelBadge = (level: "read" | "write" | "admin") => {
    const variants = {
      read: { variant: "secondary" as const, label: "Leitura" },
      write: { variant: "default" as const, label: "Escrita" },
      admin: { variant: "destructive" as const, label: "Admin" },
    };

    const { variant, label } = variants[level];
    return (
      <Badge variant={variant} className="text-xs">
        {label}
      </Badge>
    );
  };

  const isGroupFullySelected = (group: PermissionGroup) => {
    return group.permissions.every((p) => selectedPermissions.includes(p.id));
  };

  const isGroupPartiallySelected = (group: PermissionGroup) => {
    const selectedInGroup = group.permissions.filter((p) => selectedPermissions.includes(p.id));
    return selectedInGroup.length > 0 && selectedInGroup.length < group.permissions.length;
  };

  if (!user) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[800px] max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Gerenciar Fun├º├úo e Permiss├Áes</DialogTitle>
          <DialogDescription>
            Atribua fun├º├úo e permiss├Áes espec├¡ficas para {user["full_name"]}
          </DialogDescription>
        </DialogHeader>

        <Tabs defaultValue="role" className="space-y-4">
          <TabsList className="grid w-full grid-cols-2">
            <TabsTrigger value="role">Fun├º├úo</TabsTrigger>
            <TabsTrigger value="permissions">Permiss├Áes Detalhadas</TabsTrigger>
          </TabsList>

          <TabsContent value="role" className="space-y-4">
            <div className="space-y-4">
              <div>
                <Label>Fun├º├úo do Usu├írio</Label>
                <p className="text-sm text-muted-foreground">
                  Selecione uma fun├º├úo que define automaticamente as permiss├Áes b├ísicas
                </p>
              </div>

              <Select value={selectedRole} onValueChange={handleRoleChange}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="admin">Administrador</SelectItem>
                  <SelectItem value="doctor">M├®dico</SelectItem>
                </SelectContent>
              </Select>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {Object.entries(ROLE_TEMPLATES).map(([roleKey, template]) => (
                  <Card
                    key={roleKey}
                    className={`cursor-pointer transition-colors ${
                      selectedRole === roleKey ? "border-blue-500 bg-blue-50" : "hover:bg-gray-50"
                    }`}
                    onClick={() => handleRoleChange(roleKey)}
                  >
                    <CardHeader className="pb-3">
                      <CardTitle className="text-base">{template.name}</CardTitle>
                      <CardDescription className="text-sm">{template.description}</CardDescription>
                    </CardHeader>
                    <CardContent className="pt-0">
                      <div className="flex justify-between items-center">
                        <Badge variant="outline">{template.permissions.length} permiss├Áes</Badge>
                        {selectedRole === roleKey && (
                          <Badge className="bg-blue-600">Selecionado</Badge>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>

              <Alert>
                <Shield className="h-4 w-4" />
                <AlertDescription>
                  <strong>Fun├º├úo Atual:</strong>{" "}
                  {ROLE_TEMPLATES[selectedRole as RoleKey]?.name || "N├úo definido"}
                  <br />
                  Esta fun├º├úo inclui {selectedPermissions.length} permiss├Áes automaticamente.
                </AlertDescription>
              </Alert>
            </div>
          </TabsContent>

          <TabsContent value="permissions" className="space-y-4">
            <div className="space-y-4">
              <div>
                <Label>Permiss├Áes Espec├¡ficas</Label>
                <p className="text-sm text-muted-foreground">
                  Personalize as permiss├Áes espec├¡ficas para este usu├írio
                </p>
              </div>

              <div className="space-y-6">
                {PERMISSION_GROUPS.map((group) => {
                  const isFullySelected = isGroupFullySelected(group);
                  const isPartiallySelected = isGroupPartiallySelected(group);

                  return (
                    <Card key={group.id}>
                      <CardHeader className="pb-3">
                        <div className="flex items-center justify-between">
                          <div className="flex items-center gap-2">
                            {group.icon}
                            <CardTitle className="text-base">{group.name}</CardTitle>
                          </div>
                          <div className="flex items-center gap-2">
                            <Badge variant="outline">
                              {
                                group.permissions.filter((p) => selectedPermissions.includes(p.id))
                                  .length
                              }
                              /{group.permissions.length}
                            </Badge>
                            <Checkbox
                              checked={isFullySelected}
                              ref={(el) => {
                                if (el) {
                                  const element = el as any;
                                  (element as any).indeterminate = isPartiallySelected;
                                }
                              }}
                              onCheckedChange={(checked) =>
                                toggleGroupPermissions(group, !!checked)
                              }
                            />
                          </div>
                        </div>
                        <CardDescription>{group.description}</CardDescription>
                      </CardHeader>
                      <CardContent className="pt-0">
                        <div className="space-y-3">
                          {group.permissions.map((permission) => (
                            <div
                              key={permission.id}
                              className="flex items-center justify-between p-3 border rounded-lg"
                            >
                              <div className="flex items-center space-x-3">
                                <Checkbox
                                  checked={selectedPermissions.includes(permission.id)}
                                  onCheckedChange={() => togglePermission(permission.id)}
                                />
                                <div className="flex-1">
                                  <div className="flex items-center gap-2">
                                    <span className="font-medium text-sm">{permission.name}</span>
                                    {getPermissionLevelBadge(permission.level)}
                                  </div>
                                  <p className="text-xs text-muted-foreground mt-1">
                                    {permission.description}
                                  </p>
                                </div>
                              </div>
                            </div>
                          ))}
                        </div>
                      </CardContent>
                    </Card>
                  );
                })}
              </div>

              <Card>
                <CardHeader>
                  <CardTitle className="text-base">Resumo das Permiss├Áes</CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="flex flex-wrap gap-2">
                    {selectedPermissions.length > 0 ? (
                      selectedPermissions.map((permission) => (
                        <Badge key={permission} variant="outline" className="text-xs">
                          {permission}
                        </Badge>
                      ))
                    ) : (
                      <p className="text-sm text-muted-foreground">Nenhuma permiss├úo selecionada</p>
                    )}
                  </div>
                </CardContent>
              </Card>
            </div>
          </TabsContent>
        </Tabs>

        <DialogFooter>
          <Button
            variant="outline"
            onClick={() => onOpenChange(false)}
            disabled={updateRoleMutation.isPending || updatePermissionsMutation.isPending}
          >
            Cancelar
          </Button>
          <Button
            onClick={handleSave}
            disabled={
              !hasChanges || updateRoleMutation.isPending || updatePermissionsMutation.isPending
            }
          >
            {updateRoleMutation.isPending || updatePermissionsMutation.isPending ? (
              <>
                <LoadingSpinner size="sm" className="mr-2" />
                Salvando...
              </>
            ) : (
              <>
                <Save className="h-4 w-4 mr-2" />
                Salvar Altera├º├Áes
              </>
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import React, { useState, useMemo } from 'react'
import { Plus, Search, Filter, Users, UserCheck, UserX, AlertTriangle } from 'lucide-react'
import { useQuery } from '@tanstack/react-query'
import { useUserAdmin } from '@/hooks/useUserAdmin'
import { useAuth } from '@/contexts/AuthContext'
import { AdminUser, AdminUserActivity } from '@/types/admin'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Checkbox } from '@/components/ui/checkbox'
import { LoadingSpinner } from '@/components/ui/loading-spinner'
import { UsersTable } from './users/UsersTable'
import { UserCreateModal } from './UserCreateModal'
import { UserEditModal } from './UserEditModal'
import { UserDetailsPanel } from './UserDetailsPanel'
import { RoleAssignmentModal } from './RoleAssignmentModal'
import { PermissionGuard } from './PermissionGuard'
import { createLogger } from '../../lib/logger'

const logger = createLogger('UserAdminDashboard')

interface FilterState {
  search: string
  role: string
  status: string
  twoFactor: string
  dateRange: {
    from: Date | null
    to: Date | null
  }
}

export function UserAdminDashboard() {
  const { hasPermission } = useAuth()
  const { users, stats, bulkActivate, bulkDeactivate, isLoading } = useUserAdmin()

  // Modal states
  const [showCreateModal, setShowCreateModal] = useState(false)
  const [showEditModal, setShowEditModal] = useState(false)
  const [showDetailsPanel, setShowDetailsPanel] = useState(false)
  const [showRoleModal, setShowRoleModal] = useState(false)
  const [selectedUser, setSelectedUser] = useState<AdminUser | null>(null)

  // Filter and pagination states
  const [filters, setFilters] = useState<FilterState>({
    search: '',
    role: 'all',
    status: 'all',
    twoFactor: 'all',
    dateRange: { from: null, to: null }
  })
  const [currentPage, setCurrentPage] = useState(1)
  const [selectedUsers, setSelectedUsers] = useState<string[]>([])
  const [sortBy, setSortBy] = useState('created_at')
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc')

  // Filtered and sorted users
  const filteredUsers = useMemo(() => {
    if (!users) return [] as AdminUser[]

    return users.filter((user: AdminUser) => {
      // Search filter
      if (filters.search) {
        const searchLower = filters.search.toLowerCase()
        const matchesSearch =
          user.full_name.toLowerCase().includes(searchLower) ||
          user.email.toLowerCase().includes(searchLower)
        if (!matchesSearch) return false
      }

      // Role filter
      if (filters.role !== 'all' && user.role !== filters.role) return false

      // Status filter
      if (filters.status === 'active' && !user.is_active) return false
      if (filters.status === 'inactive' && user.is_active) return false
      if (filters.status === 'locked' && (!user.locked_until || new Date(user.locked_until) <= new Date())) return false

      // Two factor filter
      if (filters.twoFactor === 'enabled' && !user.two_factor_enabled) return false
      if (filters.twoFactor === 'disabled' && user.two_factor_enabled) return false

      return true
    }).sort((a: AdminUser, b: AdminUser) => {
      let aVal = a[sortBy as keyof AdminUser] as unknown as string | number | null | undefined
      let bVal = b[sortBy as keyof AdminUser] as unknown as string | number | null | undefined

      // Handle date sorting
      if (sortBy === 'created_at' || sortBy === 'last_login') {
        aVal = aVal ? new Date(aVal as any).getTime() : 0
        bVal = bVal ? new Date(bVal as any).getTime() : 0
      }

      // Normalize values for comparison
      if (typeof aVal === 'string') {
        aVal = aVal.toLowerCase()
      } else if (typeof aVal !== 'number') {
        aVal = ''
      }

      if (typeof bVal === 'string') {
        bVal = bVal.toLowerCase()
      } else if (typeof bVal !== 'number') {
        bVal = ''
      }

      if (sortOrder === 'asc') {
        return (aVal as any) > (bVal as any) ? 1 : -1
      } else {
        return (aVal as any) < (bVal as any) ? 1 : -1
      }
    })
  }, [users, filters, sortBy, sortOrder])

  // Pagination
  const itemsPerPage = 10
  const totalPages = Math.ceil(filteredUsers.length / itemsPerPage)
  const paginatedUsers = filteredUsers.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  )

  // Handlers
  const handleViewUser = (user: AdminUser) => {
    setSelectedUser(user)
    setShowDetailsPanel(true)
  }

  const handleEditUser = (user: AdminUser) => {
    setSelectedUser(user)
    setShowEditModal(true)
  }

  const handleAssignRole = (user: AdminUser) => {
    setSelectedUser(user)
    setShowRoleModal(true)
  }

  const handleBulkAction = async (action: 'activate' | 'deactivate') => {
    if (selectedUsers.length === 0) return

    try {
      if (action === 'activate') {
        await bulkActivate(selectedUsers)
      } else {
        await bulkDeactivate(selectedUsers)
      }
      setSelectedUsers([])
    } catch (error) {
      logger.error('Bulk action failed', { error, action, selectedUsers })
    }
  }

  const toggleUserSelection = (userId: string) => {
    setSelectedUsers(prev =>
      prev.includes(userId)
        ? prev.filter(id => id !== userId)
        : [...prev, userId]
    )
  }

  const toggleAllUsers = () => {
    if (selectedUsers.length === paginatedUsers.length) {
      setSelectedUsers([])
    } else {
      setSelectedUsers(paginatedUsers.map((user: AdminUser) => user.id))
    }
  }

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Gerenciamento de Usu├írios</h1>
          <p className="text-muted-foreground">
            Gerencie usu├írios do sistema, permiss├Áes e configura├º├Áes de seguran├ºa
          </p>
        </div>
        <PermissionGuard permissions={['admin.users.create']}>
          <Button onClick={() => setShowCreateModal(true)}>
            <Plus className="h-4 w-4 mr-2" />
            Novo Usu├írio
          </Button>
        </PermissionGuard>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total de Usu├írios</CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats?.users.total || 0}</div>
            <p className="text-xs text-muted-foreground">
              +{stats?.users.new_today || 0} hoje
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Usu├írios Ativos</CardTitle>
            <UserCheck className="h-4 w-4 text-green-600" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats?.users.active || 0}</div>
            <p className="text-xs text-muted-foreground">
              {stats?.users.total ? Math.round((stats.users.active / stats.users.total) * 100) : 0}% do total
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Usu├írios Bloqueados</CardTitle>
            <UserX className="h-4 w-4 text-red-600" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats?.users.locked || 0}</div>
            <p className="text-xs text-muted-foreground">
              Requer aten├º├úo
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Tentativas de Login Falhadas</CardTitle>
            <AlertTriangle className="h-4 w-4 text-orange-600" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats?.security.failed_logins || 0}</div>
            <p className="text-xs text-muted-foreground">
              ├Ültimas 24h
            </p>
          </CardContent>
        </Card>
      </div>

      {/* Filters and Search */}
      <Card>
        <CardContent className="pt-6">
          <div className="flex flex-col md:flex-row gap-4">
            {/* Search */}
            <div className="flex-1">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-4 w-4" />
                <Input
                  placeholder="Buscar por nome ou email..."
                  value={filters.search}
                  onChange={(e) => setFilters(prev => ({ ...prev, search: e.target.value }))}
                  className="pl-10"
                />
              </div>
            </div>

            {/* Role Filter */}
            <Select value={filters.role} onValueChange={(value) => setFilters(prev => ({ ...prev, role: value }))}>
              <SelectTrigger className="w-[180px]">
                <SelectValue placeholder="Filtrar por fun├º├úo" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todas as fun├º├Áes</SelectItem>
                <SelectItem value="doctor">M├®dico</SelectItem>
                <SelectItem value="admin">Administrador</SelectItem>
              </SelectContent>
            </Select>

            {/* Status Filter */}
            <Select value={filters.status} onValueChange={(value) => setFilters(prev => ({ ...prev, status: value }))}>
              <SelectTrigger className="w-[180px]">
                <SelectValue placeholder="Filtrar por status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todos os status</SelectItem>
                <SelectItem value="active">Ativo</SelectItem>
                <SelectItem value="inactive">Inativo</SelectItem>
                <SelectItem value="locked">Bloqueado</SelectItem>
              </SelectContent>
            </Select>

            {/* 2FA Filter */}
            <Select value={filters.twoFactor} onValueChange={(value) => setFilters(prev => ({ ...prev, twoFactor: value }))}>
              <SelectTrigger className="w-[180px]">
                <SelectValue placeholder="Filtrar por 2FA" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todos</SelectItem>
                <SelectItem value="enabled">2FA Ativo</SelectItem>
                <SelectItem value="disabled">2FA Inativo</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </CardContent>
      </Card>

      {/* Bulk Actions */}
      {selectedUsers.length > 0 && (
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Badge variant="secondary">
                  {selectedUsers.length} usu├írio(s) selecionado(s)
                </Badge>
              </div>
              <div className="flex gap-2">
                <PermissionGuard permissions={['admin.users.update']}>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => handleBulkAction('activate')}
                  >
                    Ativar Selecionados
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => handleBulkAction('deactivate')}
                  >
                    Desativar Selecionados
                  </Button>
                </PermissionGuard>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Users Table */}
      <Card>
        <CardContent className="pt-6">
          <div className="space-y-4">
            {/* Table Header with Bulk Select */}
            <div className="flex items-center gap-2">
              <Checkbox
                checked={selectedUsers.length === paginatedUsers.length && paginatedUsers.length > 0}
                onCheckedChange={toggleAllUsers}
              />
              <span className="text-sm text-muted-foreground">
                Selecionar todos ({paginatedUsers.length})
              </span>
            </div>

            <UsersTable
              users={paginatedUsers}
              currentPage={currentPage}
              totalPages={totalPages}
              onPageChange={setCurrentPage}
              onViewUser={handleViewUser}
              onEditUser={handleEditUser}
              selectedUsers={selectedUsers}
              onToggleUserSelection={toggleUserSelection}
              sortBy={sortBy}
              sortOrder={sortOrder}
              onSort={(field) => {
                if (sortBy === field) {
                  setSortOrder(prev => prev === 'asc' ? 'desc' : 'asc')
                } else {
                  setSortBy(field)
                  setSortOrder('asc')
                }
              }}
            />
          </div>
        </CardContent>
      </Card>

      {/* Modals */}
      <UserCreateModal
        open={showCreateModal}
        onOpenChange={setShowCreateModal}
      />

      <UserEditModal
        open={showEditModal}
        onOpenChange={setShowEditModal}
        user={selectedUser}
      />

      <UserDetailsPanel
        open={showDetailsPanel}
        onOpenChange={setShowDetailsPanel}
        user={selectedUser}
        onEdit={handleEditUser}
        onAssignRole={handleAssignRole}
      />

      <RoleAssignmentModal
        open={showRoleModal}
        onOpenChange={setShowRoleModal}
        user={selectedUser}
      />
    </div>
  )
}

import React, { useState } from 'react'
import { useMutation, useQueryClient } from '@tanstack/react-query'
import { Eye, EyeOff, AlertCircle, Check } from 'lucide-react'
import { apiClient } from '@/lib/api-client'
import { AdminUser } from '@/types/admin'
import { UserRole } from '@/types/shared'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Switch } from '@/components/ui/switch'
import { Badge } from '@/components/ui/badge'
import { Alert, AlertDescription } from '@/components/ui/alert'
import { useToast } from '@/components/ui/use-toast'
import { LoadingSpinner } from '@/components/ui/loading-spinner'

interface UserCreateModalProps {
  open: boolean
  onOpenChange: (open: boolean) => void
}

interface CreateUserForm {
  email: string
  full_name: string
  password: string
  confirm_password: string
  role: string
  permissions: string[]
  is_active: boolean
  two_factor_enabled: boolean
  notes?: string
}

const AVAILABLE_PERMISSIONS = [
  { id: 'admin.users.create', label: 'Criar Usu├írios', category: 'Usu├írios' },
  { id: 'admin.users.read', label: 'Visualizar Usu├írios', category: 'Usu├írios' },
  { id: 'admin.users.update', label: 'Editar Usu├írios', category: 'Usu├írios' },
  { id: 'admin.users.delete', label: 'Excluir Usu├írios', category: 'Usu├írios' },
  { id: 'admin.patients.create', label: 'Criar Pacientes', category: 'Pacientes' },
  { id: 'admin.patients.read', label: 'Visualizar Pacientes', category: 'Pacientes' },
  { id: 'admin.patients.update', label: 'Editar Pacientes', category: 'Pacientes' },
  { id: 'admin.patients.delete', label: 'Excluir Pacientes', category: 'Pacientes' },
  { id: 'admin.flows.create', label: 'Criar Fluxos', category: 'Fluxos' },
  { id: 'admin.flows.read', label: 'Visualizar Fluxos', category: 'Fluxos' },
  { id: 'admin.flows.update', label: 'Editar Fluxos', category: 'Fluxos' },
  { id: 'admin.flows.delete', label: 'Excluir Fluxos', category: 'Fluxos' },
  { id: 'admin.settings.read', label: 'Visualizar Configura├º├Áes', category: 'Sistema' },
  { id: 'admin.settings.update', label: 'Editar Configura├º├Áes', category: 'Sistema' },
  { id: 'admin.audit.read', label: 'Visualizar Auditoria', category: 'Sistema' },
  { id: 'admin.analytics.read', label: 'Visualizar Analytics', category: 'Sistema' },
]

export function UserCreateModal({ open, onOpenChange }: UserCreateModalProps) {
  const { toast } = useToast()
  const queryClient = useQueryClient()

  const [form, setForm] = useState<CreateUserForm>({
    email: '',
    full_name: '',
    password: '',
    confirm_password: '',
    role: 'admin',
    permissions: [],
    is_active: true,
    two_factor_enabled: false,
    notes: ''
  })

  const [showPassword, setShowPassword] = useState(false)
  const [showConfirmPassword, setShowConfirmPassword] = useState(false)
  const [validationErrors, setValidationErrors] = useState<Record<string, string>>({})

  const createUserMutation = useMutation({
    mutationFn: async (userData: Partial<AdminUser>) => {
      return apiClient.adminUsers.create(userData)
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-users'] })
      toast({
        title: 'Usu├írio criado com sucesso',
        description: 'O novo usu├írio foi adicionado ao sistema.',
      })
      onOpenChange(false)
      resetForm()
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao criar usu├írio',
        description: error.data?.message || 'Ocorreu um erro inesperado.',
        variant: 'destructive'
      })
    }
  })

  const resetForm = () => {
    setForm({
      email: '',
      full_name: '',
      password: '',
      confirm_password: '',
      role: 'admin',
      permissions: [],
      is_active: true,
      two_factor_enabled: false,
      notes: ''
    })
    setValidationErrors({})
  }

  const validateForm = (): boolean => {
    const errors: Record<string, string> = {}

    // Email validation
    if (!form['email']) {
      errors['email'] = 'Email ├® obrigat├│rio'
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form['email'])) {
      errors['email'] = 'Email inv├ílido'
    }

    // Name validation
    if (!form['full_name'].trim()) {
      errors['full_name'] = 'Nome completo ├® obrigat├│rio'
    } else if (form['full_name'].trim().length < 2) {
      errors['full_name'] = 'Nome deve ter pelo menos 2 caracteres'
    }

    // Password validation
    if (!form['password']) {
      errors['password'] = 'Senha ├® obrigat├│ria'
    } else if (form['password'].length < 8) {
      errors['password'] = 'Senha deve ter pelo menos 8 caracteres'
    } else if (!/(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/.test(form['password'])) {
      errors['password'] = 'Senha deve conter pelo menos uma letra min├║scula, uma mai├║scula e um n├║mero'
    }

    // Confirm password validation
    if (form['password'] !== form['confirm_password']) {
      errors['confirm_password'] = 'Senhas n├úo coincidem'
    }

    // Role validation
    if (!form['role']) {
      errors['role'] = 'Fun├º├úo ├® obrigat├│ria'
    }

    setValidationErrors(errors)
    return Object.keys(errors).length === 0
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()

    if (!validateForm()) return

    const userData = {
      email: form['email'].trim(),
      full_name: form['full_name'].trim(),
      password: form['password'],
      role: form['role'],
      permissions: form.permissions,
      is_active: form.is_active,
      two_factor_enabled: form.two_factor_enabled,
      notes: form.notes?.trim() || undefined
    }

      // @ts-expect-error TODO: fix role type
    createUserMutation.mutate(userData)
  }

  const togglePermission = (permissionId: string) => {
    setForm(prev => ({
      ...prev,
      permissions: prev.permissions.includes(permissionId)
        ? prev.permissions.filter(p => p !== permissionId)
        : [...prev.permissions, permissionId]
    }))
  }

  const setRolePermissions = (role: 'doctor' | 'admin') => {
    let defaultPermissions: string[] = []

    if (role === 'admin') {
      defaultPermissions = [
        'admin.users.read',
        'admin.patients.create',
        'admin.patients.read',
        'admin.patients.update',
        'admin.flows.create',
        'admin.flows.read',
        'admin.flows.update',
        'admin.settings.read',
        'admin.analytics.read'
      ]
    } else if (role === 'doctor') {
      defaultPermissions = [
        'admin.patients.create',
        'admin.patients.read',
        'admin.patients.update',
        'admin.flows.read',
        'admin.analytics.read'
      ]
    }

    setForm(prev => ({
      ...prev,
      role,
      permissions: defaultPermissions
    }))
  }

  const getPasswordStrength = (password: string) => {
    let score = 0
    if (password.length >= 8) score++
    if (/[a-z]/.test(password)) score++
    if (/[A-Z]/.test(password)) score++
    if (/\d/.test(password)) score++
    if (/[^A-Za-z\d]/.test(password)) score++

    return { score, label: ['Muito Fraca', 'Fraca', 'Regular', 'Boa', 'Forte'][score] }
  }

  const passwordStrength = getPasswordStrength(form['password'])

  const permissionsByCategory = AVAILABLE_PERMISSIONS.reduce((acc, permission) => {
    if (!acc[permission.category]) {
      acc[permission.category] = []
    }
    // acc[permission.category] is guaranteed to exist now
    acc[permission.category]!.push(permission)
    return acc
  }, {} as Record<string, typeof AVAILABLE_PERMISSIONS>)

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[600px] max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Criar Novo Usu├írio</DialogTitle>
          <DialogDescription>
            Adicione um novo usu├írio ao sistema com as permiss├Áes adequadas.
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Basic Information */}
          <div className="space-y-4">
            <h3 className="text-sm font-medium text-gray-900">Informa├º├Áes B├ísicas</h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="email">Email *</Label>
                <Input
                  id="email"
                  type="email"
                  value={form['email']}
                  onChange={(e) => setForm(prev => ({ ...prev, email: e.target.value }))}
                  className={validationErrors['email'] ? 'border-red-500' : ''}
                />
                {validationErrors['email'] && (
                  <p className="text-sm text-red-600">{validationErrors['email']}</p>
                )}
              </div>

              <div className="space-y-2">
                <Label htmlFor="full_name">Nome Completo *</Label>
                <Input
                  id="full_name"
                  value={form['full_name']}
                  onChange={(e) => setForm(prev => ({ ...prev, full_name: e.target.value }))}
                  className={validationErrors['full_name'] ? 'border-red-500' : ''}
                />
                {validationErrors['full_name'] && (
                  <p className="text-sm text-red-600">{validationErrors['full_name']}</p>
                )}
              </div>
            </div>
          </div>

          {/* Password */}
          <div className="space-y-4">
            <h3 className="text-sm font-medium text-gray-900">Senha</h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="password">Senha *</Label>
                <div className="relative">
                  <Input
                    id="password"
                    type={showPassword ? 'text' : 'password'}
                    value={form['password']}
                    onChange={(e) => setForm(prev => ({ ...prev, password: e.target.value }))}
                    className={validationErrors['password'] ? 'border-red-500' : ''}
                  />
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                    onClick={() => setShowPassword(!showPassword)}
                  >
                    {showPassword ? (
                      <EyeOff className="h-4 w-4" />
                    ) : (
                      <Eye className="h-4 w-4" />
                    )}
                  </Button>
                </div>
                {form['password'] && (
                  <div className="flex items-center gap-2">
                    <div className={`h-2 w-full rounded-full ${
                      passwordStrength.score <= 2 ? 'bg-red-200' :
                      passwordStrength.score === 3 ? 'bg-yellow-200' : 'bg-green-200'
                    }`}>
                      <div
                        className={`h-2 rounded-full transition-all ${
                          passwordStrength.score <= 2 ? 'bg-red-500' :
                          passwordStrength.score === 3 ? 'bg-yellow-500' : 'bg-green-500'
                        }`}
                        style={{ width: `${(passwordStrength.score / 5) * 100}%` }}
                      />
                    </div>
                    <span className="text-xs text-gray-500">{passwordStrength.label}</span>
                  </div>
                )}
                {validationErrors['password'] && (
                  <p className="text-sm text-red-600">{validationErrors['password']}</p>
                )}
              </div>

              <div className="space-y-2">
                <Label htmlFor="confirm_password">Confirmar Senha *</Label>
                <div className="relative">
                  <Input
                    id="confirm_password"
                    type={showConfirmPassword ? 'text' : 'password'}
                    value={form['confirm_password']}
                    onChange={(e) => setForm(prev => ({ ...prev, confirm_password: e.target.value }))}
                    className={validationErrors['confirm_password'] ? 'border-red-500' : ''}
                  />
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                    onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                  >
                    {showConfirmPassword ? (
                      <EyeOff className="h-4 w-4" />
                    ) : (
                      <Eye className="h-4 w-4" />
                    )}
                  </Button>
                </div>
                {validationErrors['confirm_password'] && (
                  <p className="text-sm text-red-600">{validationErrors['confirm_password']}</p>
                )}
              </div>
            </div>
          </div>

          {/* Role and Status */}
          <div className="space-y-4">
            <h3 className="text-sm font-medium text-gray-900">Fun├º├úo e Status</h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="role">Fun├º├úo *</Label>
                <Select value={form['role']} onValueChange={(value: 'doctor' | 'admin') => setRolePermissions(value)}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="doctor">M├®dico</SelectItem>
                    <SelectItem value="admin">Administrador</SelectItem>
                  </SelectContent>
                </Select>
                {validationErrors['role'] && (
                  <p className="text-sm text-red-600">{validationErrors['role']}</p>
                )}
              </div>

              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <Label htmlFor="is_active">Usu├írio Ativo</Label>
                  <Switch
                    id="is_active"
                    checked={form.is_active}
                    onCheckedChange={(checked) => setForm(prev => ({ ...prev, is_active: checked }))}
                  />
                </div>

                <div className="flex items-center justify-between">
                  <Label htmlFor="two_factor_enabled">Ativar 2FA</Label>
                  <Switch
                    id="two_factor_enabled"
                    checked={form.two_factor_enabled}
                    onCheckedChange={(checked) => setForm(prev => ({ ...prev, two_factor_enabled: checked }))}
                  />
                </div>
              </div>
            </div>
          </div>

          {/* Permissions */}
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="text-sm font-medium text-gray-900">Permiss├Áes</h3>
              <Badge variant="secondary">{form.permissions.length} selecionadas</Badge>
            </div>

            <div className="space-y-4 max-h-48 overflow-y-auto border rounded-lg p-4">
              {Object.entries(permissionsByCategory).map(([category, permissions]) => (
                <div key={category} className="space-y-2">
                  <h4 className="text-xs font-medium text-gray-500 uppercase tracking-wide">
                    {category}
                  </h4>
                  <div className="grid grid-cols-1 gap-2">
                    {permissions.map((permission) => (
                      <div key={permission.id} className="flex items-center space-x-2">
                        <input
                          type="checkbox"
                          id={permission.id}
                          checked={form.permissions.includes(permission.id)}
                          onChange={() => togglePermission(permission.id)}
                          className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                        />
                        <Label htmlFor={permission.id} className="text-sm">
                          {permission.label}
                        </Label>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Notes */}
          <div className="space-y-2">
            <Label htmlFor="notes">Observa├º├Áes</Label>
            <Textarea
              id="notes"
              value={form.notes}
              onChange={(e) => setForm(prev => ({ ...prev, notes: e.target.value }))}
              placeholder="Observa├º├Áes adicionais sobre o usu├írio..."
              rows={3}
            />
          </div>

          {/* Submit */}
          <DialogFooter>
            <Button
              type="button"
              variant="outline"
              onClick={() => onOpenChange(false)}
              disabled={createUserMutation.isPending}
            >
              Cancelar
            </Button>
            <Button
              type="submit"
              disabled={createUserMutation.isPending}
            >
              {createUserMutation.isPending ? (
                <>
                  <LoadingSpinner size="sm" className="mr-2" />
                  Criando...
                </>
              ) : (
                <>
                  <Check className="h-4 w-4 mr-2" />
                  Criar Usu├írio
                </>
              )}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

import React, { useState, useEffect } from 'react'
import { useMutation, useQueryClient } from '@tanstack/react-query'
import { Eye, EyeOff, Save, RotateCcw } from 'lucide-react'
import { apiClient } from '@/lib/api-client'
import { AdminUser } from '@/types/admin'
import { UserRole } from '@/types/shared'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Switch } from '@/components/ui/switch'
import { Badge } from '@/components/ui/badge'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { useToast } from '@/components/ui/use-toast'
import { LoadingSpinner } from '@/components/ui/loading-spinner'

interface UserEditModalProps {
  open: boolean
  onOpenChange: (open: boolean) => void
  user: AdminUser | null
}

interface EditUserForm {
  email: string
  full_name: string
  role: string
  is_active: boolean
  two_factor_enabled: boolean
  notes?: string
  new_password?: string
  confirm_password?: string
}

export function UserEditModal({ open, onOpenChange, user }: UserEditModalProps) {
  const { toast } = useToast()
  const queryClient = useQueryClient()

  const [form, setForm] = useState<EditUserForm>({
    email: '',
    full_name: '',
    role: 'admin',
    is_active: true,
    two_factor_enabled: false,
    notes: '',
    new_password: '',
    confirm_password: ''
  })

  const [showPassword, setShowPassword] = useState(false)
  const [showConfirmPassword, setShowConfirmPassword] = useState(false)
  const [validationErrors, setValidationErrors] = useState<Record<string, string>>({})
  const [hasChanges, setHasChanges] = useState(false)

  // Load user data into form when user changes
  useEffect(() => {
    if (user) {
      setForm({
        email: user['email'],
        full_name: user['full_name'],
        role: user['role'],
        is_active: user.is_active,
        two_factor_enabled: user.two_factor_enabled,
        notes: '',
        new_password: '',
        confirm_password: ''
      })
      setHasChanges(false)
      setValidationErrors({})
    }
  }, [user])

  // Track changes
  useEffect(() => {
    if (!user) return

    const hasFormChanges =
      form['email'] !== user['email'] ||
      form['full_name'] !== user['full_name'] ||
      form.role !== user['role'] ||
      form.is_active !== user.is_active ||
      form.two_factor_enabled !== user.two_factor_enabled ||
      form['new_password'] !== '' ||
      form.notes !== ''

    setHasChanges(hasFormChanges)
  }, [form, user])

  const updateUserMutation = useMutation({
    mutationFn: async ({ id, userData }: { id: string, userData: Partial<AdminUser> }) => {
      return apiClient.adminUsers.update(id, userData)
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-users'] })
      queryClient.invalidateQueries({ queryKey: ['admin-user', user?.id] })
      toast({
        title: 'Usu├írio atualizado com sucesso',
        description: 'As altera├º├Áes foram salvas.',
      })
      onOpenChange(false)
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao atualizar usu├írio',
        description: error.data?.message || 'Ocorreu um erro inesperado.',
        variant: 'destructive'
      })
    }
  })

  const resetPasswordMutation = useMutation({
    mutationFn: async (id: string) => {
      // Generate secure temporary password client-side
      const tempPassword = generateTemporaryPassword()

      // Send password to backend for user update
      await apiClient.adminUsers.resetPassword(id, {
        new_password: tempPassword,
        force_change: true
      })

      // Return generated password for display
      return { temporary_password: tempPassword }
    },
    onSuccess: (response) => {
      toast({
        title: 'Senha redefinida com sucesso',
        description: `Nova senha tempor├íria: ${response.temporary_password}`,
      })
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao redefinir senha',
        description: error.data?.message || 'Ocorreu um erro inesperado.',
        variant: 'destructive'
      })
    }
  })

  const validateForm = (): boolean => {
    const errors: Record<string, string> = {}

    // Email validation
    if (!form['email']) {
      errors['email'] = 'Email ├® obrigat├│rio'
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form['email'])) {
      errors['email'] = 'Email inv├ílido'
    }

    // Name validation
    if (!form['full_name'].trim()) {
      errors['full_name'] = 'Nome completo ├® obrigat├│rio'
    } else if (form['full_name'].trim().length < 2) {
      errors['full_name'] = 'Nome deve ter pelo menos 2 caracteres'
    }

    // Password validation (only if provided)
    if (form['new_password']) {
      if (form['new_password'].length < 8) {
        errors['new_password'] = 'Senha deve ter pelo menos 8 caracteres'
      } else if (!/(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/.test(form['new_password'])) {
        errors['new_password'] = 'Senha deve conter pelo menos uma letra min├║scula, uma mai├║scula e um n├║mero'
      }

      // Confirm password validation
      if (form['new_password'] !== form['confirm_password']) {
        errors['confirm_password'] = 'Senhas n├úo coincidem'
      }
    }

    setValidationErrors(errors)
    return Object.keys(errors).length === 0
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()

    if (!user || !validateForm()) return

    const userData: Partial<AdminUser> = {
      email: form['email'].trim(),
      full_name: form['full_name'].trim(),
      // @ts-expect-error TODO: fix role type
      role: form.role,
      is_active: form.is_active,
      two_factor_enabled: form.two_factor_enabled,
    }

    // Add password if provided
    if (form['new_password']) {
      userData.password = form['new_password']
    }

    updateUserMutation.mutate({ id: user['id'], userData })
  }

  const handleResetPassword = () => {
    if (!user) return
    resetPasswordMutation.mutate(user['id'])
  }

  // Generate secure temporary password
  function generateTemporaryPassword(): string {
    const length = 12
    const charset = 'ABCDEFGHJKMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789!@#$%^&*'
    const array = new Uint8Array(length)
    crypto.getRandomValues(array)
    return Array.from(array, (byte) => charset[byte % charset.length]).join('')
  }

  const resetForm = () => {
    if (user) {
      setForm({
        email: user['email'],
        full_name: user['full_name'],
        role: user['role'],
        is_active: user.is_active,
        two_factor_enabled: user.two_factor_enabled,
        notes: '',
        new_password: '',
        confirm_password: ''
      })
      setValidationErrors({})
    }
  }

  if (!user) return null

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[600px] max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Editar Usu├írio</DialogTitle>
          <DialogDescription>
            Edite as informa├º├Áes do usu├írio {user['full_name']}
          </DialogDescription>
        </DialogHeader>

        <Tabs defaultValue="basic" className="space-y-4">
          <TabsList className="grid w-full grid-cols-3">
            <TabsTrigger value="basic">Informa├º├Áes B├ísicas</TabsTrigger>
            <TabsTrigger value="security">Seguran├ºa</TabsTrigger>
            <TabsTrigger value="activity">Atividade</TabsTrigger>
          </TabsList>

          <form onSubmit={handleSubmit}>
            <TabsContent value="basic" className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="email">Email *</Label>
                  <Input
                    id="email"
                    type="email"
                    value={form['email']}
                    onChange={(e) => setForm(prev => ({ ...prev, email: e.target.value }))}
                    className={validationErrors['email'] ? 'border-red-500' : ''}
                  />
                  {validationErrors['email'] && (
                    <p className="text-sm text-red-600">{validationErrors['email']}</p>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="full_name">Nome Completo *</Label>
                  <Input
                    id="full_name"
                    value={form['full_name']}
                    onChange={(e) => setForm(prev => ({ ...prev, full_name: e.target.value }))}
                    className={validationErrors['full_name'] ? 'border-red-500' : ''}
                  />
                  {validationErrors['full_name'] && (
                    <p className="text-sm text-red-600">{validationErrors['full_name']}</p>
                  )}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="role">Fun├º├úo *</Label>
                  <Select value={form.role} onValueChange={(value: 'doctor' | 'admin') => setForm(prev => ({ ...prev, role: value }))}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="doctor">M├®dico</SelectItem>
                      <SelectItem value="admin">Administrador</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-4">
                  <div className="flex items-center justify-between">
                    <Label htmlFor="is_active">Usu├írio Ativo</Label>
                    <Switch
                      id="is_active"
                      checked={form.is_active}
                      onCheckedChange={(checked) => setForm(prev => ({ ...prev, is_active: checked }))}
                    />
                  </div>

                  <div className="flex items-center justify-between">
                    <Label htmlFor="two_factor_enabled">2FA Ativo</Label>
                    <Switch
                      id="two_factor_enabled"
                      checked={form.two_factor_enabled}
                      onCheckedChange={(checked) => setForm(prev => ({ ...prev, two_factor_enabled: checked }))}
                    />
                  </div>
                </div>
              </div>

              <div className="space-y-2">
                <Label htmlFor="notes">Observa├º├Áes</Label>
                <Textarea
                  id="notes"
                  value={form.notes}
                  onChange={(e) => setForm(prev => ({ ...prev, notes: e.target.value }))}
                  placeholder="Observa├º├Áes sobre o usu├írio..."
                  rows={3}
                />
              </div>
            </TabsContent>

            <TabsContent value="security" className="space-y-4">
              <Card>
                <CardHeader>
                  <CardTitle className="text-lg">Alterar Senha</CardTitle>
                  <CardDescription>
                    Deixe em branco para manter a senha atual
                  </CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="new_password">Nova Senha</Label>
                      <div className="relative">
                        <Input
                          id="new_password"
                          type={showPassword ? 'text' : 'password'}
                          value={form['new_password']}
                          onChange={(e) => setForm(prev => ({ ...prev, new_password: e.target.value }))}
                          className={validationErrors['new_password'] ? 'border-red-500' : ''}
                        />
                        <Button
                          type="button"
                          variant="ghost"
                          size="sm"
                          className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                          onClick={() => setShowPassword(!showPassword)}
                        >
                          {showPassword ? (
                            <EyeOff className="h-4 w-4" />
                          ) : (
                            <Eye className="h-4 w-4" />
                          )}
                        </Button>
                      </div>
                      {validationErrors['new_password'] && (
                        <p className="text-sm text-red-600">{validationErrors['new_password']}</p>
                      )}
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="confirm_password">Confirmar Nova Senha</Label>
                      <div className="relative">
                        <Input
                          id="confirm_password"
                          type={showConfirmPassword ? 'text' : 'password'}
                          value={form['confirm_password']}
                          onChange={(e) => setForm(prev => ({ ...prev, confirm_password: e.target.value }))}
                          className={validationErrors['confirm_password'] ? 'border-red-500' : ''}
                        />
                        <Button
                          type="button"
                          variant="ghost"
                          size="sm"
                          className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                          onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                        >
                          {showConfirmPassword ? (
                            <EyeOff className="h-4 w-4" />
                          ) : (
                            <Eye className="h-4 w-4" />
                          )}
                        </Button>
                      </div>
                      {validationErrors['confirm_password'] && (
                        <p className="text-sm text-red-600">{validationErrors['confirm_password']}</p>
                      )}
                    </div>
                  </div>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle className="text-lg">Redefinir Senha</CardTitle>
                  <CardDescription>
                    Gera uma nova senha tempor├íria para o usu├írio
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <Button
                    type="button"
                    variant="outline"
                    onClick={handleResetPassword}
                    disabled={resetPasswordMutation.isPending}
                  >
                    {resetPasswordMutation.isPending ? (
                      <>
                        <LoadingSpinner size="sm" className="mr-2" />
                        Redefinindo...
                      </>
                    ) : (
                      <>
                        <RotateCcw className="h-4 w-4 mr-2" />
                        Redefinir Senha
                      </>
                    )}
                  </Button>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle className="text-lg">Informa├º├Áes de Seguran├ºa</CardTitle>
                </CardHeader>
                <CardContent className="space-y-3">
                  <div className="flex justify-between items-center">
                    <span className="text-sm text-gray-600">Tentativas de Login Falhadas:</span>
                    <Badge variant={user.failed_login_attempts > 0 ? 'destructive' : 'secondary'}>
                      {user.failed_login_attempts}
                    </Badge>
                  </div>

                  <div className="flex justify-between items-center">
                    <span className="text-sm text-gray-600">Status da Conta:</span>
                    <Badge variant={user.is_active ? 'default' : 'secondary'}>
                      {user.is_active ? 'Ativa' : 'Inativa'}
                    </Badge>
                  </div>

                  <div className="flex justify-between items-center">
                    <span className="text-sm text-gray-600">Bloqueio:</span>
                    <Badge variant={user.locked_until && new Date(user.locked_until) > new Date() ? 'destructive' : 'secondary'}>
                      {user.locked_until && new Date(user.locked_until) > new Date() ? 'Bloqueada' : 'Desbloqueada'}
                    </Badge>
                  </div>

                  <div className="flex justify-between items-center">
                    <span className="text-sm text-gray-600">├Ültimo Login:</span>
                    <span className="text-sm text-gray-900">
                      {user.last_login ? new Date(user.last_login).toLocaleString('pt-BR') : 'Nunca'}
                    </span>
                  </div>
                </CardContent>
              </Card>
            </TabsContent>

            <TabsContent value="activity" className="space-y-4">
              <Card>
                <CardHeader>
                  <CardTitle className="text-lg">Informa├º├Áes da Conta</CardTitle>
                </CardHeader>
                <CardContent className="space-y-3">
                  <div className="flex justify-between items-center">
                    <span className="text-sm text-gray-600">ID do Usu├írio:</span>
                    <span className="text-sm font-mono text-gray-900">{user['id']}</span>
                  </div>

                  <div className="flex justify-between items-center">
                    <span className="text-sm text-gray-600">Criado em:</span>
                    <span className="text-sm text-gray-900">
                      {new Date(user.created_at).toLocaleString('pt-BR')}
                    </span>
                  </div>

                  <div className="flex justify-between items-center">
                    <span className="text-sm text-gray-600">Permiss├Áes:</span>
                    <Badge variant="secondary">
                      {user.permissions.length} permiss├Áes
                    </Badge>
                  </div>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle className="text-lg">Permiss├Áes Atuais</CardTitle>
                  <CardDescription>
                    Lista de todas as permiss├Áes atribu├¡das ao usu├írio
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <div className="flex flex-wrap gap-2">
                    {user.permissions.length > 0 ? (
                      user.permissions.map((permission) => (
                        <Badge key={permission} variant="outline" className="text-xs">
                          {permission}
                        </Badge>
                      ))
                    ) : (
                      <p className="text-sm text-gray-500">Nenhuma permiss├úo espec├¡fica atribu├¡da</p>
                    )}
                  </div>
                </CardContent>
              </Card>
            </TabsContent>

            <DialogFooter className="mt-6">
              <div className="flex justify-between w-full">
                <Button
                  type="button"
                  variant="outline"
                  onClick={resetForm}
                  disabled={!hasChanges || updateUserMutation.isPending}
                >
                  <RotateCcw className="h-4 w-4 mr-2" />
                  Reverter
                </Button>

                <div className="flex gap-2">
                  <Button
                    type="button"
                    variant="outline"
                    onClick={() => onOpenChange(false)}
                    disabled={updateUserMutation.isPending}
                  >
                    Cancelar
                  </Button>
                  <Button
                    type="submit"
                    disabled={!hasChanges || updateUserMutation.isPending}
                  >
                    {updateUserMutation.isPending ? (
                      <>
                        <LoadingSpinner size="sm" className="mr-2" />
                        Salvando...
                      </>
                    ) : (
                      <>
                        <Save className="h-4 w-4 mr-2" />
                        Salvar Altera├º├Áes
                      </>
                    )}
                  </Button>
                </div>
              </div>
            </DialogFooter>
          </form>
        </Tabs>
      </DialogContent>
    </Dialog>
  )
}

