const mockApiResponse = {
  items: mockUsers,
  total: mockUsers.length,
  pages: 1,
  current_page: 1,
  page_size: 10
}

// Test wrapper component
function TestWrapper({ children }: { children: React.ReactNode }) {
  const queryClient = new QueryClient({
    defaultOptions: {
      queries: {
        retry: false,
      },
    },
  })

  return (
    <QueryClientProvider client={queryClient}>
      {children}
    </QueryClientProvider>
  )
}

describe('UserListPage', () => {
  const user = userEvent.setup()

  beforeEach(() => {
    vi.clearAllMocks()
    // Default successful API response
    vi.mocked(apiClient.adminUsers.list).mockResolvedValue(mockApiResponse)
  })

  afterEach(() => {
    vi.clearAllMocks()
  })

  describe('Component Rendering', () => {
    it('renders the page header correctly', async () => {
      render(
        <TestWrapper>
          <UserListPage />
        </TestWrapper>
      )

      expect(screen.getByText('Gerenciamento de Usu├írios')).toBeInTheDocument()
      expect(screen.getByText('Gerencie usu├írios administrativos, permiss├Áes e atividades')).toBeInTheDocument()
    })

    it('renders action buttons in header', async () => {
      render(
        <TestWrapper>
          <UserListPage />
        </TestWrapper>
      )

      expect(screen.getByRole('button', { name: /exportar/i })).toBeInTheDocument()
      expect(screen.getByRole('button', { name: /novo usu├írio/i })).toBeInTheDocument()
    })

    it('renders statistics cards', async () => {
      render(
        <TestWrapper>
          <UserListPage />
        </TestWrapper>
      )

      await waitFor(() => {
        expect(screen.getByText('Total de Usu├írios')).toBeInTheDocument()
        expect(screen.getByText('Usu├írios Ativos')).toBeInTheDocument()
        expect(screen.getByText('Super Admins')).toBeInTheDocument()
        expect(screen.getByText('Bloqueados')).toBeInTheDocument()
      })
    })

    it('displays correct statistics based on user data', async () => {
      render(
        <TestWrapper>
          <UserListPage />
        </TestWrapper>
      )

      await waitFor(() => {
        // Total users
        expect(screen.getByText('3')).toBeInTheDocument()
        // Active users (2 out of 3)
        expect(screen.getByText('2')).toBeInTheDocument()
        // Super admins (1 out of 3)
        expect(screen.getByText('1')).toBeInTheDocument()
        // Locked users (1 out of 3)
        expect(screen.getByText('1')).toBeInTheDocument()
      })
    })

    it('renders filter controls', async () => {
      render(
        <TestWrapper>
          <UserListPage />
        </TestWrapper>
      )

      expect(screen.getByPlaceholderText('Buscar por nome ou email...')).toBeInTheDocument()
      expect(screen.getByRole('combobox', { name: /fun├º├úo/i })).toBeInTheDocument()
      expect(screen.getByRole('combobox', { name: /status/i })).toBeInTheDocument()
    })
