      await user.click(deleteAction)

      expect(onDeleteUser).toHaveBeenCalledWith(mockUsers[0])
    })

    it('calls onToggleStatus when status toggle is clicked', async () => {
      const onToggleStatus = vi.fn()
      render(<UsersTable {...defaultProps} onToggleStatus={onToggleStatus} />)

      // Open first user's action menu
      const firstActionMenu = screen.getAllByTestId('more-icon')[0]
      await user.click(firstActionMenu)

      // Click status toggle action
      const toggleAction = screen.getByText('Desativar') // Active user should show "Desativar"
      await user.click(toggleAction)

      expect(onToggleStatus).toHaveBeenCalledWith(mockUsers[0])
    })

    it('shows correct toggle text for active/inactive users', async () => {
      render(<UsersTable {...defaultProps} />)

      // Open active user's menu (user 1)
      const firstActionMenu = screen.getAllByTestId('more-icon')[0]
      await user.click(firstActionMenu)
      expect(screen.getByText('Desativar')).toBeInTheDocument()

      // Close first menu and open inactive user's menu (user 2)
      await user.click(firstActionMenu) // Close menu
      const secondActionMenu = screen.getAllByTestId('more-icon')[1]
      await user.click(secondActionMenu)
      expect(screen.getByText('Ativar')).toBeInTheDocument()
    })
  })

  describe('Row Selection', () => {
    it('shows checkboxes when onUserSelect is provided', () => {
      render(<UsersTable {...defaultProps} />)

      const checkboxes = screen.getAllByRole('checkbox')
      expect(checkboxes).toHaveLength(mockUsers.length + 1) // +1 for select all
    })

    it('calls onUserSelect when individual checkbox is clicked', async () => {
      const onUserSelect = vi.fn()
      render(<UsersTable {...defaultProps} onUserSelect={onUserSelect} />)

      const firstCheckbox = screen.getAllByRole('checkbox')[1] // Skip select all
      await user.click(firstCheckbox)

      expect(onUserSelect).toHaveBeenCalledWith(mockUsers[0].id, true)
    })

    it('calls onUserSelect for select all checkbox', async () => {
      const onUserSelect = vi.fn()
      render(<UsersTable {...defaultProps} onUserSelect={onUserSelect} />)

      const selectAllCheckbox = screen.getAllByRole('checkbox')[0]
      await user.click(selectAllCheckbox)

      expect(onUserSelect).toHaveBeenCalledWith('all', true)
    })

    it('shows selected state correctly', () => {
      render(<UsersTable {...defaultProps} selectedUsers={['1', '2']} />)

      const checkboxes = screen.getAllByRole('checkbox')
      expect(checkboxes[1]).toBeChecked() // First user
      expect(checkboxes[2]).toBeChecked() // Second user
      expect(checkboxes[3]).not.toBeChecked() // Third user
    })

    it('shows indeterminate state for select all when some selected', () => {
      render(<UsersTable {...defaultProps} selectedUsers={['1']} />)

      const selectAllCheckbox = screen.getAllByRole('checkbox')[0]
      expect(selectAllCheckbox).toHaveProperty('indeterminate', true)
    })
  })

  describe('Pagination', () => {
    const paginationProps = {
      ...defaultProps,
      currentPage: 2,
      totalPages: 5
    }

    it('shows pagination controls when multiple pages', () => {
      render(<UsersTable {...paginationProps} />)

      expect(screen.getByText('P├ígina 2 de 5')).toBeInTheDocument()
      expect(screen.getByRole('button', { name: /anterior/i })).toBeInTheDocument()
      expect(screen.getByRole('button', { name: /pr├│xima/i })).toBeInTheDocument()
    })

    it('disables previous button on first page', () => {
      render(<UsersTable {...defaultProps} currentPage={1} totalPages={5} />)

      const prevButton = screen.getByRole('button', { name: /anterior/i })
      expect(prevButton).toBeDisabled()
    })

    it('disables next button on last page', () => {
      render(<UsersTable {...defaultProps} currentPage={5} totalPages={5} />)

      const nextButton = screen.getByRole('button', { name: /pr├│xima/i })
      expect(nextButton).toBeDisabled()
    })

    it('calls onPageChange when pagination buttons are clicked', async () => {
      const onPageChange = vi.fn()
      render(<UsersTable {...paginationProps} onPageChange={onPageChange} />)

      const nextButton = screen.getByRole('button', { name: /pr├│xima/i })
      await user.click(nextButton)

      expect(onPageChange).toHaveBeenCalledWith(3)

      const prevButton = screen.getByRole('button', { name: /anterior/i })
      await user.click(prevButton)

      expect(onPageChange).toHaveBeenCalledWith(1)
    })

    it('hides pagination when only one page', () => {
      render(<UsersTable {...defaultProps} totalPages={1} />)

      expect(screen.queryByText(/p├ígina/i)).not.toBeInTheDocument()
    })
  })

  describe('Bulk Actions', () => {
    it('shows bulk action bar when users are selected', () => {
      render(<UsersTable {...defaultProps} selectedUsers={['1', '2']} />)

      expect(screen.getByText('2 usu├írios selecionados')).toBeInTheDocument()
      expect(screen.getByRole('button', { name: /ativar/i })).toBeInTheDocument()
      expect(screen.getByRole('button', { name: /desativar/i })).toBeInTheDocument()
      expect(screen.getByRole('button', { name: /excluir/i })).toBeInTheDocument()
    })

    it('calls onBulkAction for bulk activate', async () => {
      const onBulkAction = vi.fn()
      render(<UsersTable {...defaultProps} selectedUsers={['1', '2']} onBulkAction={onBulkAction} />)

      const activateButton = screen.getByRole('button', { name: /ativar/i })
      await user.click(activateButton)

      expect(onBulkAction).toHaveBeenCalledWith('activate', ['1', '2'])
    })

    it('calls onBulkAction for bulk deactivate', async () => {
      const onBulkAction = vi.fn()
      render(<UsersTable {...defaultProps} selectedUsers={['1', '2']} onBulkAction={onBulkAction} />)

      const deactivateButton = screen.getByRole('button', { name: /desativar/i })
      await user.click(deactivateButton)

      expect(onBulkAction).toHaveBeenCalledWith('deactivate', ['1', '2'])
    })

    it('calls onBulkAction for bulk delete', async () => {
      const onBulkAction = vi.fn()
      render(<UsersTable {...defaultProps} selectedUsers={['1', '2']} onBulkAction={onBulkAction} />)

      const deleteButton = screen.getByRole('button', { name: /excluir/i })
      await user.click(deleteButton)

      expect(onBulkAction).toHaveBeenCalledWith('delete', ['1', '2'])
    })

    it('hides bulk action bar when no users selected', () => {
      render(<UsersTable {...defaultProps} selectedUsers={[]} />)

      expect(screen.queryByText(/usu├írios selecionados/i)).not.toBeInTheDocument()
    })
  })

  describe('Performance', () => {
    it('handles large datasets efficiently', () => {
      const largeUserSet = Array.from({ length: 1000 }, (_, i) => ({
        id: `user-${i}`,
        email: `user${i}@test.com`,
        full_name: `User ${i}`,
        role: 'admin' as const,
        is_active: i % 2 === 0,
        created_at: '2024-01-01T00:00:00Z',
        updated_at: '2024-01-01T00:00:00Z',
        last_login: i % 3 === 0 ? '2024-01-01T00:00:00Z' : null,
        login_count: i,
        locked_until: null,
        permissions: ['read'],
    two_factor_enabled: false,
    failed_login_attempts: 0
      }))

      const startTime = performance.now()

      render(<UsersTable {...defaultProps} users={largeUserSet} />)

      const endTime = performance.now()
      const renderTime = endTime - startTime

      // Should render within reasonable time
      expect(renderTime).toBeLessThan(1000) // 1 second max
    })

    it('optimizes re-renders for selection changes', () => {
      const renderSpy = vi.fn()

      const TestComponent = ({ selectedUsers }: { selectedUsers: string[] }) => {
        renderSpy()
        return <UsersTable {...defaultProps} selectedUsers={selectedUsers} />
      }

      const { rerender } = render(<TestComponent selectedUsers={[]} />)

      const initialRenderCount = renderSpy.mock.calls.length

      // Change selection
      rerender(<TestComponent selectedUsers={['1']} />)

      // Should not cause excessive re-renders
      expect(renderSpy.mock.calls.length - initialRenderCount).toBeLessThanOrEqual(2)
    })
  })

  describe('Accessibility', () => {
    it('has proper table structure for screen readers', () => {
      render(<UsersTable {...defaultProps} />)

      const table = screen.getByRole('table')
      expect(table).toBeInTheDocument()

      const columnHeaders = screen.getAllByRole('columnheader')
      expect(columnHeaders.length).toBeGreaterThan(0)

      const rows = screen.getAllByRole('row')
      expect(rows.length).toBe(mockUsers.length + 1) // +1 for header
    })

    it('provides accessible labels for actions', () => {
      render(<UsersTable {...defaultProps} />)

      const actionButtons = screen.getAllByLabelText(/a├º├Áes para/i)
      expect(actionButtons).toHaveLength(mockUsers.length)
    })

    it('supports keyboard navigation for checkboxes', async () => {
      render(<UsersTable {...defaultProps} />)

      const firstCheckbox = screen.getAllByRole('checkbox')[1]

      firstCheckbox.focus()
      expect(document.activeElement).toBe(firstCheckbox)

      await user.keyboard('{space}')
      expect(defaultProps.onUserSelect).toHaveBeenCalled()
    })

    it('has accessible sort buttons', () => {
      render(<UsersTable {...defaultProps} />)

      const sortButtons = screen.getAllByRole('button', { name: /ordenar por/i })
      expect(sortButtons.length).toBeGreaterThan(0)
    })

    it('provides status indicators for screen readers', () => {
      render(<UsersTable {...defaultProps} />)

      // Should have aria-labels or text for status indicators
      const statusElements = screen.getAllByText(/ativo|inativo/i)
      expect(statusElements.length).toBeGreaterThan(0)
    })
  })

  describe('Error Handling', () => {
    it('handles undefined user data gracefully', () => {
      const usersWithUndefined = [
        ...mockUsers,
        {
          id: '4',
          email: undefined as any,
          full_name: undefined as any,
          role: 'admin' as const,
          is_active: true,
          created_at: '2024-01-01T00:00:00Z',
          updated_at: '2024-01-01T00:00:00Z',
          last_login: null,
          login_count: 0,
          locked_until: null,
          permissions: []
        }
      ]

      expect(() => {
        render(<UsersTable {...defaultProps} users={usersWithUndefined} />)
      }).not.toThrow()
    })

    it('handles invalid date formats gracefully', () => {
      const usersWithInvalidDates = [
        {
          ...mockUsers[0],
          created_at: 'invalid-date',
          last_login: 'another-invalid-date'
        }
      ]

      expect(() => {
        render(<UsersTable {...defaultProps} users={usersWithInvalidDates} />)
      }).not.toThrow()
    })
  })
})

import React from 'react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { useMutation, useQueryClient } from '@tanstack/react-query'
import { Loader2 } from 'lucide-react'
import { apiClient } from '@/lib/api-client'
import { createUserSchema, CreateUserFormData } from '@/lib/validations/user-schemas'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Switch } from '@/components/ui/switch'
import { useToast } from '@/components/ui/use-toast'
import { UserPermissionsEditor } from './UserPermissionsEditor'

interface CreateUserModalProps {
  open: boolean
  onOpenChange: (open: boolean) => void
}

export function CreateUserModal({ open, onOpenChange }: CreateUserModalProps) {
  const { toast } = useToast()
  const queryClient = useQueryClient()

  const {
    register,
    handleSubmit,
    formState: { errors },
    setValue,
    watch,
    reset
  } = useForm<CreateUserFormData>({
    resolver: zodResolver(createUserSchema),
    defaultValues: {
      email: '',
      full_name: '',
      role: 'doctor',
      password: '',
      confirm_password: '',
      permissions: [],
      is_active: true,
      two_factor_enabled: false
    }
  })

  const createMutation = useMutation({
    mutationFn: (data: CreateUserFormData) => {
      const { confirm_password, ...userData } = data
      return apiClient.adminUsers.create(userData)
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-users'] })
      toast({
        title: 'Usu├írio criado com sucesso',
        description: 'O novo usu├írio foi adicionado ao sistema.'
      })
      reset()
      onOpenChange(false)
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao criar usu├írio',
        description: error.data?.message || 'Ocorreu um erro inesperado.',
        variant: 'destructive'
      })
    }
  })

  const onSubmit = (data: CreateUserFormData) => {
    createMutation.mutate(data)
  }

  const handlePermissionsChange = (permissions: string[]) => {
    setValue('permissions', permissions)
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Criar Novo Usu├írio</DialogTitle>
          <DialogDescription>
            Preencha os dados abaixo para criar um novo usu├írio administrativo.
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
          <div className="grid gap-4">
            {/* Full Name */}
            <div className="space-y-2">
              <Label htmlFor="full_name">Nome Completo *</Label>
              <Input
                id="full_name"
                {...register('full_name')}
                placeholder="Ex: Jo├úo Silva"
                disabled={createMutation.isPending}
              />
              {errors['full_name'] && (
                <p className="text-sm text-red-500">{errors['full_name'].message}</p>
              )}
            </div>

            {/* Email */}
            <div className="space-y-2">
              <Label htmlFor="email">Email *</Label>
              <Input
                id="email"
                type="email"
                {...register('email')}
                placeholder="Ex: joao@example.com"
                disabled={createMutation.isPending}
              />
              {errors['email'] && (
                <p className="text-sm text-red-500">{errors['email'].message}</p>
              )}
            </div>

            {/* Role */}
            <div className="space-y-2">
              <Label htmlFor="role">Fun├º├úo *</Label>
              <Select
                value={watch('role')}
                onValueChange={(value: 'doctor' | 'admin') => setValue('role', value)}
                disabled={createMutation.isPending}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="doctor">M├®dico</SelectItem>
                  <SelectItem value="admin">Administrador</SelectItem>
                </SelectContent>
              </Select>
              {errors['role'] && (
                <p className="text-sm text-red-500">{errors['role'].message}</p>
              )}
            </div>

            {/* Password */}
            <div className="space-y-2">
              <Label htmlFor="password">Senha *</Label>
              <Input
                id="password"
                type="password"
                {...register('password')}
                placeholder="M├¡nimo 8 caracteres"
                disabled={createMutation.isPending}
              />
              {errors['password'] && (
                <p className="text-sm text-red-500">{errors['password'].message}</p>
              )}
            </div>

            {/* Confirm Password */}
            <div className="space-y-2">
              <Label htmlFor="confirm_password">Confirmar Senha *</Label>
              <Input
                id="confirm_password"
                type="password"
                {...register('confirm_password')}
                placeholder="Digite a senha novamente"
                disabled={createMutation.isPending}
              />
              {errors['confirm_password'] && (
                <p className="text-sm text-red-500">{errors['confirm_password'].message}</p>
              )}
            </div>

            {/* Permissions */}
            <div className="space-y-2">
              <Label>Permiss├Áes</Label>
              <UserPermissionsEditor
                selectedPermissions={watch('permissions') || []}
                onChange={handlePermissionsChange}
                disabled={createMutation.isPending}
              />
            </div>

            {/* Active Status */}
            <div className="flex items-center justify-between">
              <div className="space-y-0.5">
                <Label htmlFor="is_active">Usu├írio Ativo</Label>
                <p className="text-sm text-muted-foreground">
                  Permite que o usu├írio fa├ºa login no sistema
                </p>
              </div>
              <Switch
                id="is_active"
                checked={watch('is_active')}
                onCheckedChange={(checked) => setValue('is_active', checked)}
                disabled={createMutation.isPending}
              />
            </div>

            {/* 2FA */}
            <div className="flex items-center justify-between">
              <div className="space-y-0.5">
                <Label htmlFor="two_factor_enabled">Autentica├º├úo de Dois Fatores</Label>
                <p className="text-sm text-muted-foreground">
                  Requer c├│digo de verifica├º├úo adicional no login
                </p>
              </div>
              <Switch
                id="two_factor_enabled"
                checked={watch('two_factor_enabled')}
                onCheckedChange={(checked) => setValue('two_factor_enabled', checked)}
                disabled={createMutation.isPending}
              />
            </div>
          </div>

          <DialogFooter>
            <Button
              type="button"
              variant="outline"
              onClick={() => onOpenChange(false)}
              disabled={createMutation.isPending}
            >
              Cancelar
            </Button>
            <Button type="submit" disabled={createMutation.isPending}>
              {createMutation.isPending && (
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              )}
              Criar Usu├írio
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

import React, { useState } from 'react'
import { useQuery } from '@tanstack/react-query'
import { formatDistanceToNow } from 'date-fns'
import { ptBR } from 'date-fns/locale'
import { Activity, AlertCircle, CheckCircle, Info, XCircle, Filter } from 'lucide-react'
import { apiClient } from '@/lib/api-client'
import { AdminUserActivity } from '@/types/admin'
import { ScrollArea } from '@/components/ui/scroll-area'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import { Pagination } from '@/components/ui/pagination'

interface UserActivityLogProps {
  userId: string
}

const ACTION_COLORS: Record<string, string> = {
  login: 'bg-blue-100 text-blue-800',
  logout: 'bg-gray-100 text-gray-800',
  create: 'bg-green-100 text-green-800',
  update: 'bg-yellow-100 text-yellow-800',
  delete: 'bg-red-100 text-red-800',
  view: 'bg-purple-100 text-purple-800',
  export: 'bg-orange-100 text-orange-800'
}

const ACTION_ICONS: Record<string, React.ReactNode> = {
  login: <CheckCircle className="h-4 w-4" />,
  logout: <Info className="h-4 w-4" />,
  create: <CheckCircle className="h-4 w-4" />,
  update: <AlertCircle className="h-4 w-4" />,
  delete: <XCircle className="h-4 w-4" />,
  view: <Info className="h-4 w-4" />,
  export: <Activity className="h-4 w-4" />
}

export function UserActivityLog({ userId }: UserActivityLogProps) {
  const [currentPage, setCurrentPage] = useState(1)
  const [actionFilter, setActionFilter] = useState<string>('all')
  const pageSize = 10

  const { data, isLoading, error } = useQuery({
    queryKey: ['user-activity', userId, currentPage, actionFilter],
    queryFn: async () => {
      const params: any = {
        page: currentPage,
        size: pageSize
      }

      if (actionFilter !== 'all') {
        params.action = actionFilter
      }

      return apiClient.adminUsers.getActivity(userId, params)
    }
  })

  const formatTimestamp = (timestamp: string) => {
    try {
      return formatDistanceToNow(new Date(timestamp), {
        addSuffix: true,
        locale: ptBR
      })
    } catch {
      return 'Data inv├ílida'
    }
  }

  const getActionBadge = (action: string) => {
    const colorClass = ACTION_COLORS[action.toLowerCase()] || 'bg-gray-100 text-gray-800'
    const icon = ACTION_ICONS[action.toLowerCase()] || <Activity className="h-4 w-4" />

    return (
      <Badge className={`${colorClass} flex items-center gap-1`}>
        {icon}
        {action}
      </Badge>
    )
  }

  const getUniqueActions = () => {
    const actions = new Set<string>()
    data?.items?.forEach((activity: AdminUserActivity) => {
      actions.add(activity.action)
    })
    return Array.from(actions)
  }

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary" />
      </div>
    )
  }

  if (error) {
    return (
      <div className="text-center py-8">
        <p className="text-red-500">Erro ao carregar atividades</p>
        <p className="text-sm text-muted-foreground mt-1">
          {error instanceof Error ? error.message : 'Erro desconhecido'}
        </p>
      </div>
    )
  }

  const activities = data?.items || []

  return (
    <div className="space-y-4">
      {/* Filters */}
      <div className="flex items-center gap-4">
        <div className="flex items-center gap-2">
          <Filter className="h-4 w-4 text-muted-foreground" />
          <span className="text-sm font-medium">Filtrar por a├º├úo:</span>
        </div>
        <Select value={actionFilter} onValueChange={setActionFilter}>
          <SelectTrigger className="w-[180px]">
            <SelectValue placeholder="Todas as a├º├Áes" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">Todas as a├º├Áes</SelectItem>
            {getUniqueActions().map((action) => (
              <SelectItem key={action} value={action}>
                {action}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
        {actionFilter !== 'all' && (
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setActionFilter('all')}
          >
            Limpar
          </Button>
        )}
      </div>

      {/* Activity List */}
      {activities.length === 0 ? (
        <div className="text-center py-8">
          <Activity className="h-12 w-12 text-muted-foreground mx-auto mb-2" />
          <p className="text-muted-foreground">Nenhuma atividade registrada</p>
        </div>
      ) : (
        <ScrollArea className="h-[400px] border rounded-lg">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>A├º├úo</TableHead>
                <TableHead>Recurso</TableHead>
                <TableHead>Detalhes</TableHead>
                <TableHead>IP</TableHead>
                <TableHead>Quando</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {activities.map((activity: AdminUserActivity) => (
                <TableRow key={activity['id']}>
                  <TableCell>
                    {getActionBadge(activity.action)}
                  </TableCell>
                  <TableCell>
                    <div className="space-y-1">
                      <p className="font-medium">{activity.resource}</p>
                      {activity.details?.['id'] && (
                        <p className="text-xs text-muted-foreground">
                          ID: {activity.details['id']}
                        </p>
                      )}
                    </div>
                  </TableCell>
                  <TableCell>
                    {activity.details && Object.keys(activity.details).length > 0 ? (
                      <div className="text-sm text-muted-foreground max-w-[200px] truncate">
                        {JSON.stringify(activity.details)}
                      </div>
                    ) : (
                      <span className="text-muted-foreground">-</span>
                    )}
                  </TableCell>
                  <TableCell>
                    <span className="text-sm font-mono">{activity.ip_address}</span>
                  </TableCell>
                  <TableCell>
                    <span className="text-sm text-muted-foreground">
                      {formatTimestamp(activity.timestamp)}
                    </span>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </ScrollArea>
      )}

      {/* Pagination */}
      {data?.pages && data.pages > 1 && (
        <Pagination
          currentPage={currentPage}
          totalPages={data.pages}
          onPageChange={setCurrentPage}
        />
      )}
    </div>
  )
}

import React, { useState } from 'react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { useMutation, useQueryClient } from '@tanstack/react-query'
import { formatDistanceToNow } from 'date-fns'
import { ptBR } from 'date-fns/locale'
import { Loader2, Shield, Lock, Key, Activity } from 'lucide-react'
import { apiClient } from '@/lib/api-client'
import { updateUserSchema, UpdateUserFormData } from '@/lib/validations/user-schemas'
import { AdminUser } from '@/types/admin'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Switch } from '@/components/ui/switch'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Badge } from '@/components/ui/badge'
