interface UsersTableProps {
  users: AdminUser[]
  currentPage: number
  totalPages: number
  onPageChange: (page: number) => void
  onViewUser: (user: AdminUser) => void
  onEditUser: (user: AdminUser) => void
  selectedUsers?: string[]
  onToggleUserSelection?: (userId: string) => void
  sortBy?: string
  sortOrder?: 'asc' | 'desc'
  onSort?: (field: string) => void
}

export function UsersTable({
  users,
  currentPage,
  totalPages,
  onPageChange,
  onViewUser,
  onEditUser,
  selectedUsers = [],
  onToggleUserSelection,
  sortBy = 'created_at',
  sortOrder = 'desc',
  onSort
}: UsersTableProps) {
  const { toast } = useToast()
  const queryClient = useQueryClient()
  const [deleteUserId, setDeleteUserId] = React.useState<string | null>(null)

  const mutationOptions = {
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-users'] })
    },
    onError: (error: any) => {
      toast({
        title: 'Erro',
        description: error.data?.message || 'Ocorreu um erro inesperado.',
        variant: 'destructive'
      })
    }
  }

  const deleteMutation = useMutation({
    mutationFn: (id: string) => apiClient.adminUsers.delete(id),
    ...mutationOptions,
    onSuccess: () => {
      mutationOptions.onSuccess()
      toast({ title: 'Usu├írio exclu├¡do com sucesso' })
      setDeleteUserId(null)
    }
  })

  const activateMutation = useMutation({
    mutationFn: (id: string) => apiClient.adminUsers.activate(id),
    ...mutationOptions,
    onSuccess: () => {
      mutationOptions.onSuccess()
      toast({ title: 'Usu├írio ativado com sucesso' })
    }
  })

  const deactivateMutation = useMutation({
    mutationFn: (id: string) => apiClient.adminUsers.deactivate(id),
    ...mutationOptions,
    onSuccess: () => {
      mutationOptions.onSuccess()
      toast({ title: 'Usu├írio desativado com sucesso' })
    }
  })

  const unlockMutation = useMutation({
    mutationFn: (id: string) => apiClient.adminUsers.unlock(id),
    ...mutationOptions,
    onSuccess: () => {
      mutationOptions.onSuccess()
      toast({ title: 'Usu├írio desbloqueado com sucesso' })
    }
  })

  const enable2FAMutation = useMutation({
    mutationFn: (id: string) => apiClient.adminUsers.enable2FA(id),
    ...mutationOptions,
    onSuccess: () => {
      mutationOptions.onSuccess()
      toast({ title: '2FA habilitado com sucesso' })
    }
  })

  const disable2FAMutation = useMutation({
    mutationFn: (id: string) => apiClient.adminUsers.disable2FA(id),
    ...mutationOptions,
    onSuccess: () => {
      mutationOptions.onSuccess()
      toast({ title: '2FA desabilitado com sucesso' })
    }
  })

  const getRoleBadge = (role: string) => {
    const colorClasses = getRoleColor(role)
    const label = getRoleLabel(role)
    return <Badge className={colorClasses}>{label}</Badge>
  }

  const getStatusBadge = (user: AdminUser) => {
    if (user.locked_until && new Date(user.locked_until) > new Date()) {
      return <Badge variant="destructive">Bloqueado</Badge>
    }
    if (!user.is_active) {
      return <Badge variant="secondary">Inativo</Badge>
    }
    return <Badge className="bg-green-100 text-green-800">Ativo</Badge>
  }

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map(n => n[0])
      .join('')
      .toUpperCase()
      .slice(0, 2)
  }

  const formatLastLogin = (lastLogin?: string | null) => {
    if (!lastLogin) return 'Nunca'

    try {
      return formatDistanceToNow(new Date(lastLogin), {
        addSuffix: true,
        locale: ptBR
      })
    } catch {
      return 'Data inv├ílida'
    }
  }

  const isUserLocked = (user: AdminUser) => {
    return user.locked_until && new Date(user.locked_until) > new Date()
  }

  const getSortIcon = (field: string) => {
    if (sortBy !== field) {
      return <ArrowUpDown className="h-4 w-4" />
    }
    return sortOrder === 'asc' ? <ArrowUp className="h-4 w-4" /> : <ArrowDown className="h-4 w-4" />
  }

  const handleSort = (field: string) => {
    if (onSort) {
      onSort(field)
    }
  }

  if (users.length === 0) {
    return (
      <div className="text-center py-8">
        <p className="text-gray-500">Nenhum usu├írio encontrado</p>
        <p className="text-sm text-gray-400 mt-1">
          Tente ajustar os filtros ou criar um novo usu├írio
        </p>
      </div>
    )
  }

  return (
    <>
      <div className="space-y-4">
        <Table>
          <TableHeader>
            <TableRow>
              {onToggleUserSelection && (
                <TableHead className="w-[50px]">
                  <span className="sr-only">Selecionar</span>
                </TableHead>
              )}
              <TableHead
                className="cursor-pointer hover:bg-gray-50"
                onClick={() => handleSort('full_name')}
              >
                <div className="flex items-center space-x-1">
                  <span>Usu├írio</span>
                  {getSortIcon('full_name')}
                </div>
              </TableHead>
              <TableHead
                className="cursor-pointer hover:bg-gray-50"
                onClick={() => handleSort('role')}
              >
                <div className="flex items-center space-x-1">
                  <span>Fun├º├úo</span>
                  {getSortIcon('role')}
                </div>
              </TableHead>
              <TableHead
                className="cursor-pointer hover:bg-gray-50"
                onClick={() => handleSort('is_active')}
              >
                <div className="flex items-center space-x-1">
                  <span>Status</span>
                  {getSortIcon('is_active')}
                </div>
              </TableHead>
              <TableHead
                className="cursor-pointer hover:bg-gray-50"
                onClick={() => handleSort('two_factor_enabled')}
              >
                <div className="flex items-center space-x-1">
                  <span>2FA</span>
                  {getSortIcon('two_factor_enabled')}
                </div>
              </TableHead>
              <TableHead
                className="cursor-pointer hover:bg-gray-50"
                onClick={() => handleSort('failed_login_attempts')}
              >
                <div className="flex items-center space-x-1">
                  <span>Tentativas Falhas</span>
                  {getSortIcon('failed_login_attempts')}
                </div>
              </TableHead>
              <TableHead
                className="cursor-pointer hover:bg-gray-50"
                onClick={() => handleSort('last_login')}
              >
                <div className="flex items-center space-x-1">
                  <span>├Ültimo Login</span>
                  {getSortIcon('last_login')}
                </div>
              </TableHead>
              <TableHead className="w-[70px]">A├º├Áes</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {users.map((user) => (
              <TableRow
                key={user['id']}
                className={`cursor-pointer hover:bg-muted/50 ${
                  selectedUsers.includes(user['id']) ? 'bg-blue-50' : ''
                }`}
                onClick={() => onViewUser(user)}
              >
                {onToggleUserSelection && (
                  <TableCell onClick={(e) => e.stopPropagation()}>
                    <Checkbox
                      checked={selectedUsers.includes(user['id'])}
                      onCheckedChange={() => onToggleUserSelection(user['id'])}
                    />
                  </TableCell>
                )}
                <TableCell>
                  <div className="flex items-center space-x-3">
                    <Avatar className="h-8 w-8">
                      <AvatarFallback className="bg-blue-600 text-white text-xs">
                        {getInitials(user['full_name'])}
                      </AvatarFallback>
                    </Avatar>
                    <div>
                      <p className="font-medium text-gray-900">{user['full_name']}</p>
                      <p className="text-sm text-gray-500">{user['email']}</p>
                    </div>
                  </div>
                </TableCell>
                <TableCell>
                  {getRoleBadge(user['role'])}
                </TableCell>
                <TableCell>
                  {getStatusBadge(user)}
                </TableCell>
                <TableCell>
                  {user.two_factor_enabled ? (
                    <Badge className="bg-green-100 text-green-800">Ativo</Badge>
                  ) : (
                    <Badge variant="outline">Inativo</Badge>
                  )}
                </TableCell>
                <TableCell>
                  {user.failed_login_attempts > 0 ? (
                    <span className="text-red-600 font-medium">{user.failed_login_attempts}</span>
                  ) : (
                    <span className="text-gray-500">0</span>
                  )}
                </TableCell>
                <TableCell>
                  <span className="text-sm text-gray-600">
                    {formatLastLogin(user.last_login)}
                  </span>
                </TableCell>
                <TableCell>
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button
                        variant="ghost"
                        className="h-8 w-8 p-0"
                        onClick={(e) => e.stopPropagation()}
                      >
                        <MoreHorizontal className="h-4 w-4" />
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end">
                      <DropdownMenuLabel>A├º├Áes</DropdownMenuLabel>
                      <DropdownMenuItem
                        onClick={(e) => {
                          e.stopPropagation()
                          onViewUser(user)
                        }}
                      >
                        <Eye className="mr-2 h-4 w-4" />
                        Visualizar
                      </DropdownMenuItem>
                      <DropdownMenuItem
                        onClick={(e) => {
                          e.stopPropagation()
                          onEditUser(user)
                        }}
                      >
                        <Edit className="mr-2 h-4 w-4" />
                        Editar
                      </DropdownMenuItem>
                      <DropdownMenuSeparator />
                      {isUserLocked(user) ? (
                        <DropdownMenuItem
                          onClick={(e) => {
                            e.stopPropagation()
                            unlockMutation.mutate(user['id'])
                          }}
                        >
                          <Unlock className="mr-2 h-4 w-4" />
                          Desbloquear
                        </DropdownMenuItem>
                      ) : user.is_active ? (
                        <DropdownMenuItem
                          onClick={(e) => {
                            e.stopPropagation()
                            deactivateMutation.mutate(user['id'])
                          }}
                        >
                          <Lock className="mr-2 h-4 w-4" />
                          Desativar
                        </DropdownMenuItem>
                      ) : (
                        <DropdownMenuItem
                          onClick={(e) => {
                            e.stopPropagation()
                            activateMutation.mutate(user['id'])
                          }}
                        >
                          <Unlock className="mr-2 h-4 w-4" />
                          Ativar
                        </DropdownMenuItem>
                      )}
                      {user.two_factor_enabled ? (
                        <DropdownMenuItem
                          onClick={(e) => {
                            e.stopPropagation()
                            disable2FAMutation.mutate(user['id'])
                          }}
                        >
                          <ShieldOff className="mr-2 h-4 w-4" />
                          Desabilitar 2FA
                        </DropdownMenuItem>
                      ) : (
                        <DropdownMenuItem
                          onClick={(e) => {
                            e.stopPropagation()
                            enable2FAMutation.mutate(user['id'])
                          }}
                        >
                          <Shield className="mr-2 h-4 w-4" />
                          Habilitar 2FA
                        </DropdownMenuItem>
                      )}
                      <DropdownMenuSeparator />
                      <DropdownMenuItem
                        className="text-red-600"
                        onClick={(e) => {
                          e.stopPropagation()
                          setDeleteUserId(user['id'])
                        }}
                      >
                        <Trash2 className="mr-2 h-4 w-4" />
                        Excluir
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>

        {totalPages > 1 && (
          <Pagination
            currentPage={currentPage}
            totalPages={totalPages}
            onPageChange={onPageChange}
          />
        )}
      </div>

      {/* Delete Confirmation Dialog */}
      <AlertDialog open={!!deleteUserId} onOpenChange={(open) => !open && setDeleteUserId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Tem certeza?</AlertDialogTitle>
            <AlertDialogDescription>
              Esta a├º├úo n├úo pode ser desfeita. O usu├írio ser├í permanentemente exclu├¡do do sistema.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => deleteUserId && deleteMutation.mutate(deleteUserId)}
              className="bg-red-600 hover:bg-red-700"
            >
              Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  )
}

import React, { useState, useRef, useEffect } from 'react'
import { Send, Bot, User, Loader2, Lightbulb, AlertTriangle } from 'lucide-react'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Badge } from '@/components/ui/badge'
import { ScrollArea } from '@/components/ui/scroll-area'
import { Separator } from '@/components/ui/separator'
import { useToast } from '@/components/ui/use-toast'
import { AIChatMessage as ChatMessage, ChatRole, ChatSession } from '@/types/api'
import { ChatResponse } from '@/lib/types/ai'
import { apiClient } from '../../lib/api-client'
import { FEATURES } from '../../config'
import { createLogger } from '@/lib/logger'

const logger = createLogger('AIChatInterface')

interface AIChatInterfaceProps {
  patientId?: string
  sessionId?: string
  onSessionChange?: (session: ChatSession) => void
  className?: string
}

export function AIChatInterface({ 
  patientId, 
  sessionId, 
  onSessionChange,
  className 
}: AIChatInterfaceProps) {
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const [inputValue, setInputValue] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [session, setSession] = useState<ChatSession | null>(null)
  const { toast } = useToast()
  const messagesEndRef = useRef<HTMLDivElement>(null)
  const inputRef = useRef<HTMLInputElement>(null)

  // Check if AI features are enabled
  if (!FEATURES.AI_CHAT) {
    return (
      <Card className={className}>
        <CardContent className="pt-6">
          <div className="text-center text-muted-foreground">
            <Bot className="mx-auto h-8 w-8 mb-2" />
            <p>Chat com IA n├úo dispon├¡vel</p>
            <p className="text-sm">Configure VITE_OPENAI_API_KEY para habilitar</p>
          </div>
        </CardContent>
      </Card>
    )
  }

  // Scroll to bottom when new messages arrive
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  // Focus input on mount
  useEffect(() => {
    inputRef.current?.focus()
  }, [])

  // Initialize session
  useEffect(() => {
    if (sessionId) {
      loadSession(sessionId)
    } else {
      createNewSession()
    }
  }, [sessionId, patientId])

  const loadSession = async (id: string) => {
    try {
      // In a real implementation, load from API
      // const sessionData = await apiClient.ai.getSession(id)
      // setSession(sessionData)
      // setMessages(sessionData.messages)
      
      // Mock session for demo
      const mockSession: ChatSession = {
        id,
        patient_id: patientId || "",
        user_id: 'current-user',
        title: 'Chat com IA',
        messages: [],
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
        status: 'active'
      }
      setSession(mockSession)
      setMessages([])
    } catch (error) {
      logger.error('Failed to load session:', error)
      toast({
        title: 'Erro',
        description: 'N├úo foi poss├¡vel carregar a sess├úo de chat',
        variant: 'destructive'
      })
    }
  }

  const createNewSession = async () => {
    try {
      const newSession: ChatSession = {
        id: `session-${Date.now()}`,
        patient_id: patientId || "",
        user_id: 'current-user',
        title: patientId ? `Chat - Paciente ${patientId}` : 'Chat com IA',
        messages: [],
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
        status: 'active'
      }
      
      setSession(newSession)
      setMessages([])
      onSessionChange?.(newSession)
      
      // Add welcome message
      const welcomeMessage: ChatMessage = {
        id: `msg-${Date.now()}`,
        role: ChatRole.ASSISTANT,
        content: patientId
          ? `Ol├í! Sou a IA assistente da Hormonia. Como posso ajudar com o paciente ${patientId}?`
          : 'Ol├í! Sou a IA assistente da Hormonia. Como posso ajud├í-lo hoje?',
        timestamp: new Date().toISOString(),
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
        ...(patientId && { patient_id: patientId })
      }

      setMessages([welcomeMessage])
    } catch (error) {
      logger.error('Failed to create session:', error)
    }
  }

  const sendMessage = async () => {
    if (!inputValue.trim() || isLoading) return

    const userMessage: ChatMessage = {
      id: `msg-${Date.now()}`,
      role: ChatRole.USER,
      content: inputValue.trim(),
      timestamp: new Date().toISOString(),
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
      ...(patientId && { patient_id: patientId })
    }

    setMessages(prev => [...prev, userMessage])
    setInputValue('')
    setIsLoading(true)

    try {
      // Build context for AI
      const context = {
        patient_id: patientId || "",
        session_id: session?.id,
        conversation_history: messages.slice(-10) // Last 10 messages for context
      }

      // Mock response for demo when API is not available
      let response: any
      try {
        response = await apiClient.ai.chat(userMessage.content, context)
      } catch (error) {
        // Fallback to mock response
        response = {
          message: `Entendi sua mensagem: "${userMessage.content}". Esta ├® uma resposta simulada da IA. Configure a API do OpenAI para respostas reais.`,
          confidence: 0.85,
          intent: 'general_inquiry',
          suggestions: ['Como posso ajudar mais?', 'Precisa de informa├º├Áes espec├¡ficas?'],
          requires_human_review: false
        }
      }
      
      const assistantMessage: ChatMessage = {
        id: `msg-${Date.now() + 1}`,
        role: ChatRole.ASSISTANT,
        content: response.message || 'Desculpe, n├úo consegui processar sua mensagem.',
        timestamp: new Date().toISOString(),
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
        ...(patientId && { patient_id: patientId }),
        metadata: {
          confidence: response.confidence,
          ...(response.intent && { intent: response.intent }),
          ...(response.requires_human_review && { requires_review: response.requires_human_review })
        }
      }

      setMessages(prev => [...prev, assistantMessage])

      // Show suggestions if available
      if (response.suggestions && response.suggestions.length > 0) {
        toast({
          title: 'Sugest├Áes',
          description: response.suggestions.join(', ')
        })
      }

      // Alert if human review is needed
      if (response.requires_human_review) {
        toast({
          title: 'Revis├úo Necess├íria',
          description: 'Esta resposta pode precisar de revis├úo humana',
          variant: 'destructive'
        })
      }

    } catch (error) {
      logger.error('Failed to send message:', error)

      const errorMessage: ChatMessage = {
        id: `msg-${Date.now() + 1}`,
        role: ChatRole.ASSISTANT,
        content: 'Desculpe, ocorreu um erro ao processar sua mensagem. Tente novamente.',
        timestamp: new Date().toISOString(),
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
        ...(patientId && { patient_id: patientId })
      }
      
      setMessages(prev => [...prev, errorMessage])
      
      toast({
        title: 'Erro',
        description: 'N├úo foi poss├¡vel enviar a mensagem',
        variant: 'destructive'
      })
    } finally {
      setIsLoading(false)
    }
  }

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      sendMessage()
    }
  }

  const formatTime = (timestamp: string) => {
    return new Date(timestamp).toLocaleTimeString('pt-BR', {
      hour: '2-digit',
      minute: '2-digit'
    })
  }

  const getMessageIcon = (role: ChatMessage['role']) => {
    switch (role) {
      case ChatRole.ASSISTANT:
        return <Bot className="h-4 w-4" />
      case ChatRole.USER:
        return <User className="h-4 w-4" />
      default:
        return null
    }
  }

  const getConfidenceBadge = (confidence?: number) => {
    if (!confidence) return null
    
    const variant = confidence > 0.8 ? 'default' : confidence > 0.6 ? 'secondary' : 'destructive'
    return (
      <Badge variant={variant} className="text-xs">
        {Math.round(confidence * 100)}%
      </Badge>
    )
  }

  return (
    <Card className={className}>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Bot className="h-5 w-5" />
          Chat com IA
          {patientId && (
            <Badge variant="outline">Paciente: {patientId}</Badge>
          )}
        </CardTitle>
      </CardHeader>
      
      <CardContent className="p-0">
        <ScrollArea className="h-96 p-4">
          <div className="space-y-4">
            {messages.map((message) => (
              <div
                key={message.id}
                className={`flex gap-3 ${
                  message.role === ChatRole.USER ? 'justify-end' : 'justify-start'
                }`}
              >
                {message.role !== ChatRole.USER && (
                  <div className="flex-shrink-0">
                    <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center">
                      {getMessageIcon(message.role)}
                    </div>
                  </div>
                )}
                
                <div className={`max-w-[80%] ${message.role === ChatRole.USER ? 'order-first' : ''}`}>
                  <div
                    className={`rounded-lg p-3 ${
                      message.role === ChatRole.USER
                        ? 'bg-primary text-primary-foreground ml-auto'
                        : 'bg-muted'
                    }`}
                  >
                    <p className="text-sm whitespace-pre-wrap">{message.content}</p>
                  </div>
                  
                  <div className="flex items-center gap-2 mt-1 text-xs text-muted-foreground">
                    <span>{formatTime(message.timestamp)}</span>
                    {message.metadata?.['confidence'] && getConfidenceBadge(message.metadata['confidence'] as number)}

                    {message.metadata?.['requires_review'] && (
                      <AlertTriangle className="h-3 w-3 text-yellow-500" />
                    )}
                    {message.metadata?.['intent'] && (
                      <Badge variant="outline" className="text-xs">
                        {String(message.metadata['intent'])}
                      </Badge>
                    )}
                  </div>
                </div>
                
                {message.role === ChatRole.USER && (
                  <div className="flex-shrink-0">
                    <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center">
                      {getMessageIcon(message.role)}
                    </div>
                  </div>
                )}
              </div>
            ))}
            
            {isLoading && (
              <div className="flex gap-3 justify-start">
                <div className="flex-shrink-0">
                  <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center">
                    <Bot className="h-4 w-4" />
                  </div>
                </div>
                <div className="bg-muted rounded-lg p-3">
                  <div className="flex items-center gap-2">
                    <Loader2 className="h-4 w-4 animate-spin" />
                    <span className="text-sm text-muted-foreground">Pensando...</span>
                  </div>
                </div>
              </div>
            )}
            
            <div ref={messagesEndRef} />
          </div>
        </ScrollArea>
        
        <Separator />
        
        <div className="p-4">
          <div className="flex gap-2">
            <Input
              ref={inputRef}
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="Digite sua mensagem..."
              disabled={isLoading}
              className="flex-1"
            />
            <Button
              onClick={sendMessage}
              disabled={!inputValue.trim() || isLoading}
              size="icon"
            >
              {isLoading ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <Send className="h-4 w-4" />
              )}
            </Button>
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

import React, { ReactNode } from "react";
import { Navigate, useLocation } from "react-router-dom";
import { useAuth } from "@/contexts/AuthContext";
import { LoadingSpinner } from "@/components/ui/loading-spinner";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { AlertTriangle } from "lucide-react";
import {
  UserRole,
  getRolePermissions,
  isAdmin,
  isDoctor,
  type RolePermissions,
} from "@/types/shared";

interface ProtectedRouteProps {
  children: ReactNode;
  /**
   * @deprecated Use requiredPermission instead. Will be removed in next version.
   * Required role for accessing this route (legacy)
   */
  requiredRole?: string;
  /**
   * @deprecated Use requiredPermission instead. Will be removed in next version.
   * Multiple roles (any match) for accessing this route (legacy)
   */
  requiredRoles?: string[];
  /**
   * Required permission key from RolePermissions
   * @example "canAccessAdmin", "canManageUsers", "canManagePatients"
   */
  requiredPermission?: keyof RolePermissions;
  /**
   * Redirect path for unauthorized access (default: /unauthorized)
   */
  redirectTo?: string;
}

/**
 * ProtectedRoute Component
 *
 * Protects routes based on authentication and role-based permissions.
 *
 * System Roles:
 * - ADMIN: Full system access (all permissions)
 * - DOCTOR: Clinical operations (patients, reports)
 *
 * @example
 * // Protect admin-only route
 * <ProtectedRoute requiredPermission="canAccessAdmin">
 *   <AdminPanel />
 * </ProtectedRoute>
 *
 * @example
 * // Protect doctor + admin route
 * <ProtectedRoute requiredPermission="canManagePatients">
 *   <PatientsPage />
 * </ProtectedRoute>
 *
 * @example
 * // Just check authentication (any authenticated user)
 * <ProtectedRoute>
 *   <DashboardPage />
 * </ProtectedRoute>
 */
export function ProtectedRoute({
  children,
  requiredRole,
  requiredRoles,
  requiredPermission,
  redirectTo = "/unauthorized",
}: ProtectedRouteProps) {
  const { isAuthenticated, isLoading, user } = useAuth();
  const location = useLocation();

  // Show loading spinner while checking authentication
  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <LoadingSpinner size="lg" />
      </div>
    );
  }

  // Redirect to login if not authenticated
  if (!isAuthenticated) {
    return <Navigate to="/login" state={{ from: location }} replace />;
  }

  // Get user role (with fallback)
  const userRole = user?.role || "";

  // Permission-based access control (NEW - Preferred)
  if (requiredPermission) {
    const permissions = getRolePermissions(userRole);

    if (!permissions[requiredPermission]) {
      return (
        <div className="container mx-auto p-6">
          <Alert variant="destructive">
            <AlertTriangle className="h-4 w-4" />
            <AlertTitle>Acesso Negado</AlertTitle>
            <AlertDescription>
