              {user && (
                <>
                  <br />
                  <span className="text-sm mt-2 block">
                    Sua role: <strong>{userRole}</strong>
                  </span>
                  <span className="text-sm block">
                    Permiss├úo necess├íria: <strong>{requiredPermission}</strong>
                  </span>
                </>
              )}
            </AlertDescription>
          </Alert>
        </div>
      );
    }
  }

  // Legacy: Single role check (DEPRECATED)
  if (requiredRole) {
    const normalizedRequired = requiredRole.toLowerCase();
    const normalizedUser = userRole.toLowerCase();

    // Map legacy roles to new system
    const isAuthorized =
      normalizedUser === normalizedRequired ||
      // Legacy role mappings
      (normalizedRequired === "physician" && isDoctor(userRole)) ||
      (normalizedRequired === "super_admin" && isAdmin(userRole)) ||
      // Admin has access to everything
      isAdmin(userRole);

    if (!isAuthorized) {
      return (
        <div className="container mx-auto p-6">
          <Alert variant="destructive">
            <AlertTriangle className="h-4 w-4" />
            <AlertTitle>Acesso Negado</AlertTitle>
            <AlertDescription>
              Voc├¬ n├úo tem permiss├úo para acessar esta p├ígina.
              {user && (
                <>
                  <br />
                  <span className="text-sm mt-2 block">
                    Role necess├íria: <strong>{requiredRole}</strong>
                  </span>
                  <span className="text-sm block">
                    Sua role atual: <strong>{userRole}</strong>
                  </span>
                  <span className="text-xs mt-2 block text-muted-foreground">
                    ÔÜá´©Å Este componente usa API legada. Migre para requiredPermission.
                  </span>
                </>
              )}
            </AlertDescription>
          </Alert>
        </div>
      );
    }
  }

  // Legacy: Multiple roles check (DEPRECATED)
  if (requiredRoles && requiredRoles.length > 0) {
    const normalizedUser = userRole.toLowerCase();

    const isAuthorized = requiredRoles.some((role) => {
      const normalizedRequired = role.toLowerCase();

      return (
        normalizedUser === normalizedRequired ||
        // Legacy role mappings
        (normalizedRequired === "physician" && isDoctor(userRole)) ||
        (normalizedRequired === "super_admin" && isAdmin(userRole)) ||
        // Admin has access to everything
        isAdmin(userRole)
      );
    });

    if (!isAuthorized) {
      return (
        <div className="container mx-auto p-6">
          <Alert variant="destructive">
            <AlertTriangle className="h-4 w-4" />
            <AlertTitle>Acesso Negado</AlertTitle>
            <AlertDescription>
              Voc├¬ n├úo tem permiss├úo para acessar esta p├ígina.
              {user && (
                <>
                  <br />
                  <span className="text-sm mt-2 block">
                    Roles necess├írias: <strong>{requiredRoles.join(", ")}</strong>
                  </span>
                  <span className="text-sm block">
                    Sua role atual: <strong>{userRole}</strong>
                  </span>
                  <span className="text-xs mt-2 block text-muted-foreground">
                    ÔÜá´©Å Este componente usa API legada. Migre para requiredPermission.
                  </span>
                </>
              )}
            </AlertDescription>
          </Alert>
        </div>
      );
    }
  }

  // All checks passed - render children
  return <>{children}</>;
}

/**
 * Hook for checking permissions in components
 *
 * @example
 * const { canAccess, permissions } = useRoleGuard();
 *
 * if (!permissions.canAccessAdmin) {
 *   return <Unauthorized />;
 * }
 */
export function useRoleGuard() {
  const { user, isAuthenticated } = useAuth();
  const userRole = user?.role || "";
  const permissions = getRolePermissions(userRole);

  return {
    isAuthenticated,
    userRole,
    permissions,
    isAdmin: isAdmin(userRole),
    isDoctor: isDoctor(userRole),
    /**
     * Check if user can access a specific permission
     */
    canAccess: (permission: keyof RolePermissions) => permissions[permission],
    /**
     * Check if user has admin role
     */
    hasAdminAccess: () => isAdmin(userRole),
    /**
     * Check if user has doctor role
     */
    hasDoctorAccess: () => isDoctor(userRole),
  };
}

/**
 * Component for conditional rendering based on permissions
 *
 * @example
 * <PermissionGate permission="canManageUsers">
 *   <Button>Create User</Button>
 * </PermissionGate>
 *
 * @example
 * <PermissionGate permission="canAccessAdmin" fallback={<p>Admins only</p>}>
 *   <AdminPanel />
 * </PermissionGate>
 */
export function PermissionGate({
  permission,
  children,
  fallback = null,
}: {
  permission: keyof RolePermissions;
  children: ReactNode;
  fallback?: ReactNode;
}) {
  const { canAccess } = useRoleGuard();

  if (!canAccess(permission)) {
    return <>{fallback}</>;
  }

  return <>{children}</>;
}

import React, { Component, ReactNode } from 'react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card'
import { Button } from '../ui/button'
import { Alert, AlertDescription } from '../ui/alert'
import { AlertTriangle, RefreshCw, Bug, Home } from 'lucide-react'
import { toast } from '@/components/ui/use-toast'
import { createLogger } from '../../lib/logger'

const logger = createLogger('ErrorBoundary')

interface ErrorBoundaryState {
  hasError: boolean
  error: Error | null
  errorInfo: any
  errorId: string
}

interface ErrorBoundaryProps {
  children: ReactNode
  fallback?: ReactNode
  onError?: (error: Error, errorInfo: any) => void
  showDetails?: boolean
}

export class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props)
    this.state = {
      hasError: false,
      error: null,
      errorInfo: null,
      errorId: ''
    }
  }

  static getDerivedStateFromError(error: Error): Partial<ErrorBoundaryState> {
    // Update state so the next render will show the fallback UI
    return {
      hasError: true,
      error,
      errorId: `err_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
    }
  }

  componentDidCatch(error: Error, errorInfo: any) {
    // Log error details
    logger.error('Error boundary caught an error:', {
      error: error.message,
      stack: error.stack,
      errorInfo
    })

    this.setState({
      error,
      errorInfo,
      errorId: `err_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
    })

    // Call custom error handler if provided
    if (this.props.onError) {
      this.props.onError(error, errorInfo)
    }

    // In production, you might want to report this to an error reporting service
    if (process.env['NODE_ENV'] === 'production') {
      // Report to Sentry, LogRocket, etc.
      console.error('Production Error:', error, errorInfo)
    }
  }

  handleReload = () => {
    window.location.reload()
  }

  handleReset = () => {
    this.setState({
      hasError: false,
      error: null,
      errorInfo: null,
      errorId: ''
    })
  }

  handleReportError = () => {
    const { error, errorInfo, errorId } = this.state

    // Create error report
    const errorReport = {
      id: errorId,
      timestamp: new Date().toISOString(),
      userAgent: navigator.userAgent,
      url: window.location.href,
      error: {
        message: error?.message,
        stack: error?.stack,
        name: error?.name
      },
      errorInfo,
      userData: {
        // Add any user context that might be helpful
        sessionStorage: Object.keys(sessionStorage),
        localStorage: Object.keys(localStorage)
      }
    }

    // Copy to clipboard for now (in production, send to error reporting service)
    navigator.clipboard.writeText(JSON.stringify(errorReport, null, 2))
      .then(() => {
        toast({
          title: 'Relatorio copiado',
          description: 'Os detalhes do erro estao na area de transferencia.',
        })
      })
      .catch(() => {
        logger.warn('Error report copy fallback', errorReport)
        toast({
          title: 'Relatorio registrado',
          description: 'Nao foi possivel copiar, mas o log foi registrado localmente.',
        })
      })
  }

  render() {
    if (this.state.hasError) {
      // Custom fallback UI
      if (this.props.fallback) {
        return this.props.fallback
      }

      // Default error UI
      return (
        <div className="min-h-screen flex items-center justify-center bg-gray-50 px-4">
          <Card className="w-full max-w-2xl">
            <CardHeader className="text-center">
              <div className="w-16 h-16 mx-auto mb-4 bg-red-100 rounded-full flex items-center justify-center">
                <AlertTriangle className="w-8 h-8 text-red-600" />
              </div>
              <CardTitle className="text-2xl text-gray-900">
                Oops! Algo deu errado
              </CardTitle>
              <CardDescription className="text-lg">
                Ocorreu um erro inesperado na aplica├º├úo
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              <Alert variant="destructive">
                <Bug className="h-4 w-4" />
                <AlertDescription>
                  <strong>Erro:</strong> {this.state.error?.message || 'Erro desconhecido'}
                  <br />
                  <strong>ID do Erro:</strong> <code className="text-xs">{this.state.errorId}</code>
                </AlertDescription>
              </Alert>

              {this.props.showDetails && this.state.error && (
                <details className="bg-gray-100 p-4 rounded-lg">
                  <summary className="cursor-pointer font-medium text-gray-700 mb-2">
                    Detalhes T├®cnicos
                  </summary>
                  <div className="text-xs text-gray-600 space-y-2">
                    <div>
                      <strong>Stack Trace:</strong>
                      <pre className="whitespace-pre-wrap text-xs bg-white p-2 rounded border mt-1">
                        {this.state.error.stack}
                      </pre>
                    </div>
                    {this.state.errorInfo && (
                      <div>
                        <strong>Component Stack:</strong>
                        <pre className="whitespace-pre-wrap text-xs bg-white p-2 rounded border mt-1">
                          {this.state.errorInfo.componentStack}
                        </pre>
                      </div>
                    )}
                  </div>
                </details>
              )}

              <div className="text-center space-y-4">
                <p className="text-gray-600">
                  N├úo se preocupe! Voc├¬ pode tentar uma das op├º├Áes abaixo para continuar:
                </p>

                <div className="flex flex-col sm:flex-row gap-3 justify-center">
                  <Button
                    onClick={this.handleReset}
                    variant="default"
                    className="flex items-center space-x-2"
                  >
                    <RefreshCw className="w-4 h-4" />
                    <span>Tentar Novamente</span>
                  </Button>

                  <Button
                    onClick={this.handleReload}
                    variant="outline"
                    className="flex items-center space-x-2"
                  >
                    <RefreshCw className="w-4 h-4" />
                    <span>Recarregar P├ígina</span>
                  </Button>

                  <Button
                    onClick={() => window.location.href = '/'}
                    variant="outline"
                    className="flex items-center space-x-2"
                  >
                    <Home className="w-4 h-4" />
                    <span>Ir para In├¡cio</span>
                  </Button>
                </div>

                <div className="pt-4 border-t">
                  <Button
                    onClick={this.handleReportError}
                    variant="ghost"
                    size="sm"
                    className="text-gray-500 hover:text-gray-700"
                  >
                    <Bug className="w-4 h-4 mr-2" />
                    Reportar Erro
                  </Button>
                  <p className="text-xs text-gray-500 mt-2">
                    Clique para copiar os detalhes do erro e reportar ao suporte t├®cnico
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      )
    }

    return this.props.children
  }
}

// Hook version for functional components
export function useErrorHandler() {
  return (error: Error, errorInfo?: any) => {
    logger.error('Manual error handler triggered:', {
      error: error.message,
      stack: error.stack,
      errorInfo
    })

    // In production, report to error service
    if (process.env['NODE_ENV'] === 'production') {
      console.error('Production Error (Manual):', error, errorInfo)
    }
  }
}

// HOC version
export function withErrorBoundary<P extends object>(
  Component: React.ComponentType<P>,
  errorBoundaryProps?: Omit<ErrorBoundaryProps, 'children'>
) {
  const WrappedComponent = (props: P) => (
    <ErrorBoundary {...errorBoundaryProps}>
      <Component {...props} />
    </ErrorBoundary>
  )

  WrappedComponent.displayName = `withErrorBoundary(${Component.displayName || Component.name})`
  return WrappedComponent
}

// Simple error fallback component
export function SimpleErrorFallback({
  error,
  resetError
}: {
  error: Error
  resetError: () => void
}) {
  return (
    <div className="text-center py-8">
      <AlertTriangle className="w-12 h-12 text-red-500 mx-auto mb-4" />
      <h3 className="text-lg font-medium text-gray-900 mb-2">
        Algo deu errado
      </h3>
      <p className="text-gray-600 mb-4">
        {error.message}
      </p>
      <Button onClick={resetError} variant="outline">
        Tentar novamente
      </Button>
    </div>
  )
}

import React, { useCallback, useState } from 'react'
import { Upload, X, FileText, Image, File } from 'lucide-react'
import { Card, CardContent } from '../ui/card'
import { Button } from '../ui/button'
import { Progress } from '../ui/progress'
import { useToast } from '@/hooks/use-toast'

interface FileUploadProps {
  accept?: string
  multiple?: boolean
  maxSize?: number // in MB
  onUpload: (files: File[]) => Promise<void>
  onRemove?: (index: number) => void
  disabled?: boolean
  className?: string
}

export const FileUpload: React.FC<FileUploadProps> = ({
  accept = '*',
  multiple = false,
  maxSize = 10,
  onUpload,
  onRemove,
  disabled = false,
  className = ''
}) => {
  const { toast } = useToast()
  const [files, setFiles] = useState<File[]>([])
  const [uploading, setUploading] = useState(false)
  const [uploadProgress, setUploadProgress] = useState(0)
  const [dragActive, setDragActive] = useState(false)

  const validateFile = (file: File): boolean => {
    const maxSizeBytes = maxSize * 1024 * 1024

    if (file.size > maxSizeBytes) {
      toast({
        variant: 'destructive',
        title: 'File too large',
        description: `File "${file.name}" exceeds the maximum size of ${maxSize}MB`
      })
      return false
    }

    if (accept !== '*') {
      const acceptedTypes = accept.split(',').map(type => type.trim())
      const fileType = file.type || ''
      const fileExtension = `.${file.name.split('.').pop()}`

      const isAccepted = acceptedTypes.some(type =>
        type === fileType || type === fileExtension ||
        (type.endsWith('/*') && fileType.startsWith(type.replace('/*', '')))
      )

      if (!isAccepted) {
        toast({
          variant: 'destructive',
          title: 'Invalid file type',
          description: `File "${file.name}" is not an accepted file type`
        })
        return false
      }
    }

    return true
  }

  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true)
    } else if (e.type === 'dragleave') {
      setDragActive(false)
    }
  }, [])

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault()
      e.stopPropagation()
      setDragActive(false)

      if (disabled || uploading) return

      const droppedFiles = Array.from(e.dataTransfer.files)
      const validFiles = droppedFiles.filter(validateFile)

      if (validFiles.length > 0) {
        const newFiles = multiple ? [...files, ...validFiles] : validFiles.slice(0, 1)
        setFiles(newFiles)
      }
    },
    [disabled, uploading, files, multiple]
  )

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (disabled || uploading) return

    const selectedFiles = e.target.files ? Array.from(e.target.files) : []
    const validFiles = selectedFiles.filter(validateFile)

    if (validFiles.length > 0) {
      const newFiles = multiple ? [...files, ...validFiles] : validFiles.slice(0, 1)
      setFiles(newFiles)
    }
  }

  const handleUpload = async () => {
    if (files.length === 0) {
      toast({
        variant: 'destructive',
        title: 'No files selected',
        description: 'Please select at least one file to upload'
      })
      return
    }

    setUploading(true)
    setUploadProgress(0)

    try {
      // Simulate progress (in real app, track actual upload progress)
      const progressInterval = setInterval(() => {
        setUploadProgress(prev => Math.min(prev + 10, 90))
      }, 200)

      await onUpload(files)

      clearInterval(progressInterval)
      setUploadProgress(100)

      toast({
        variant: 'success',
        title: 'Upload successful',
        description: `Successfully uploaded ${files.length} file(s)`
      })

      setFiles([])
      setUploadProgress(0)
    } catch (error) {
      toast({
        variant: 'destructive',
        title: 'Upload failed',
        description: error instanceof Error ? error.message : 'An error occurred during upload'
      })
    } finally {
      setUploading(false)
      setUploadProgress(0)
    }
  }

  const handleRemoveFile = (index: number) => {
    const newFiles = files.filter((_, i) => i !== index)
    setFiles(newFiles)
    if (onRemove) {
      onRemove(index)
    }
  }

  const getFileIcon = (file: File) => {
    if (file.type.startsWith('image/')) return <Image className="h-4 w-4" />
    if (file.type.startsWith('text/')) return <FileText className="h-4 w-4" />
    return <File className="h-4 w-4" />
  }

  const formatFileSize = (bytes: number) => {
    if (bytes < 1024) return `${bytes} B`
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`
  }

  return (
    <div className={className}>
      <Card
        className={`border-2 border-dashed transition-colors ${
          dragActive ? 'border-primary bg-primary/5' : 'border-gray-300'
        } ${disabled || uploading ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
      >
        <CardContent className="p-6">
          <input
            id="file-upload"
            type="file"
            className="hidden"
            accept={accept}
            multiple={multiple}
            onChange={handleFileSelect}
            disabled={disabled || uploading}
          />

          <label
            htmlFor="file-upload"
            className="flex flex-col items-center justify-center cursor-pointer"
          >
            <Upload className="h-10 w-10 text-gray-400 mb-3" />
            <p className="text-sm font-medium text-gray-700">
              Click to upload or drag and drop
            </p>
            <p className="text-xs text-gray-500 mt-1">
              {accept === '*' ? 'Any file type' : `Accepted: ${accept}`}
            </p>
            <p className="text-xs text-gray-500">
              Max size: {maxSize}MB {multiple && 'ÔÇó Multiple files allowed'}
            </p>
          </label>
        </CardContent>
      </Card>

      {files.length > 0 && (
        <div className="mt-4 space-y-2">
          {files.map((file, index) => (
            <Card key={index}>
              <CardContent className="p-3 flex items-center justify-between">
                <div className="flex items-center space-x-3">
                  {getFileIcon(file)}
                  <div>
                    <p className="text-sm font-medium">{file.name}</p>
                    <p className="text-xs text-gray-500">{formatFileSize(file.size)}</p>
                  </div>
                </div>
                <Button
                  size="sm"
                  variant="ghost"
                  onClick={() => handleRemoveFile(index)}
                  disabled={uploading}
                >
                  <X className="h-4 w-4" />
                </Button>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {uploading && (
        <div className="mt-4">
          <Progress value={uploadProgress} className="h-2" />
          <p className="text-xs text-gray-500 mt-1 text-center">
            Uploading... {uploadProgress}%
          </p>
        </div>
      )}

      {files.length > 0 && !uploading && (
        <Button
          className="mt-4 w-full"
          onClick={handleUpload}
          disabled={disabled}
        >
          Upload {files.length} file{files.length !== 1 ? 's' : ''}
        </Button>
      )}
    </div>
  )
}

export default FileUpload

import React from 'react'
import type { LucideIcon } from 'lucide-react'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { cn } from '@/lib/utils'

interface MetricCardProps {
  title: string
  value: string | number
  change?: number
  icon: LucideIcon
  trend?: 'up' | 'down'
  variant?: 'default' | 'warning' | 'success'
  description?: string
  format?: string
}

export function MetricCard({
  title,
  value,
  change,
  icon: Icon,
  trend = 'up',
  variant = 'default',
  description,
  format
}: MetricCardProps) {
  const formatChange = (change: number) => {
    const sign = change >= 0 ? '+' : ''
    return `${sign}${change}`
  }

  const getChangeColor = (change: number, trend: 'up' | 'down') => {
    if (change === 0) return 'text-gray-500'
    
    const isPositive = change > 0
    const isGoodChange = (trend === 'up' && isPositive) || (trend === 'down' && !isPositive)
    
    return isGoodChange ? 'text-green-600' : 'text-red-600'
  }

  const getVariantStyles = (variant: string) => {
    switch (variant) {
      case 'warning':
        return 'border-orange-200 bg-orange-50'
      case 'success':
        return 'border-green-200 bg-green-50'
      default:
        return ''
    }
  }

  return (
    <Card className={cn('transition-all hover:shadow-md', getVariantStyles(variant))}>
      <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
        <CardTitle className="text-sm font-medium text-gray-600">
          {title}
        </CardTitle>
        <Icon className={cn(
          'h-4 w-4',
          variant === 'warning' ? 'text-orange-600' : 
          variant === 'success' ? 'text-green-600' : 
          'text-gray-400'
        )} />
      </CardHeader>
      <CardContent>
        <div className="text-2xl font-bold text-gray-900 font-mono tabular-nums">
          {typeof value === 'number' ? value.toLocaleString() : value}
        </div>
        {change !== undefined && (
          <div className="flex items-center mt-2">
            <Badge
              variant="outline"
              className={cn(
                'text-xs font-mono tabular-nums',
                getChangeColor(change, trend)
              )}
            >
              {formatChange(change)}
            </Badge>
            <span className="text-xs text-gray-500 ml-2">
              vs. per├¡odo anterior
            </span>
          </div>
        )}
        {description && (
          <div className="text-xs text-gray-500 mt-1">
            {description}
          </div>
        )}
      </CardContent>
    </Card>
  )
}

