    {
      title: 'Alertas Ativos',
      value: metrics?.alerts_pending || 0,
      change: metrics?.alerts_change || 0,
      icon: AlertTriangle,
      description: 'Requerem atencao'
    },
    {
      title: 'Questionarios',
      value: metrics?.completed_quizzes || 0,
      change: metrics?.quizzes_change || 0,
