import React from 'react'
import { useQuery } from '@tanstack/react-query'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { LoadingSpinner } from '@/components/ui/loading-spinner'
import { FileText, CheckCircle, Clock, ArrowRight } from 'lucide-react'
import { Link } from 'react-router-dom'
import { apiClient } from '@/lib/api-client'

interface QuizSession {
  id: string
  patient_id: string
  patient_name?: string
  quiz_template_id: string
  template_name?: string
  status: string
  score?: number
  completed_at?: string
  started_at: string
}

export function RecentQuizCompletions() {
  // Fetch recent quiz sessions across all patients
  const { data: sessionsData, isLoading, error } = useQuery({
    queryKey: ['recent-quiz-sessions'],
    queryFn: async () => {
      // Get all quiz sessions
      const response = await apiClient.quiz.sessions({})
      return response
    },
    refetchInterval: 60000 // Refresh every minute
  })

  // Format date
  const formatDate = (dateString: string) => {
    const date = new Date(dateString)
    const now = new Date()
    const diffMs = now.getTime() - date.getTime()
    const diffMins = Math.floor(diffMs / 60000)
    const diffHours = Math.floor(diffMs / 3600000)
    const diffDays = Math.floor(diffMs / 86400000)

    if (diffMins < 1) return 'Agora mesmo'
    if (diffMins < 60) return `${diffMins}m atr├ís`
    if (diffHours < 24) return `${diffHours}h atr├ís`
    if (diffDays < 7) return `${diffDays}d atr├ís`
    
    return date.toLocaleDateString('pt-BR', {
      day: '2-digit',
      month: 'short'
    })
  }

  // Get status badge variant
  const getStatusBadgeVariant = (status: string): 'default' | 'secondary' | 'outline' => {
    switch (status) {
      case 'completed':
        return 'default'
      case 'started':
        return 'secondary'
      default:
        return 'outline'
    }
  }

  // Get recent completed sessions (last 5)
  const recentSessions = React.useMemo(() => {
    if (!sessionsData?.items) return []
    
    return sessionsData.items
      .filter((session: QuizSession) => session.status === 'completed')
      .sort((a: QuizSession, b: QuizSession) => {
        const dateA = new Date(a.completed_at || a.started_at).getTime()
        const dateB = new Date(b.completed_at || b.started_at).getTime()
        return dateB - dateA
      })
      .slice(0, 5)
  }, [sessionsData])

  if (isLoading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <FileText className="h-5 w-5" />
            Quiz Recentes
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex items-center justify-center py-8">
            <LoadingSpinner size="md" />
          </div>
        </CardContent>
      </Card>
    )
  }

  if (error) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <FileText className="h-5 w-5" />
            Quiz Recentes
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="text-center text-red-600 py-4 text-sm">
            Erro ao carregar quiz recentes
          </div>
        </CardContent>
      </Card>
    )
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <FileText className="h-5 w-5" />
          Quiz Recentes
        </CardTitle>
        <CardDescription>
          ├Ültimos question├írios completados
        </CardDescription>
      </CardHeader>
      <CardContent>
        {recentSessions.length === 0 ? (
          <div className="text-center py-8">
            <FileText className="mx-auto h-12 w-12 text-gray-400 mb-4" />
            <p className="text-gray-500 text-sm">Nenhum quiz completado recentemente</p>
          </div>
        ) : (
          <div className="space-y-4">
            {recentSessions.map((session: QuizSession) => (
              <Link
                key={session.id}
                to={`/patients/${session.patient_id}?tab=quiz-responses`}
                className="block"
              >
                <div className="flex items-start gap-3 p-3 rounded-lg border hover:border-blue-300 hover:bg-blue-50 transition-all cursor-pointer">
                  <div className="flex-shrink-0 mt-1">
                    <CheckCircle className="h-5 w-5 text-green-600" />
                  </div>
                  
                  <div className="flex-1 min-w-0 space-y-1">
                    <div className="flex items-center justify-between gap-2">
                      <p className="text-sm font-medium text-gray-900 truncate">
                        {session.patient_name || `Paciente ${session.patient_id.slice(0, 8)}`}
                      </p>
                      <Badge variant={getStatusBadgeVariant(session.status)} className="flex-shrink-0">
                        {session.status}
                      </Badge>
                    </div>
                    
                    <p className="text-xs text-gray-600 truncate">
                      {session.template_name || 'Quiz'}
                    </p>
                    
                    <div className="flex items-center justify-between gap-2">
                      <span className="text-xs text-gray-500">
                        {formatDate(session.completed_at || session.started_at)}
                      </span>
                      {session.score !== undefined && session.score !== null && (
                        <span className="text-xs font-medium text-blue-600">
                          Score: {session.score}
                        </span>
                      )}
                    </div>
                  </div>
                  
                  <div className="flex-shrink-0">
                    <ArrowRight className="h-4 w-4 text-gray-400" />
                  </div>
                </div>
              </Link>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  )
}

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { ErrorFallback } from './ErrorFallback';

export interface ErrorBoundaryProps {
  children: ReactNode;
  fallback?: ReactNode;
  onError?: (error: Error, errorInfo: ErrorInfo) => void;
  level?: 'page' | 'component' | 'critical';
  maxRetries?: number;
  enableReporting?: boolean;
}

interface Props extends ErrorBoundaryProps {}

interface State {
  hasError: boolean;
  error: Error | null;
  errorInfo: ErrorInfo | null;
  errorId: string | null;
  retryCount: number;
}

const DEFAULT_MAX_RETRIES = 3;
const RETRY_DELAY = 1000;

/**
 * Enhanced Error Boundary Component with production features
 * Catches unhandled errors in the component tree and displays a fallback UI
 *
 * Features:
 * - Automatic retry with exponential backoff
 * - Error reporting to monitoring services
 * - Different severity levels
 * - Production-safe error display
 *
 * @example
 * ```tsx
 * <ErrorBoundary level="critical" maxRetries={3}>
 *   <App />
 * </ErrorBoundary>
 * ```
 */
export class ErrorBoundary extends Component<Props, State> {
  private retryTimeoutId: NodeJS.Timeout | null = null;

  constructor(props: Props) {
    super(props);
    this.state = {
      hasError: false,
      error: null,
      errorInfo: null,
      errorId: null,
      retryCount: 0,
    };
  }

  static getDerivedStateFromError(error: Error): Partial<State> {
    // Generate unique error ID for tracking
    const errorId = `ERR_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

    // Update state so the next render will show the fallback UI
    return {
      hasError: true,
      error,
      errorId
    };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo): void {
    const { level = 'component', enableReporting = true } = this.props;

    // Log error details for debugging
    console.error('Error Boundary caught an error:', {
      error,
      errorInfo,
      componentStack: errorInfo.componentStack,
      timestamp: new Date().toISOString(),
      level,
      errorId: this.state.errorId
    });

    // Update state with error details
    this.setState({
      errorInfo,
    });

    // Report error in production
    if (enableReporting && process.env['NODE_ENV'] === 'production') {
      this.reportError(error, errorInfo, level);
    }

    // Call custom error handler if provided
    if (this.props.onError) {
      this.props.onError(error, errorInfo);
    }
  }

  private reportError = (error: Error, errorInfo: ErrorInfo, level: string) => {
    try {
      // Report to Sentry if available
      if (typeof window !== 'undefined' && (window as any).Sentry) {
        (window as any).Sentry.withScope((scope: any) => {
          scope.setTag('errorBoundary', true);
          scope.setLevel(level === 'critical' ? 'error' : 'warning');
          scope.setContext('errorInfo', {
            componentStack: errorInfo.componentStack,
            errorBoundaryLevel: level,
            errorId: this.state.errorId
          });
          (window as any).Sentry.captureException(error);
        });
      }

      // Send to backend error tracking
      fetch('/api/v2/errors/client', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          error: {
            message: error.message,
            stack: error.stack,
            name: error.name
          },
          errorInfo: {
            componentStack: errorInfo.componentStack
          },
          level,
          errorId: this.state.errorId,
          url: window.location.href,
          userAgent: navigator.userAgent,
          timestamp: new Date().toISOString()
        })
      }).catch(reportError => {
        console.error('Failed to report error to backend:', reportError);
      });
    } catch (reportError) {
      console.error('Error reporting failed:', reportError);
    }
  };

  handleRetry = (): void => {
    const { maxRetries = DEFAULT_MAX_RETRIES } = this.props;
    const { retryCount } = this.state;

    if (retryCount >= maxRetries) {
      console.warn('Max retries reached, not retrying');
      return;
    }

    this.setState({
      retryCount: retryCount + 1
    });

    // Clear any existing timeout
    if (this.retryTimeoutId) {
      clearTimeout(this.retryTimeoutId);
    }

    // Retry after delay with exponential backoff
    this.retryTimeoutId = setTimeout(() => {
      this.setState({
        hasError: false,
        error: null,
        errorInfo: null
      });
    }, RETRY_DELAY * (retryCount + 1));
  };

  handleReset = (): void => {
    this.setState({
      hasError: false,
      error: null,
      errorInfo: null,
      errorId: null,
      retryCount: 0,
    });

    // Reload the page to ensure clean state
    window.location.reload();
  };

  componentWillUnmount(): void {
    if (this.retryTimeoutId) {
      clearTimeout(this.retryTimeoutId);
    }
  }

  render(): ReactNode {
    if (this.state.hasError) {
      const { maxRetries = DEFAULT_MAX_RETRIES } = this.props;
      const { retryCount } = this.state;

      // Use custom fallback if provided
      if (this.props.fallback) {
        return this.props.fallback;
      }

      // Use enhanced fallback UI with retry functionality
      return (
        <ErrorFallback
          error={this.state.error}
          errorInfo={this.state.errorInfo}
          errorId={this.state.errorId}
          level={this.props.level || 'component'}
          retryCount={retryCount}
          maxRetries={maxRetries}
          onReset={this.handleReset}
          onRetry={this.handleRetry}
        />
      );
    }

    return this.props.children;
  }
}

// Higher-order component for easier use
export function withErrorBoundary<P extends object>(
  Component: React.ComponentType<P>,
  errorBoundaryProps?: Omit<ErrorBoundaryProps, 'children'>
) {
  const WrappedComponent = (props: P) => (
    <ErrorBoundary {...errorBoundaryProps}>
      <Component {...props} />
    </ErrorBoundary>
  );

  WrappedComponent.displayName = `withErrorBoundary(${Component.displayName || Component.name})`;
  return WrappedComponent;
}

// Hook for reporting errors manually
export function useErrorReporting() {
  const reportError = (error: Error, context?: Record<string, any>) => {
    if (process.env['NODE_ENV'] === 'production' && typeof window !== 'undefined' && (window as any).Sentry) {
      (window as any).Sentry.withScope((scope: any) => {
        if (context) {
          scope.setContext('manual_report', context);
        }
        (window as any).Sentry.captureException(error);
      });
    } else {
      console.error('Manual error report:', error, context);
    }
  };

  return { reportError };
}

export default ErrorBoundary;

import React, { ErrorInfo } from 'react';
import { AlertTriangle, RefreshCw, Home, Bug } from 'lucide-react';
