import React, { useRef, useCallback, useState, useEffect } from 'react'
import { 
  FlowDesign, 
  FlowNode, 
  FlowConnection, 
  DesignerMode,
  FlowValidationResult 
} from '@/lib/types/flow-designer'
import { FlowNodeComponent } from './FlowNodeComponent'
import { FlowConnectionComponent } from './FlowConnectionComponent'

interface FlowCanvasProps {
  design: FlowDesign
  selectedNodes: string[]
  selectedConnections: string[]
  zoom: number
  pan: { x: number; y: number }
  mode: DesignerMode
  onNodeSelect: (nodeId: string, multiSelect?: boolean) => void
  onConnectionSelect: (connectionId: string) => void
  onNodeUpdate: (nodeId: string, updates: Partial<FlowNode>) => void
  onAddConnection: (source: string, target: string) => void
  onPanChange: (pan: { x: number; y: number }) => void
  validation?: FlowValidationResult | null
}

export function FlowCanvas({
  design,
  selectedNodes,
  selectedConnections,
  zoom,
  pan,
  mode,
  onNodeSelect,
  onConnectionSelect,
  onNodeUpdate,
  onAddConnection,
  onPanChange,
  validation
}: FlowCanvasProps) {
  const canvasRef = useRef<HTMLDivElement>(null)
  const [isDragging, setIsDragging] = useState(false)
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 })
  const [connecting, setConnecting] = useState<{ from: string; to?: string } | null>(null)

  // Handle canvas mouse events
  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    if (mode === DesignerMode.PAN) {
      setIsDragging(true)
      setDragStart({ x: e.clientX - pan.x, y: e.clientY - pan.y })
    }
  }, [mode, pan])

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (isDragging && mode === DesignerMode.PAN) {
      onPanChange({
        x: e.clientX - dragStart.x,
        y: e.clientY - dragStart.y
      })
    }
  }, [isDragging, mode, dragStart, onPanChange])

  const handleMouseUp = useCallback(() => {
    setIsDragging(false)
  }, [])

  // Handle node drag
  const handleNodeDrag = useCallback((nodeId: string, position: { x: number; y: number }) => {
    onNodeUpdate(nodeId, { position })
  }, [onNodeUpdate])

  // Handle connection creation
  const handleConnectionStart = useCallback((nodeId: string) => {
    if (mode === DesignerMode.CONNECT) {
      setConnecting({ from: nodeId })
    }
  }, [mode])

  const handleConnectionEnd = useCallback((nodeId: string) => {
    if (connecting && connecting.from !== nodeId) {
      onAddConnection(connecting.from, nodeId)
      setConnecting(null)
    }
  }, [connecting, onAddConnection])

  // Handle canvas click (deselect)
  const handleCanvasClick = useCallback((e: React.MouseEvent) => {
    if (e.target === e.currentTarget) {
      onNodeSelect('', false) // Deselect all
    }
  }, [onNodeSelect])

  // Get node validation errors
  const getNodeErrors = useCallback((nodeId: string) => {
    if (!validation) return []
    return validation.errors.filter(error => error.node_id === nodeId)
  }, [validation])

  // Get connection validation errors
  const getConnectionErrors = useCallback((connectionId: string) => {
    if (!validation) return []
    return validation.errors.filter(error => error.connection_id === connectionId)
  }, [validation])

  return (
    <div
      ref={canvasRef}
      className="relative w-full h-full bg-gray-50 overflow-hidden cursor-crosshair"
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onClick={handleCanvasClick}
      style={{
        backgroundImage: `
          radial-gradient(circle, #e5e7eb 1px, transparent 1px)
        `,
        backgroundSize: `${20 * zoom}px ${20 * zoom}px`,
        backgroundPosition: `${pan.x}px ${pan.y}px`
      }}
    >
      {/* Canvas Transform Container */}
      <div
        style={{
          transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
          transformOrigin: '0 0',
          width: '100%',
          height: '100%',
          position: 'relative'
        }}
      >
        {/* Render Connections */}
        <svg
          className="absolute inset-0 pointer-events-none"
          style={{ width: '100%', height: '100%', overflow: 'visible' }}
        >
          {design.connections.map(connection => (
            <FlowConnectionComponent
              key={connection.id}
              connection={connection}
              nodes={design.nodes}
              selected={selectedConnections.includes(connection.id)}
              errors={getConnectionErrors(connection.id)}
              onSelect={() => onConnectionSelect(connection.id)}
            />
          ))}
          
          {/* Temporary connection while connecting */}
          {connecting && (
            <line
              x1={getNodePosition(connecting.from)?.x || 0}
              y1={getNodePosition(connecting.from)?.y || 0}
              x2={getNodePosition(connecting.from)?.x || 0}
              y2={getNodePosition(connecting.from)?.y || 0}
              stroke="#3b82f6"
              strokeWidth="2"
              strokeDasharray="5,5"
              className="pointer-events-none"
            />
          )}
        </svg>

        {/* Render Nodes */}
        {design.nodes.map(node => (
          <FlowNodeComponent
            key={node.id}
            node={node}
            selected={selectedNodes.includes(node.id)}
            errors={getNodeErrors(node.id)}
            mode={mode}
            onSelect={(multiSelect) => onNodeSelect(node.id, multiSelect)}
            onDrag={(position) => handleNodeDrag(node.id, position)}
            onConnectionStart={() => handleConnectionStart(node.id)}
            onConnectionEnd={() => handleConnectionEnd(node.id)}
          />
        ))}
      </div>

      {/* Mode Indicator */}
      <div className="absolute top-4 left-4 bg-white rounded-lg shadow-sm border px-3 py-2">
        <div className="flex items-center gap-2 text-sm">
          <div className={`w-2 h-2 rounded-full ${getModeColor(mode)}`} />
          <span>{getModeLabel(mode)}</span>
        </div>
      </div>

      {/* Zoom Indicator */}
      <div className="absolute bottom-4 right-4 bg-white rounded-lg shadow-sm border px-3 py-2">
        <span className="text-sm font-medium">{Math.round(zoom * 100)}%</span>
      </div>

      {/* Validation Summary */}
      {validation && !validation.isValid && (
        <div className="absolute top-4 right-4 bg-red-50 border border-red-200 rounded-lg p-3 max-w-sm">
          <div className="text-sm font-medium text-red-800 mb-1">
            Erros de Valida├º├úo ({validation.errors.length})
          </div>
          <div className="text-xs text-red-600 space-y-1">
            {validation.errors.slice(0, 3).map(error => (
              <div key={error.id}>{error.message}</div>
            ))}
            {validation.errors.length > 3 && (
              <div>... e mais {validation.errors.length - 3} erro(s)</div>
            )}
          </div>
        </div>
      )}
    </div>
  )

  // Helper function to get node position
  function getNodePosition(nodeId: string) {
    const node = design.nodes.find(n => n.id === nodeId)
    return node?.position
  }
}

// Helper functions
function getModeColor(mode: DesignerMode): string {
  switch (mode) {
    case DesignerMode.SELECT:
      return 'bg-blue-500'
    case DesignerMode.CONNECT:
      return 'bg-green-500'
    case DesignerMode.PAN:
      return 'bg-purple-500'
    default:
      return 'bg-gray-500'
  }
}

function getModeLabel(mode: DesignerMode): string {
  switch (mode) {
    case DesignerMode.SELECT:
      return 'Selecionar'
    case DesignerMode.CONNECT:
      return 'Conectar'
    case DesignerMode.PAN:
      return 'Navegar'
    default:
      return 'Desconhecido'
  }
}

import React from 'react'
import { FlowConnection, FlowNode, FlowValidationError } from '@/lib/types/flow-designer'

interface FlowConnectionComponentProps {
  connection: FlowConnection
  nodes: FlowNode[]
  selected: boolean
  errors: FlowValidationError[]
  onSelect: () => void
}

export function FlowConnectionComponent({
  connection,
  nodes,
  selected,
  errors,
  onSelect
}: FlowConnectionComponentProps) {
  // Find source and target nodes
  const sourceNode = nodes.find(node => node.id === connection.source)
  const targetNode = nodes.find(node => node.id === connection.target)

  if (!sourceNode || !targetNode) {
    return null
  }

  // Calculate connection points
  const sourcePoint = {
    x: sourceNode.position.x + 60, // Assuming node width of 120px
    y: sourceNode.position.y + 40  // Assuming node height of 80px
  }

  const targetPoint = {
    x: targetNode.position.x + 60,
    y: targetNode.position.y + 40
  }

  // Calculate control points for curved line
  const dx = targetPoint.x - sourcePoint.x
  const dy = targetPoint.y - sourcePoint.y
  const distance = Math.sqrt(dx * dx + dy * dy)
  
  // Control points for smooth curve
  const controlOffset = Math.min(distance * 0.3, 100)
  const control1 = {
    x: sourcePoint.x + controlOffset,
    y: sourcePoint.y
  }
  const control2 = {
    x: targetPoint.x - controlOffset,
    y: targetPoint.y
  }

  // Create SVG path
  const pathData = `M ${sourcePoint.x} ${sourcePoint.y} C ${control1.x} ${control1.y}, ${control2.x} ${control2.y}, ${targetPoint.x} ${targetPoint.y}`

  // Calculate midpoint for label
  const midPoint = {
    x: (sourcePoint.x + targetPoint.x) / 2,
    y: (sourcePoint.y + targetPoint.y) / 2
  }

  const hasErrors = errors.length > 0
  const strokeColor = hasErrors ? '#ef4444' : selected ? '#3b82f6' : '#6b7280'
  const strokeWidth = selected ? 3 : 2

  return (
    <g>
      {/* Main connection path */}
      <path
        d={pathData}
        fill="none"
        stroke={strokeColor}
        strokeWidth={strokeWidth}
        strokeDasharray={connection.animated ? '5,5' : 'none'}
        className={`
          cursor-pointer transition-all duration-200
          ${connection.animated ? 'animate-pulse' : ''}
          hover:stroke-blue-500
        `}
        onClick={(e) => {
          e.stopPropagation()
          onSelect()
        }}
      />

      {/* Arrow head */}
      <defs>
        <marker
          id={`arrowhead-${connection.id}`}
          markerWidth="10"
          markerHeight="7"
          refX="9"
          refY="3.5"
          orient="auto"
        >
          <polygon
            points="0 0, 10 3.5, 0 7"
            fill={strokeColor}
          />
        </marker>
      </defs>
      
      <path
        d={pathData}
        fill="none"
        stroke="transparent"
        strokeWidth="1"
        markerEnd={`url(#arrowhead-${connection.id})`}
      />

      {/* Connection label */}
      {connection.label && (
        <g>
          {/* Label background */}
          <rect
            x={midPoint.x - 30}
            y={midPoint.y - 10}
            width="60"
            height="20"
            fill="white"
            stroke={strokeColor}
            strokeWidth="1"
            rx="10"
            className="cursor-pointer"
            onClick={(e) => {
              e.stopPropagation()
              onSelect()
            }}
          />
          {/* Label text */}
          <text
            x={midPoint.x}
            y={midPoint.y + 4}
            textAnchor="middle"
            className="text-xs font-medium fill-current pointer-events-none"
            style={{ color: strokeColor }}
          >
            {connection.label}
          </text>
        </g>
      )}

      {/* Condition label */}
      {connection.condition && (
        <g>
          {/* Condition background */}
          <rect
            x={midPoint.x - 40}
            y={midPoint.y + 15}
            width="80"
            height="16"
            fill="yellow"
            stroke="#f59e0b"
            strokeWidth="1"
            rx="8"
            className="cursor-pointer opacity-90"
            onClick={(e) => {
              e.stopPropagation()
              onSelect()
            }}
          />
          {/* Condition text */}
          <text
            x={midPoint.x}
            y={midPoint.y + 26}
            textAnchor="middle"
            className="text-xs font-medium fill-current pointer-events-none"
            style={{ color: '#92400e' }}
          >
            {connection.condition}
          </text>
        </g>
      )}

      {/* Error indicator */}
      {hasErrors && (
        <g>
          {/* Error background */}
          <circle
            cx={midPoint.x}
            cy={midPoint.y - 20}
            r="8"
            fill="#fef2f2"
            stroke="#ef4444"
            strokeWidth="2"
            className="cursor-pointer"
            onClick={(e) => {
              e.stopPropagation()
              onSelect()
            }}
          />
          {/* Error icon */}
          <text
            x={midPoint.x}
            y={midPoint.y - 16}
            textAnchor="middle"
            className="text-xs font-bold fill-current pointer-events-none"
            style={{ color: '#ef4444' }}
          >
            !
          </text>
        </g>
      )}

      {/* Selection indicator */}
      {selected && (
        <path
          d={pathData}
          fill="none"
          stroke="#3b82f6"
          strokeWidth="6"
          opacity="0.3"
          className="pointer-events-none"
        />
      )}
    </g>
  )
}

import React, { useState, useCallback, useRef, useEffect } from 'react'
import { 
  Play, 
  Save, 
  Download, 
  Upload, 
  Undo, 
  Redo, 
  ZoomIn, 
  ZoomOut, 
  Move,
  MousePointer,
  Link,
  Settings,
  Eye,
  AlertTriangle,
  CheckCircle
} from 'lucide-react'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Separator } from '@/components/ui/separator'
import { Badge } from '@/components/ui/badge'
import { useToast } from '@/components/ui/use-toast'
import { 
  FlowDesign, 
  FlowNode, 
  FlowConnection, 
  FlowDesignerState, 
  DesignerMode,
  FlowValidationResult
} from '@/lib/types/flow-designer'
import { FlowCanvas } from './FlowCanvas'
import { NodePalette } from './NodePalette'
import { PropertyPanel } from './PropertyPanel'
import { FlowValidator } from './FlowValidator'

interface FlowDesignerProps {
  initialDesign?: FlowDesign
  onSave?: (design: FlowDesign) => void
  onTest?: (design: FlowDesign) => void
  className?: string
}

export function FlowDesigner({ 
  initialDesign, 
  onSave, 
  onTest,
  className 
}: FlowDesignerProps) {
  const [designerState, setDesignerState] = useState<FlowDesignerState>(() => ({
    design: initialDesign || createEmptyDesign(),
    selectedNodes: [],
    selectedConnections: [],
    clipboard: [],
    history: [],
    historyIndex: -1,
    zoom: 1,
    pan: { x: 0, y: 0 },
    mode: DesignerMode.SELECT,
    isModified: false
  }))

  const [validation, setValidation] = useState<FlowValidationResult | null>(null)
  const [showPropertyPanel, setShowPropertyPanel] = useState(true)
  const [showNodePalette, setShowNodePalette] = useState(true)
  const canvasRef = useRef<HTMLDivElement>(null)
  const { toast } = useToast()

  // Validate flow whenever design changes
  useEffect(() => {
    const validator = new FlowValidator()
    const result = validator.validate(designerState.design)
    setValidation(result)
  }, [designerState.design])

  // Handle node selection
  const handleNodeSelect = useCallback((nodeId: string, multiSelect = false) => {
    setDesignerState(prev => ({
      ...prev,
      selectedNodes: multiSelect 
        ? prev.selectedNodes.includes(nodeId)
          ? prev.selectedNodes.filter(id => id !== nodeId)
          : [...prev.selectedNodes, nodeId]
        : [nodeId],
      selectedConnections: []
    }))
  }, [])

  // Handle connection selection
  const handleConnectionSelect = useCallback((connectionId: string) => {
    setDesignerState(prev => ({
      ...prev,
      selectedConnections: [connectionId],
      selectedNodes: []
    }))
  }, [])

  // Add node to canvas
  const handleAddNode = useCallback((nodeType: string, position: { x: number; y: number }) => {
    const newNode: FlowNode = {
      id: `node-${Date.now()}`,
      type: nodeType as any,
      position,
      data: {
        label: `${nodeType} Node`,
        config: getDefaultNodeConfig(nodeType)
      }
    }

    setDesignerState(prev => ({
      ...prev,
      design: {
        ...prev.design,
        nodes: [...prev.design.nodes, newNode]
      },
      isModified: true
    }))

    // Add to history
    addToHistory('Add Node', `Added ${nodeType} node`)
  }, [])

  // Update node
  const handleUpdateNode = useCallback((nodeId: string, updates: Partial<FlowNode>) => {
    setDesignerState(prev => ({
      ...prev,
      design: {
        ...prev.design,
        nodes: prev.design.nodes.map(node =>
          node.id === nodeId ? { ...node, ...updates } : node
        )
      },
      isModified: true
    }))
  }, [])

  // Delete selected items
  const handleDelete = useCallback(() => {
    setDesignerState(prev => {
      const newNodes = prev.design.nodes.filter(
        node => !prev.selectedNodes.includes(node.id)
      )
      const newConnections = prev.design.connections.filter(
        conn => !prev.selectedConnections.includes(conn.id) &&
                !prev.selectedNodes.includes(conn.source) &&
                !prev.selectedNodes.includes(conn.target)
      )

      return {
        ...prev,
        design: {
          ...prev.design,
          nodes: newNodes,
          connections: newConnections
        },
        selectedNodes: [],
        selectedConnections: [],
        isModified: true
      }
    })

    addToHistory('Delete', 'Deleted selected items')
  }, [])

  // Add connection
  const handleAddConnection = useCallback((source: string, target: string) => {
    const newConnection: FlowConnection = {
      id: `conn-${Date.now()}`,
      source,
      target
    }

    setDesignerState(prev => ({
      ...prev,
      design: {
        ...prev.design,
        connections: [...prev.design.connections, newConnection]
      },
      isModified: true
    }))

    addToHistory('Add Connection', `Connected ${source} to ${target}`)
  }, [])

  // Zoom controls
  const handleZoomIn = useCallback(() => {
    setDesignerState(prev => ({
      ...prev,
      zoom: Math.min(prev.zoom * 1.2, 3)
    }))
  }, [])

  const handleZoomOut = useCallback(() => {
    setDesignerState(prev => ({
      ...prev,
      zoom: Math.max(prev.zoom / 1.2, 0.1)
    }))
  }, [])

  const handleZoomReset = useCallback(() => {
    setDesignerState(prev => ({
      ...prev,
      zoom: 1,
      pan: { x: 0, y: 0 }
    }))
  }, [])

  // Mode switching
  const handleModeChange = useCallback((mode: DesignerMode) => {
    setDesignerState(prev => ({
      ...prev,
      mode
    }))
  }, [])

  // Save design
  const handleSave = useCallback(() => {
    if (validation && !validation.isValid) {
      toast({
        title: 'Erro de Valida├º├úo',
        description: 'Corrija os erros antes de salvar',
        variant: 'destructive'
      })
      return
    }

    onSave?.(designerState.design)
    setDesignerState(prev => ({ ...prev, isModified: false }))
    
    toast({
      title: 'Salvo',
      description: 'Flow salvo com sucesso'
    })
  }, [designerState.design, validation, onSave, toast])

  // Test flow
  const handleTest = useCallback(() => {
    if (validation && !validation.isValid) {
      toast({
        title: 'Erro de Valida├º├úo',
        description: 'Corrija os erros antes de testar',
        variant: 'destructive'
      })
      return
    }

    onTest?.(designerState.design)
  }, [designerState.design, validation, onTest, toast])

  // History management
  const addToHistory = useCallback((action: string, description: string) => {
    setDesignerState(prev => ({
      ...prev,
      history: [
        ...prev.history.slice(0, prev.historyIndex + 1),
        {
          action,
          timestamp: Date.now(),
          data: prev.design,
          description
        }
      ],
      historyIndex: prev.historyIndex + 1
    }))
  }, [])

  const handleUndo = useCallback(() => {
    if (designerState.historyIndex > 0) {
      const previousState = designerState.history[designerState.historyIndex - 1]
      if (!previousState) return
      setDesignerState(prev => ({
        ...prev,
        design: previousState.data as FlowDesign,
        historyIndex: prev.historyIndex - 1,
        isModified: true
      }))
    }
  }, [designerState.historyIndex, designerState.history])

  const handleRedo = useCallback(() => {
    if (designerState.historyIndex < designerState.history.length - 1) {
      const nextState = designerState.history[designerState.historyIndex + 1]
      if (!nextState) return
      setDesignerState(prev => ({
        ...prev,
        design: nextState.data as FlowDesign,
        historyIndex: prev.historyIndex + 1,
        isModified: true
      }))
    }
  }, [designerState.historyIndex, designerState.history])

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.ctrlKey || e.metaKey) {
        switch (e.key) {
          case 's':
            e.preventDefault()
            handleSave()
            break
          case 'z':
            e.preventDefault()
            if (e.shiftKey) {
              handleRedo()
            } else {
              handleUndo()
            }
            break
          case 'Delete':
          case 'Backspace':
            e.preventDefault()
            handleDelete()
            break
        }
      }
    }

    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [handleSave, handleUndo, handleRedo, handleDelete])

  const getValidationStatus = () => {
    if (!validation) return null
    
    if (validation.isValid) {
      return (
        <Badge variant="default" className="bg-green-500">
          <CheckCircle className="h-3 w-3 mr-1" />
          V├ílido
        </Badge>
      )
    } else {
      return (
        <Badge variant="destructive">
          <AlertTriangle className="h-3 w-3 mr-1" />
          {validation.errors.length} erro(s)
        </Badge>
      )
    }
  }

  return (
    <div className={`flex flex-col h-full ${className}`}>
      {/* Toolbar */}
      <Card className="rounded-none border-x-0 border-t-0">
        <CardHeader className="pb-3">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <CardTitle className="text-lg">Flow Designer</CardTitle>
              {designerState.isModified && (
                <Badge variant="outline">Modificado</Badge>
              )}
              {getValidationStatus()}
            </div>
            
            <div className="flex items-center gap-2">
              {/* Mode Controls */}
              <div className="flex items-center gap-1 border rounded-md p-1">
                <Button
                  variant={designerState.mode === DesignerMode.SELECT ? "default" : "ghost"}
                  size="sm"
                  onClick={() => handleModeChange(DesignerMode.SELECT)}
                >
                  <MousePointer className="h-4 w-4" />
                </Button>
                <Button
                  variant={designerState.mode === DesignerMode.CONNECT ? "default" : "ghost"}
                  size="sm"
                  onClick={() => handleModeChange(DesignerMode.CONNECT)}
                >
                  <Link className="h-4 w-4" />
                </Button>
                <Button
                  variant={designerState.mode === DesignerMode.PAN ? "default" : "ghost"}
                  size="sm"
                  onClick={() => handleModeChange(DesignerMode.PAN)}
                >
                  <Move className="h-4 w-4" />
                </Button>
              </div>

              <Separator orientation="vertical" className="h-6" />

              {/* History Controls */}
              <Button
                variant="ghost"
                size="sm"
                onClick={handleUndo}
                disabled={designerState.historyIndex <= 0}
              >
                <Undo className="h-4 w-4" />
              </Button>
              <Button
                variant="ghost"
                size="sm"
                onClick={handleRedo}
                disabled={designerState.historyIndex >= designerState.history.length - 1}
              >
                <Redo className="h-4 w-4" />
              </Button>

              <Separator orientation="vertical" className="h-6" />

              {/* Zoom Controls */}
              <Button variant="ghost" size="sm" onClick={handleZoomOut}>
                <ZoomOut className="h-4 w-4" />
              </Button>
              <span className="text-sm min-w-[3rem] text-center">
                {Math.round(designerState.zoom * 100)}%
              </span>
              <Button variant="ghost" size="sm" onClick={handleZoomIn}>
                <ZoomIn className="h-4 w-4" />
              </Button>

              <Separator orientation="vertical" className="h-6" />

              {/* Action Buttons */}
              <Button variant="ghost" size="sm" onClick={handleTest}>
                <Play className="h-4 w-4 mr-2" />
                Testar
              </Button>
              <Button variant="default" size="sm" onClick={handleSave}>
                <Save className="h-4 w-4 mr-2" />
                Salvar
              </Button>
            </div>
          </div>
        </CardHeader>
      </Card>

      {/* Main Content */}
      <div className="flex flex-1 overflow-hidden">
        {/* Node Palette */}
        {showNodePalette && (
          <div className="w-64 border-r bg-background">
            <NodePalette onAddNode={handleAddNode} />
          </div>
        )}

        {/* Canvas */}
        <div className="flex-1 relative" ref={canvasRef}>
          <FlowCanvas
            design={designerState.design}
            selectedNodes={designerState.selectedNodes}
            selectedConnections={designerState.selectedConnections}
            zoom={designerState.zoom}
            pan={designerState.pan}
            mode={designerState.mode}
            onNodeSelect={handleNodeSelect}
            onConnectionSelect={handleConnectionSelect}
            onNodeUpdate={handleUpdateNode}
            onAddConnection={handleAddConnection}
            onPanChange={(pan) => setDesignerState(prev => ({ ...prev, pan }))}
            validation={validation}
          />
        </div>

        {/* Property Panel */}
        {showPropertyPanel && (
          <div className="w-80 border-l bg-background">
            <PropertyPanel
              design={designerState.design}
              selectedNodes={designerState.selectedNodes}
              selectedConnections={designerState.selectedConnections}
              onUpdateNode={handleUpdateNode}
              validation={validation}
            />
          </div>
        )}
      </div>
    </div>
  )
}

// Helper functions
function createEmptyDesign(): FlowDesign {
  return {
    id: `design-${Date.now()}`,
    name: 'Novo Flow',
    description: '',
    version: '1.0.0',
    nodes: [],
    connections: [],
    variables: [],
    metadata: {
      author: 'current-user',
      tags: [],
      category: 'general',
      complexity_level: 'simple'
    },
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString()
  }
}

function getDefaultNodeConfig(nodeType: string): Record<string, any> {
  switch (nodeType) {
    case 'message':
      return {
        content: 'Nova mensagem',
        message_type: 'text'
      }
    case 'condition':
      return {
        conditions: [],
        operator: 'AND'
      }
    case 'delay':
      return {
        duration: 1,
        unit: 'minutes'
      }
    case 'action':
      return {
        action_type: 'set_variable',
        parameters: {}
      }
    default:
      return {}
  }
}

import React, { useState, useCallback } from 'react'
import { 
  MessageSquare, 
  GitBranch, 
  Clock, 
  Zap, 
  Play, 
  Square,
  Bot,
  HelpCircle,
  Webhook,
  AlertTriangle
} from 'lucide-react'
import { FlowNode, FlowNodeType, DesignerMode, FlowValidationError } from '@/lib/types/flow-designer'

interface FlowNodeComponentProps {
  node: FlowNode
  selected: boolean
  errors: FlowValidationError[]
  mode: DesignerMode
  onSelect: (multiSelect?: boolean) => void
  onDrag: (position: { x: number; y: number }) => void
  onConnectionStart: () => void
  onConnectionEnd: () => void
}

export function FlowNodeComponent({
  node,
  selected,
  errors,
  mode,
  onSelect,
  onDrag,
  onConnectionStart,
  onConnectionEnd
}: FlowNodeComponentProps) {
  const [isDragging, setIsDragging] = useState(false)
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 })

  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    e.stopPropagation()
    
    if (mode === DesignerMode.SELECT) {
      setIsDragging(true)
      setDragStart({
        x: e.clientX - node.position.x,
        y: e.clientY - node.position.y
      })
      onSelect(e.ctrlKey || e.metaKey)
    } else if (mode === DesignerMode.CONNECT) {
      onConnectionStart()
    }
  }, [mode, node.position, onSelect, onConnectionStart])

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (isDragging && mode === DesignerMode.SELECT) {
      onDrag({
        x: e.clientX - dragStart.x,
        y: e.clientY - dragStart.y
      })
    }
  }, [isDragging, mode, dragStart, onDrag])

  const handleMouseUp = useCallback((e: React.MouseEvent) => {
    e.stopPropagation()
    setIsDragging(false)
    
    if (mode === DesignerMode.CONNECT) {
      onConnectionEnd()
    }
  }, [mode, onConnectionEnd])

  const getNodeIcon = (type: FlowNodeType) => {
    switch (type) {
      case FlowNodeType.START:
        return <Play className="h-4 w-4" />
      case FlowNodeType.MESSAGE:
        return <MessageSquare className="h-4 w-4" />
      case FlowNodeType.CONDITION:
        return <GitBranch className="h-4 w-4" />
      case FlowNodeType.DELAY:
        return <Clock className="h-4 w-4" />
      case FlowNodeType.ACTION:
        return <Zap className="h-4 w-4" />
      case FlowNodeType.END:
        return <Square className="h-4 w-4" />
      case FlowNodeType.AI_RESPONSE:
        return <Bot className="h-4 w-4" />
      case FlowNodeType.QUIZ:
        return <HelpCircle className="h-4 w-4" />
      case FlowNodeType.WEBHOOK:
        return <Webhook className="h-4 w-4" />
      default:
        return <Square className="h-4 w-4" />
    }
  }

  const getNodeColor = (type: FlowNodeType) => {
    switch (type) {
      case FlowNodeType.START:
        return 'bg-green-100 border-green-300 text-green-800'
      case FlowNodeType.MESSAGE:
        return 'bg-blue-100 border-blue-300 text-blue-800'
      case FlowNodeType.CONDITION:
        return 'bg-yellow-100 border-yellow-300 text-yellow-800'
      case FlowNodeType.DELAY:
        return 'bg-purple-100 border-purple-300 text-purple-800'
      case FlowNodeType.ACTION:
        return 'bg-orange-100 border-orange-300 text-orange-800'
      case FlowNodeType.END:
        return 'bg-red-100 border-red-300 text-red-800'
      case FlowNodeType.AI_RESPONSE:
        return 'bg-indigo-100 border-indigo-300 text-indigo-800'
      case FlowNodeType.QUIZ:
        return 'bg-pink-100 border-pink-300 text-pink-800'
      case FlowNodeType.WEBHOOK:
        return 'bg-gray-100 border-gray-300 text-gray-800'
      default:
        return 'bg-gray-100 border-gray-300 text-gray-800'
    }
  }

  const hasErrors = errors.length > 0
  const nodeColorClass = hasErrors 
    ? 'bg-red-100 border-red-500 text-red-800' 
    : getNodeColor(node.type)

  return (
    <div
      className={`
        absolute cursor-pointer select-none transition-all duration-200
        ${isDragging ? 'z-50' : 'z-10'}
        ${mode === DesignerMode.CONNECT ? 'cursor-crosshair' : 'cursor-move'}
      `}
      style={{
        left: node.position.x,
        top: node.position.y,
        transform: isDragging ? 'scale(1.05)' : 'scale(1)'
      }}
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
    >
      {/* Node Body */}
      <div
        className={`
          relative min-w-[120px] max-w-[200px] p-3 rounded-lg border-2 shadow-sm
          ${nodeColorClass}
          ${selected ? 'ring-2 ring-blue-500 ring-offset-2' : ''}
          ${isDragging ? 'shadow-lg' : ''}
          hover:shadow-md transition-shadow
        `}
      >
        {/* Node Header */}
        <div className="flex items-center gap-2 mb-1">
          {getNodeIcon(node.type)}
          <span className="font-medium text-sm truncate">
            {node.data.label}
          </span>
          {hasErrors && (
            <AlertTriangle className="h-4 w-4 text-red-500 flex-shrink-0" />
          )}
        </div>

        {/* Node Description */}
        {node.data.description && (
          <div className="text-xs opacity-75 truncate">
            {node.data.description}
          </div>
        )}

        {/* Connection Points */}
        <div className="absolute -top-2 left-1/2 transform -translate-x-1/2">
          <div className="w-3 h-3 bg-white border-2 border-gray-400 rounded-full hover:border-blue-500 transition-colors" />
        </div>
        <div className="absolute -bottom-2 left-1/2 transform -translate-x-1/2">
          <div className="w-3 h-3 bg-white border-2 border-gray-400 rounded-full hover:border-blue-500 transition-colors" />
        </div>
        <div className="absolute -left-2 top-1/2 transform -translate-y-1/2">
          <div className="w-3 h-3 bg-white border-2 border-gray-400 rounded-full hover:border-blue-500 transition-colors" />
        </div>
        <div className="absolute -right-2 top-1/2 transform -translate-y-1/2">
          <div className="w-3 h-3 bg-white border-2 border-gray-400 rounded-full hover:border-blue-500 transition-colors" />
        </div>

        {/* Node Type Badge */}
        <div className="absolute -top-1 -right-1">
          <div className="bg-white border border-gray-300 rounded-full p-1 text-xs">
            {node.type.charAt(0).toUpperCase()}
          </div>
        </div>
      </div>

      {/* Error Tooltip */}
      {hasErrors && (
        <div className="absolute top-full left-0 mt-2 p-2 bg-red-50 border border-red-200 rounded-md shadow-lg z-50 min-w-[200px]">
          <div className="text-xs font-medium text-red-800 mb-1">Erros:</div>
          {errors.map(error => (
            <div key={error.id} className="text-xs text-red-600">
              ÔÇó {error.message}
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

import { 
  FlowDesign, 
  FlowNode, 
  FlowConnection, 
  FlowValidationResult, 
  FlowValidationError,
  FlowValidationWarning,
  FlowNodeType 
} from '@/lib/types/flow-designer'

export class FlowValidator {
  validate(design: FlowDesign): FlowValidationResult {
    const errors: FlowValidationError[] = []
    const warnings: FlowValidationWarning[] = []

    // Basic structure validation
    this.validateBasicStructure(design, errors)
    
    // Node validation
    this.validateNodes(design, errors, warnings)
    
    // Connection validation
    this.validateConnections(design, errors, warnings)
    
    // Flow logic validation
    this.validateFlowLogic(design, errors, warnings)

    return {
      isValid: errors.length === 0,
      errors,
      warnings
    }
  }

  private validateBasicStructure(design: FlowDesign, errors: FlowValidationError[]) {
    // Check for at least one start node
    const startNodes = design.nodes.filter(node => node.type === FlowNodeType.START)
    if (startNodes.length === 0) {
      errors.push({
        id: 'no-start-node',
        type: 'missing_connection',
        message: 'O fluxo deve ter pelo menos um n├│ de in├¡cio',
        severity: 'error'
      })
    } else if (startNodes.length > 1) {
      errors.push({
        id: 'multiple-start-nodes',
        type: 'invalid_config',
        message: 'O fluxo deve ter apenas um n├│ de in├¡cio',
        severity: 'error'
      })
    }

    // Check for at least one end node
    const endNodes = design.nodes.filter(node => node.type === FlowNodeType.END)
    if (endNodes.length === 0) {
      errors.push({
        id: 'no-end-node',
        type: 'missing_connection',
        message: 'O fluxo deve ter pelo menos um n├│ de fim',
        severity: 'error'
      })
    }
  }

  private validateNodes(design: FlowDesign, errors: FlowValidationError[], warnings: FlowValidationWarning[]) {
    design.nodes.forEach(node => {
      // Validate node data
      if (!node.data.label || node.data.label.trim() === '') {
        errors.push({
          id: `node-${node.id}-no-label`,
          type: 'invalid_config',
          node_id: node.id,
          message: 'O n├│ deve ter um r├│tulo',
          severity: 'error'
        })
      }

      // Type-specific validation
      this.validateNodeByType(node, errors, warnings)

      // Check for isolated nodes (no connections)
      const hasIncoming = design.connections.some(conn => conn.target === node.id)
      const hasOutgoing = design.connections.some(conn => conn.source === node.id)
      
      if (!hasIncoming && node.type !== FlowNodeType.START) {
        warnings.push({
          id: `node-${node.id}-no-incoming`,
          type: 'best_practice',
          node_id: node.id,
          message: 'N├│ sem conex├Áes de entrada (exceto n├│s de in├¡cio)',
          suggestion: 'Conecte este n├│ a um n├│ anterior'
        })
      }

      if (!hasOutgoing && node.type !== FlowNodeType.END) {
        warnings.push({
          id: `node-${node.id}-no-outgoing`,
          type: 'best_practice',
          node_id: node.id,
          message: 'N├│ sem conex├Áes de sa├¡da (exceto n├│s de fim)',
          suggestion: 'Conecte este n├│ a um pr├│ximo n├│'
        })
      }
    })
  }

  private validateNodeByType(node: FlowNode, errors: FlowValidationError[], warnings: FlowValidationWarning[]) {
    switch (node.type) {
      case FlowNodeType.MESSAGE:
        this.validateMessageNode(node, errors, warnings)
        break
      case FlowNodeType.CONDITION:
        this.validateConditionNode(node, errors, warnings)
        break
      case FlowNodeType.DELAY:
        this.validateDelayNode(node, errors, warnings)
        break
      case FlowNodeType.ACTION:
        this.validateActionNode(node, errors, warnings)
        break
      case FlowNodeType.AI_RESPONSE:
        this.validateAIResponseNode(node, errors, warnings)
        break
      case FlowNodeType.QUIZ:
        this.validateQuizNode(node, errors, warnings)
        break
      case FlowNodeType.WEBHOOK:
        this.validateWebhookNode(node, errors, warnings)
        break
    }
  }

  private validateMessageNode(node: FlowNode, errors: FlowValidationError[], warnings: FlowValidationWarning[]) {
    const config = node.data.config
    
    if (!config['content'] || config['content'].trim() === '') {
      errors.push({
        id: `node-${node.id}-no-content`,
        type: 'invalid_config',
        node_id: node.id,
        message: 'Mensagem deve ter conte├║do',
        severity: 'error'
      })
    }

    if (config['content'] && config['content'].length > 1000) {
      warnings.push({
        id: `node-${node.id}-long-content`,
        type: 'best_practice',
        node_id: node.id,
        message: 'Mensagem muito longa (>1000 caracteres)',
        suggestion: 'Considere dividir em mensagens menores'
      })
    }
  }

  private validateConditionNode(node: FlowNode, errors: FlowValidationError[], warnings: FlowValidationWarning[]) {
    const config = node.data.config
    
    if (!config['conditions'] || config['conditions'].length === 0) {
      errors.push({
        id: `node-${node.id}-no-conditions`,
        type: 'invalid_config',
        node_id: node.id,
        message: 'N├│ de condi├º├úo deve ter pelo menos uma condi├º├úo',
        severity: 'error'
      })
    }
  }

  private validateDelayNode(node: FlowNode, errors: FlowValidationError[], warnings: FlowValidationWarning[]) {
    const config = node.data.config
    
    if (!config['duration'] || config['duration'] <= 0) {
      errors.push({
        id: `node-${node.id}-invalid-duration`,
        type: 'invalid_config',
        node_id: node.id,
        message: 'Dura├º├úo do atraso deve ser maior que zero',
        severity: 'error'
      })
    }

    if (config['duration'] > 365 && config['unit'] === 'days') {
      warnings.push({
        id: `node-${node.id}-long-delay`,
        type: 'performance',
        node_id: node.id,
        message: 'Atraso muito longo (>365 dias)',
        suggestion: 'Considere usar um atraso menor'
      })
    }
  }

  private validateActionNode(node: FlowNode, errors: FlowValidationError[], warnings: FlowValidationWarning[]) {
    const config = node.data.config
    
    if (!config['action_type']) {
      errors.push({
        id: `node-${node.id}-no-action-type`,
        type: 'invalid_config',
        node_id: node.id,
        message: 'Tipo de a├º├úo deve ser especificado',
        severity: 'error'
      })
    }
  }

  private validateAIResponseNode(node: FlowNode, errors: FlowValidationError[], warnings: FlowValidationWarning[]) {
    const config = node.data.config
    
    if (!config['prompt_template'] || config['prompt_template'].trim() === '') {
      errors.push({
        id: `node-${node.id}-no-prompt`,
        type: 'invalid_config',
        node_id: node.id,
        message: 'Template do prompt ├® obrigat├│rio',
        severity: 'error'
      })
    }

    if (!config['fallback_message']) {
      warnings.push({
        id: `node-${node.id}-no-fallback`,
        type: 'best_practice',
        node_id: node.id,
        message: 'Recomendado ter mensagem de fallback',
        suggestion: 'Adicione uma mensagem caso a IA falhe'
      })
    }
  }

  private validateQuizNode(node: FlowNode, errors: FlowValidationError[], warnings: FlowValidationWarning[]) {
    const config = node.data.config
    
    if (!config['questions'] || config['questions'].length === 0) {
      errors.push({
        id: `node-${node.id}-no-questions`,
        type: 'invalid_config',
        node_id: node.id,
        message: 'Quiz deve ter pelo menos uma pergunta',
        severity: 'error'
      })
    }
  }

  private validateWebhookNode(node: FlowNode, errors: FlowValidationError[], warnings: FlowValidationWarning[]) {
    const config = node.data.config
    
    if (!config['url'] || !this.isValidUrl(config['url'])) {
      errors.push({
        id: `node-${node.id}-invalid-url`,
        type: 'invalid_config',
        node_id: node.id,
        message: 'URL do webhook deve ser v├ílida',
        severity: 'error'
      })
    }
  }

  private validateConnections(design: FlowDesign, errors: FlowValidationError[], warnings: FlowValidationWarning[]) {
    design.connections.forEach(connection => {
      // Check if source and target nodes exist
      const sourceNode = design.nodes.find(node => node.id === connection.source)
      const targetNode = design.nodes.find(node => node.id === connection.target)

      if (!sourceNode) {
        errors.push({
          id: `connection-${connection.id}-invalid-source`,
          type: 'missing_connection',
          connection_id: connection.id,
          message: 'N├│ de origem da conex├úo n├úo existe',
          severity: 'error'
        })
      }

      if (!targetNode) {
        errors.push({
          id: `connection-${connection.id}-invalid-target`,
          type: 'missing_connection',
          connection_id: connection.id,
          message: 'N├│ de destino da conex├úo n├úo existe',
          severity: 'error'
        })
      }

      // Check for self-connections
      if (connection.source === connection.target) {
        errors.push({
          id: `connection-${connection.id}-self-connection`,
          type: 'invalid_config',
          connection_id: connection.id,
          message: 'N├│ n├úo pode se conectar a si mesmo',
          severity: 'error'
        })
      }
    })

    // Check for duplicate connections
    const connectionPairs = design.connections.map(conn => `${conn.source}-${conn.target}`)
    const duplicates = connectionPairs.filter((pair, index) => connectionPairs.indexOf(pair) !== index)
    
    duplicates.forEach(duplicate => {
      const [source, target] = duplicate.split('-')
      errors.push({
        id: `duplicate-connection-${source}-${target}`,
        type: 'invalid_config',
        message: `Conex├úo duplicada entre ${source} e ${target}`,
        severity: 'error'
      })
    })
  }

  private validateFlowLogic(design: FlowDesign, errors: FlowValidationError[], warnings: FlowValidationWarning[]) {
    // Check for circular dependencies
    this.detectCircularDependencies(design, errors)
    
    // Check for unreachable nodes
    this.detectUnreachableNodes(design, warnings)
  }

  private detectCircularDependencies(design: FlowDesign, errors: FlowValidationError[]) {
    const visited = new Set<string>()
    const recursionStack = new Set<string>()

    const hasCycle = (nodeId: string): boolean => {
      if (recursionStack.has(nodeId)) {
        return true
      }
      if (visited.has(nodeId)) {
        return false
      }

      visited.add(nodeId)
      recursionStack.add(nodeId)

      const outgoingConnections = design.connections.filter(conn => conn.source === nodeId)
      for (const connection of outgoingConnections) {
        if (hasCycle(connection.target)) {
          return true
        }
      }

      recursionStack.delete(nodeId)
      return false
    }

    design.nodes.forEach(node => {
      if (!visited.has(node.id) && hasCycle(node.id)) {
        errors.push({
          id: `circular-dependency-${node.id}`,
          type: 'circular_dependency',
          node_id: node.id,
          message: 'Depend├¬ncia circular detectada',
          severity: 'error'
        })
      }
    })
  }

  private detectUnreachableNodes(design: FlowDesign, warnings: FlowValidationWarning[]) {
    const startNodes = design.nodes.filter(node => node.type === FlowNodeType.START)
    if (startNodes.length === 0) return

    const reachable = new Set<string>()
    const queue = [...startNodes.map(node => node.id)]

    while (queue.length > 0) {
      const currentId = queue.shift()!
      if (reachable.has(currentId)) continue

      reachable.add(currentId)
      
      const outgoingConnections = design.connections.filter(conn => conn.source === currentId)
      outgoingConnections.forEach(conn => {
        if (!reachable.has(conn.target)) {
          queue.push(conn.target)
        }
      })
    }

    design.nodes.forEach(node => {
      if (!reachable.has(node.id) && node.type !== FlowNodeType.START) {
        warnings.push({
          id: `unreachable-node-${node.id}`,
          type: 'best_practice',
          node_id: node.id,
          message: 'N├│ n├úo ├® alcan├º├ível a partir do in├¡cio',
          suggestion: 'Conecte este n├│ ao fluxo principal'
        })
      }
    })
  }

  private isValidUrl(url: string): boolean {
    try {
      new URL(url)
      return true
    } catch {
      return false
    }
  }
}

