          <SelectTrigger className="mt-1">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="AND">E (AND)</SelectItem>
            <SelectItem value="OR">OU (OR)</SelectItem>
          </SelectContent>
        </Select>
      </div>
    </div>
  )
}

function DelayNodeProperties({ node, onUpdate }: { node: FlowNode; onUpdate: (field: string, value: any) => void }) {
