import React from 'react'
import { formatDistanceToNow } from 'date-fns'
import { ptBR } from 'date-fns/locale'
import { Play, Pause, Calendar, Clock } from 'lucide-react'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Avatar, AvatarFallback } from '@/components/ui/avatar'
import { Skeleton } from '@/components/ui/skeleton'
import { usePauseFlow, useResumeFlow, FlowData } from '@/hooks/useFlows'

interface FlowsTableProps {
  flows?: FlowData[]
  isLoading?: boolean
}

export function FlowsTable({ flows, isLoading }: FlowsTableProps) {
  const pauseFlow = usePauseFlow()
  const resumeFlow = useResumeFlow()

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'active':
        return (
          <Badge className="bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200">
            Ativo
          </Badge>
        )
      case 'paused':
        return (
          <Badge className="bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200">
            Pausado
          </Badge>
        )
      case 'completed':
        return (
          <Badge className="bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200">
            Conclu├¡do
          </Badge>
        )
      case 'cancelled':
        return (
          <Badge variant="secondary">
            Cancelado
          </Badge>
        )
      default:
        return <Badge variant="outline">{status}</Badge>
    }
  }

  const getFlowTypeName = (flowType: string) => {
    const typeMap: Record<string, string> = {
      'initial_15_days': 'Inicial 1-15 dias',
      'days_16_45': 'Dias 16-45',
      'monthly_recurring': 'Mensal Recorrente',
    }
    return typeMap[flowType] || flowType
  }

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map(n => n[0])
      .join('')
      .toUpperCase()
      .slice(0, 2)
  }

  const formatLastMessage = (lastMessage?: string) => {
    if (!lastMessage) return 'Nunca'

    try {
      return formatDistanceToNow(new Date(lastMessage), {
        addSuffix: true,
        locale: ptBR
      })
    } catch {
      return 'Data inv├ílida'
    }
  }

  const handlePauseResume = (flow: FlowData) => {
    if (flow.status === 'active') {
      pauseFlow.mutate(flow.patient_id)
    } else if (flow.status === 'paused') {
      resumeFlow.mutate(flow.patient_id)
    }
  }

  if (isLoading) {
    return (
      <div className="space-y-3">
        {[1, 2, 3, 4, 5].map((i) => (
          <div key={i} className="flex items-center space-x-4 py-3">
            <Skeleton className="h-10 w-10 rounded-full" />
            <div className="space-y-2 flex-1">
              <Skeleton className="h-4 w-48" />
              <Skeleton className="h-3 w-32" />
            </div>
            <Skeleton className="h-6 w-24" />
            <Skeleton className="h-6 w-16" />
            <Skeleton className="h-8 w-24" />
          </div>
        ))}
      </div>
    )
  }

  if (!flows || flows.length === 0) {
    return (
      <div className="text-center py-12 border rounded-lg bg-muted/10">
        <Calendar className="h-12 w-12 mx-auto text-muted-foreground mb-3" />
        <p className="text-muted-foreground mb-1">Nenhum fluxo encontrado</p>
        <p className="text-sm text-muted-foreground">
          Inicie um novo fluxo para come├ºar o acompanhamento
        </p>
      </div>
    )
  }

  return (
    <div className="rounded-md border">
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Paciente</TableHead>
            <TableHead>Tipo de Fluxo</TableHead>
            <TableHead>Dia Atual</TableHead>
            <TableHead>Status</TableHead>
            <TableHead>├Ültima Mensagem</TableHead>
            <TableHead className="text-right">A├º├Áes</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {flows.map((flow) => (
            <TableRow key={flow.id}>
              <TableCell>
                <div className="flex items-center space-x-3">
                  <Avatar className="h-9 w-9">
                    <AvatarFallback className="bg-blue-600 text-white text-xs">
                      {getInitials(flow.patient_name)}
                    </AvatarFallback>
                  </Avatar>
                  <div>
                    <p className="font-medium text-sm">{flow.patient_name}</p>
                    <p className="text-xs text-muted-foreground">
                      {flow.monthly_cycle ? `Ciclo ${flow.monthly_cycle}` : 'Primeiro ciclo'}
                    </p>
                  </div>
                </div>
              </TableCell>
              <TableCell>
                <Badge variant="outline">
                  {getFlowTypeName(flow.flow_type)}
                </Badge>
              </TableCell>
              <TableCell>
                <div className="flex items-center gap-1.5">
                  <Clock className="h-3.5 w-3.5 text-muted-foreground" />
                  <span className="font-medium">{flow.current_day}</span>
                </div>
              </TableCell>
              <TableCell>
                {getStatusBadge(flow.status)}
              </TableCell>
              <TableCell>
                <span className="text-sm text-muted-foreground">
                  {formatLastMessage(flow.last_message_sent)}
                </span>
              </TableCell>
              <TableCell className="text-right">
                {(flow.status === 'active' || flow.status === 'paused') && (
                  <Button
                    size="sm"
                    variant={flow.status === 'active' ? 'outline' : 'default'}
                    onClick={() => handlePauseResume(flow)}
                    disabled={pauseFlow.isPending || resumeFlow.isPending}
                  >
                    {flow.status === 'active' ? (
                      <>
                        <Pause className="h-3.5 w-3.5 mr-1.5" />
                        Pausar
                      </>
                    ) : (
                      <>
                        <Play className="h-3.5 w-3.5 mr-1.5" />
                        Retomar
                      </>
                    )}
                  </Button>
                )}
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  )
}

import React, { useState, useEffect } from 'react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card'
import { Button } from '../ui/button'
import { Badge } from '../ui/badge'
import { Progress } from '../ui/progress'
import {
  CheckCircle,
  XCircle,
  AlertTriangle,
  Database,
  RefreshCw,
  Activity,
  HardDrive,
  Users,
  FileText
} from 'lucide-react'
import { Alert, AlertDescription } from '../ui/alert'
import { LoadingSpinner } from './LoadingSpinner'
import { toast } from '../../hooks/use-toast'
import { createLogger } from '../../lib/logger'
import { apiClient } from '../../lib/api-client'

const logger = createLogger('DatabaseChecker')

interface DatabaseTest {
  id: string
  name: string
  description: string
  status: 'pending' | 'running' | 'success' | 'error'
  duration?: number | undefined
  error?: string | undefined
  details?: any
}

interface DatabaseStats {
  version?: string
  uptime?: string
  connections?: number
  maxConnections?: number
  size?: string
  tables?: number
  indexes?: number
  lastBackup?: string
}

interface DatabaseCheckerProps {
  onComplete: () => void
  onError: (error: string) => void
}

export function DatabaseChecker({ onComplete, onError }: DatabaseCheckerProps) {
  const [tests, setTests] = useState<DatabaseTest[]>([
    {
      id: 'connection',
      name: 'Conex├úo com Banco',
      description: 'Verifica se ├® poss├¡vel conectar ao banco de dados',
      status: 'pending'
    },
    {
      id: 'tables',
      name: 'Estrutura de Tabelas',
      description: 'Verifica se todas as tabelas necess├írias existem',
      status: 'pending'
    },
    {
      id: 'indexes',
      name: '├ìndices de Performance',
      description: 'Verifica se os ├¡ndices de busca est├úo criados',
      status: 'pending'
    },
    {
      id: 'permissions',
      name: 'Permiss├Áes de Usu├írio',
      description: 'Verifica se o usu├írio tem as permiss├Áes necess├írias',
      status: 'pending'
    },
    {
      id: 'migrations',
      name: 'Estado das Migra├º├Áes',
      description: 'Verifica se todas as migra├º├Áes foram aplicadas',
      status: 'pending'
    },
    {
      id: 'performance',
      name: 'Teste de Performance',
      description: 'Executa consultas de teste para medir performance',
      status: 'pending'
    }
  ])

  const [stats, setStats] = useState<DatabaseStats>({})
  const [isChecking, setIsChecking] = useState(false)
  const [currentTestIndex, setCurrentTestIndex] = useState(0)
  const [overallProgress, setOverallProgress] = useState(0)

  useEffect(() => {
    // Auto-start database checks
    handleCheckDatabase()
  }, [])

  const updateTestStatus = (
    id: string,
    status: DatabaseTest['status'],
    duration?: number,
    error?: string,
    details?: any
  ) => {
    setTests(prev => prev.map(test =>
      test.id === id
        ? { ...test, status, duration, error, details }
        : test
    ))
  }

  const handleCheckDatabase = async () => {
    setIsChecking(true)
    setCurrentTestIndex(0)
    setOverallProgress(0)
    logger.log('Starting database checks')

    try {
      // Reset all tests to pending
      setTests(prev => prev.map(test => ({ ...test, status: 'pending' as const })))

      for (let i = 0; i < tests.length; i++) {
        const test = tests[i]
        if (!test) continue

        setCurrentTestIndex(i)
        updateTestStatus(test.id, 'running')

        const startTime = Date.now()

        try {
          await executeTest(test.id)
          const duration = Date.now() - startTime
          updateTestStatus(test.id, 'success', duration)
        } catch (error) {
          const duration = Date.now() - startTime
          const errorMessage = error instanceof Error ? error.message : 'Teste falhou'
          updateTestStatus(test.id, 'error', duration, errorMessage)
          logger.error(`Database test '${test.id}' failed:`, error)
        }

        // Update progress
        const progress = Math.round(((i + 1) / tests.length) * 100)
        setOverallProgress(progress)

        // Small delay for visual feedback
        await new Promise(resolve => setTimeout(resolve, 500))
      }

      // Load database stats
      await loadDatabaseStats()

      // Check results
      const failedTests = tests.filter(t => t.status === 'error')
      if (failedTests.length > 0) {
        onError(`Testes de banco falharam: ${failedTests.map(t => t.name).join(', ')}`)
      } else {
        toast({
          title: 'Banco de Dados Verificado',
          description: 'Todos os testes passaram com sucesso.',
        })
        onComplete()
      }

    } catch (error) {
      logger.error('Database check failed:', error)
      onError('Falha na verifica├º├úo do banco de dados: ' + (error as Error).message)
    } finally {
      setIsChecking(false)
    }
  }

  const executeTest = async (testId: string): Promise<void> => {
    switch (testId) {
      case 'connection':
        await testConnection()
        break
      case 'tables':
        await testTableStructure()
        break
      case 'indexes':
        await testIndexes()
        break
      case 'permissions':
        await testPermissions()
        break
      case 'migrations':
        await testMigrations()
        break
      case 'performance':
        await testPerformance()
        break
      default:
        throw new Error(`Unknown test: ${testId}`)
    }
  }

  const testConnection = async () => {
    const response = await apiClient.get('/admin/database/health') as Response
    if (!response.ok) {
      throw new Error('Falha na conex├úo com o banco de dados')
    }
  }

  const testTableStructure = async () => {
    const response = await apiClient.get('/admin/database/tables') as Response
    const data = await response.json() as { tables: string[] }

    const requiredTables = [
      'users', 'patients', 'consultations', 'treatments',
      'medications', 'reports', 'audit_logs'
    ]

    const missingTables = requiredTables.filter(
      table => !data.tables.includes(table)
    )

    if (missingTables.length > 0) {
      throw new Error(`Tabelas em falta: ${missingTables.join(', ')}`)
    }

    updateTestStatus('tables', 'running', undefined, undefined, {
      totalTables: data.tables.length,
      requiredTables: requiredTables.length
    })
  }

  const testIndexes = async () => {
    const response = await apiClient.get('/admin/database/indexes') as Response
    const data = await response.json() as { indexes: Array<{ name: string }> }

    const requiredIndexes = [
      'idx_patients_cpf',
      'idx_users_email',
      'idx_consultations_date',
      'idx_treatments_patient_id'
    ]

    const missingIndexes = requiredIndexes.filter(
      index => !data.indexes.some((idx) => idx.name === index)
    )

    if (missingIndexes.length > 0) {
      throw new Error(`├ìndices em falta: ${missingIndexes.join(', ')}`)
    }

    updateTestStatus('indexes', 'running', undefined, undefined, {
      totalIndexes: data.indexes.length,
      requiredIndexes: requiredIndexes.length
    })
  }

  const testPermissions = async () => {
    const response = await apiClient.get('/admin/database/permissions') as Response
    const data = await response.json() as { permissions: string[] }

    const requiredPermissions = ['SELECT', 'INSERT', 'UPDATE', 'DELETE']
    const missingPermissions = requiredPermissions.filter(
      perm => !data.permissions.includes(perm)
    )

    if (missingPermissions.length > 0) {
      throw new Error(`Permiss├Áes em falta: ${missingPermissions.join(', ')}`)
    }

    updateTestStatus('permissions', 'running', undefined, undefined, {
      permissions: data.permissions
    })
  }

  const testMigrations = async () => {
    const response = await apiClient.get('/admin/database/migrations') as Response
    const data = await response.json() as {
      pendingMigrations?: string[]
      appliedMigrations?: string[]
    }

    if (data.pendingMigrations && data.pendingMigrations.length > 0) {
      throw new Error(`${data.pendingMigrations.length} migra├º├Áes pendentes`)
    }

    updateTestStatus('migrations', 'running', undefined, undefined, {
      appliedMigrations: data.appliedMigrations?.length || 0,
      pendingMigrations: data.pendingMigrations?.length || 0
    })
  }

  const testPerformance = async () => {
    const response = await apiClient.get('/admin/database/performance') as Response
    const data = await response.json() as {
      averageQueryTime: number
      slowQueries?: number
    }

    // Check if average query time is reasonable (< 100ms)
    if (data.averageQueryTime > 100) {
      throw new Error(`Performance baixa: ${data.averageQueryTime}ms por consulta`)
    }

    updateTestStatus('performance', 'running', undefined, undefined, {
      averageQueryTime: data.averageQueryTime,
      slowQueries: data.slowQueries || 0
    })
  }

  const loadDatabaseStats = async () => {
    try {
      const response = await apiClient.get('/admin/database/stats') as Response
      const data = await response.json() as DatabaseStats
      setStats(data)
    } catch (error) {
      logger.error('Failed to load database stats:', error)
    }
  }

  const getStatusIcon = (status: DatabaseTest['status']) => {
    switch (status) {
      case 'success':
        return <CheckCircle className="w-5 h-5 text-green-500" />
      case 'error':
        return <XCircle className="w-5 h-5 text-red-500" />
      case 'running':
        return <RefreshCw className="w-5 h-5 text-blue-500 animate-spin" />
      default:
        return <div className="w-5 h-5 border-2 border-gray-300 rounded-full" />
    }
  }

  const getStatusBadge = (status: DatabaseTest['status']) => {
    switch (status) {
      case 'success':
        return <Badge variant="default" className="bg-green-100 text-green-800">OK</Badge>
      case 'error':
        return <Badge variant="destructive">Erro</Badge>
      case 'running':
        return <Badge variant="default" className="bg-blue-100 text-blue-800">Testando</Badge>
      default:
        return <Badge variant="outline">Pendente</Badge>
    }
  }

  const formatDuration = (ms?: number) => {
    if (!ms) return ''
    return `${ms}ms`
  }

  return (
    <div className="space-y-6">
      {/* Progress Overview */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle className="flex items-center space-x-2">
                <Database className="w-5 h-5" />
                <span>Verifica├º├úo do Banco de Dados</span>
              </CardTitle>
              <CardDescription>
                Executando testes de conectividade e integridade
              </CardDescription>
            </div>
            <div className="text-right">
              <div className="text-2xl font-bold text-blue-600">{overallProgress}%</div>
              <div className="text-sm text-gray-600">Progresso</div>
            </div>
          </div>
          {isChecking && (
            <div className="mt-4">
              <Progress value={overallProgress} />
              <div className="text-sm text-gray-600 mt-2">
                Teste {currentTestIndex + 1} de {tests.length}:
                {tests[currentTestIndex]?.name}
              </div>
            </div>
          )}
        </CardHeader>
      </Card>

      {/* Database Stats */}
      {Object.keys(stats).length > 0 && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <Card>
            <CardContent className="pt-4">
              <div className="flex items-center space-x-2">
                <Activity className="w-4 h-4 text-blue-500" />
                <div>
                  <div className="text-sm font-medium">Vers├úo</div>
                  <div className="text-xs text-gray-600">{stats.version || 'N/A'}</div>
                </div>
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-4">
              <div className="flex items-center space-x-2">
                <Users className="w-4 h-4 text-green-500" />
                <div>
                  <div className="text-sm font-medium">Conex├Áes</div>
                  <div className="text-xs text-gray-600">
                    {stats.connections || 0}/{stats.maxConnections || 0}
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-4">
              <div className="flex items-center space-x-2">
                <HardDrive className="w-4 h-4 text-purple-500" />
                <div>
                  <div className="text-sm font-medium">Tamanho</div>
                  <div className="text-xs text-gray-600">{stats.size || 'N/A'}</div>
                </div>
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="pt-4">
              <div className="flex items-center space-x-2">
                <FileText className="w-4 h-4 text-orange-500" />
                <div>
                  <div className="text-sm font-medium">Tabelas</div>
                  <div className="text-xs text-gray-600">{stats.tables || 0}</div>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Test Results */}
      <Card>
        <CardHeader>
          <CardTitle>Resultados dos Testes</CardTitle>
          <CardDescription>
            Status detalhado de cada verifica├º├úo do banco de dados
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {tests.map((test, index) => (
            <div
              key={test.id}
              className={`flex items-center justify-between p-4 border rounded-lg transition-colors ${
                index === currentTestIndex && isChecking
                  ? 'bg-blue-50 border-blue-200'
                  : ''
              }`}
            >
              <div className="flex items-start space-x-3 flex-1">
                {getStatusIcon(test.status)}
                <div className="flex-1">
                  <div className="flex items-center space-x-2">
                    <h4 className="font-medium">{test.name}</h4>
                    {test.duration && (
                      <span className="text-xs text-gray-500">
                        ({formatDuration(test.duration)})
                      </span>
                    )}
                  </div>
                  <p className="text-sm text-gray-600 mt-1">{test.description}</p>
                  {test.details && (
                    <div className="mt-2 text-xs text-gray-500">
                      {Object.entries(test.details).map(([key, value]) => (
                        <span key={key} className="mr-4">
                          {key}: {String(value)}
                        </span>
                      ))}
                    </div>
                  )}
                  {test.error && (
                    <Alert className="mt-2" variant="destructive">
                      <AlertDescription className="text-xs">{test.error}</AlertDescription>
                    </Alert>
                  )}
                </div>
              </div>
              <div className="flex-shrink-0">
                {getStatusBadge(test.status)}
              </div>
            </div>
          ))}
        </CardContent>
      </Card>

      {/* Action Buttons */}
      <div className="flex flex-col sm:flex-row gap-4">
        <Button
          onClick={handleCheckDatabase}
          disabled={isChecking}
          className="flex-1"
        >
          {isChecking ? (
            <>
              <RefreshCw className="w-4 h-4 mr-2 animate-spin" />
              Testando...
            </>
          ) : (
            <>
              <RefreshCw className="w-4 h-4 mr-2" />
              Testar Novamente
            </>
          )}
        </Button>

        <Button
          variant="outline"
          onClick={() => {
            toast({
              title: 'Logs de Banco',
              description: 'Funcionalidade em desenvolvimento.',
            })
          }}
          className="flex-1 sm:flex-none"
        >
          <FileText className="w-4 h-4 mr-2" />
          Ver Logs
        </Button>
      </div>

      {isChecking && (
        <div className="text-center py-8">
          <LoadingSpinner
            size="lg"
            text={`Executando: ${tests[currentTestIndex]?.name}...`}
            showProgress
            progress={overallProgress}
          />
        </div>
      )}
    </div>
  )
}

import React, { useState, useEffect } from 'react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card'
import { Button } from '../ui/button'
import { Input } from '../ui/input'
import { Label } from '../ui/label'
import { Switch } from '../ui/switch'
import { Badge } from '../ui/badge'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '../ui/tabs'
import {
  CheckCircle,
  XCircle,
  AlertTriangle,
  Settings,
  Cloud,
  Shield,
  RefreshCw,
  Eye,
  EyeOff
} from 'lucide-react'
import { Alert, AlertDescription } from '../ui/alert'
import { LoadingSpinner } from './LoadingSpinner'
import { toast } from '../../hooks/use-toast'
import { createLogger } from '../../lib/logger'
import { loadConfig, getRuntimeConfigSync } from '../../config'

const logger = createLogger('EnvironmentSetup')

interface EnvironmentCheck {
  id: string
  name: string
  description: string
  status: 'pending' | 'checking' | 'success' | 'warning' | 'error'
  required: boolean
  value?: string | undefined
  error?: string | undefined
  category: 'api' | 'services' | 'security'
}

interface EnvironmentSetupProps {
  onComplete: () => void
  onError: (error: string) => void
}

export function EnvironmentSetup({ onComplete, onError }: EnvironmentSetupProps) {
  const [checks, setChecks] = useState<EnvironmentCheck[]>([
    // API Configuration
    {
      id: 'api_base_url',
      name: 'API Base URL',
      description: 'URL base para comunica├º├úo com o backend',
      status: 'pending',
      required: true,
      category: 'api'
    },
    {
      id: 'ws_url',
      name: 'WebSocket URL',
      description: 'URL para conex├Áes WebSocket em tempo real',
      status: 'pending',
      required: false,
      category: 'api'
    },

    // External Services
    {
      id: 'firebase_config',
      name: 'Firebase Configuration',
      description: 'Configura├º├úo de autentica├º├úo Firebase',
      status: 'pending',
      required: true,
      category: 'services'
    },
    {
      id: 'whatsapp_instance',
      name: 'WhatsApp Instance',
      description: 'Inst├óncia do WhatsApp Business API',
      status: 'pending',
      required: false,
      category: 'services'
    },

    // Security & Monitoring
    {
      id: 'sentry_dsn',
      name: 'Sentry DSN',
      description: 'Configura├º├úo de monitoramento de erros',
      status: 'pending',
      required: false,
      category: 'security'
    },
    {
      id: 'session_config',
      name: 'Session Configuration',
      description: 'Configura├º├Áes de sess├úo e seguran├ºa',
      status: 'pending',
      required: true,
      category: 'security'
    }
  ])

  const [isChecking, setIsChecking] = useState(false)
  const [showAdvanced, setShowAdvanced] = useState(false)
  const [manualConfig, setManualConfig] = useState<Record<string, string>>({})
  const [showSecrets, setShowSecrets] = useState<Record<string, boolean>>({})

  const categoryIcons = {
    api: <Cloud className="w-5 h-5" />,
    services: <Settings className="w-5 h-5" />,
    security: <Shield className="w-5 h-5" />
  }

  const categoryNames = {
    api: 'API & Comunica├º├úo',
    database: 'Banco de Dados',
    services: 'Servi├ºos Externos',
    security: 'Seguran├ºa & Monitoramento'
  }

  useEffect(() => {
    // Auto-start environment check
    handleCheckEnvironment()
  }, [])

  const updateCheckStatus = (
    id: string,
    status: EnvironmentCheck['status'],
    value?: string,
    error?: string
  ) => {
    setChecks(prev => prev.map(check =>
      check.id === id
        ? { ...check, status, value, error }
        : check
    ))
  }

  const handleCheckEnvironment = async () => {
    setIsChecking(true)
    logger.log('Starting environment checks')

    try {
      // Load configuration
      const config = await loadConfig()
      const runtimeConfig = getRuntimeConfigSync()

      // Check API configuration
      updateCheckStatus('api_base_url', 'checking')
      if (config.API_BASE_URL) {
        try {
          const response = await fetch(`${config.API_BASE_URL}/health`, {
            method: 'GET',
            signal: AbortSignal.timeout(5000)
          })
          if (response.ok) {
            updateCheckStatus('api_base_url', 'success', config.API_BASE_URL)
          } else {
            updateCheckStatus('api_base_url', 'warning', config.API_BASE_URL,
              `API retornou status ${response.status}`)
          }
        } catch (error) {
          updateCheckStatus('api_base_url', 'error', config.API_BASE_URL,
            'Falha ao conectar com a API')
        }
      } else {
        updateCheckStatus('api_base_url', 'error', '', 'URL da API n├úo configurada')
      }

      // Check WebSocket URL
      updateCheckStatus('ws_url', 'checking')
      if (config.WS_BASE_URL) {
        updateCheckStatus('ws_url', 'success', config.WS_BASE_URL)
      } else {
        updateCheckStatus('ws_url', 'warning', '', 'WebSocket n├úo configurado')
      }

      // Check Firebase configuration
      updateCheckStatus('firebase_config', 'checking')
      if (runtimeConfig?.VITE_FIREBASE_API_KEY) {
        updateCheckStatus('firebase_config', 'success', 'Configurado')
      } else {
        updateCheckStatus('firebase_config', 'error', '', 'Firebase n├úo configurado')
      }

      // Check WhatsApp instance
      updateCheckStatus('whatsapp_instance', 'checking')
      if (config.WHATSAPP_INSTANCE_NAME) {
        updateCheckStatus('whatsapp_instance', 'success', config.WHATSAPP_INSTANCE_NAME)
      } else {
        updateCheckStatus('whatsapp_instance', 'warning', '', 'WhatsApp n├úo configurado')
      }

      // Check Sentry DSN
      updateCheckStatus('sentry_dsn', 'checking')
      if (config.SENTRY_DSN) {
        updateCheckStatus('sentry_dsn', 'success', '****')
      } else {
        updateCheckStatus('sentry_dsn', 'warning', '', 'Sentry n├úo configurado')
      }

      // Check session configuration
      updateCheckStatus('session_config', 'checking')
      if (config.SESSION_TIMEOUT && config.TOKEN_REFRESH_THRESHOLD) {
        updateCheckStatus('session_config', 'success',
          `Timeout: ${config.SESSION_TIMEOUT}ms`)
      } else {
        updateCheckStatus('session_config', 'warning', '',
          'Configura├º├Áes de sess├úo usando padr├Áes')
      }

      // Wait a moment for visual feedback
      await new Promise(resolve => setTimeout(resolve, 1000))

      // Check if all required configurations are valid
      const requiredChecks = checks.filter(check => check.required)
      const failedRequired = requiredChecks.filter(check =>
        check.status === 'error'
      )

      if (failedRequired.length > 0) {
        onError(`Configura├º├Áes obrigat├│rias falharam: ${failedRequired.map(c => c.name).join(', ')}`)
      } else {
        toast({
          title: 'Ambiente Verificado',
          description: 'Todas as configura├º├Áes essenciais est├úo funcionando.',
        })
        onComplete()
      }

    } catch (error) {
      logger.error('Environment check failed:', error)
      onError('Falha na verifica├º├úo do ambiente: ' + (error as Error).message)
    } finally {
      setIsChecking(false)
    }
  }

  const getStatusIcon = (status: EnvironmentCheck['status']) => {
    switch (status) {
      case 'success':
        return <CheckCircle className="w-4 h-4 text-green-500" />
      case 'error':
        return <XCircle className="w-4 h-4 text-red-500" />
      case 'warning':
        return <AlertTriangle className="w-4 h-4 text-yellow-500" />
      case 'checking':
        return <RefreshCw className="w-4 h-4 text-blue-500 animate-spin" />
      default:
        return <div className="w-4 h-4 border border-gray-300 rounded-full" />
    }
  }

  const getStatusBadge = (status: EnvironmentCheck['status']) => {
    switch (status) {
      case 'success':
        return <Badge variant="default" className="bg-green-100 text-green-800">OK</Badge>
      case 'error':
        return <Badge variant="destructive">Erro</Badge>
      case 'warning':
        return <Badge variant="secondary" className="bg-yellow-100 text-yellow-800">Aviso</Badge>
      case 'checking':
        return <Badge variant="outline">Verificando...</Badge>
      default:
        return <Badge variant="outline">Pendente</Badge>
    }
  }

  const toggleSecret = (checkId: string) => {
    setShowSecrets(prev => ({
      ...prev,
      [checkId]: !prev[checkId]
    }))
  }

  const categorizedChecks = checks.reduce((acc, check) => {
    const category = check.category
    if (!acc[category]) {
      acc[category] = []
    }
    acc[category]?.push(check)
    return acc
  }, {} as Record<string, EnvironmentCheck[]>)

  const summaryStats = {
    total: checks.length,
    success: checks.filter(c => c.status === 'success').length,
    error: checks.filter(c => c.status === 'error').length,
    warning: checks.filter(c => c.status === 'warning').length
  }

  return (
    <div className="space-y-6">
      {/* Summary Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <Card className="text-center">
          <CardContent className="pt-4">
            <div className="text-2xl font-bold text-green-600">{summaryStats.success}</div>
            <div className="text-sm text-gray-600">Sucessos</div>
          </CardContent>
        </Card>
        <Card className="text-center">
          <CardContent className="pt-4">
            <div className="text-2xl font-bold text-yellow-600">{summaryStats.warning}</div>
            <div className="text-sm text-gray-600">Avisos</div>
          </CardContent>
        </Card>
        <Card className="text-center">
          <CardContent className="pt-4">
            <div className="text-2xl font-bold text-red-600">{summaryStats.error}</div>
            <div className="text-sm text-gray-600">Erros</div>
          </CardContent>
        </Card>
        <Card className="text-center">
          <CardContent className="pt-4">
            <div className="text-2xl font-bold text-blue-600">{summaryStats.total}</div>
            <div className="text-sm text-gray-600">Total</div>
          </CardContent>
        </Card>
      </div>

      {/* Environment Checks by Category */}
      <Tabs defaultValue="api" className="space-y-4">
        <TabsList className="grid w-full grid-cols-4">
          {Object.keys(categoryNames).map(category => (
            <TabsTrigger
              key={category}
              value={category}
              className="flex items-center space-x-2"
            >
              {categoryIcons[category as keyof typeof categoryIcons]}
              <span className="hidden sm:inline">
                {categoryNames[category as keyof typeof categoryNames]}
              </span>
            </TabsTrigger>
          ))}
        </TabsList>

        {Object.entries(categorizedChecks).map(([category, categoryChecks]) => (
          <TabsContent key={category} value={category}>
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center space-x-2">
                  {categoryIcons[category as keyof typeof categoryIcons]}
                  <span>{categoryNames[category as keyof typeof categoryNames]}</span>
                </CardTitle>
                <CardDescription>
                  Verifica├º├úo das configura├º├Áes de {categoryNames[category as keyof typeof categoryNames].toLowerCase()}
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                {categoryChecks.map(check => (
                  <div
                    key={check.id}
                    className="flex items-center justify-between p-4 border rounded-lg"
                  >
                    <div className="flex items-start space-x-3 flex-1">
                      {getStatusIcon(check.status)}
                      <div className="flex-1">
                        <div className="flex items-center space-x-2">
                          <h4 className="font-medium">{check.name}</h4>
                          {check.required && (
                            <Badge variant="outline" className="text-xs">Obrigat├│rio</Badge>
                          )}
                        </div>
                        <p className="text-sm text-gray-600 mt-1">{check.description}</p>
                        {check.value && (
                          <div className="flex items-center space-x-2 mt-2">
                            <code className="text-xs bg-gray-100 px-2 py-1 rounded">
                              {check.id.includes('key') || check.id.includes('dsn') ?
                                (showSecrets[check.id] ? check.value : '****') :
                                check.value
                              }
                            </code>
                            {(check.id.includes('key') || check.id.includes('dsn')) && (
                              <Button
                                variant="ghost"
                                size="sm"
                                onClick={() => toggleSecret(check.id)}
                                className="h-6 w-6 p-0"
                              >
                                {showSecrets[check.id] ?
                                  <EyeOff className="w-3 h-3" /> :
                                  <Eye className="w-3 h-3" />
                                }
                              </Button>
                            )}
                          </div>
                        )}
                        {check.error && (
                          <Alert className="mt-2" variant="destructive">
                            <AlertDescription className="text-xs">{check.error}</AlertDescription>
                          </Alert>
                        )}
                      </div>
                    </div>
                    <div className="flex-shrink-0">
                      {getStatusBadge(check.status)}
                    </div>
                  </div>
                ))}
              </CardContent>
            </Card>
          </TabsContent>
        ))}
      </Tabs>

      {/* Action Buttons */}
      <div className="flex flex-col sm:flex-row gap-4 pt-6">
        <Button
          onClick={handleCheckEnvironment}
          disabled={isChecking}
          className="flex-1"
        >
          {isChecking ? (
            <>
              <RefreshCw className="w-4 h-4 mr-2 animate-spin" />
              Verificando...
            </>
          ) : (
            <>
              <RefreshCw className="w-4 h-4 mr-2" />
              Verificar Novamente
            </>
          )}
        </Button>

        <Button
          variant="outline"
          onClick={() => setShowAdvanced(!showAdvanced)}
          className="flex-1 sm:flex-none"
        >
          <Settings className="w-4 h-4 mr-2" />
          Configura├º├úo Manual
        </Button>
      </div>

      {/* Advanced Configuration Panel */}
      {showAdvanced && (
        <Card>
          <CardHeader>
            <CardTitle>Configura├º├úo Manual</CardTitle>
            <CardDescription>
              Configure manualmente as vari├íveis de ambiente se necess├írio
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <Alert>
              <AlertTriangle className="h-4 w-4" />
              <AlertDescription>
                As configura├º├Áes manuais s├úo tempor├írias e n├úo persistem ap├│s o reload.
                Para configura├º├úo permanente, defina as vari├íveis de ambiente no servidor.
              </AlertDescription>
            </Alert>

            {checks.filter(c => c.status === 'error' || c.status === 'warning').map(check => (
              <div key={check.id} className="space-y-2">
                <Label htmlFor={check.id}>{check.name}</Label>
                <Input
                  id={check.id}
                  type={check.id.includes('key') || check.id.includes('dsn') ? 'password' : 'text'}
                  placeholder={`Digite ${check.name.toLowerCase()}`}
                  value={manualConfig[check.id] || ''}
                  onChange={(e) => setManualConfig(prev => ({
                    ...prev,
                    [check.id]: e.target.value
                  }))}
                />
              </div>
            ))}

            <Button
              onClick={() => {
                // Apply manual configuration and re-check
                toast({
                  title: 'Configura├º├úo Aplicada',
                  description: 'Configura├º├Áes manuais aplicadas. Verificando novamente...',
                })
                setTimeout(handleCheckEnvironment, 1000)
              }}
              className="w-full"
            >
              Aplicar Configura├º├Áes
            </Button>
          </CardContent>
        </Card>
      )}

      {isChecking && (
        <div className="text-center py-8">
          <LoadingSpinner size="lg" text="Verificando configura├º├Áes do ambiente..." />
        </div>
      )}
    </div>
  )
}

import React, { useState } from 'react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card'
import { Button } from '../ui/button'
import { Input } from '../ui/input'
import { Label } from '../ui/label'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../ui/select'
import { Checkbox } from '../ui/checkbox'
import { Badge } from '../ui/badge'
import {
  User,
  Mail,
  Phone,
  Shield,
  Key,
  UserPlus,
  CheckCircle,
  AlertTriangle,
  Eye,
  EyeOff
} from 'lucide-react'
import { Alert, AlertDescription } from '../ui/alert'
import { LoadingSpinner } from './LoadingSpinner'
import { toast } from '../../hooks/use-toast'
import { createLogger } from '../../lib/logger'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'

const logger = createLogger('InitialUserSetup')

const userSetupSchema = z.object({
  name: z.string().min(2, 'Nome deve ter pelo menos 2 caracteres'),
  email: z.string().email('Email inv├ílido'),
  phone: z.string().min(10, 'Telefone deve ter pelo menos 10 d├¡gitos'),
  crm: z.string().min(4, 'CRM deve ter pelo menos 4 caracteres'),
  specialization: z.string().min(1, 'Especializa├º├úo ├® obrigat├│ria'),
  password: z.string().min(8, 'Senha deve ter pelo menos 8 caracteres'),
  confirmPassword: z.string(),
  role: z.enum(['admin', 'medico', 'enfermeiro']),
  acceptTerms: z.boolean().refine(val => val === true, 'Voc├¬ deve aceitar os termos'),
  enableNotifications: z.boolean().optional()
}).refine(data => data.password === data.confirmPassword, {
  message: 'Senhas n├úo coincidem',
  path: ['confirmPassword']
})

type UserSetupForm = z.infer<typeof userSetupSchema>

interface InitialUserSetupProps {
  onComplete: () => void
  onError: (error: string) => void
}

export function InitialUserSetup({ onComplete, onError }: InitialUserSetupProps) {
  const [isCreating, setIsCreating] = useState(false)
  const [showPassword, setShowPassword] = useState(false)
  const [showConfirmPassword, setShowConfirmPassword] = useState(false)
  const [step, setStep] = useState(1)

  const {
    register,
    handleSubmit,
    formState: { errors, isValid },
    watch,
    setValue,
    trigger
  } = useForm<UserSetupForm>({
    resolver: zodResolver(userSetupSchema),
    mode: 'onChange',
    defaultValues: {
      role: 'admin',
      acceptTerms: false,
      enableNotifications: true
    }
  })

  const watchedValues = watch()

  const specializations = [
    'Oncologia Cl├¡nica',
    'Oncologia Cir├║rgica',
    'Radio-oncologia',
    'Hematologia',
    'Oncologia Pedi├ítrica',
    'Ginecologia Oncol├│gica',
    'Mastologia',
    'Urologia Oncol├│gica',
    'Administra├º├úo',
    'Outra'
  ]

  const roles = [
    { value: 'admin', label: 'Administrador', description: 'Acesso completo ao sistema' },
    { value: 'medico', label: 'M├®dico', description: 'Acesso a pacientes e tratamentos' },
    { value: 'enfermeiro', label: 'Enfermeiro', description: 'Acesso limitado a cuidados' }
  ]

  const handleCreateUser = async (data: UserSetupForm) => {
    setIsCreating(true)
    logger.log('Creating initial admin user:', data.email)

    try {
      // Simulate user creation API call
      await new Promise(resolve => setTimeout(resolve, 2000))

      // In real implementation, call the API to create user
      const response = await fetch('/api/auth/setup-admin', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          name: data.name,
          email: data.email,
          phone: data.phone,
          crm: data.crm,
          specialization: data.specialization,
          password: data.password,
          role: data.role,
          enableNotifications: data.enableNotifications
        })
      })

      if (!response.ok) {
        throw new Error('Falha ao criar usu├írio')
      }

      toast({
        title: 'Usu├írio Criado com Sucesso',
        description: `Administrador ${data.name} foi criado e pode fazer login no sistema.`,
      })

      logger.log('Initial admin user created successfully')
      onComplete()

    } catch (error) {
      logger.error('Failed to create initial user:', error)
      onError('Falha ao criar usu├írio inicial: ' + (error as Error).message)
    } finally {
      setIsCreating(false)
    }
  }

  const handleNextStep = async () => {
    const fieldsToValidate = step === 1
      ? ['name', 'email', 'phone']
      : ['crm', 'specialization', 'role']

    const isStepValid = await trigger(fieldsToValidate as any)
    if (isStepValid) {
      setStep(step + 1)
    }
  }

  const handlePreviousStep = () => {
    setStep(step - 1)
  }

  const getPasswordStrength = (password: string) => {
    let strength = 0
    if (password.length >= 8) strength++
    if (/[A-Z]/.test(password)) strength++
    if (/[a-z]/.test(password)) strength++
    if (/\d/.test(password)) strength++
    if (/[^A-Za-z\d]/.test(password)) strength++

    if (strength < 2) return { level: 'weak', color: 'red', text: 'Fraca' }
    if (strength < 4) return { level: 'medium', color: 'yellow', text: 'M├®dia' }
    return { level: 'strong', color: 'green', text: 'Forte' }
  }

  const passwordStrength = watchedValues.password ? getPasswordStrength(watchedValues.password) : null

  return (
    <div className="space-y-6">
      {/* Progress Steps */}
      <div className="flex items-center justify-center space-x-4 mb-8">
        {[1, 2, 3].map((stepNumber) => (
          <div key={stepNumber} className="flex items-center">
            <div
              className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${
                stepNumber < step
                  ? 'bg-green-500 text-white'
                  : stepNumber === step
                  ? 'bg-blue-500 text-white'
                  : 'bg-gray-300 text-gray-600'
              }`}
            >
              {stepNumber < step ? <CheckCircle className="w-4 h-4" /> : stepNumber}
            </div>
            {stepNumber < 3 && (
              <div
                className={`w-16 h-1 mx-2 ${
                  stepNumber < step ? 'bg-green-500' : 'bg-gray-300'
                }`}
              />
            )}
          </div>
        ))}
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <UserPlus className="w-5 h-5" />
            <span>Criar Usu├írio Administrador</span>
          </CardTitle>
          <CardDescription>
            Configure o primeiro usu├írio administrador do sistema
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit(handleCreateUser)} className="space-y-6">
            {/* Step 1: Personal Information */}
            {step === 1 && (
              <div className="space-y-4">
                <h3 className="text-lg font-semibold flex items-center space-x-2">
                  <User className="w-5 h-5" />
                  <span>Informa├º├Áes Pessoais</span>
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="name">Nome Completo *</Label>
                    <Input
                      id="name"
                      {...register('name')}
                      placeholder="Dr. Jo├úo Silva"
                      className={errors.name ? 'border-red-500' : ''}
                    />
                    {errors.name && (
                      <p className="text-sm text-red-600">{errors.name.message}</p>
                    )}
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="email">Email *</Label>
                    <Input
                      id="email"
                      type="email"
                      {...register('email')}
                      placeholder="joao@clinica.com"
                      className={errors.email ? 'border-red-500' : ''}
                    />
                    {errors.email && (
                      <p className="text-sm text-red-600">{errors.email.message}</p>
                    )}
                  </div>

                  <div className="space-y-2 md:col-span-2">
                    <Label htmlFor="phone">Telefone *</Label>
                    <Input
                      id="phone"
                      {...register('phone')}
                      placeholder="(11) 99999-9999"
                      className={errors.phone ? 'border-red-500' : ''}
                    />
                    {errors.phone && (
                      <p className="text-sm text-red-600">{errors.phone.message}</p>
                    )}
                  </div>
                </div>
              </div>
            )}

            {/* Step 2: Professional Information */}
            {step === 2 && (
              <div className="space-y-4">
                <h3 className="text-lg font-semibold flex items-center space-x-2">
                  <Shield className="w-5 h-5" />
                  <span>Informa├º├Áes Profissionais</span>
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="crm">CRM *</Label>
                    <Input
                      id="crm"
                      {...register('crm')}
                      placeholder="CRM/SP 123456"
                      className={errors.crm ? 'border-red-500' : ''}
                    />
                    {errors.crm && (
                      <p className="text-sm text-red-600">{errors.crm.message}</p>
                    )}
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="specialization">Especializa├º├úo *</Label>
                    <Select
                      value={watchedValues.specialization}
                      onValueChange={(value) => setValue('specialization', value)}
                    >
                      <SelectTrigger className={errors.specialization ? 'border-red-500' : ''}>
                        <SelectValue placeholder="Selecione a especializa├º├úo" />
                      </SelectTrigger>
                      <SelectContent>
                        {specializations.map((spec) => (
                          <SelectItem key={spec} value={spec}>
                            {spec}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    {errors.specialization && (
                      <p className="text-sm text-red-600">{errors.specialization.message}</p>
                    )}
                  </div>

                  <div className="space-y-2 md:col-span-2">
                    <Label>N├¡vel de Acesso *</Label>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                      {roles.map((role) => (
                        <Card
                          key={role.value}
                          className={`cursor-pointer transition-colors ${
                            watchedValues.role === role.value
                              ? 'border-blue-500 bg-blue-50'
                              : 'hover:border-gray-400'
                          }`}
                          onClick={() => setValue('role', role.value as any)}
                        >
                          <CardContent className="pt-4">
                            <div className="flex items-center space-x-2 mb-2">
                              <input
                                type="radio"
                                {...register('role')}
                                value={role.value}
                                className="sr-only"
                              />
                              <Badge variant={watchedValues.role === role.value ? 'default' : 'outline'}>
                                {role.label}
                              </Badge>
                            </div>
                            <p className="text-xs text-gray-600">{role.description}</p>
                          </CardContent>
                        </Card>
                      ))}
                    </div>
                    {errors.role && (
                      <p className="text-sm text-red-600">{errors.role.message}</p>
                    )}
                  </div>
                </div>
              </div>
            )}

            {/* Step 3: Security */}
            {step === 3 && (
              <div className="space-y-4">
                <h3 className="text-lg font-semibold flex items-center space-x-2">
                  <Key className="w-5 h-5" />
                  <span>Configura├º├Áes de Seguran├ºa</span>
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="password">Senha *</Label>
                    <div className="relative">
                      <Input
                        id="password"
                        type={showPassword ? 'text' : 'password'}
                        {...register('password')}
                        placeholder="Digite uma senha segura"
                        className={errors.password ? 'border-red-500 pr-10' : 'pr-10'}
                      />
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        className="absolute right-0 top-0 h-full px-3"
                        onClick={() => setShowPassword(!showPassword)}
                      >
                        {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                      </Button>
                    </div>
                    {watchedValues.password && passwordStrength && (
                      <div className="flex items-center space-x-2 text-sm">
                        <div
                          className={`w-3 h-3 rounded-full bg-${passwordStrength.color}-500`}
                        />
                        <span className={`text-${passwordStrength.color}-600`}>
                          For├ºa da senha: {passwordStrength.text}
                        </span>
                      </div>
                    )}
                    {errors.password && (
                      <p className="text-sm text-red-600">{errors.password.message}</p>
                    )}
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="confirmPassword">Confirmar Senha *</Label>
                    <div className="relative">
                      <Input
                        id="confirmPassword"
                        type={showConfirmPassword ? 'text' : 'password'}
                        {...register('confirmPassword')}
                        placeholder="Confirme sua senha"
                        className={errors.confirmPassword ? 'border-red-500 pr-10' : 'pr-10'}
                      />
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        className="absolute right-0 top-0 h-full px-3"
                        onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                      >
                        {showConfirmPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                      </Button>
                    </div>
                    {errors.confirmPassword && (
                      <p className="text-sm text-red-600">{errors.confirmPassword.message}</p>
                    )}
                  </div>
                </div>

                <div className="space-y-4 pt-4">
                  <div className="flex items-center space-x-2">
                    <Checkbox
                      id="enableNotifications"
                      checked={watchedValues.enableNotifications ?? false}
                      onCheckedChange={(checked) => setValue('enableNotifications', checked === true)}
                    />
                    <Label htmlFor="enableNotifications" className="text-sm">
                      Habilitar notifica├º├Áes por email e WhatsApp
                    </Label>
                  </div>

                  <div className="flex items-start space-x-2">
                    <Checkbox
                      id="acceptTerms"
                      checked={watchedValues.acceptTerms ?? false}
                      onCheckedChange={(checked) => setValue('acceptTerms', checked === true)}
                      className={errors.acceptTerms ? 'border-red-500' : ''}
                    />
                    <Label htmlFor="acceptTerms" className="text-sm leading-relaxed">
                      Aceito os <a href="#" className="text-blue-600 hover:underline">termos de uso</a> e
                      confirmo que tenho autoriza├º├úo para criar este usu├írio administrador *
                    </Label>
                  </div>
                  {errors.acceptTerms && (
                    <p className="text-sm text-red-600 ml-6">{errors.acceptTerms.message}</p>
                  )}
                </div>

                <Alert className="bg-blue-50 border-blue-200">
                  <AlertTriangle className="h-4 w-4 text-blue-600" />
                  <AlertDescription className="text-blue-800">
                    <strong>Importante:</strong> Este ser├í o primeiro usu├írio administrador do sistema.
                    Guarde as credenciais em local seguro e certifique-se de que apenas pessoas
                    autorizadas tenham acesso.
                  </AlertDescription>
                </Alert>
              </div>
            )}

            {/* Navigation Buttons */}
            <div className="flex items-center justify-between pt-6">
              <Button
                type="button"
                variant="outline"
                onClick={handlePreviousStep}
                disabled={step === 1}
              >
                Anterior
              </Button>

              <span className="text-sm text-gray-500">
                Etapa {step} de 3
              </span>

              {step < 3 ? (
                <Button
                  type="button"
                  onClick={handleNextStep}
                >
                  Pr├│ximo
                </Button>
              ) : (
                <Button
                  type="submit"
                  disabled={!isValid || isCreating}
                  className="min-w-[120px]"
                >
                  {isCreating ? (
                    <LoadingSpinner size="sm" text="Criando..." />
                  ) : (
                    <>
                      <UserPlus className="w-4 h-4 mr-2" />
                      Criar Usu├írio
                    </>
                  )}
                </Button>
              )}
            </div>
          </form>
        </CardContent>
      </Card>

      {isCreating && (
        <div className="text-center py-8">
          <LoadingSpinner
            size="lg"
            text="Criando usu├írio administrador..."
            showProgress
            progress={70}
          />
        </div>
      )}
    </div>
  )
}

import React from 'react'
import { Loader2, RefreshCw, CheckCircle, XCircle } from 'lucide-react'
import { cn } from '../../lib/utils'

interface LoadingSpinnerProps {
  size?: 'sm' | 'md' | 'lg' | 'xl'
  variant?: 'spinner' | 'refresh' | 'pulse' | 'bounce'
  status?: 'loading' | 'success' | 'error'
  text?: string
  className?: string
  showProgress?: boolean
  progress?: number
}

export function LoadingSpinner({
  size = 'md',
  variant = 'spinner',
  status = 'loading',
  text,
  className,
  showProgress = false,
  progress = 0
}: LoadingSpinnerProps) {
  const sizeClasses = {
    sm: 'w-4 h-4',
    md: 'w-6 h-6',
    lg: 'w-8 h-8',
    xl: 'w-12 h-12'
  }

  const textSizeClasses = {
    sm: 'text-xs',
    md: 'text-sm',
    lg: 'text-base',
    xl: 'text-lg'
  }

  const getIcon = () => {
    if (status === 'success') {
      return <CheckCircle className={cn(sizeClasses[size], 'text-green-500')} />
    }

    if (status === 'error') {
      return <XCircle className={cn(sizeClasses[size], 'text-red-500')} />
    }

    switch (variant) {
      case 'refresh':
        return <RefreshCw className={cn(sizeClasses[size], 'animate-spin text-blue-500')} />
      case 'pulse':
        return (
          <div className={cn(
            sizeClasses[size],
            'bg-blue-500 rounded-full animate-pulse'
          )} />
        )
      case 'bounce':
        return (
          <div className="flex space-x-1">
            {[...Array(3)].map((_, i) => (
              <div
                key={i}
                className={cn(
                  'w-2 h-2 bg-blue-500 rounded-full animate-bounce',
                  size === 'sm' && 'w-1.5 h-1.5',
                  size === 'lg' && 'w-3 h-3',
                  size === 'xl' && 'w-4 h-4'
                )}
                style={{
                  animationDelay: `${i * 0.1}s`
                }}
              />
            ))}
          </div>
        )
      default:
        return <Loader2 className={cn(sizeClasses[size], 'animate-spin text-blue-500')} />
    }
  }

  return (
    <div className={cn('flex flex-col items-center justify-center space-y-2', className)}>
      {getIcon()}

      {text && (
        <p className={cn(
          'text-gray-600 text-center',
          textSizeClasses[size]
        )}>
          {text}
        </p>
      )}

      {showProgress && status === 'loading' && (
        <div className="w-full max-w-xs">
          <div className="flex justify-between text-xs text-gray-500 mb-1">
            <span>Progresso</span>
            <span>{Math.round(progress)}%</span>
          </div>
          <div className="w-full bg-gray-200 rounded-full h-2">
            <div
              className="bg-blue-500 h-2 rounded-full transition-all duration-300 ease-out"
              style={{ width: `${Math.min(100, Math.max(0, progress))}%` }}
            />
          </div>
        </div>
      )}
    </div>
  )
}

interface LoadingOverlayProps {
  isVisible: boolean
  text?: string
  progress?: number
  showProgress?: boolean
  variant?: LoadingSpinnerProps['variant']
  backdrop?: 'light' | 'dark' | 'blur'
  size?: LoadingSpinnerProps['size']
}

export function LoadingOverlay({
  isVisible,
  text = 'Carregando...',
  progress = 0,
  showProgress = false,
  variant = 'spinner',
  backdrop = 'light',
  size = 'lg'
}: LoadingOverlayProps) {
  if (!isVisible) return null

  const backdropClasses = {
    light: 'bg-white/80',
    dark: 'bg-black/60',
    blur: 'bg-white/60 backdrop-blur-sm'
  }

  return (
    <div className={cn(
      'fixed inset-0 z-50 flex items-center justify-center',
      backdropClasses[backdrop]
    )}>
      <div className="bg-white rounded-lg shadow-lg p-6 max-w-sm w-full mx-4">
        <LoadingSpinner
          size={size}
          variant={variant}
          text={text}
          showProgress={showProgress}
          progress={progress}
        />
      </div>
    </div>
  )
}

interface LoadingCardProps {
  title?: string
  description?: string
  progress?: number
  showProgress?: boolean
  variant?: LoadingSpinnerProps['variant']
  size?: LoadingSpinnerProps['size']
  className?: string
}

export function LoadingCard({
  title = 'Processando...',
  description,
  progress = 0,
  showProgress = false,
  variant = 'spinner',
  size = 'md',
  className
}: LoadingCardProps) {
  return (
    <div className={cn(
      'bg-white rounded-lg border shadow-sm p-6',
      className
    )}>
      <div className="text-center space-y-4">
        <LoadingSpinner
          size={size}
          variant={variant}
          showProgress={showProgress}
          progress={progress}
        />

        <div>
          <h3 className="text-lg font-medium text-gray-900">{title}</h3>
          {description && (
            <p className="text-sm text-gray-600 mt-1">{description}</p>
          )}
        </div>
      </div>
    </div>
  )
}

// Skeleton loading components for different content types
export function LoadingSkeleton({ className }: { className?: string }) {
  return (
    <div className={cn('animate-pulse bg-gray-200 rounded', className)} />
  )
}

export function LoadingTableRow({ columns = 4 }: { columns?: number }) {
  return (
    <tr>
      {[...Array(columns)].map((_, i) => (
        <td key={i} className="px-6 py-4">
          <LoadingSkeleton className="h-4 w-full" />
        </td>
      ))}
    </tr>
