}

export function LoadingCard_Skeleton() {
  return (
    <div className="bg-white rounded-lg border shadow-sm p-6 space-y-4">
      <LoadingSkeleton className="h-4 w-3/4" />
      <LoadingSkeleton className="h-3 w-full" />
      <LoadingSkeleton className="h-3 w-5/6" />
      <div className="flex space-x-2">
        <LoadingSkeleton className="h-8 w-20" />
        <LoadingSkeleton className="h-8 w-16" />
      </div>
    </div>
  )
}

export function LoadingList({ items = 3 }: { items?: number }) {
  return (
    <div className="space-y-3">
      {[...Array(items)].map((_, i) => (
        <div key={i} className="flex items-center space-x-3 p-3 border rounded-lg">
          <LoadingSkeleton className="h-10 w-10 rounded-full" />
          <div className="flex-1 space-y-2">
            <LoadingSkeleton className="h-4 w-3/4" />
            <LoadingSkeleton className="h-3 w-1/2" />
          </div>
        </div>
      ))}
    </div>
  )
}

import React, { useState, useEffect } from 'react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card'
import { Button } from '../ui/button'
import { Badge } from '../ui/badge'
import { Progress } from '../ui/progress'
import {
  CheckCircle,
  XCircle,
  AlertTriangle,
  RefreshCw,
  Wifi,
  MessageSquare,
  Shield,
  Activity,
  Clock,
  ExternalLink
} from 'lucide-react'
import { Alert, AlertDescription } from '../ui/alert'
import { LoadingSpinner } from './LoadingSpinner'
import { toast } from '../../hooks/use-toast'
import { createLogger } from '../../lib/logger'
import { loadConfig } from '../../config'

const logger = createLogger('ServiceMonitor')

interface Service {
  id: string
  name: string
  description: string
  category: 'auth' | 'messaging' | 'monitoring' | 'ai' | 'websocket'
  status: 'pending' | 'checking' | 'healthy' | 'degraded' | 'unhealthy' | 'unknown'
  required: boolean
  url?: string | undefined
  responseTime?: number | undefined
  lastCheck?: Date | undefined
  error?: string | undefined
  details?: any
}

interface ServiceMonitorProps {
  onComplete: () => void
  onError: (error: string) => void
}

export function ServiceMonitor({ onComplete, onError }: ServiceMonitorProps) {
  const [services, setServices] = useState<Service[]>([
    {
      id: 'firebase-auth',
      name: 'Firebase Authentication',
      description: 'Servi├ºo de autentica├º├úo de usu├írios',
      category: 'auth',
      status: 'pending',
      required: true
    },
    {
      id: 'websocket',
      name: 'WebSocket Server',
      description: 'Comunica├º├úo em tempo real',
      category: 'websocket',
      status: 'pending',
      required: false
    },
    {
      id: 'whatsapp',
      name: 'WhatsApp Business API',
      description: 'Integra├º├úo com WhatsApp para notifica├º├Áes',
      category: 'messaging',
      status: 'pending',
      required: false
    },
    {
      id: 'sentry',
      name: 'Sentry Error Tracking',
      description: 'Monitoramento de erros em produ├º├úo',
      category: 'monitoring',
      status: 'pending',
      required: false
    },
    {
      id: 'openai',
      name: 'OpenAI API',
      description: 'Servi├ºos de intelig├¬ncia artificial',
      category: 'ai',
      status: 'pending',
      required: false
    },
    {
      id: 'gemini',
      name: 'Google Gemini API',
      description: 'Servi├ºos de IA alternativo',
      category: 'ai',
      status: 'pending',
      required: false
    }
  ])

  const [isChecking, setIsChecking] = useState(false)
  const [currentServiceIndex, setCurrentServiceIndex] = useState(0)
  const [overallProgress, setOverallProgress] = useState(0)

  const categoryIcons = {
    auth: <Shield className="w-4 h-4" />,
    messaging: <MessageSquare className="w-4 h-4" />,
    monitoring: <Activity className="w-4 h-4" />,
    ai: <Wifi className="w-4 h-4" />,
    websocket: <Wifi className="w-4 h-4" />
  }

  const categoryNames = {
    auth: 'Autentica├º├úo',
    messaging: 'Mensagens',
    monitoring: 'Monitoramento',
    ai: 'Intelig├¬ncia Artificial',
    websocket: 'Tempo Real'
  }

  useEffect(() => {
    // Auto-start service checks
    handleCheckServices()
  }, [])

  const updateServiceStatus = (
    id: string,
    status: Service['status'],
    responseTime?: number,
    error?: string,
    details?: any
  ) => {
    setServices(prev => prev.map(service =>
      service.id === id
        ? {
            ...service,
            status,
            responseTime,
            error,
            details,
            lastCheck: new Date()
          }
        : service
    ))
  }

  const handleCheckServices = async () => {
    setIsChecking(true)
    setCurrentServiceIndex(0)
    setOverallProgress(0)
    logger.log('Starting service checks')

    try {
      // Load configuration
      const config = await loadConfig()

      // Reset all services to pending
      setServices(prev => prev.map(service => ({ ...service, status: 'pending' as const })))

      for (let i = 0; i < services.length; i++) {
        const service = services[i]
        if (!service) continue

        setCurrentServiceIndex(i)
        updateServiceStatus(service.id, 'checking')

        const startTime = Date.now()

        try {
          await checkService(service, config)
          const responseTime = Date.now() - startTime
          updateServiceStatus(service.id, 'healthy', responseTime)
        } catch (error) {
          const responseTime = Date.now() - startTime
          const errorMessage = error instanceof Error ? error.message : 'Servi├ºo indispon├¡vel'

          // Determine status based on error type
          const status = errorMessage.includes('timeout') || errorMessage.includes('network')
            ? 'degraded'
            : 'unhealthy'

          updateServiceStatus(service.id, status, responseTime, errorMessage)
          logger.error(`Service '${service.id}' check failed:`, error)
        }

        // Update progress
        const progress = Math.round(((i + 1) / services.length) * 100)
        setOverallProgress(progress)

        // Small delay for visual feedback
        await new Promise(resolve => setTimeout(resolve, 300))
      }

      // Check results - only fail if required services are unhealthy
      const failedRequiredServices = services.filter(s =>
        s.required && s.status === 'unhealthy'
      )

      if (failedRequiredServices.length > 0) {
        onError(`Servi├ºos cr├¡ticos falharam: ${failedRequiredServices.map(s => s.name).join(', ')}`)
      } else {
        const degradedServices = services.filter(s => s.status === 'degraded').length
        const unhealthyServices = services.filter(s => s.status === 'unhealthy').length

        let message = 'Verifica├º├úo de servi├ºos conclu├¡da.'
        if (degradedServices > 0 || unhealthyServices > 0) {
          message += ` ${degradedServices + unhealthyServices} servi├ºos com problemas.`
        }

        toast({
          title: 'Servi├ºos Verificados',
          description: message,
          variant: failedRequiredServices.length > 0 ? 'destructive' : 'default'
        })
        onComplete()
      }

    } catch (error) {
      logger.error('Service monitoring failed:', error)
      onError('Falha na verifica├º├úo dos servi├ºos: ' + (error as Error).message)
    } finally {
      setIsChecking(false)
    }
  }

  const checkService = async (service: Service, config: any): Promise<void> => {
    switch (service.id) {
      case 'firebase-auth':
        await checkFirebaseAuth(config)
        break
      case 'websocket':
        await checkWebSocket(config)
        break
      case 'whatsapp':
        await checkWhatsApp(config)
        break
      case 'sentry':
        await checkSentry(config)
        break
      case 'openai':
        await checkOpenAI(config)
        break
      case 'gemini':
        await checkGemini(config)
        break
      default:
        throw new Error(`Unknown service: ${service.id}`)
    }
  }

  const checkFirebaseAuth = async (config: any) => {
    if (!config.FIREBASE_CONFIG) {
      throw new Error('Firebase n├úo configurado')
    }

    // Try to validate Firebase configuration
    try {
      const { firebaseAuthLazy } = await import('../../lib/firebase-lazy')
      if (!firebaseAuthLazy.isConfigured()) {
        throw new Error('Configura├º├úo Firebase inv├ílida')
      }
      updateServiceStatus('firebase-auth', 'checking', undefined, undefined, {
        configured: true,
        projectId: (config.FIREBASE_CONFIG as { projectId?: string }).projectId || 'N/A'
      })
    } catch (error) {
      throw new Error('Falha na valida├º├úo Firebase')
    }
  }

  const checkWebSocket = async (config: any) => {
    if (!config.WS_BASE_URL) {
      throw new Error('WebSocket n├úo configurado')
    }

    // Try to create a test WebSocket connection
    return new Promise<void>((resolve, reject) => {
      const timeout = setTimeout(() => {
        reject(new Error('Timeout na conex├úo WebSocket'))
      }, 5000)

      try {
        const wsUrl = config.WS_BASE_URL.replace(/^http/, 'ws')
        const ws = new WebSocket(wsUrl)

        ws.onopen = () => {
          clearTimeout(timeout)
          ws.close()
          updateServiceStatus('websocket', 'checking', undefined, undefined, {
            url: wsUrl,
            protocol: ws.protocol || 'default'
          })
          resolve()
        }

        ws.onerror = () => {
          clearTimeout(timeout)
          reject(new Error('Erro na conex├úo WebSocket'))
        }

        ws.onclose = (event) => {
          if (event.code !== 1000) {
            clearTimeout(timeout)
            reject(new Error(`WebSocket fechou com c├│digo: ${event.code}`))
          }
        }
      } catch (error) {
        clearTimeout(timeout)
        reject(error)
      }
    })
  }

  const checkWhatsApp = async (config: any) => {
    if (!config.WHATSAPP_INSTANCE_NAME) {
      throw new Error('WhatsApp n├úo configurado')
    }

    // Mock check - in real implementation, ping WhatsApp API
    await new Promise(resolve => setTimeout(resolve, 1000))

    updateServiceStatus('whatsapp', 'checking', undefined, undefined, {
      instance: config.WHATSAPP_INSTANCE_NAME,
      status: 'mock_healthy'
    })
  }

  const checkSentry = async (config: any) => {
    if (!config.SENTRY_DSN) {
      throw new Error('Sentry n├úo configurado')
    }

    // Validate Sentry DSN format
    const sentryDsnRegex = /^https:\/\/[a-f0-9]+@[a-z0-9]+\.ingest\.sentry\.io\/[0-9]+$/
    if (!sentryDsnRegex.test(config.SENTRY_DSN)) {
      throw new Error('DSN Sentry inv├ílido')
    }

    updateServiceStatus('sentry', 'checking', undefined, undefined, {
      configured: true,
      environment: config.ENVIRONMENT || 'development'
    })
  }

  const checkOpenAI = async (config: any) => {
    if (!config.OPENAI_API_KEY) {
      throw new Error('OpenAI n├úo configurado')
    }

    // Mock API check - in real implementation, make test API call
    await new Promise(resolve => setTimeout(resolve, 800))

    updateServiceStatus('openai', 'checking', undefined, undefined, {
      keyLength: config.OPENAI_API_KEY.length,
      configured: true
    })
  }

  const checkGemini = async (config: any) => {
    if (!config.GEMINI_API_KEY) {
      throw new Error('Gemini n├úo configurado')
    }

    // Mock API check
    await new Promise(resolve => setTimeout(resolve, 700))

    updateServiceStatus('gemini', 'checking', undefined, undefined, {
      keyLength: config.GEMINI_API_KEY.length,
      configured: true
    })
  }

  const getStatusIcon = (status: Service['status']) => {
    switch (status) {
      case 'healthy':
        return <CheckCircle className="w-5 h-5 text-green-500" />
      case 'degraded':
        return <AlertTriangle className="w-5 h-5 text-yellow-500" />
      case 'unhealthy':
        return <XCircle className="w-5 h-5 text-red-500" />
      case 'checking':
        return <RefreshCw className="w-5 h-5 text-blue-500 animate-spin" />
      default:
        return <div className="w-5 h-5 border-2 border-gray-300 rounded-full" />
    }
  }

  const getStatusBadge = (status: Service['status']) => {
    switch (status) {
      case 'healthy':
        return <Badge variant="default" className="bg-green-100 text-green-800">Saud├ível</Badge>
      case 'degraded':
        return <Badge variant="secondary" className="bg-yellow-100 text-yellow-800">Degradado</Badge>
      case 'unhealthy':
        return <Badge variant="destructive">Indispon├¡vel</Badge>
      case 'checking':
        return <Badge variant="outline" className="bg-blue-100 text-blue-800">Verificando</Badge>
      default:
        return <Badge variant="outline">Pendente</Badge>
    }
  }

  const formatResponseTime = (ms?: number) => {
    if (!ms) return ''
    if (ms < 1000) return `${ms}ms`
    return `${(ms / 1000).toFixed(1)}s`
  }

  const servicesByCategory = services.reduce((acc, service) => {
    const category = service.category
    if (!acc[category]) {
      acc[category] = []
    }
    acc[category]?.push(service)
    return acc
  }, {} as Record<string, Service[]>)

  const summaryStats = {
    total: services.length,
    healthy: services.filter(s => s.status === 'healthy').length,
    degraded: services.filter(s => s.status === 'degraded').length,
    unhealthy: services.filter(s => s.status === 'unhealthy').length
  }

  return (
    <div className="space-y-6">
      {/* Progress Overview */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle className="flex items-center space-x-2">
                <Activity className="w-5 h-5" />
                <span>Monitoramento de Servi├ºos</span>
              </CardTitle>
              <CardDescription>
                Verificando conectividade e sa├║de dos servi├ºos externos
              </CardDescription>
            </div>
            <div className="text-right">
              <div className="text-2xl font-bold text-blue-600">{overallProgress}%</div>
              <div className="text-sm text-gray-600">Progresso</div>
            </div>
          </div>
          {isChecking && (
            <div className="mt-4">
              <Progress value={overallProgress} />
              <div className="text-sm text-gray-600 mt-2">
                Verificando: {services[currentServiceIndex]?.name}
              </div>
            </div>
          )}
        </CardHeader>
      </Card>

      {/* Summary Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <Card className="text-center">
          <CardContent className="pt-4">
            <div className="text-2xl font-bold text-green-600">{summaryStats.healthy}</div>
            <div className="text-sm text-gray-600">Saud├íveis</div>
          </CardContent>
        </Card>
        <Card className="text-center">
          <CardContent className="pt-4">
            <div className="text-2xl font-bold text-yellow-600">{summaryStats.degraded}</div>
            <div className="text-sm text-gray-600">Degradados</div>
          </CardContent>
        </Card>
        <Card className="text-center">
          <CardContent className="pt-4">
            <div className="text-2xl font-bold text-red-600">{summaryStats.unhealthy}</div>
            <div className="text-sm text-gray-600">Indispon├¡veis</div>
          </CardContent>
        </Card>
        <Card className="text-center">
          <CardContent className="pt-4">
            <div className="text-2xl font-bold text-blue-600">{summaryStats.total}</div>
            <div className="text-sm text-gray-600">Total</div>
          </CardContent>
        </Card>
      </div>

      {/* Services by Category */}
      {Object.entries(servicesByCategory).map(([category, categoryServices]) => (
        <Card key={category}>
          <CardHeader>
            <CardTitle className="flex items-center space-x-2">
              {categoryIcons[category as keyof typeof categoryIcons]}
              <span>{categoryNames[category as keyof typeof categoryNames]}</span>
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            {categoryServices.map((service, index) => (
              <div
                key={service.id}
                className={`flex items-center justify-between p-4 border rounded-lg transition-colors ${
                  index === currentServiceIndex && isChecking
                    ? 'bg-blue-50 border-blue-200'
                    : ''
                }`}
              >
                <div className="flex items-start space-x-3 flex-1">
                  {getStatusIcon(service.status)}
                  <div className="flex-1">
                    <div className="flex items-center space-x-2">
                      <h4 className="font-medium">{service.name}</h4>
                      {service.required && (
                        <Badge variant="outline" className="text-xs">Obrigat├│rio</Badge>
                      )}
                      {service.responseTime && (
                        <span className="text-xs text-gray-500 flex items-center">
                          <Clock className="w-3 h-3 mr-1" />
                          {formatResponseTime(service.responseTime)}
                        </span>
                      )}
                    </div>
                    <p className="text-sm text-gray-600 mt-1">{service.description}</p>
                    {service.lastCheck && (
                      <div className="text-xs text-gray-500 mt-1">
                        ├Ültima verifica├º├úo: {service.lastCheck.toLocaleTimeString()}
                      </div>
                    )}
                    {service.details && (
                      <div className="mt-2 text-xs text-gray-500">
                        {Object.entries(service.details).map(([key, value]) => (
                          <span key={key} className="mr-4">
                            {key}: {String(value)}
                          </span>
                        ))}
                      </div>
                    )}
                    {service.error && (
                      <Alert className="mt-2" variant="destructive">
                        <AlertDescription className="text-xs">{service.error}</AlertDescription>
                      </Alert>
                    )}
                  </div>
                </div>
                <div className="flex items-center space-x-2">
                  {getStatusBadge(service.status)}
                  {service.url && (
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => window.open(service.url, '_blank')}
                      className="h-6 w-6 p-0"
                    >
                      <ExternalLink className="w-3 h-3" />
                    </Button>
                  )}
                </div>
              </div>
            ))}
          </CardContent>
        </Card>
      ))}

      {/* Action Buttons */}
      <div className="flex flex-col sm:flex-row gap-4">
        <Button
          onClick={handleCheckServices}
          disabled={isChecking}
          className="flex-1"
        >
          {isChecking ? (
            <>
              <RefreshCw className="w-4 h-4 mr-2 animate-spin" />
              Verificando...
            </>
          ) : (
            <>
              <RefreshCw className="w-4 h-4 mr-2" />
              Verificar Novamente
            </>
          )}
        </Button>

        <Button
          variant="outline"
          onClick={() => {
            toast({
              title: 'Relat├│rio de Servi├ºos',
              description: 'Funcionalidade em desenvolvimento.',
            })
          }}
          className="flex-1 sm:flex-none"
        >
          <Activity className="w-4 h-4 mr-2" />
