      </div>

      {isChecking && (
        <div className="text-center py-8">
          <LoadingSpinner
            size="lg"
            text={`Verificando: ${services[currentServiceIndex]?.name}...`}
            showProgress
            progress={overallProgress}
          />
        </div>
      )}
    </div>
  )
}

import React, { useState, useEffect } from 'react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card'
import { Button } from '../ui/button'
import { Progress } from '../ui/progress'
import { Badge } from '../ui/badge'
import { CheckCircle, XCircle, AlertTriangle, Play, RefreshCw } from 'lucide-react'
import { Alert, AlertDescription } from '../ui/alert'
import { LoadingSpinner } from './LoadingSpinner'
import { EnvironmentSetup } from './EnvironmentSetup'
import { DatabaseChecker } from './DatabaseChecker'
import { ServiceMonitor } from './ServiceMonitor'
import { WelcomeFlow } from './WelcomeFlow'
import { InitialUserSetup } from './InitialUserSetup'
import { ErrorBoundary } from '../common/ErrorBoundary'
import { toast } from '../../hooks/use-toast'
import { createLogger } from '../../lib/logger'

const logger = createLogger('SystemInitializationWizard')

interface InitializationStep {
  id: string
  title: string
  description: string
  component: React.ComponentType<{ onComplete: () => void; onError: (error: string) => void }>
  required: boolean
  status: 'pending' | 'running' | 'completed' | 'error' | 'skipped'
  error?: string | undefined
}

interface SystemInitializationWizardProps {
  onComplete: () => void
  autoStart?: boolean
  skipWelcome?: boolean
}

export function SystemInitializationWizard({
  onComplete,
  autoStart = false,
  skipWelcome = false
}: SystemInitializationWizardProps) {
  const [currentStep, setCurrentStep] = useState(0)
  const [isInitializing, setIsInitializing] = useState(false)
  const [hasStarted, setHasStarted] = useState(autoStart)
  const [initializationSteps, setInitializationSteps] = useState<InitializationStep[]>([
    {
      id: 'welcome',
      title: 'Bem-vindo',
      description: 'Configura├º├úo inicial do sistema',
      component: WelcomeFlow,
      required: !skipWelcome,
      status: 'pending'
    },
    {
      id: 'environment',
      title: 'Ambiente',
      description: 'Verifica├º├úo das configura├º├Áes do ambiente',
      component: EnvironmentSetup,
      required: true,
      status: 'pending'
    },
    {
      id: 'database',
      title: 'Banco de Dados',
      description: 'Conex├úo e verifica├º├úo do banco de dados',
      component: DatabaseChecker,
      required: true,
      status: 'pending'
    },
    {
      id: 'services',
      title: 'Servi├ºos',
      description: 'Verifica├º├úo dos servi├ºos externos',
      component: ServiceMonitor,
      required: false,
      status: 'pending'
    },
    {
      id: 'user-setup',
      title: 'Usu├írio Inicial',
      description: 'Configura├º├úo do primeiro usu├írio administrador',
      component: InitialUserSetup,
      required: true,
      status: 'pending'
    }
  ])

  const totalSteps = initializationSteps.filter(step => step.required || !skipWelcome).length
  const completedSteps = initializationSteps.filter(step => step.status === 'completed').length
  const progress = Math.round((completedSteps / totalSteps) * 100)

  useEffect(() => {
    if (autoStart && !hasStarted) {
      handleStart()
    }
  }, [autoStart, hasStarted])

  const handleStart = () => {
    logger.log('Starting system initialization')
    setHasStarted(true)
    setIsInitializing(true)

    // Skip welcome step if requested
    if (skipWelcome) {
      setCurrentStep(1)
      updateStepStatus('welcome', 'skipped')
    }

    toast({
      title: 'Inicializando Sistema',
      description: 'Verificando configura├º├Áes e conectando servi├ºos...',
    })
  }

  const updateStepStatus = (stepId: string, status: InitializationStep['status'], error?: string) => {
    setInitializationSteps(prev =>
      prev.map(step =>
        step.id === stepId
          ? { ...step, status, error }
          : step
      )
    )
  }

  const handleStepComplete = () => {
    const currentStepData = initializationSteps[currentStep]
    if (!currentStepData) return

    updateStepStatus(currentStepData.id, 'completed')

    logger.log(`Step '${currentStepData.id}' completed`)

    // Move to next step
    const nextStepIndex = currentStep + 1
    if (nextStepIndex < initializationSteps.length) {
      setCurrentStep(nextStepIndex)
      const nextStep = initializationSteps[nextStepIndex]
      if (nextStep) {
        updateStepStatus(nextStep.id, 'running')
      }
    } else {
      // All steps completed
      handleInitializationComplete()
    }
  }

  const handleStepError = (error: string) => {
    const currentStepData = initializationSteps[currentStep]
    if (!currentStepData) return

    updateStepStatus(currentStepData.id, 'error', error)

    logger.error(`Step '${currentStepData.id}' failed:`, error)

    toast({
      title: 'Erro na Inicializa├º├úo',
      description: `Falha na etapa: ${currentStepData.title}`,
      variant: 'destructive'
    })
  }

  const handleSkipStep = () => {
    const currentStepData = initializationSteps[currentStep]
    if (!currentStepData) return

    if (!currentStepData.required) {
      updateStepStatus(currentStepData.id, 'skipped')
      handleStepComplete()
    }
  }

  const handleRetryStep = () => {
    const currentStepData = initializationSteps[currentStep]
    if (!currentStepData) return

    updateStepStatus(currentStepData.id, 'running')
    logger.log(`Retrying step '${currentStepData.id}'`)
  }

  const handleInitializationComplete = () => {
    setIsInitializing(false)
    logger.log('System initialization completed successfully')

    toast({
      title: 'Inicializa├º├úo Conclu├¡da',
      description: 'Sistema configurado com sucesso!',
      variant: 'default'
    })

    onComplete()
  }

  const getStatusIcon = (status: InitializationStep['status']) => {
    switch (status) {
      case 'completed':
        return <CheckCircle className="w-5 h-5 text-green-500" />
      case 'error':
        return <XCircle className="w-5 h-5 text-red-500" />
      case 'running':
        return <RefreshCw className="w-5 h-5 text-blue-500 animate-spin" />
      case 'skipped':
        return <AlertTriangle className="w-5 h-5 text-yellow-500" />
      default:
        return <div className="w-5 h-5 border-2 border-gray-300 rounded-full" />
    }
  }

  const getStatusBadge = (status: InitializationStep['status']) => {
    switch (status) {
      case 'completed':
        return <Badge variant="default" className="bg-green-100 text-green-800">Conclu├¡do</Badge>
      case 'error':
        return <Badge variant="destructive">Erro</Badge>
      case 'running':
        return <Badge variant="default" className="bg-blue-100 text-blue-800">Em Execu├º├úo</Badge>
      case 'skipped':
        return <Badge variant="secondary">Ignorado</Badge>
      default:
        return <Badge variant="outline">Pendente</Badge>
    }
  }

  if (!hasStarted) {
    return (
      <ErrorBoundary>
        <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-50 to-indigo-100">
          <Card className="w-full max-w-2xl mx-4">
            <CardHeader className="text-center">
              <CardTitle className="text-3xl font-bold text-gray-900">
                Sistema Cl├¡nica Oncol├│gica
              </CardTitle>
              <CardDescription className="text-lg text-gray-600 mt-2">
                Bem-vindo! Vamos configurar seu sistema de gest├úo m├®dica.
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              <div className="text-center">
                <Play className="w-16 h-16 mx-auto text-blue-500 mb-4" />
                <p className="text-gray-600 mb-6">
                  O assistente de configura├º├úo ir├í verificar as conex├Áes necess├írias
                  e configurar o sistema automaticamente.
                </p>
                <Button
                  onClick={handleStart}
                  size="lg"
                  className="w-full sm:w-auto px-8"
                >
                  Iniciar Configura├º├úo
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      </ErrorBoundary>
    )
  }

  const currentStepData = initializationSteps[currentStep]
  const CurrentStepComponent = currentStepData?.component

  return (
    <ErrorBoundary>
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 py-8">
        <div className="container mx-auto px-4">
          {/* Progress Header */}
          <Card className="mb-8">
            <CardHeader>
              <div className="flex items-center justify-between">
                <div>
                  <CardTitle>Configura├º├úo do Sistema</CardTitle>
                  <CardDescription>
                    Etapa {currentStep + 1} de {totalSteps}
                  </CardDescription>
                </div>
                <div className="text-right">
                  <div className="text-2xl font-bold text-blue-600">{progress}%</div>
                  <div className="text-sm text-gray-600">Conclu├¡do</div>
                </div>
              </div>
              <Progress value={progress} className="mt-4" />
            </CardHeader>
          </Card>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Steps Sidebar */}
            <div className="lg:col-span-1">
              <Card>
                <CardHeader>
                  <CardTitle className="text-lg">Etapas</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  {initializationSteps.map((step, index) => (
                    <div
                      key={step.id}
                      className={`flex items-start space-x-3 p-3 rounded-lg transition-colors ${
                        index === currentStep
                          ? 'bg-blue-50 border border-blue-200'
                          : 'hover:bg-gray-50'
                      }`}
                    >
                      <div className="flex-shrink-0 mt-0.5">
                        {getStatusIcon(step.status)}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between">
                          <h4 className="text-sm font-medium text-gray-900 truncate">
                            {step.title}
                          </h4>
                          {getStatusBadge(step.status)}
                        </div>
                        <p className="text-xs text-gray-600 mt-1">
                          {step.description}
                        </p>
                        {step.error && (
                          <p className="text-xs text-red-600 mt-1">
                            {step.error}
                          </p>
                        )}
                      </div>
                    </div>
                  ))}
                </CardContent>
              </Card>
            </div>

            {/* Main Content */}
            <div className="lg:col-span-2">
              <Card className="min-h-[500px]">
                <CardHeader>
                  <div className="flex items-center justify-between">
                    <div>
                      <CardTitle className="flex items-center space-x-2">
                        {getStatusIcon(currentStepData?.status || 'pending')}
                        <span>{currentStepData?.title}</span>
                      </CardTitle>
                      <CardDescription>{currentStepData?.description}</CardDescription>
                    </div>
                    {currentStepData?.status === 'error' && (
                      <Button onClick={handleRetryStep} variant="outline" size="sm">
                        <RefreshCw className="w-4 h-4 mr-2" />
                        Tentar Novamente
                      </Button>
                    )}
                  </div>
                </CardHeader>
                <CardContent>
                  {currentStepData?.status === 'error' && currentStepData.error && (
                    <Alert className="mb-6" variant="destructive">
                      <XCircle className="h-4 w-4" />
                      <AlertDescription>{currentStepData.error}</AlertDescription>
                    </Alert>
                  )}

                  {CurrentStepComponent && (
                    <CurrentStepComponent
                      onComplete={handleStepComplete}
                      onError={handleStepError}
                    />
                  )}

                  {!currentStepData?.required && currentStepData?.status !== 'completed' && (
                    <div className="mt-6 pt-6 border-t">
                      <Button
                        onClick={handleSkipStep}
                        variant="outline"
                        className="w-full sm:w-auto"
                      >
                        Pular Esta Etapa
                      </Button>
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>
          </div>
        </div>
      </div>
    </ErrorBoundary>
  )
}

import React from 'react';
import { Link, useLocation, useParams } from 'react-router-dom';
import {
  ChevronRight,
  Home,
  Users,
  MessageSquare,
  Settings,
  User,
  FileText,
  BarChart3,
  AlertTriangle,
  HelpCircle,
  GitBranch,
  ClipboardList,
  Activity
} from 'lucide-react';
import { cn } from '@/lib/utils';

interface BreadcrumbItem {
  label: string;
  href?: string;
  icon?: React.ReactNode;
  isActive?: boolean;
}

interface BreadcrumbProps {
  className?: string;
  items?: BreadcrumbItem[];
  showIcons?: boolean;
  showHome?: boolean;
  separator?: React.ReactNode;
  maxItems?: number;
}

// Comprehensive route mapping with icons and Portuguese labels
const routeConfig: Record<string, { name: string; icon: React.ReactNode }> = {
  dashboard: { name: 'Dashboard', icon: <BarChart3 className="h-4 w-4" /> },
  patients: { name: 'Pacientes', icon: <Users className="h-4 w-4" /> },
  messages: { name: 'Mensagens', icon: <MessageSquare className="h-4 w-4" /> },
  settings: { name: 'Configura├º├Áes', icon: <Settings className="h-4 w-4" /> },
  profile: { name: 'Perfil', icon: <User className="h-4 w-4" /> },
  reports: { name: 'Relat├│rios', icon: <FileText className="h-4 w-4" /> },
  analytics: { name: 'An├ílises', icon: <Activity className="h-4 w-4" /> },
  alerts: { name: 'Alertas', icon: <AlertTriangle className="h-4 w-4" /> },
  help: { name: 'Ajuda', icon: <HelpCircle className="h-4 w-4" /> },
  flows: { name: 'Fluxos', icon: <GitBranch className="h-4 w-4" /> },
  questionarios: { name: 'Question├írios', icon: <ClipboardList className="h-4 w-4" /> },
  quiz: { name: 'Quiz', icon: <ClipboardList className="h-4 w-4" /> },
};

// Helper to get patient name from ID (in real app, this would fetch from API/context)
const getPatientName = (id: string): string => {
  // In a real application, you would fetch this from your patient context or API
  // For now, return a formatted ID
  return `Paciente #${id}`;
};

export function Breadcrumb({
  className,
  items,
  showIcons = true,
  showHome = true,
  separator = <ChevronRight className="h-4 w-4 text-muted-foreground/60" />,
  maxItems = 4
}: BreadcrumbProps) {
  const location = useLocation();
  const params = useParams();

  // Generate breadcrumb items from URL path if not provided
  const breadcrumbItems = React.useMemo(() => {
    if (items) return items;

    const paths = location.pathname.split('/').filter(Boolean);
    const generatedItems: BreadcrumbItem[] = [];

    paths.forEach((path, index) => {
      const href = '/' + paths.slice(0, index + 1).join('/');
      const isLastItem = index === paths.length - 1;

      // Handle dynamic routes (e.g., /patients/123)
      if (!isNaN(Number(path))) {
        // Check if this is a patient ID
        const parentPath = paths[index - 1];
        if (parentPath === 'patients') {
          generatedItems.push({
            label: getPatientName(path),
            ...(isLastItem ? {} : { href }),
            ...(showIcons ? { icon: <User className="h-4 w-4" /> } : {}),
            isActive: isLastItem
          });
        } else {
          // Generic ID handling
          generatedItems.push({
            label: `#${path}`,
            ...(isLastItem ? {} : { href }),
            isActive: isLastItem
          });
        }
      } else {
        // Regular route
        const config = routeConfig[path];
        generatedItems.push({
          label: config?.name || path.charAt(0).toUpperCase() + path.slice(1),
          ...(isLastItem ? {} : { href }),
          ...(showIcons && config?.icon ? { icon: config.icon } : {}),
          isActive: isLastItem
        });
      }
    });

    // Implement breadcrumb truncation for long paths
    if (generatedItems.length > maxItems) {
      const firstItem = generatedItems[0];
      const lastItems = generatedItems.slice(-2);
      return [
        firstItem,
        { label: '...', href: undefined, isActive: false },
        ...lastItems
      ];
    }

    return generatedItems;
  }, [location.pathname, params, items, showIcons, maxItems]);

  if (breadcrumbItems.length === 0 && !showHome) return null;

  return (
    <nav
      aria-label="Navega├º├úo estrutural"
      className={cn(
        "flex items-center space-x-1 text-sm",
        className
      )}
      role="navigation"
    >
      {showHome && (
        <>
          <Link
            to="/dashboard"
            className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground transition-colors rounded-md p-1 hover:bg-accent/50"
            aria-label="Voltar ao dashboard"
          >
            <Home className="h-4 w-4" />
            <span className="hidden sm:inline font-medium">In├¡cio</span>
          </Link>
          {breadcrumbItems.length > 0 && (
            <span className="text-muted-foreground/60" aria-hidden="true">
              {separator}
            </span>
          )}
        </>
      )}

      {breadcrumbItems.map((item, index) => (
        <React.Fragment key={`${item?.href || item?.label}-${index}`}>
          {index > 0 && (
            <span className="text-muted-foreground/60" aria-hidden="true">
              {separator}
            </span>
          )}
          {item?.href && !item?.isActive ? (
            <Link
              to={item?.href}
              className={cn(
                "flex items-center gap-1.5 text-muted-foreground hover:text-foreground transition-colors rounded-md p-1 hover:bg-accent/50",
                "focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
              )}
              aria-current={item?.isActive ? "page" : undefined}
            >
              {item && 'icon' in item && item.icon && (
                <span className="hidden sm:inline" aria-hidden="true">
                  {item.icon}
                </span>
              )}
              <span className="font-medium truncate max-w-[120px] sm:max-w-none">
                {item?.label}
              </span>
            </Link>
          ) : (
            <span
              className={cn(
                "flex items-center gap-1.5",
                item?.isActive
                  ? "text-foreground font-semibold"
                  : "text-muted-foreground"
              )}
              aria-current={item?.isActive ? "page" : undefined}
            >
              {item && 'icon' in item && item.icon && (
                <span className="hidden sm:inline" aria-hidden="true">
                  {item.icon}
                </span>
              )}
              <span className="truncate max-w-[120px] sm:max-w-none">
                {item?.label}
              </span>
            </span>
          )}
        </React.Fragment>
      ))}
    </nav>
  );
}

// Compact variant for mobile or space-constrained areas
export function BreadcrumbCompact({ className, ...props }: BreadcrumbProps) {
  return (
    <Breadcrumb
      {...props}
      className={cn("space-x-0.5 text-xs", className)}
      showIcons={false}
      separator={<ChevronRight className="h-3 w-3 text-muted-foreground/60" />}
      maxItems={2}
    />
  );
}

// Breadcrumb with dropdown for overflow items
export function BreadcrumbWithDropdown({
  className,
  items,
  showIcons = true,
  maxVisibleItems = 3
}: BreadcrumbProps & { maxVisibleItems?: number }) {
  const location = useLocation();

  const allItems = React.useMemo(() => {
    if (items) return items;

    const paths = location.pathname.split('/').filter(Boolean);
    return paths.map((path, index) => {
      const href = '/' + paths.slice(0, index + 1).join('/');
      const isLastItem = index === paths.length - 1;
      const config = routeConfig[path];

      return {
        label: config?.name || path.charAt(0).toUpperCase() + path.slice(1),
        ...(isLastItem ? {} : { href }),
        ...(showIcons && config?.icon ? { icon: config.icon } : {}),
        isActive: isLastItem
      };
    });
  }, [location.pathname, items, showIcons]);

  if (allItems.length <= maxVisibleItems) {
    return <Breadcrumb {...(className ? { className } : {})} items={allItems} showIcons={showIcons} />;
  }

  const visibleItems = [
    allItems[0],
    ...allItems.slice(-2)
  ];

  return (
    <nav
      aria-label="Navega├º├úo estrutural"
      className={cn("flex items-center space-x-1 text-sm", className)}
    >
      <Link
        to="/dashboard"
        className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground transition-colors rounded-md p-1 hover:bg-accent/50"
      >
        <Home className="h-4 w-4" />
        <span className="hidden sm:inline font-medium">In├¡cio</span>
      </Link>

      {visibleItems.map((item, index) => (
        <React.Fragment key={`${item?.href || item?.label}-${index}`}>
          <ChevronRight className="h-4 w-4 text-muted-foreground/60" />
          {item?.href && !item?.isActive ? (
            <Link
              to={item?.href}
              className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground transition-colors rounded-md p-1 hover:bg-accent/50"
            >
              {item?.icon && <span className="hidden sm:inline">{item?.icon}</span>}
              <span className="font-medium">{item?.label}</span>
            </Link>
          ) : (
            <span className="flex items-center gap-1.5 text-foreground font-semibold">
              {item?.icon && <span className="hidden sm:inline">{item?.icon}</span>}
              <span>{item?.label}</span>
            </span>
          )}
        </React.Fragment>
      ))}
    </nav>
  );
}

export default Breadcrumb;

