} from '@/components/ui/popover'
import { Separator } from '@/components/ui/separator'
import { LoadingSpinner } from '@/components/ui/loading-spinner'

interface Notification {
  id: string
  type: 'alert' | 'message' | 'report' | 'quiz'
  title: string
  message: string
  is_read: boolean
  created_at: string
  metadata?: Record<string, any>
}

export function NotificationCenter() {
  const [isOpen, setIsOpen] = useState(false)
  const { user, isLoading: authLoading } = useAuth()

  const { data: notificationsData, isLoading } = useQuery({
    queryKey: ['notifications'],
    queryFn: () => apiClient.notifications.list(),
    enabled: !!user && !authLoading, // Only run when authenticated
    refetchInterval: 30000 // Refresh every 30 seconds
  })

  const notifications = notificationsData?.items || []
  const unreadCount = notificationsData?.unread_count || 0

  const getNotificationIcon = (type: string) => {
    switch (type) {
      case 'alert':
        return AlertTriangle
      case 'message':
        return MessageSquare
      case 'report':
        return FileText
      default:
        return Bell
    }
  }

  const getNotificationColor = (type: string) => {
    switch (type) {
      case 'alert':
        return 'text-red-600'
      case 'message':
        return 'text-blue-600'
      case 'report':
        return 'text-green-600'
      default:
        return 'text-gray-600'
    }
  }

  return (
    <Popover open={isOpen} onOpenChange={setIsOpen}>
      <PopoverTrigger asChild>
        <Button variant="ghost" size="sm" className="relative">
          <Bell className="h-5 w-5" />
          {unreadCount > 0 && (
            <Badge 
              variant="destructive" 
              className="absolute -top-1 -right-1 h-5 w-5 flex items-center justify-center p-0 text-xs"
            >
              {unreadCount > 9 ? '9+' : unreadCount}
            </Badge>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-80 p-0" align="end">
        <div className="flex items-center justify-between p-4 border-b">
          <h3 className="font-semibold">Notifica├º├Áes</h3>
          {unreadCount > 0 && (
            <Button variant="ghost" size="sm" className="text-xs">
              Marcar todas como lidas
            </Button>
          )}
        </div>
        
        <ScrollArea className="h-[400px]">
          {isLoading ? (
            <div className="flex items-center justify-center py-8">
              <LoadingSpinner size="md" />
            </div>
          ) : notifications.length === 0 ? (
            <div className="text-center py-8">
              <Bell className="mx-auto h-8 w-8 text-gray-400 mb-2" />
              <p className="text-sm text-gray-500">Nenhuma notifica├º├úo</p>
            </div>
          ) : (
            <div className="divide-y">
              {notifications.map((notification: Notification) => {
                const Icon = getNotificationIcon(notification.type)
                const iconColor = getNotificationColor(notification.type)
                
                return (
                  <div
                    key={notification.id}
                    className={`p-4 hover:bg-gray-50 cursor-pointer ${
                      !notification.is_read ? 'bg-blue-50' : ''
                    }`}
                  >
                    <div className="flex items-start space-x-3">
                      <div className={`flex-shrink-0 ${iconColor}`}>
                        <Icon className="h-4 w-4" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between">
                          <p className={`text-sm font-medium ${
                            !notification.is_read ? 'text-gray-900' : 'text-gray-700'
                          }`}>
                            {notification.title}
                          </p>
                          {!notification.is_read && (
                            <div className="w-2 h-2 bg-blue-600 rounded-full flex-shrink-0" />
                          )}
                        </div>
                        <p className="text-sm text-gray-600 mt-1">
                          {notification.message}
                        </p>
                        <p className="text-xs text-gray-400 mt-1">
                          {formatDistanceToNow(new Date(notification.created_at), {
                            addSuffix: true,
                            locale: ptBR
                          })}
                        </p>
                      </div>
                    </div>
                  </div>
                )
              })}
            </div>
          )}
        </ScrollArea>
        
        {notifications && notifications.length > 0 && (
          <>
            <Separator />
            <div className="p-2">
              <Button variant="ghost" size="sm" className="w-full text-xs">
                Ver todas as notifica├º├Áes
              </Button>
            </div>
          </>
        )}
      </PopoverContent>
    </Popover>
  )
}

import React from "react";
import { NavLink, useLocation } from "react-router-dom";
import {
  LayoutDashboard,
  Users,
  MessageSquare,
  FileText,
  TriangleAlert as AlertTriangle,
  Settings,
  ChartBar as BarChart3,
  ClipboardList,
  Shield,
  Calendar,
  X,
  AlertOctagon,
  Workflow,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useAuth } from "@/contexts/AuthContext";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { useRoleGuard, PermissionGate } from "@/components/auth/ProtectedRoute";
import { getRoleLabel, getRoleColor, type RolePermissions } from "@/types/shared";

interface NavigationItem {
  name: string;
  href: string;
  icon: React.ElementType;
  requiredPermission?: keyof RolePermissions;
  badge?: string;
  badgeVariant?: "default" | "secondary" | "destructive" | "outline";
}

/**
 * Navigation items available to all authenticated users
 */
const baseNavigation: NavigationItem[] = [
  {
    name: "Dashboard",
    href: "/dashboard",
    icon: LayoutDashboard,
  },
  {
    name: "Pacientes",
    href: "/patients",
    icon: Users,
    requiredPermission: "canManagePatients",
  },
  {
    name: "Mensagens",
    href: "/messages",
    icon: MessageSquare,
  },
  {
    name: "Question├írios",
    href: "/quiz",
    icon: ClipboardList,
  },
  {
    name: "Quiz Mensal",
    href: "/monthly-quiz",
    icon: Calendar,
  },
  {
    name: "Relat├│rios",
    href: "/reports",
    icon: FileText,
    requiredPermission: "canViewReports",
  },
  {
    name: "Alertas",
    href: "/alerts",
    icon: AlertTriangle,
  },
  {
    name: "An├ílises",
    href: "/analytics",
    icon: BarChart3,
  },
];

/**
 * Admin-only navigation items
 */
const adminNavigation: NavigationItem[] = [
  {
    name: "Administra├º├úo",
    href: "/admin",
    icon: Shield,
    requiredPermission: "canAccessAdmin",
    badge: "Admin",
    badgeVariant: "destructive",
  },
  {
    name: "Configura├º├Áes",
    href: "/settings",
    icon: Settings,
    requiredPermission: "canManageSettings",
  },
  {
    name: "Flows",
    href: "/flows",
    icon: Workflow,
    requiredPermission: "canManageFlows",
  },
  {
    name: "Dead Letter Queue",
    href: "/dlq",
    icon: AlertOctagon,
    requiredPermission: "canAccessAdmin",
    badge: "Dev",
    badgeVariant: "outline",
  },
];

interface SidebarProps {
  isOpen: boolean;
  onClose: () => void;
}

export function Sidebar({ isOpen, onClose }: SidebarProps) {
  const location = useLocation();
  const { user } = useAuth();
  const { permissions, userRole, isAdmin } = useRoleGuard();

  /**
   * Filter navigation items based on user permissions
   */
  const getFilteredNavigation = (): NavigationItem[] => {
    const allItems = [...baseNavigation, ...adminNavigation];

    return allItems.filter((item) => {
      // If no permission required, show to everyone
      if (!item.requiredPermission) {
        return true;
      }

      // Check if user has the required permission
      return permissions[item.requiredPermission];
    });
  };

  const filteredNavigation = getFilteredNavigation();

  /**
   * Get role badge color classes
   */
  const getRoleBadgeClasses = () => {
    return getRoleColor(userRole);
  };

  return (
    <>
      {/* Mobile overlay */}
      {isOpen && (
        <div
          className="fixed inset-0 bg-black/50 z-40 lg:hidden"
          onClick={onClose}
          aria-hidden="true"
        />
      )}

      {/* Sidebar */}
      <aside
        className={cn(
          "flex flex-col w-64 bg-white border-r border-gray-200 fixed lg:static inset-y-0 left-0 z-50 transform transition-transform duration-300 ease-in-out",
          isOpen ? "translate-x-0" : "-translate-x-full lg:translate-x-0",
        )}
        aria-label="Navega├º├úo principal"
      >
        {/* Logo */}
        <div className="flex items-center justify-between h-16 px-4 md:px-6 border-b border-gray-200">
          <div className="flex-1" />
          <img
            src="/images/logo_system.svg"
            alt="Neoplasias Litoral Logo"
            className="h-14 w-auto"
          />
          <div className="flex-1 flex justify-end">
            {/* Close button (mobile only) */}
            <Button
              variant="ghost"
              size="sm"
              className="lg:hidden"
              onClick={onClose}
              aria-label="Fechar menu"
            >
              <X className="h-5 w-5" />
            </Button>
          </div>
        </div>

        {/* User Info with Role Badge */}
        {user && (
          <div className="px-4 py-3 border-b border-gray-200 bg-gray-50">
            <div className="flex items-center justify-between">
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-gray-900 truncate">
                  {user["full_name"] || user["email"]}
                </p>
                <p className="text-xs text-gray-500 truncate">{user["email"]}</p>
              </div>
              <Badge
                variant={isAdmin ? "default" : "secondary"}
                className={cn("ml-2 shrink-0", getRoleBadgeClasses())}
              >
                {getRoleLabel(userRole)}
              </Badge>
            </div>
          </div>
        )}

        {/* Navigation */}
        <nav
          className="flex-1 px-3 md:px-4 py-4 md:py-6 space-y-1 overflow-y-auto"
          aria-label="Menu de navega├º├úo"
        >
          {filteredNavigation.map((item) => {
            const isActive =
              location.pathname === item.href ||
              (item.href !== "/dashboard" && location.pathname.startsWith(item.href));

            return (
              <NavLink
                key={item.name}
                to={item.href}
                onClick={() => onClose()}
                className={cn(
                  "flex items-center justify-between px-3 py-2 text-sm font-medium rounded-lg transition-colors group",
                  isActive
                    ? "bg-blue-50 text-blue-700"
                    : "text-gray-700 hover:bg-gray-50 hover:text-gray-900",
                )}
                aria-current={isActive ? "page" : undefined}
              >
                <div className="flex items-center min-w-0 flex-1">
                  <item.icon
                    className={cn(
                      "mr-3 h-5 w-5 shrink-0",
                      isActive ? "text-blue-700" : "text-gray-400 group-hover:text-gray-600",
                    )}
                  />
                  <span className="truncate">{item.name}</span>
                </div>

                {/* Optional badge */}
                {item.badge && (
                  <Badge
                    variant={item.badgeVariant || "secondary"}
                    className="ml-2 text-xs shrink-0"
                  >
                    {item.badge}
                  </Badge>
                )}
              </NavLink>
            );
          })}
        </nav>

        {/* Permission Summary (visible in dev mode or for admins) */}
        {isAdmin && (
          <div className="px-4 py-3 border-t border-gray-200 bg-gray-50">
            <details className="group">
              <summary className="text-xs font-medium text-gray-700 cursor-pointer hover:text-gray-900 flex items-center justify-between">
                <span>Permiss├Áes</span>
                <span className="text-gray-400 group-open:rotate-90 transition-transform">ÔûÂ</span>
              </summary>
              <div className="mt-2 space-y-1 text-xs">
                {Object.entries(permissions).map(([key, value]) => (
                  <div key={key} className="flex items-center justify-between py-1">
                    <span className="text-gray-600 truncate flex-1">{key.replace(/^can/, "")}</span>
                    <span className={value ? "text-green-600" : "text-red-600"}>
                      {value ? "Ô£ô" : "Ô£ù"}
                    </span>
                  </div>
                ))}
              </div>
            </details>
          </div>
        )}

        {/* Footer */}
        <div className="p-3 md:p-4 border-t border-gray-200">
          <div className="text-xs text-gray-500 text-center space-y-1">
            <p className="font-medium">Neoplasias Litoral</p>
            <p>Sistema de Oncologia v1.0.0</p>
            <PermissionGate permission="canAccessAdmin">
              <p className="text-blue-600 font-medium">­ƒøí´©Å Admin Mode</p>
            </PermissionGate>
          </div>
        </div>
      </aside>
    </>
  );
}

/**
 * Skeleton Components for Suspense Fallbacks
 *
 * Provides loading skeletons for different component types.
 * Optimized for performance and accessibility.
 *
 * Features:
 * - Semantic HTML with proper ARIA labels
 * - CSS-based animations (no JS)
 * - Responsive designs
 * - Dark mode support
 * - Reduced motion support
 *
 * Usage:
 * ```tsx
 * <Suspense fallback={<PageSkeleton />}>
 *   <LazyPage />
 * </Suspense>
 * ```
 */

import { cn } from '@/lib/utils'

interface SkeletonProps {
  className?: string
  'aria-label'?: string
}

/**
 * Base Skeleton Component
 */
export function Skeleton({ className, 'aria-label': ariaLabel, ...props }: SkeletonProps) {
  return (
    <div
      role="status"
      aria-label={ariaLabel || 'Carregando...'}
      className={cn(
        'animate-pulse rounded-md bg-muted',
        'motion-reduce:animate-none', // Respect reduced motion preference
        className
      )}
      {...props}
    />
  )
}

/**
 * Page-level Loading Skeleton
 * Full-screen centered spinner
 */
export function PageSkeleton() {
  return (
    <div
      role="status"
      aria-label="Carregando p├ígina..."
      className="min-h-screen flex items-center justify-center bg-background"
    >
      <div className="flex flex-col items-center gap-4">
        <div className="h-12 w-12 rounded-full border-4 border-primary border-t-transparent animate-spin" />
        <p className="text-sm text-muted-foreground">Carregando...</p>
      </div>
    </div>
  )
}

/**
 * Card Skeleton
 * For dashboard cards, stat cards, etc.
 */
export function CardSkeleton({ className }: SkeletonProps) {
  return (
    <div
      role="status"
      aria-label="Carregando card..."
      className={cn('p-6 border rounded-lg space-y-4 bg-card', className)}
    >
      <Skeleton className="h-4 w-3/4" />
      <Skeleton className="h-4 w-1/2" />
      <Skeleton className="h-8 w-full" />
      <div className="flex gap-2">
        <Skeleton className="h-6 w-20" />
        <Skeleton className="h-6 w-20" />
      </div>
    </div>
  )
}

/**
 * Table Skeleton
 * For data tables and lists
 */
export function TableSkeleton({ rows = 5, columns = 4 }: { rows?: number; columns?: number }) {
  return (
    <div role="status" aria-label="Carregando tabela..." className="space-y-3">
      {/* Table header */}
      <div className="flex gap-4 pb-3 border-b">
        {Array.from({ length: columns }).map((_, i) => (
          <Skeleton key={`header-${i}`} className="h-4 flex-1" />
        ))}
      </div>

      {/* Table rows */}
      {Array.from({ length: rows }).map((_, rowIndex) => (
        <div key={`row-${rowIndex}`} className="flex gap-4 py-2">
          {Array.from({ length: columns }).map((_, colIndex) => (
            <Skeleton key={`cell-${rowIndex}-${colIndex}`} className="h-4 flex-1" />
          ))}
        </div>
      ))}
    </div>
  )
}

