import { Textarea } from '@/components/ui/textarea'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { useToast } from '@/components/ui/use-toast'
import { LoadingSpinner } from '../ui/loading-spinner'
import { Input } from '@/components/ui/input'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'

interface MessageComposerProps {
  patientId: string
  patientName: string
  onMessageSent?: () => void
}

export function MessageComposer({ patientId, patientName, onMessageSent }: MessageComposerProps) {
  const [message, setMessage] = useState('')
  const [messageType, setMessageType] = useState<MessageType>(MessageType.TEXT)
  const [scheduledFor, setScheduledFor] = useState('')
  const [showTemplates, setShowTemplates] = useState(false)
  const { toast } = useToast()
  const queryClient = useQueryClient()
  const textareaRef = React.useRef<HTMLTextAreaElement>(null)

  const MAX_CHARS = 1000

  const sendMessageMutation = useMutation({
    mutationFn: (data: { patient_id: string; content: string; type?: MessageType; scheduled_for?: string }) =>
      apiClient.messages.send(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['messages'] })
      toast({
        title: 'Mensagem enviada',
        description: 'A mensagem foi enviada com sucesso.',
      })
      setMessage('')
      setScheduledFor('')
      onMessageSent?.()
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao enviar mensagem',
        description: error.data?.message || 'Ocorreu um erro inesperado.',
        variant: 'destructive'
      })
    }
  })

  const handleSend = () => {
    if (!message.trim()) {
      toast({
        title: 'Mensagem vazia',
        description: 'Digite uma mensagem antes de enviar.',
        variant: 'destructive'
      })
      return
    }

    sendMessageMutation.mutate({
      patient_id: patientId,
      content: message.trim(),
      type: messageType,
      // Default to current time if no schedule is provided (backend requires this field)
      scheduled_for: scheduledFor && scheduledFor.trim() ? scheduledFor : new Date().toISOString()
    })
  }

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey && e.ctrlKey) {
      e.preventDefault()
      handleSend()
    }
  }

  const applyTemplate = (content: string) => {
    setMessage(content)
    setShowTemplates(false)
    textareaRef.current?.focus()
  }

  const messageTemplates = [
    {
      label: 'Lembrete de medica├º├úo',
      content: 'Ol├í! Este ├® um lembrete para tomar sua medica├º├úo conforme prescrito. Lembre-se de seguir as orienta├º├Áes m├®dicas.'
    },
    {
      label: 'Agendamento de consulta',
      content: 'Gostar├¡amos de agendar sua pr├│xima consulta. Por favor, entre em contato para marcarmos um hor├írio conveniente.'
    },
    {
      label: 'Question├írio dispon├¡vel',
      content: 'H├í um novo question├írio dispon├¡vel para voc├¬. Por favor, acesse o sistema para respond├¬-lo.'
    },
    {
      label: 'Resultados de exames',
      content: 'Seus resultados de exames est├úo prontos. Agende uma consulta para discutirmos os resultados.'
    }
  ]

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center justify-between">
          <CardTitle>Enviar Mensagem</CardTitle>
          <Badge variant="outline">{patientName}</Badge>
        </div>
      </CardHeader>
      <CardContent className="space-y-4">
        {/* Message Type */}
        <div className="flex items-center space-x-4">
          <label className="text-sm font-medium">Tipo:</label>
          <Select value={messageType} onValueChange={(value) => setMessageType(value as MessageType)}>
            <SelectTrigger className="w-[150px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value={MessageType.TEXT}>Texto</SelectItem>
              <SelectItem value={MessageType.TEMPLATE}>Lembrete</SelectItem>
              <SelectItem value={MessageType.INTERACTIVE}>Agendamento</SelectItem>
              <SelectItem value={MessageType.TEXT}>Educativo</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Quick Templates Toggle */}
        <div className="flex items-center justify-between">
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={() => setShowTemplates(!showTemplates)}
            className="text-blue-600"
          >
            {showTemplates ? 'Ocultar' : 'Mostrar'} Templates
          </Button>
        </div>

        {/* Quick Templates */}
        {showTemplates && (
          <div className="space-y-2 border-t pt-3">
            <label className="text-sm font-medium text-gray-700">Templates r├ípidos:</label>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
              {messageTemplates.map((template, index) => (
                <Button
                  key={index}
                  type="button"
                  variant="outline"
                  size="sm"
                  className="justify-start text-left h-auto p-3 hover:bg-blue-50 hover:border-blue-300 transition-colors"
                  onClick={() => applyTemplate(template.content)}
                >
                  <div className="w-full">
                    <p className="font-medium text-xs text-gray-900 mb-1">{template.label}</p>
                    <p className="text-xs text-gray-500 line-clamp-2">
                      {template.content}
                    </p>
                  </div>
                </Button>
              ))}
            </div>
          </div>
        )}

        {/* Message Input */}
        <div className="space-y-2">
          <label className="text-sm font-medium">Mensagem:</label>
          <Textarea
            ref={textareaRef}
            placeholder="Digite sua mensagem aqui... (Ctrl+Enter para enviar)"
            value={message}
            onChange={(e) => {
              if (e.target.value.length <= MAX_CHARS) {
                setMessage(e.target.value)
              }
            }}
            onKeyDown={handleKeyPress}
            rows={5}
            className="resize-none focus:ring-2 focus:ring-blue-500"
            maxLength={MAX_CHARS}
          />
          <div className="flex items-center justify-between">
            <span className={`text-xs ${
              message.length > MAX_CHARS * 0.9 ? 'text-orange-500 font-medium' : 'text-gray-500'
            }`}>
              {message.length}/{MAX_CHARS} caracteres
            </span>
            <span className="text-xs text-gray-400">
              Ctrl+Enter para enviar
            </span>
          </div>
        </div>

        {/* Scheduling */}
        <div className="space-y-2">
          <label className="text-sm font-medium flex items-center">
            <Calendar className="mr-2 h-4 w-4" />
            Agendar envio (opcional)
          </label>
          <Input
            type="datetime-local"
            value={scheduledFor}
            onChange={(e) => setScheduledFor(e.target.value)}
          />
        </div>

        {/* Actions */}
        <div className="flex items-center justify-between pt-2 border-t">
          <div className="flex items-center space-x-2">
            <Button variant="ghost" size="sm" disabled title="Em breve">
              <Paperclip className="h-4 w-4 text-gray-400" />
            </Button>
            <Button variant="ghost" size="sm" disabled title="Em breve">
              <Smile className="h-4 w-4 text-gray-400" />
            </Button>
          </div>

          <div className="flex items-center space-x-2">
            {message.trim() && (
              <Button
                type="button"
                variant="ghost"
                size="sm"
                onClick={() => {
                  setMessage('')
                  textareaRef.current?.focus()
                }}
                className="text-gray-500 hover:text-gray-700"
              >
                Limpar
              </Button>
            )}
            <Button
              onClick={handleSend}
              disabled={sendMessageMutation.isPending || !message.trim()}
              className="min-w-[120px]"
            >
              {sendMessageMutation.isPending ? (
                <>
                  <LoadingSpinner size="sm" className="mr-2" />
                  Enviando...
                </>
              ) : (
                <>
                  <Send className="mr-2 h-4 w-4" />
                  {scheduledFor ? 'Agendar' : 'Enviar'}
                </>
              )}
            </Button>
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

import React, { useEffect, useRef } from 'react'
import { formatDistanceToNow } from 'date-fns'
import { ptBR } from 'date-fns/locale'
import { useMutation, useQueryClient } from '@tanstack/react-query'
import { MessageSquare, Send, Inbox, RefreshCw, Check, CheckCheck, Clock } from 'lucide-react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { ScrollArea } from '@/components/ui/scroll-area'
import { LoadingSpinner } from '../ui/loading-spinner'
import { Button } from '../ui/button'
import { apiClient } from '../../lib/api-client'
import { useToast } from '../ui/use-toast'

interface Message {
  id: string
  patient_id: string
  content: string
  direction: 'inbound' | 'outbound'
  message_type: string
  status: string
  created_at: string
}

interface MessagesListProps {
  messages: Message[]
  isLoading: boolean
  patientName?: string
}

export function MessagesList({ messages, isLoading, patientName }: MessagesListProps) {
  const { toast } = useToast()
  const queryClient = useQueryClient()
  const scrollRef = useRef<HTMLDivElement>(null)
  const messagesEndRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (messages.length > 0 && messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' })
    }
  }, [messages])

  const retryMutation = useMutation({
    mutationFn: (messageId: string) => apiClient.messages.retry(messageId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['messages'] })
      toast({
        title: 'Mensagem reenviada',
        description: 'A mensagem foi colocada na fila para ser reenviada.',
      })
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao reenviar',
        description: error.data?.message || 'Ocorreu um erro inesperado.',
        variant: 'destructive'
      })
    }
  })

  const formatTime = (timestamp: string) => {
    try {
      return new Date(timestamp).toLocaleTimeString('pt-BR', {
        hour: '2-digit',
        minute: '2-digit'
      })
    } catch {
      return ''
    }
  }

  const formatDateSeparator = (timestamp: string) => {
    try {
      const date = new Date(timestamp)
      const today = new Date()
      const yesterday = new Date(today)
      yesterday.setDate(yesterday.getDate() - 1)

      if (date.toDateString() === today.toDateString()) {
        return 'Hoje'
      } else if (date.toDateString() === yesterday.toDateString()) {
        return 'Ontem'
      } else {
        return date.toLocaleDateString('pt-BR', {
          day: '2-digit',
          month: 'long',
          year: 'numeric'
        })
      }
    } catch {
      return ''
    }
  }

  const groupMessagesByDate = (messages: Message[]) => {
    const groups: { date: string; messages: Message[] }[] = []
    let currentDate = ''

    messages.forEach((message) => {
      const messageDate = new Date(message.created_at).toDateString()
      if (messageDate !== currentDate) {
        currentDate = messageDate
        groups.push({
          date: message.created_at,
          messages: [message]
        })
      } else {
        const lastGroup = groups[groups.length - 1]
        if (lastGroup) {
          lastGroup.messages.push(message)
        }
      }
    })

    return groups
  }

  const getMessageStatusIcon = (status: string) => {
    switch (status) {
      case 'sent':
        return <Check className="h-3 w-3" />
      case 'delivered':
        return <CheckCheck className="h-3 w-3" />
      case 'read':
        return <CheckCheck className="h-3 w-3 text-blue-400" />
      case 'failed':
        return <span className="text-red-400 text-xs">!</span>
      case 'pending':
        return <Clock className="h-3 w-3 animate-pulse" />
      default:
        return null
    }
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center space-x-2">
          <MessageSquare className="h-5 w-5" />
          <span>Mensagens</span>
          {patientName && (
            <span className="text-sm font-normal text-gray-500">
              - {patientName}
            </span>
          )}
        </CardTitle>
        <CardDescription>
          Hist├│rico de conversas com o paciente
        </CardDescription>
      </CardHeader>
      <CardContent>
        {isLoading ? (
          <div className="flex items-center justify-center py-8">
            <LoadingSpinner size="md" />
          </div>
        ) : messages.length === 0 ? (
          <div className="text-center py-8">
            <Inbox className="mx-auto h-12 w-12 text-gray-400 mb-4" />
            <p className="text-gray-500">Nenhuma mensagem encontrada</p>
            <p className="text-sm text-gray-400">
              As mensagens aparecer├úo aqui quando enviadas
            </p>
          </div>
        ) : (
          <ScrollArea className="h-[350px] md:h-[400px]" ref={scrollRef}>
            <div className="space-y-6 p-2">
              {groupMessagesByDate(messages).map((group, groupIndex) => (
                <div key={groupIndex}>
                  <div className="flex items-center justify-center mb-4">
                    <div className="bg-gray-200 text-gray-600 text-xs font-medium px-3 py-1 rounded-full">
                      {formatDateSeparator(group.date)}
                    </div>
                  </div>
                  <div className="space-y-3">
                    {group.messages.map((message) => (
                      <div
                        key={message.id}
                        className={`flex ${
                          message.direction === 'outbound' ? 'justify-end' : 'justify-start'
                        }`}
                      >
                        <div
                          className={`max-w-xs lg:max-w-md px-4 py-2.5 rounded-2xl shadow-sm ${
                            message.direction === 'outbound'
                              ? 'bg-blue-600 text-white rounded-br-sm'
                              : 'bg-gray-100 text-gray-900 rounded-bl-sm'
                          }`}
                        >
                          <p className="text-sm leading-relaxed break-words">{message.content}</p>
                          <div className="flex items-center justify-end mt-1.5 space-x-1">
                            <span className={`text-xs ${
                              message.direction === 'outbound' ? 'text-white/80' : 'text-gray-500'
                            }`}>
                              {formatTime(message.created_at)}
                            </span>
                            {message.direction === 'outbound' && (
                              <div className="flex items-center space-x-1">
                                {getMessageStatusIcon(message.status)}
                                {message.status === 'failed' && (
                                  <Button
                                    variant="ghost"
                                    size="sm"
                                    className="h-5 w-5 p-0 text-white hover:bg-blue-700 ml-1"
                                    onClick={() => retryMutation.mutate(message.id)}
                                    disabled={retryMutation.isPending}
                                    title="Reenviar mensagem"
                                  >
                                    <RefreshCw className="h-3 w-3" />
                                  </Button>
                                )}
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
              <div ref={messagesEndRef} />
            </div>
          </ScrollArea>
        )}
      </CardContent>
    </Card>
  )
}

´╗┐/**
 * Alerts Panel Component for Healthcare Metrics Dashboard
