import React, { useState } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Alert, AlertDescription } from '@/components/ui/alert';
import {
  AlertTriangle, Clock, CheckCircle, X, Filter,
  AlertCircle, Info, Zap, Heart
} from 'lucide-react';

interface AlertType {
  id: string;
  title: string;
  description: string;
  severity: 'low' | 'medium' | 'high' | 'critical';
  category: 'system' | 'healthcare' | 'security' | 'performance' | 'data_integrity' | 'ai_service';
  created_at: string;
  current_value?: number;
  threshold_value?: number;
  source: string;
  metadata: Record<string, any>;
}

interface AlertsPanelProps {
  alerts: AlertType[];
  onAcknowledge: (alertId: string) => Promise<void>;
  userRole: 'doctor' | 'admin';
}

export const AlertsPanel: React.FC<AlertsPanelProps> = ({
  alerts,
  onAcknowledge,
  userRole
}) => {
  const [selectedSeverity, setSelectedSeverity] = useState<string>('all');
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [acknowledging, setAcknowledging] = useState<Set<string>>(new Set());

  const getSeverityIcon = (severity: string) => {
    switch (severity) {
      case 'critical':
        return <AlertTriangle className="w-4 h-4 text-red-600" />;
      case 'high':
        return <AlertCircle className="w-4 h-4 text-orange-600" />;
      case 'medium':
        return <Info className="w-4 h-4 text-yellow-600" />;
      case 'low':
        return <Info className="w-4 h-4 text-blue-600" />;
      default:
        return <Info className="w-4 h-4 text-gray-600" />;
    }
  };

  const getSeverityBadge = (severity: string) => {
    const variants = {
      critical: 'bg-red-100 text-red-800 hover:bg-red-200',
      high: 'bg-orange-100 text-orange-800 hover:bg-orange-200',
      medium: 'bg-yellow-100 text-yellow-800 hover:bg-yellow-200',
      low: 'bg-blue-100 text-blue-800 hover:bg-blue-200'
    };

    return (
      <Badge className={variants[severity as keyof typeof variants] || variants.low}>
        {severity.toUpperCase()}
      </Badge>
    );
  };

  const getCategoryIcon = (category: string) => {
    switch (category) {
      case 'healthcare':
        return <Heart className="w-4 h-4" />;
      case 'ai_service':
        return <Zap className="w-4 h-4" />;
      case 'performance':
        return <Clock className="w-4 h-4" />;
      default:
        return <AlertTriangle className="w-4 h-4" />;
    }
  };

  const getCategoryLabel = (category: string) => {
    const labels = {
      system: 'Sistema',
      healthcare: 'Sa├║de',
      security: 'Seguran├ºa',
      performance: 'Performance',
      data_integrity: 'Dados',
      ai_service: 'IA'
    };
    return labels[category as keyof typeof labels] || category;
  };

  const formatTimeAgo = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffInSeconds = Math.floor((now.getTime() - date.getTime()) / 1000);

    if (diffInSeconds < 60) {
      return 'h├í poucos segundos';
    } else if (diffInSeconds < 3600) {
      const minutes = Math.floor(diffInSeconds / 60);
      return `h├í ${minutes} minuto${minutes > 1 ? 's' : ''}`;
    } else if (diffInSeconds < 86400) {
      const hours = Math.floor(diffInSeconds / 3600);
      return `h├í ${hours} hora${hours > 1 ? 's' : ''}`;
    } else {
      const days = Math.floor(diffInSeconds / 86400);
      return `h├í ${days} dia${days > 1 ? 's' : ''}`;
    }
  };

  const handleAcknowledge = async (alertId: string) => {
    setAcknowledging(prev => new Set(prev).add(alertId));
    try {
      await onAcknowledge(alertId);
    } finally {
      setAcknowledging(prev => {
        const next = new Set(prev);
        next.delete(alertId);
        return next;
