              <div>
                <div className="text-2xl font-bold text-blue-600">
                  {filteredAlerts.length}
                </div>
                <div className="text-sm text-muted-foreground">Total Ativo</div>
              </div>
              <AlertTriangle className="w-8 h-8 text-blue-600" />
