  if (error) {
    return (
      <Card>
        <CardContent className="pt-6">
          <div className="text-center text-red-500">
            <AlertCircle className="mx-auto h-8 w-8 mb-2" />
            <p>Erro ao carregar status do fluxo</p>
          </div>
        </CardContent>
      </Card>
    )
