  if (!flowState) {
    return (
      <Card>
        <CardContent className="pt-6">
          <div className="text-center text-muted-foreground">
            <MessageSquare className="mx-auto h-8 w-8 mb-2" />
            <p>Nenhum fluxo ativo</p>
            <div className="mt-4 space-y-2">
              <Button 
                className="w-full" 
                size="sm"
                onClick={() => operations.start(FlowType.INITIAL_15_DAYS)}
                disabled={isOperationLoading}
              >
                {isOperationLoading ? (
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                ) : null}
                Iniciar Fluxo 15 Dias
              </Button>
              <Button 
                variant="outline" 
                className="w-full" 
                size="sm"
                onClick={() => operations.start(FlowType.MONTHLY_RECURRING)}
                disabled={isOperationLoading}
              >
                Iniciar Fluxo Mensal
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>
    )
  }

  const getStatusColor = (status: FlowStatusEnum) => {
    switch (status) {
      case FlowStatusEnum.ACTIVE: return 'bg-green-500'
      case FlowStatusEnum.PAUSED: return 'bg-yellow-500'
      case FlowStatusEnum.COMPLETED: return 'bg-blue-500'
      case FlowStatusEnum.CANCELLED: return 'bg-red-500'
      default: return 'bg-gray-500'
    }
  }

  const getStatusIcon = (status: FlowStatusEnum) => {
    switch (status) {
      case FlowStatusEnum.ACTIVE: return <Play className="h-4 w-4" />
      case FlowStatusEnum.PAUSED: return <Pause className="h-4 w-4" />
      case FlowStatusEnum.COMPLETED: return <CheckCircle className="h-4 w-4" />
      case FlowStatusEnum.CANCELLED: return <AlertCircle className="h-4 w-4" />
      default: return <Clock className="h-4 w-4" />
    }
  }

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('pt-BR')
  }

  const formatDateTime = (dateString: string) => {
    return new Date(dateString).toLocaleString('pt-BR')
  }

  const getFlowTypeLabel = (flowType: FlowType) => {
    switch (flowType) {
      case FlowType.INITIAL_15_DAYS: return 'Primeiros 15 Dias'
      case FlowType.DAYS_16_45: return 'Dias 16-45'
      case FlowType.MONTHLY_RECURRING: return 'Mensal Recorrente'
      default: return flowType
    }
  }

  // Calculate progress based on flow type
  const getTotalDays = (flowType: FlowType) => {
    switch (flowType) {
      case FlowType.INITIAL_15_DAYS: return 15
      case FlowType.DAYS_16_45: return 30
      case FlowType.MONTHLY_RECURRING: return 30
      default: return 30
    }
  }

  const totalDays = getTotalDays(flowState.flow_type)
  const completionRate = (flowState.current_day / totalDays) * 100

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center justify-between">
          <div>
            <CardTitle className="text-lg">Status do Fluxo</CardTitle>
            <CardDescription>
              {getFlowTypeLabel(flowState.flow_type)}
            </CardDescription>
          </div>
          <Badge 
            variant="secondary" 
            className={`${getStatusColor(flowState.status)} text-white`}
          >
            <span className="flex items-center gap-1">
              {getStatusIcon(flowState.status)}
              {flowState.status.toUpperCase()}
            </span>
          </Badge>
        </div>
      </CardHeader>
      
      <CardContent className="space-y-4">
        {/* Progress */}
        <div className="space-y-2">
          <div className="flex justify-between text-sm">
            <span>Progresso</span>
            <span>{flowState.current_day}/{totalDays} dias</span>
          </div>
          <Progress value={completionRate} className="h-2" />
        </div>

        {/* Timeline Info */}
        <div className="grid grid-cols-2 gap-4 text-sm">
          <div className="space-y-1">
            <div className="flex items-center gap-2 text-muted-foreground">
              <Calendar className="h-4 w-4" />
              <span>In├¡cio</span>
            </div>
            <p className="font-medium">{formatDate(flowState.enrollment_date)}</p>
          </div>
          
          {flowState.last_message_sent && (
            <div className="space-y-1">
              <div className="flex items-center gap-2 text-muted-foreground">
                <MessageSquare className="h-4 w-4" />
                <span>├Ültima mensagem</span>
              </div>
              <p className="font-medium">{formatDateTime(flowState.last_message_sent)}</p>
            </div>
          )}
        </div>

        {/* State Data */}
        {Object.keys(flowState.state_data).length > 0 && (
          <div className="p-3 bg-muted rounded-lg">
            <div className="text-sm text-muted-foreground mb-2">Dados do Estado</div>
            <div className="space-y-1 text-sm">
              {Object.entries(flowState.state_data).map(([key, value]) => (
                <div key={key} className="flex justify-between">
                  <span className="capitalize">{key.replace('_', ' ')}:</span>
                  <span className="font-medium">{String(value)}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Actions */}
        <div className="flex gap-2 pt-2">
          {flowState.status === FlowStatusEnum.ACTIVE && (
            <>
              <Button 
                variant="outline" 
                size="sm" 
                onClick={operations.pause}
                disabled={isOperationLoading}
                className="flex items-center gap-2"
              >
                {isOperationLoading ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <Pause className="h-4 w-4" />
                )}
                Pausar
              </Button>
              <Button 
                variant="outline" 
                size="sm" 
                onClick={() => operations.advance()}
                disabled={isOperationLoading}
                className="flex items-center gap-2"
              >
                <SkipForward className="h-4 w-4" />
                Avan├ºar
              </Button>
            </>
          )}
          
          {flowState.status === FlowStatusEnum.PAUSED && (
            <Button 
              variant="default" 
              size="sm" 
              onClick={operations.resume}
              disabled={isOperationLoading}
              className="flex items-center gap-2"
            >
              {isOperationLoading ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <Play className="h-4 w-4" />
              )}
              Retomar
            </Button>
          )}
        </div>
      </CardContent>
    </Card>
  )
}

import React from 'react'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from '@/components/ui/tooltip'
import { Send, Clock, Eye, CheckCircle, XCircle, RefreshCw } from 'lucide-react'
import { formatDistanceToNow } from 'date-fns'
import { ptBR } from 'date-fns/locale'
import { mapBackendStatus, getStatusLabel } from '@/utils/monthlyQuizStatusMapper'

export type QuizLinkStatus = 'not_sent' | 'sent' | 'accessed' | 'completed' | 'expired'

export interface MonthlyQuizStatusProps {
  status: QuizLinkStatus | string // Allow backend status values
  lastSent?: Date | string
  accessDate?: Date | string
  completionDate?: Date | string
  expiresAt?: Date | string
  onResend?: () => void
  isResending?: boolean
}

export function MonthlyQuizStatus({
  status,
  lastSent,
  accessDate,
  completionDate,
  expiresAt,
  onResend,
  isResending = false
}: MonthlyQuizStatusProps) {
  // Map backend status to UI status
  const mappedStatus = mapBackendStatus(status)

  const getStatusConfig = () => {
    switch (mappedStatus) {
      case 'not_sent':
        return {
          icon: Send,
          label: 'N├úo Enviado',
          className: 'bg-gray-100 text-gray-700 border-gray-200',
          iconClassName: 'text-gray-600'
        }
      case 'sent':
        return {
          icon: Clock,
          label: 'Pendente',
          className: 'bg-yellow-100 text-yellow-700 border-yellow-200',
          iconClassName: 'text-yellow-600'
        }
      case 'accessed':
        return {
          icon: Eye,
          label: 'Acessado',
          className: 'bg-blue-100 text-blue-700 border-blue-200',
          iconClassName: 'text-blue-600'
        }
      case 'completed':
        return {
          icon: CheckCircle,
          label: 'Completado',
          className: 'bg-green-100 text-green-700 border-green-200',
          iconClassName: 'text-green-600'
        }
      case 'expired':
        return {
          icon: XCircle,
          label: 'Expirado',
          className: 'bg-red-100 text-red-700 border-red-200',
          iconClassName: 'text-red-600'
        }
      default:
        return {
          icon: Clock,
          label: getStatusLabel(status),
          className: 'bg-gray-100 text-gray-700 border-gray-200',
          iconClassName: 'text-gray-600'
        }
    }
  }

  const config = getStatusConfig()
  const Icon = config.icon

  const formatDate = (date?: Date | string) => {
    if (!date) return 'N├úo dispon├¡vel'

    try {
      const dateObj = typeof date === 'string' ? new Date(date) : date
      return formatDistanceToNow(dateObj, {
        addSuffix: true,
        locale: ptBR
      })
    } catch {
      return 'Data inv├ílida'
    }
  }

  const formatExpirationTime = () => {
    if (!expiresAt) return null

    try {
      const now = new Date()
      const expires = typeof expiresAt === 'string' ? new Date(expiresAt) : expiresAt

      if (expires <= now) {
        return 'Expirado'
      }

      return `Expira ${formatDistanceToNow(expires, {
        addSuffix: true,
        locale: ptBR
      })}`
    } catch {
      return 'Data inv├ílida'
    }
  }

  const canResend = mappedStatus === 'expired' || mappedStatus === 'sent'

  const tooltipContent = (
    <div className="space-y-1.5 text-xs">
      <div>
        <span className="font-semibold">Status:</span> {config.label}
      </div>
      {lastSent && (
        <div>
          <span className="font-semibold">Enviado:</span> {formatDate(lastSent)}
        </div>
      )}
      {accessDate && (
        <div>
          <span className="font-semibold">Acessado:</span> {formatDate(accessDate)}
        </div>
      )}
      {completionDate && (
        <div>
          <span className="font-semibold">Completado:</span> {formatDate(completionDate)}
        </div>
      )}
      {expiresAt && mappedStatus !== 'completed' && (
        <div>
          <span className="font-semibold">Validade:</span> {formatExpirationTime()}
        </div>
      )}
      {canResend && onResend && (
        <div className="pt-1 border-t border-gray-200">
          <span className="text-gray-500">Clique para reenviar</span>
        </div>
      )}
    </div>
  )

  return (
    <TooltipProvider>
      <Tooltip>
        <TooltipTrigger asChild>
          <div className="flex items-center gap-2">
            <Badge className={`${config.className} border cursor-help`}>
              <Icon className={`h-3 w-3 mr-1 ${config.iconClassName}`} />
              {config.label}
            </Badge>
            {canResend && onResend && (
              <Button
                variant="ghost"
                size="sm"
                onClick={(e) => {
                  e.stopPropagation()
                  onResend()
                }}
                disabled={isResending}
                className="h-7 px-2"
              >
                <RefreshCw className={`h-3 w-3 ${isResending ? 'animate-spin' : ''}`} />
              </Button>
            )}
          </div>
        </TooltipTrigger>
        <TooltipContent>
          {tooltipContent}
        </TooltipContent>
      </Tooltip>
    </TooltipProvider>
  )
}

import React from 'react'
import { useQuery } from '@tanstack/react-query'
import { Users, Activity, Clock, CheckCircle } from 'lucide-react'
import { apiClient } from '../../lib/api-client'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { LoadingSpinner } from '../ui/loading-spinner'
import type { Patient } from '@/lib/api-client'

export function PatientStats() {
  const { data: patientsData, isLoading } = useQuery({
    queryKey: ['patients', { size: 100 }],
    queryFn: () => apiClient.patients.list({ size: 100 })
  })

  if (isLoading) {
    return (
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[...Array(4)].map((_, i) => (
          <Card key={i}>
            <CardContent className="pt-6">
              <div className="flex items-center justify-center">
                <LoadingSpinner size="md" />
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    )
  }

  const patients = ((patientsData as any)?.items || (patientsData as any)?.data || []) as Patient[]
  const totalPatients = patients.length
  const activePatients = patients.filter((p: Patient) => p.status === 'active').length
  const pausedPatients = patients.filter((p: Patient) => p.status === 'paused').length
  const completedPatients = patients.filter((p: Patient) => p.status === 'completed').length

  const stats = [
    {
      title: 'Total de Pacientes',
      value: totalPatients,
      icon: Users,
      description: 'Pacientes cadastrados'
    },
    {
      title: 'Pacientes Ativos',
      value: activePatients,
      icon: Activity,
      description: 'Em tratamento ativo'
    },
    {
      title: 'Pacientes Pausados',
      value: pausedPatients,
      icon: Clock,
      description: 'Tratamento pausado'
    },
    {
      title: 'Tratamentos Conclu├¡dos',
      value: completedPatients,
      icon: CheckCircle,
      description: 'Finalizados com sucesso'
    }
  ]

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
      {stats.map((stat) => {
        const Icon = stat.icon
        return (
          <Card key={stat.title}>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">
                {stat.title}
              </CardTitle>
              <Icon className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stat.value}</div>
              <p className="text-xs text-muted-foreground">
                {stat.description}
              </p>
            </CardContent>
          </Card>
        )
      })}
    </div>
  )
}

import React from 'react'
import { formatDistanceToNow } from 'date-fns'
import { ptBR } from 'date-fns/locale'
import {
  MessageSquare,
  AlertTriangle,
  Activity,
  FileText,
  Clock
} from 'lucide-react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { ScrollArea } from '@/components/ui/scroll-area'
import { LoadingSpinner } from '../ui/loading-spinner'
import type { TimelineEvent } from '@/types/api-responses'

interface PatientTimelineProps {
  timeline?: { events: TimelineEvent[] } | undefined
  isLoading: boolean
}

export function PatientTimeline({ timeline, isLoading }: PatientTimelineProps) {
  const getEventIcon = (type: string) => {
    switch (type) {
      case 'message':
        return MessageSquare
      case 'quiz':
        return FileText
      case 'alert':
        return AlertTriangle
      case 'flow_change':
        return Activity
      case 'report':
        return FileText
      default:
        return Clock
    }
  }

  const getEventColor = (type: string) => {
    switch (type) {
      case 'message':
        return 'text-blue-600 bg-blue-100'
      case 'quiz':
        return 'text-purple-600 bg-purple-100'
      case 'alert':
        return 'text-red-600 bg-red-100'
      case 'flow_change':
        return 'text-green-600 bg-green-100'
      case 'report':
        return 'text-orange-600 bg-orange-100'
      default:
        return 'text-gray-600 bg-gray-100'
    }
  }

  const getEventLabel = (type: string) => {
    switch (type) {
      case 'message':
        return 'Mensagem'
      case 'quiz':
        return 'Question├írio'
      case 'alert':
        return 'Alerta'
      case 'flow_change':
        return 'Fluxo'
      case 'report':
        return 'Relat├│rio'
      default:
        return 'Evento'
    }
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Timeline do Paciente</CardTitle>
        <CardDescription>
          Hist├│rico de atividades e eventos
        </CardDescription>
      </CardHeader>
      <CardContent>
        {isLoading ? (
          <div className="flex items-center justify-center py-8">
            <LoadingSpinner size="md" />
          </div>
        ) : !timeline?.events || timeline.events.length === 0 ? (
          <div className="text-center py-8">
            <Clock className="mx-auto h-12 w-12 text-gray-400 mb-4" />
            <p className="text-gray-500">Nenhum evento registrado</p>
            <p className="text-sm text-gray-400">
              Os eventos aparecer├úo aqui conforme o paciente interage com o sistema
            </p>
          </div>
        ) : (
          <ScrollArea className="h-[500px]">
            <div className="space-y-4">
              {timeline.events.map((event, index) => {
                const Icon = getEventIcon(event.event_type)
                const colorClass = getEventColor(event.event_type)
                const isLast = index === timeline.events.length - 1

                return (
                  <div key={event.id} className="relative">
                    {/* Timeline line */}
                    {!isLast && (
                      <div className="absolute left-4 top-8 w-0.5 h-full bg-gray-200" />
                    )}

                    <div className="flex items-start space-x-3">
                      <div className={`flex items-center justify-center w-8 h-8 rounded-full ${colorClass} relative z-10`}>
                        <Icon className="w-4 h-4" />
                      </div>

                      <div className="flex-1 min-w-0 pb-4">
                        <div className="flex items-center justify-between mb-1">
                          <h4 className="text-sm font-medium text-gray-900">
                            {event.title}
                          </h4>
                          <div className="flex items-center space-x-2">
                            <Badge variant="outline" className="text-xs">
                              {getEventLabel(event.event_type)}
                            </Badge>
                            <span className="text-xs text-gray-500">
                              {formatDistanceToNow(new Date(event.created_at), {
                                addSuffix: true,
                                locale: ptBR
                              })}
                            </span>
                          </div>
                        </div>
                        
                        <p className="text-sm text-gray-600">
                          {event.description}
                        </p>
                        
                        {event.metadata && Object.keys(event.metadata).length > 0 && (
                          <div className="mt-2 text-xs text-gray-500">
                            {Object.entries(event.metadata).map(([key, value]) => (
                              <div key={key}>
                                <strong>{key}:</strong> {String(value)}
                              </div>
                            ))}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                )
              })}
            </div>
          </ScrollArea>
        )}
      </CardContent>
    </Card>
  )
}

import React, { useState, useEffect } from 'react'
import { Search, X, Calendar, Filter } from 'lucide-react'
import { format } from 'date-fns'
import { ptBR } from 'date-fns/locale'
import { DateRange } from 'react-day-picker'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Calendar as CalendarComponent } from '@/components/ui/calendar'
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { cn } from '@/lib/utils'
import type { PatientFilters } from '@/hooks/usePatients'

interface PatientsFiltersProps {
  filters: PatientFilters
  onFiltersChange: (filters: PatientFilters) => void
  treatmentTypes?: string[]
  isLoadingTreatmentTypes?: boolean
  disabled?: boolean
}

export function PatientsFilters({
  filters,
  onFiltersChange,
  treatmentTypes = [],
  isLoadingTreatmentTypes = false,
  disabled = false
}: PatientsFiltersProps) {
  const [dateRange, setDateRange] = useState<DateRange | undefined>(undefined)

  // Initialize date range from filters
  useEffect(() => {
    if (filters.start_date_from || filters.start_date_to) {
      const newDateRange: DateRange = {
        from: filters.start_date_from ? new Date(filters.start_date_from) : undefined,
        to: filters.start_date_to ? new Date(filters.start_date_to) : undefined
      }
      setDateRange(newDateRange)
    } else {
      setDateRange(undefined)
    }
  }, [filters.start_date_from, filters.start_date_to])

  // Calculate active filters
  const hasActiveFilters = Boolean(
    filters.search ||
    filters.status ||
    filters.treatment_type ||
    filters.start_date_from ||
    filters.start_date_to
  )

  const activeFilterCount = [
    filters.search,
    filters.status,
    filters.treatment_type,
    filters.start_date_from || filters.start_date_to
  ].filter(Boolean).length

  const updateFilter = (key: keyof PatientFilters, value: any) => {
    onFiltersChange({
      ...filters,
      [key]: value,
      // Reset page when filters change
      page: key === 'page' ? value : 1
    })
  }

  const resetFilters = () => {
    setDateRange(undefined)
    const resetFiltersObj: PatientFilters = {
      search: '',
      treatment_type: '',
      start_date_from: '',
      start_date_to: '',
      page: 1,
      ...(filters.size !== undefined && { size: filters.size })
    }
    onFiltersChange(resetFiltersObj)
  }

  const handleSearchChange = (value: string) => {
    updateFilter('search', value)
  }

  const handleStatusChange = (value: string) => {
    updateFilter('status', value === 'all' ? undefined : value as any)
  }

  const handleTreatmentTypeChange = (value: string) => {
    updateFilter('treatment_type', value === 'all' ? '' : value)
  }

  const handleDateRangeChange = (range: DateRange | undefined) => {
    setDateRange(range)
    updateFilter('start_date_from', range?.from ? format(range.from, 'yyyy-MM-dd') : '')
    updateFilter('start_date_to', range?.to ? format(range.to, 'yyyy-MM-dd') : '')
  }

  const clearDateRange = () => {
    setDateRange(undefined)
    onFiltersChange({
      ...filters,
      start_date_from: '',
      start_date_to: '',
      page: 1
    })
  }

  const getStatusLabel = (status: string) => {
    const statusLabels = {
      active: 'Ativo',
      paused: 'Pausado',
      completed: 'Conclu├¡do',
      inactive: 'Inativo'
    }
    return statusLabels[status as keyof typeof statusLabels] || status
  }

  return (
    <div className="space-y-4">
      {/* Header with title and clear button */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Filter className="h-4 w-4 text-gray-600" />
          <h3 className="text-sm font-medium text-gray-900">Filtros</h3>
          {activeFilterCount > 0 && (
            <span className="inline-flex items-center justify-center w-5 h-5 text-xs font-bold text-white bg-blue-600 rounded-full">
              {activeFilterCount}
            </span>
          )}
        </div>
        {hasActiveFilters && (
          <Button
            variant="ghost"
            size="sm"
            onClick={resetFilters}
            disabled={disabled}
            className="text-gray-500 hover:text-gray-700"
          >
            <X className="mr-1 h-3 w-3" />
            Limpar filtros
          </Button>
        )}
      </div>

      {/* Search input */}
      <div className="space-y-2">
        <Label htmlFor="search-input">Buscar pacientes</Label>
        <div className="relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
          <Input
            id="search-input"
            type="text"
            placeholder="Nome, email ou telefone..."
            value={filters.search || ''}
            onChange={(e) => handleSearchChange(e.target.value)}
            disabled={disabled}
            className="pl-10"
          />
        </div>
      </div>

      {/* Filter controls */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {/* Status filter */}
        <div className="space-y-2">
          <Label htmlFor="status-filter">Status</Label>
          <Select
            value={filters.status || 'all'}
            onValueChange={handleStatusChange}
            disabled={disabled}
          >
            <SelectTrigger>
              <SelectValue placeholder="Todos os status" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos os status</SelectItem>
              <SelectItem value="active">Ativo</SelectItem>
              <SelectItem value="paused">Pausado</SelectItem>
              <SelectItem value="completed">Conclu├¡do</SelectItem>
              <SelectItem value="inactive">Inativo</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Treatment type filter */}
        <div className="space-y-2">
          <Label htmlFor="treatment-filter">Tipo de Tratamento</Label>
          <Select
            value={filters.treatment_type || 'all'}
            onValueChange={handleTreatmentTypeChange}
            disabled={disabled || isLoadingTreatmentTypes}
          >
            <SelectTrigger>
              <SelectValue placeholder="Todos os tratamentos" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos os tratamentos</SelectItem>
              {treatmentTypes?.map((type) => (
                <SelectItem key={type} value={type}>
                  {type}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        {/* Start date range filter */}
        <div className="space-y-2">
          <Label>Data de In├¡cio do Tratamento</Label>
          <Popover>
            <PopoverTrigger asChild>
              <Button
                variant="outline"
                disabled={disabled}
                className={cn(
                  "w-full justify-start text-left font-normal",
                  !dateRange?.from && "text-muted-foreground"
                )}
              >
                <Calendar className="mr-2 h-4 w-4" />
                {dateRange?.from ? (
                  dateRange?.to ? (
                    <>
                      {format(dateRange.from, "dd/MM/yyyy", { locale: ptBR })} -{" "}
                      {format(dateRange.to, "dd/MM/yyyy", { locale: ptBR })}
                    </>
                  ) : (
                    format(dateRange.from, "dd/MM/yyyy", { locale: ptBR })
                  )
                ) : (
                  "Selecionar per├¡odo"
                )}
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-auto p-0" align="start">
              <CalendarComponent
                initialFocus
                mode="range"
                {...(dateRange?.from && { defaultMonth: dateRange.from })}
                selected={dateRange}
                onSelect={handleDateRangeChange}
                numberOfMonths={2}
                locale={ptBR}
              />
              {(dateRange?.from || dateRange?.to) && (
                <div className="p-3 border-t">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={clearDateRange}
                    disabled={disabled}
                    className="w-full"
                  >
                    Limpar per├¡odo
                  </Button>
                </div>
              )}
            </PopoverContent>
          </Popover>
        </div>

      </div>

      {/* Active filters display */}
      {hasActiveFilters && (
        <div className="flex flex-wrap items-center gap-2 pt-2 border-t">
          <span className="text-sm text-gray-600">Filtros ativos:</span>

          {filters.search && (
            <div className="inline-flex items-center gap-1 px-2 py-1 bg-blue-100 text-blue-800 rounded-md text-sm">
              <Search className="h-3 w-3" />
              <span>"{filters.search}"</span>
              <button
                onClick={() => updateFilter('search', '')}
                disabled={disabled}
                className="ml-1 hover:bg-blue-200 rounded disabled:opacity-50"
              >
                <X className="h-3 w-3" />
              </button>
            </div>
          )}

          {filters.status && (
            <div className="inline-flex items-center gap-1 px-2 py-1 bg-green-100 text-green-800 rounded-md text-sm">
              <span>Status: {getStatusLabel(filters.status)}</span>
              <button
                onClick={() => updateFilter('status', '')}
                disabled={disabled}
                className="ml-1 hover:bg-green-200 rounded disabled:opacity-50"
              >
                <X className="h-3 w-3" />
              </button>
            </div>
          )}

          {filters.treatment_type && (
            <div className="inline-flex items-center gap-1 px-2 py-1 bg-purple-100 text-purple-800 rounded-md text-sm">
              <span>Tratamento: {filters.treatment_type}</span>
              <button
                onClick={() => updateFilter('treatment_type', '')}
                disabled={disabled}
                className="ml-1 hover:bg-purple-200 rounded disabled:opacity-50"
              >
                <X className="h-3 w-3" />
              </button>
            </div>
          )}

          {(dateRange?.from || dateRange?.to) && (
            <div className="inline-flex items-center gap-1 px-2 py-1 bg-orange-100 text-orange-800 rounded-md text-sm">
              <Calendar className="h-3 w-3" />
              <span>
                {dateRange?.from && dateRange?.to ? (
                  `${format(dateRange.from, "dd/MM/yy")} - ${format(dateRange.to, "dd/MM/yy")}`
                ) : dateRange?.from ? (
                  `A partir de ${format(dateRange.from, "dd/MM/yy")}`
                ) : dateRange?.to ? (
                  `At├® ${format(dateRange.to, "dd/MM/yy")}`
                ) : (
                  'Data'
                )}
              </span>
              <button
                onClick={clearDateRange}
                disabled={disabled}
                className="ml-1 hover:bg-orange-200 rounded disabled:opacity-50"
              >
                <X className="h-3 w-3" />
              </button>
            </div>
          )}
        </div>
      )}

    </div>
  )
}

import React, { useState } from 'react'
import { formatDistanceToNow } from 'date-fns'
import { ptBR } from 'date-fns/locale'
import { useNavigate } from 'react-router-dom'
import { useMutation, useQueryClient } from '@tanstack/react-query'
import { MoveHorizontal as MoreHorizontal, Eye, CreditCard as Edit, Trash2, Play, Pause, Send } from 'lucide-react'
import { apiClient } from '../../lib/api-client'
import { MonthlyQuizStatus } from '@/components/patients/MonthlyQuizStatus'
import { SendQuizLinkModal } from '@/components/quiz/SendQuizLinkModal'
import { useMonthlyQuizStatus, useResendQuizLink } from '@/hooks/useMonthlyQuizStatus'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import { Pagination } from '../ui/pagination'
import { useToast } from '@/components/ui/use-toast'

interface Patient {
  id: string
  name: string
  phone: string
  email?: string
  treatment_type: string
  status: 'active' | 'inactive' | 'completed' | 'paused' | 'cancelled'
  current_day?: number
  last_contact?: string
  created_at: string
}

interface PatientsTableProps {
  patients: Patient[]
  currentPage: number
  totalPages: number
  onPageChange: (page: number) => void
  onEditPatient?: (patient: Patient) => void
}

export function PatientsTable({
  patients,
  currentPage,
  totalPages,
  onPageChange,
  onEditPatient
}: PatientsTableProps) {
  const navigate = useNavigate()
  const { toast } = useToast()
  const queryClient = useQueryClient()
  const [selectedPatient, setSelectedPatient] = useState<{ id: string; name: string } | null>(null)
  const [showSendQuizModal, setShowSendQuizModal] = useState(false)
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null)
  const resendQuizLinkMutation = useResendQuizLink()

  const mutationOptions = {
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['patients'] })
    },
    onError: (error: any) => {
      toast({
        title: 'Erro',
        description: error.data?.message || 'Ocorreu um erro inesperado.',
        variant: 'destructive'
      })
    }
  }

  const deleteMutation = useMutation({
    mutationFn: (id: string) => apiClient.patients.deletePatient(id),
    ...mutationOptions,
    onSuccess: () => {
      mutationOptions.onSuccess()
      toast({ title: 'Paciente exclu├¡do com sucesso' })
    }
  })

  const activateMutation = useMutation({
    mutationFn: (id: string) => apiClient.patients.activate(id),
    ...mutationOptions,
    onSuccess: () => {
      mutationOptions.onSuccess()
      toast({ title: 'Paciente ativado com sucesso' })
    }
  })

  const deactivateMutation = useMutation({
    mutationFn: (id: string) => apiClient.patients.deactivate(id),
    ...mutationOptions,
    onSuccess: () => {
      mutationOptions.onSuccess()
      toast({ title: 'Paciente desativado (pausado) com sucesso' })
    }
  })

  const handleDelete = (e: React.MouseEvent, patientId: string, patientName: string) => {
    e.stopPropagation()
    if (confirmDeleteId === patientId) {
      setConfirmDeleteId(null)
      deleteMutation.mutate(patientId)
      return
    }
    setConfirmDeleteId(patientId)
    toast({
      title: 'Confirme a exclus├úo',
      description: `Clique novamente para excluir ${patientName}.`,
      variant: 'destructive'
    })
    setTimeout(() => {
      setConfirmDeleteId((prev) => (prev === patientId ? null : prev))
    }, 3000)
  }

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'active':
        return <Badge className="bg-green-100 text-green-800">Ativo</Badge>
      case 'paused':
        return <Badge className="bg-yellow-100 text-yellow-800">Pausado</Badge>
      case 'completed':
        return <Badge className="bg-blue-100 text-blue-800">Conclu├¡do</Badge>
      case 'inactive':
        return <Badge variant="secondary">Inativo</Badge>
      case 'cancelled':
        return <Badge className="bg-red-100 text-red-800">Cancelado</Badge>
      default:
        return <Badge variant="outline">{status}</Badge>
    }
  }

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map(n => n[0])
      .join('')
      .toUpperCase()
      .slice(0, 2)
  }

  const formatLastContact = (lastContact?: string) => {
    if (!lastContact) return 'Nunca'
    
    try {
      return formatDistanceToNow(new Date(lastContact), {
        addSuffix: true,
        locale: ptBR
      })
    } catch {
      return 'Data inv├ílida'
    }
  }

  if (patients.length === 0) {
    return (
      <div className="text-center py-8">
        <p className="text-gray-500">Nenhum paciente encontrado</p>
        <p className="text-sm text-gray-400 mt-1">
          Tente ajustar os filtros ou criar um novo paciente
        </p>
      </div>
    )
  }

  return (
    <div className="space-y-4">
      <div className="overflow-x-auto -mx-4 md:mx-0">
        <div className="inline-block min-w-full align-middle">
          <div className="overflow-hidden border md:rounded-lg">
            <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Paciente</TableHead>
            <TableHead>Contato</TableHead>
            <TableHead>Tratamento</TableHead>
            <TableHead>Status</TableHead>
            <TableHead>Quiz Mensal</TableHead>
            <TableHead>Dia Atual</TableHead>
            <TableHead>├Ültimo Contato</TableHead>
            <TableHead className="w-[70px]">A├º├Áes</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {patients.map((patient) => {
            // Hook call inside the component body - conditionally rendered
            const PatientQuizStatus = () => {
              const { data: quizStatus, isLoading } = useMonthlyQuizStatus(patient.id)

              if (isLoading) {
                return <Badge variant="outline" className="animate-pulse">Carregando...</Badge>
              }

              if (!quizStatus || quizStatus.status === 'not_sent') {
                return <Button variant="ghost" size="sm" onClick={(e) => {
                  e.stopPropagation()
                  setSelectedPatient({ id: patient.id, name: patient.name })
                  setShowSendQuizModal(true)
                }}>
                  <Send className="h-4 w-4 mr-1" />
                  Enviar
                </Button>
              }

              return (
                <MonthlyQuizStatus
                  status={quizStatus.status}
                  {...(quizStatus.last_sent && { lastSent: quizStatus.last_sent })}
                  {...(quizStatus.access_date && { accessDate: quizStatus.access_date })}
                  {...(quizStatus.completion_date && { completionDate: quizStatus.completion_date })}
                  {...(quizStatus.expires_at && { expiresAt: quizStatus.expires_at })}
                  {...(quizStatus.session_id && { onResend: () => resendQuizLinkMutation.mutate(quizStatus.session_id!) })}
                  isResending={resendQuizLinkMutation.isPending}
                />
              )
            }

            return (
              <TableRow
                key={patient.id}
                className="cursor-pointer hover:bg-muted/50"
                onClick={() => navigate(`/patients/${patient.id}`)}
              >
                <TableCell>
                  <div className="flex items-center space-x-3">
                    <Avatar className="h-8 w-8">
                      <AvatarImage src="" alt={patient.name} />
                      <AvatarFallback className="bg-blue-600 text-white text-xs">
                        {getInitials(patient.name)}
                      </AvatarFallback>
                    </Avatar>
                    <div>
                      <p className="font-medium text-gray-900">{patient.name}</p>
                      {patient.email && (
                        <p className="text-sm text-gray-500">{patient.email}</p>
                      )}
                    </div>
                  </div>
                </TableCell>
                <TableCell>
                  <p className="text-sm">{patient.phone}</p>
                </TableCell>
                <TableCell>
                  <Badge variant="outline">{patient.treatment_type}</Badge>
                </TableCell>
                <TableCell>
                  {getStatusBadge(patient.status)}
                </TableCell>
                <TableCell onClick={(e) => e.stopPropagation()}>
                  <PatientQuizStatus />
                </TableCell>
                <TableCell>
                  <span className="font-medium">{patient.current_day ?? 0}</span>
                </TableCell>
                <TableCell>
                  <span className="text-sm text-gray-600">
                    {formatLastContact(patient.last_contact)}
                  </span>
                </TableCell>
              <TableCell>
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button 
                      variant="ghost" 
                      className="h-8 w-8 p-0"
                      onClick={(e) => e.stopPropagation()}
                    >
                      <MoreHorizontal className="h-4 w-4" />
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="end">
                    <DropdownMenuLabel>A├º├Áes</DropdownMenuLabel>
                    <DropdownMenuItem 
                      onClick={(e) => {
                        e.stopPropagation()
                        navigate(`/patients/${patient.id}`)
                      }}
                    >
                      <Eye className="mr-2 h-4 w-4" />
                      Visualizar
                    </DropdownMenuItem>
                    <DropdownMenuItem 
                      onClick={(e) => {
                        e.stopPropagation()
                        onEditPatient?.(patient)
                      }}
                    >
                      <Edit className="mr-2 h-4 w-4" />
                      Editar
                    </DropdownMenuItem>
                    <DropdownMenuSeparator />
                    {patient.status === 'active' ? (
                      <DropdownMenuItem 
                        onClick={(e) => {
                          e.stopPropagation()
                          deactivateMutation.mutate(patient.id)
                        }}
                      >
                        <Pause className="mr-2 h-4 w-4" />
                        Pausar
                      </DropdownMenuItem>
                    ) : (
                      <DropdownMenuItem 
                        onClick={(e) => {
                          e.stopPropagation()
                          activateMutation.mutate(patient.id)
                        }}
                      >
                        <Play className="mr-2 h-4 w-4" />
                        Ativar
                      </DropdownMenuItem>
                    )}
                    <DropdownMenuSeparator />
                    <DropdownMenuItem 
                      className="text-red-600"
                      onClick={(e) => handleDelete(e, patient.id, patient.name)}
                    >
                      <Trash2 className="mr-2 h-4 w-4" />
                      Excluir
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </TableCell>
              </TableRow>
            )
          })}
        </TableBody>
      </Table>
          </div>
        </div>
      </div>

      {totalPages > 1 && (
        <Pagination
          currentPage={currentPage}
          totalPages={totalPages}
          onPageChange={onPageChange}
        />
      )}

      {/* Send Quiz Modal */}
      {selectedPatient && (
        <SendQuizLinkModal
          open={showSendQuizModal}
          onOpenChange={setShowSendQuizModal}
          patientId={selectedPatient.id}
          patientName={selectedPatient.name}
          onSuccess={() => {
            setSelectedPatient(null)
            queryClient.invalidateQueries({ queryKey: ['monthly-quiz-status'] })
          }}
        />
      )}
    </div>
  )
}

import React from 'react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { AlertTriangle, TrendingUp, Lightbulb, Brain } from 'lucide-react'
import type { QuizAnalysisResponse } from '@/types/quiz'

interface QuizAnalysisCardProps {
  analysis: QuizAnalysisResponse
  className?: string
}

export function QuizAnalysisCard({ analysis, className }: QuizAnalysisCardProps) {
  // Get risk level badge variant
  const getRiskBadgeVariant = (level?: string) => {
    switch (level) {
      case 'critical':
        return 'destructive'
      case 'high':
        return 'destructive'
      case 'medium':
        return 'default'
      case 'low':
        return 'secondary'
      default:
        return 'outline'
    }
  }

  // Get risk level color
  const getRiskColor = (level?: string) => {
    switch (level) {
      case 'critical':
        return 'text-red-600'
      case 'high':
        return 'text-orange-600'
      case 'medium':
        return 'text-yellow-600'
      case 'low':
        return 'text-green-600'
      default:
        return 'text-gray-600'
    }
  }

  // Get sentiment indicator
  const getSentimentIndicator = (score?: number) => {
    if (score === undefined || score === null) return { text: 'N/A', color: 'text-gray-500' }
    if (score > 0.3) return { text: 'Positivo', color: 'text-green-600' }
    if (score < -0.3) return { text: 'Negativo', color: 'text-red-600' }
    return { text: 'Neutro', color: 'text-gray-600' }
  }

  const sentiment = getSentimentIndicator(analysis.sentiment_score)

  return (
    <Card className={className}>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Brain className="h-5 w-5" />
          An├ílise de IA
        </CardTitle>
        <CardDescription>
          {analysis.template_name} - {analysis.template_version}
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        {/* Risk Score Section */}
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <span className="text-sm font-medium">N├¡vel de Risco</span>
            {analysis.risk_level && (
              <Badge variant={getRiskBadgeVariant(analysis.risk_level)}>
                {analysis.risk_level.toUpperCase()}
              </Badge>
            )}
          </div>
          {analysis.risk_score !== undefined && analysis.risk_score !== null && (
            <div className="space-y-1">
              <div className="flex items-center justify-between text-sm">
                <span className="text-muted-foreground">Pontua├º├úo</span>
                <span className={`font-semibold ${getRiskColor(analysis.risk_level)}`}>
                  {analysis.risk_score.toFixed(1)}/100
                </span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div
                  className={`h-2 rounded-full ${
                    analysis.risk_level === 'critical' || analysis.risk_level === 'high'
                      ? 'bg-red-600'
                      : analysis.risk_level === 'medium'
                      ? 'bg-yellow-600'
                      : 'bg-green-600'
                  }`}
                  style={{ width: `${analysis.risk_score}%` }}
                />
              </div>
            </div>
          )}
        </div>

        {/* Sentiment Section */}
        {analysis.sentiment_score !== undefined && analysis.sentiment_score !== null && (
          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <span className="text-sm font-medium">Sentimento</span>
              <span className={`text-sm font-semibold ${sentiment.color}`}>
                {sentiment.text}
              </span>
            </div>
            <div className="text-xs text-muted-foreground">
              Score: {analysis.sentiment_score.toFixed(2)}
            </div>
          </div>
        )}

        {/* Key Concerns Section */}
        {analysis.key_concerns && analysis.key_concerns.length > 0 && (
          <div className="space-y-2">
            <div className="flex items-center gap-2 text-sm font-medium">
              <AlertTriangle className="h-4 w-4 text-orange-600" />
              Preocupa├º├Áes Identificadas
            </div>
            <ul className="space-y-1">
              {analysis.key_concerns.map((concern, index) => (
                <li key={index} className="text-sm text-muted-foreground flex items-start gap-2">
                  <span className="text-orange-600 mt-0.5">ÔÇó</span>
                  <span>{concern}</span>
                </li>
              ))}
            </ul>
          </div>
        )}

        {/* Recommendations Section */}
        {analysis.recommendations && analysis.recommendations.length > 0 && (
          <div className="space-y-2">
            <div className="flex items-center gap-2 text-sm font-medium">
              <Lightbulb className="h-4 w-4 text-blue-600" />
              Recomenda├º├Áes
            </div>
            <ul className="space-y-1">
              {analysis.recommendations.map((recommendation, index) => (
                <li key={index} className="text-sm text-muted-foreground flex items-start gap-2">
                  <span className="text-blue-600 mt-0.5">ÔÇó</span>
                  <span>{recommendation}</span>
                </li>
              ))}
            </ul>
          </div>
        )}

        {/* Response Summary */}
        <div className="pt-4 border-t space-y-2">
          <div className="flex items-center justify-between text-sm">
            <span className="text-muted-foreground">Total de Respostas</span>
            <span className="font-semibold">{analysis.total_responses}</span>
          </div>
          {analysis.flagged_responses > 0 && (
            <div className="flex items-center justify-between text-sm">
              <span className="text-muted-foreground">Respostas Sinalizadas</span>
              <Badge variant="destructive">{analysis.flagged_responses}</Badge>
            </div>
          )}
        </div>
      </CardContent>
    </Card>
  )
}

import React, { useRef } from 'react'
import { Button } from '@/components/ui/button'
import { FileDown } from 'lucide-react'
import type { QuizResponseWithContext, QuizAnalysisResponse } from '@/types/quiz'

interface QuizResponsePDFExportProps {
  responses: QuizResponseWithContext[]
  analysis?: QuizAnalysisResponse
  patientName: string
  className?: string
}

export function QuizResponsePDFExport({ 
  responses, 
  analysis, 
  patientName,
  className 
}: QuizResponsePDFExportProps) {
  const printRef = useRef<HTMLDivElement>(null)

  const handleExport = () => {
    // Create a new window for printing
    const printWindow = window.open('', '_blank')
    if (!printWindow) {
      alert('Por favor, permita pop-ups para exportar o PDF')
      return
    }

    // Format date
    const formatDate = (dateString: string) => {
      const date = new Date(dateString)
      return date.toLocaleDateString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      })
    }

    // Build HTML content
    const htmlContent = `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="UTF-8">
          <title>Respostas de Quiz - ${patientName}</title>
          <style>
            body {
              font-family: Arial, sans-serif;
              margin: 20px;
              color: #333;
            }
            h1 {
              color: #1e40af;
              border-bottom: 2px solid #1e40af;
              padding-bottom: 10px;
            }
            h2 {
