              `).join('')}
            </tbody>
          </table>

          <script>
            window.onload = function() {
              window.print();
            }
          </script>
        </body>
      </html>
    `

    printWindow.document.write(htmlContent)
    printWindow.document.close()
  }

  return (
    <>
      <Button 
        onClick={handleExport} 
        variant="outline"
        className={className}
      >
        <FileDown className="mr-2 h-4 w-4" />
        Exportar PDF
      </Button>
      
      {/* Hidden div for reference (not used in this implementation) */}
      <div ref={printRef} style={{ display: 'none' }} />
    </>
  )
}

import React from 'react'
import { useQuery } from '@tanstack/react-query'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { ScrollArea } from '@/components/ui/scroll-area'
import { LoadingSpinner } from '@/components/ui/loading-spinner'
import { FileText, CheckCircle, Clock, AlertCircle } from 'lucide-react'
import { apiClient } from '@/lib/api-client'
import type { PatientQuizResponsesResponse } from '@/types/quiz'

interface QuizResponseTimelineProps {
  patientId: string
  onSessionClick?: (sessionId: string) => void
  className?: string
}

interface TimelineSession {
  id: string
  template_name: string
  template_version: string
  status: string
  date: string
  responseCount: number
}

export function QuizResponseTimeline({ patientId, onSessionClick, className }: QuizResponseTimelineProps) {
  // Fetch patient quiz responses
  const { data: responsesData, isLoading, error } = useQuery<PatientQuizResponsesResponse>({
    queryKey: ['patient-quiz-responses-timeline', patientId],
    queryFn: () => apiClient.quiz.getPatientResponses(patientId, {
      page: 1,
      size: 100 // Get more responses for timeline
    })
  })

  // Group responses by session
  const sessions = React.useMemo(() => {
    if (!responsesData?.items) return []
    
    const sessionMap = new Map<string, TimelineSession>()
    
    responsesData.items.forEach(response => {
      if (response.quiz_session_id) {
        const existing = sessionMap.get(response.quiz_session_id)
        if (existing) {
          existing.responseCount++
        } else {
          sessionMap.set(response.quiz_session_id, {
            id: response.quiz_session_id,
            template_name: response.template_name || 'Quiz',
            template_version: response.template_version || '1.0',
            status: response.session_status || 'completed',
            date: response.responded_at,
            responseCount: 1
          })
        }
      }
    })
    
    // Sort by date (most recent first)
    return Array.from(sessionMap.values()).sort((a, b) => 
      new Date(b.date).getTime() - new Date(a.date).getTime()
    )
  }, [responsesData])

  // Format date
  const formatDate = (dateString: string) => {
    const date = new Date(dateString)
    return date.toLocaleDateString('pt-BR', {
      day: '2-digit',
      month: 'short',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    })
  }

  // Get status icon
  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'completed':
        return CheckCircle
      case 'started':
        return Clock
      case 'cancelled':
        return AlertCircle
      default:
        return FileText
    }
  }

  // Get status color
  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed':
        return 'text-green-600 bg-green-100'
      case 'started':
        return 'text-blue-600 bg-blue-100'
      case 'cancelled':
        return 'text-red-600 bg-red-100'
      default:
        return 'text-gray-600 bg-gray-100'
    }
  }

  // Get status badge variant
  const getStatusBadgeVariant = (status: string): 'default' | 'secondary' | 'destructive' | 'outline' => {
    switch (status) {
      case 'completed':
        return 'default'
      case 'started':
        return 'secondary'
      case 'cancelled':
        return 'destructive'
      default:
        return 'outline'
    }
  }

  if (isLoading) {
    return (
      <Card className={className}>
        <CardContent className="pt-6">
          <div className="flex items-center justify-center py-8">
            <LoadingSpinner size="md" />
          </div>
        </CardContent>
      </Card>
    )
  }

  if (error) {
    return (
      <Card className={className}>
        <CardContent className="pt-6">
          <div className="text-center text-red-600 py-8">
            Erro ao carregar timeline de quiz. Por favor, tente novamente.
          </div>
        </CardContent>
      </Card>
    )
  }

  return (
    <Card className={className}>
      <CardHeader>
        <CardTitle>Timeline de Quiz</CardTitle>
        <CardDescription>
          {sessions.length === 0 
            ? 'Nenhuma sess├úo de quiz encontrada'
            : `${sessions.length} ${sessions.length === 1 ? 'sess├úo' : 'sess├Áes'} de quiz`
          }
        </CardDescription>
      </CardHeader>
      <CardContent>
        {sessions.length === 0 ? (
          <div className="text-center py-8">
            <FileText className="mx-auto h-12 w-12 text-gray-400 mb-4" />
            <p className="text-gray-500">Nenhuma sess├úo de quiz registrada</p>
            <p className="text-sm text-gray-400">
              As sess├Áes de quiz aparecer├úo aqui quando o paciente completar question├írios
            </p>
          </div>
        ) : (
          <ScrollArea className="h-[400px]">
            <div className="space-y-4">
              {sessions.map((session, index) => {
                const Icon = getStatusIcon(session.status)
                const colorClass = getStatusColor(session.status)
                
                return (
                  <div
                    key={session.id}
                    className={`relative flex gap-4 pb-4 ${
                      index !== sessions.length - 1 ? 'border-l-2 border-gray-200 ml-4' : ''
                    }`}
                  >
                    {/* Timeline dot */}
                    <div className={`absolute -left-[9px] top-0 w-4 h-4 rounded-full ${colorClass} flex items-center justify-center`}>
                      <div className="w-2 h-2 rounded-full bg-white" />
                    </div>
                    
                    {/* Content */}
                    <div 
                      className={`flex-1 ml-8 p-4 rounded-lg border bg-white ${
                        onSessionClick ? 'cursor-pointer hover:border-blue-300 hover:shadow-sm transition-all' : ''
                      }`}
                      onClick={() => onSessionClick?.(session.id)}
                    >
                      <div className="flex items-start justify-between gap-4">
                        <div className="flex-1 space-y-2">
                          <div className="flex items-center gap-2">
                            <Icon className={`h-4 w-4 ${colorClass.split(' ')[0]}`} />
                            <span className="font-medium text-sm">{session.template_name}</span>
                          </div>
                          
                          <div className="text-xs text-muted-foreground space-y-1">
                            <div>Vers├úo: {session.template_version}</div>
                            <div>{formatDate(session.date)}</div>
                            <div>{session.responseCount} {session.responseCount === 1 ? 'resposta' : 'respostas'}</div>
                          </div>
                        </div>
                        
                        <Badge variant={getStatusBadgeVariant(session.status)}>
                          {session.status}
                        </Badge>
                      </div>
                    </div>
                  </div>
                )
              })}
            </div>
          </ScrollArea>
        )}
      </CardContent>
    </Card>
  )
}

import React, { useState } from 'react'
import { useQuery } from '@tanstack/react-query'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { LoadingSpinner } from '@/components/ui/loading-spinner'
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table'
import { ChevronLeft, ChevronRight, FileText, Calendar } from 'lucide-react'
import { apiClient } from '@/lib/api-client'
import { QuizAnalysisCard } from './QuizAnalysisCard'
import { QuizResponsePDFExport } from './QuizResponsePDFExport'
import type { PatientQuizResponsesResponse, QuizAnalysisResponse } from '@/types/quiz'

interface QuizResponseViewerProps {
  patientId: string
  patientName?: string
  className?: string
}

export function QuizResponseViewer({ patientId, patientName = 'Paciente', className }: QuizResponseViewerProps) {
  const [currentPage, setCurrentPage] = useState(1)
  const [selectedSessionId, setSelectedSessionId] = useState<string | null>(null)
  const pageSize = 20

  // Fetch patient quiz responses
  const { data: responsesData, isLoading: responsesLoading, error: responsesError } = useQuery<PatientQuizResponsesResponse>({
    queryKey: ['patient-quiz-responses', patientId, currentPage],
    queryFn: () => apiClient.quiz.getPatientResponses(patientId, {
      page: currentPage,
      size: pageSize
    })
  })

  // Fetch analysis for selected session
  const { data: analysisData, isLoading: analysisLoading } = useQuery<QuizAnalysisResponse>({
    queryKey: ['quiz-session-analysis', selectedSessionId],
    queryFn: () => apiClient.quiz.getSessionAnalysis(selectedSessionId!),
    enabled: !!selectedSessionId
  })

  // Format date
  const formatDate = (dateString: string) => {
    const date = new Date(dateString)
    return date.toLocaleDateString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    })
  }

  // Get unique sessions from responses
  const sessions = React.useMemo(() => {
    if (!responsesData?.items) return []
    const sessionMap = new Map()
    responsesData.items.forEach(response => {
      if (response.quiz_session_id && !sessionMap.has(response.quiz_session_id)) {
        sessionMap.set(response.quiz_session_id, {
          id: response.quiz_session_id,
          template_name: response.template_name,
          template_version: response.template_version,
          status: response.session_status,
          date: response.responded_at
        })
      }
    })
    return Array.from(sessionMap.values())
  }, [responsesData])

  // Handle page change
  const handlePageChange = (newPage: number) => {
    setCurrentPage(newPage)
  }

  if (responsesLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  if (responsesError) {
    return (
      <Card className={className}>
        <CardContent className="pt-6">
          <div className="text-center text-red-600">
            Erro ao carregar respostas do quiz. Por favor, tente novamente.
          </div>
        </CardContent>
      </Card>
    )
  }

  if (!responsesData || responsesData.items.length === 0) {
    return (
      <Card className={className}>
        <CardHeader>
          <CardTitle>Respostas de Quiz</CardTitle>
          <CardDescription>Hist├│rico de respostas do paciente</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="text-center text-muted-foreground py-8">
            Nenhuma resposta de quiz encontrada para este paciente.
          </div>
        </CardContent>
      </Card>
    )
  }

  const totalPages = responsesData.pages || Math.ceil(responsesData.total / pageSize)

  return (
    <div className={`space-y-6 ${className}`}>
      {/* Sessions Overview */}
      {sessions.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Calendar className="h-5 w-5" />
              Sess├Áes de Quiz
            </CardTitle>
            <CardDescription>
              {sessions.length} {sessions.length === 1 ? 'sess├úo encontrada' : 'sess├Áes encontradas'}
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {sessions.map((session) => (
                <div
                  key={session.id}
                  className={`p-4 border rounded-lg cursor-pointer transition-colors ${
                    selectedSessionId === session.id
                      ? 'border-blue-600 bg-blue-50'
                      : 'border-gray-200 hover:border-gray-300'
                  }`}
                  onClick={() => setSelectedSessionId(session.id)}
                >
                  <div className="space-y-2">
                    <div className="font-medium text-sm">{session.template_name}</div>
                    <div className="text-xs text-muted-foreground">
                      Vers├úo: {session.template_version}
                    </div>
                    <div className="text-xs text-muted-foreground">
                      {formatDate(session.date)}
                    </div>
                    {session.status && (
                      <Badge variant={session.status === 'completed' ? 'default' : 'secondary'}>
                        {session.status}
                      </Badge>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* AI Analysis Card */}
      {selectedSessionId && analysisData && (
        <QuizAnalysisCard analysis={analysisData} />
      )}

      {selectedSessionId && analysisLoading && (
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-center">
              <LoadingSpinner size="md" />
              <span className="ml-2 text-sm text-muted-foreground">Carregando an├ílise...</span>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Responses Table */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle className="flex items-center gap-2">
                <FileText className="h-5 w-5" />
                Respostas do Quiz
              </CardTitle>
              <CardDescription>
                Mostrando {responsesData.items.length} de {responsesData.total} respostas
              </CardDescription>
            </div>
            <QuizResponsePDFExport
              responses={responsesData.items}
              {...(analysisData ? { analysis: analysisData } : {})}
              patientName={patientName}
            />
          </div>
        </CardHeader>
        <CardContent>
          <div className="rounded-md border">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Pergunta</TableHead>
                  <TableHead>Resposta</TableHead>
                  <TableHead>Tipo</TableHead>
                  <TableHead>Template</TableHead>
                  <TableHead>Data</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {responsesData.items.map((response) => (
                  <TableRow key={response.id}>
                    <TableCell className="font-medium max-w-xs">
                      <div className="truncate" title={response.question_text}>
                        {response.question_text}
                      </div>
                    </TableCell>
                    <TableCell className="max-w-xs">
                      <div className="truncate" title={response.response_value}>
                        {response.response_value}
                      </div>
                      {response.other_text && (
                        <div className="text-xs text-muted-foreground mt-1">
                          Outro: {response.other_text}
                        </div>
                      )}
                    </TableCell>
                    <TableCell>
                      <Badge variant="outline">{response.response_type}</Badge>
                    </TableCell>
                    <TableCell className="text-sm text-muted-foreground">
                      {response.template_name}
                    </TableCell>
                    <TableCell className="text-sm text-muted-foreground">
                      {formatDate(response.responded_at)}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>

          {/* Pagination */}
          {totalPages > 1 && (
            <div className="flex items-center justify-between mt-4">
              <div className="text-sm text-muted-foreground">
                P├ígina {currentPage} de {totalPages}
              </div>
              <div className="flex items-center gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handlePageChange(currentPage - 1)}
                  disabled={currentPage === 1}
                >
                  <ChevronLeft className="h-4 w-4 mr-1" />
                  Anterior
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handlePageChange(currentPage + 1)}
                  disabled={currentPage === totalPages}
                >
                  Pr├│xima
                  <ChevronRight className="h-4 w-4 ml-1" />
                </Button>
              </div>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  )
}

