import React, { useState } from 'react'
import { useForm } from 'react-hook-form'
import { useMutation, useQueryClient } from '@tanstack/react-query'
import { CheckCircle, Circle, Star } from 'lucide-react'
import { apiClient } from '../../lib/api-client'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group'
import { Checkbox } from '@/components/ui/checkbox'
import { Slider } from '@/components/ui/slider'
import { useToast } from '@/components/ui/use-toast'
import { LoadingSpinner } from '../ui/loading-spinner'

interface Question {
  id: string
  type: 'multiple_choice' | 'yes_no' | 'scale' | 'text' | 'checkbox'
  question: string
  options?: string[]
  min?: number
  max?: number
  required: boolean
}

interface QuizSession {
  id: string
  patient_id: string
  template_id: string
  template_name?: string
  questions: Question[]
  status: string
  responses: Record<string, any>
}

interface QuizFormProps {
  session: QuizSession
  onComplete?: () => void
}

export function QuizForm({ session, onComplete }: QuizFormProps) {
  const [responses, setResponses] = useState<Record<string, any>>(session.responses || {})
  const { toast } = useToast()
  const queryClient = useQueryClient()

  const submitResponseMutation = useMutation({
    mutationFn: async (data: { session_id: string; responses: Record<string, any> }) => {
      // Submit each question response individually
      const submissions = Object.entries(data.responses).map(([questionId, answer]) =>
        apiClient.quiz.submitResponse(data.session_id, questionId, String(answer))
      )

      // Wait for all submissions to complete
      await Promise.all(submissions)
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['quiz-sessions'] })
      queryClient.invalidateQueries({ queryKey: ['quiz-session', session.id] })
      toast({
        title: 'Question├írio enviado',
        description: 'Suas respostas foram salvas com sucesso.',
      })
      onComplete?.()
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao enviar question├írio',
        description: error.data?.message || 'Ocorreu um erro inesperado.',
        variant: 'destructive'
      })
    }
  })

  const handleResponseChange = (questionId: string, value: any) => {
    setResponses(prev => ({
      ...prev,
      [questionId]: value
    }))
  }

  const handleSubmit = () => {
    // Validate required questions
    const requiredQuestions = session.questions.filter(q => q.required)
    const missingResponses = requiredQuestions.filter(q => 
      !responses[q.id] || responses[q.id] === '' || responses[q.id] === null
    )

    if (missingResponses.length > 0) {
      toast({
        title: 'Campos obrigat├│rios',
        description: `Por favor, responda todas as perguntas obrigat├│rias (${missingResponses.length} restantes).`,
        variant: 'destructive'
      })
      return
    }

    submitResponseMutation.mutate({
      session_id: session.id,
      responses
    })
  }

  const renderQuestion = (question: Question) => {
    const value = responses[question.id]

    switch (question.type) {
      case 'multiple_choice':
        return (
          <RadioGroup
            value={value || ''}
            onValueChange={(newValue) => handleResponseChange(question.id, newValue)}
          >
            {question.options?.map((option, index) => (
              <div key={index} className="flex items-center space-x-2">
                <RadioGroupItem value={option} id={`${question.id}-${index}`} />
                <Label htmlFor={`${question.id}-${index}`}>{option}</Label>
              </div>
            ))}
          </RadioGroup>
        )

      case 'yes_no':
        return (
          <RadioGroup
            value={value || ''}
            onValueChange={(newValue) => handleResponseChange(question.id, newValue)}
          >
            <div className="flex items-center space-x-2">
              <RadioGroupItem value="yes" id={`${question.id}-yes`} />
              <Label htmlFor={`${question.id}-yes`}>Sim</Label>
            </div>
            <div className="flex items-center space-x-2">
              <RadioGroupItem value="no" id={`${question.id}-no`} />
              <Label htmlFor={`${question.id}-no`}>N├úo</Label>
            </div>
          </RadioGroup>
        )

      case 'scale':
        const scaleValue = value || question.min || 1
        return (
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <span className="text-sm text-gray-500">{question.min}</span>
              <span className="font-medium text-lg">{scaleValue}</span>
              <span className="text-sm text-gray-500">{question.max}</span>
            </div>
            <Slider
              value={[scaleValue]}
              onValueChange={(newValue) => handleResponseChange(question.id, newValue[0])}
              min={question.min || 1}
              max={question.max || 10}
              step={1}
              className="w-full"
            />
            <div className="flex justify-between text-xs text-gray-400">
              {Array.from({ length: (question.max || 10) - (question.min || 1) + 1 }, (_, i) => (
                <span key={i}>{(question.min || 1) + i}</span>
              ))}
            </div>
          </div>
        )

      case 'text':
        return (
          <Textarea
            value={value || ''}
            onChange={(e) => handleResponseChange(question.id, e.target.value)}
            placeholder="Digite sua resposta..."
            rows={4}
          />
        )

      case 'checkbox':
        const checkboxValues = value || []
        return (
          <div className="space-y-2">
            {question.options?.map((option, index) => (
              <div key={index} className="flex items-center space-x-2">
                <Checkbox
                  id={`${question.id}-${index}`}
                  checked={checkboxValues.includes(option)}
                  onCheckedChange={(checked) => {
                    if (checked) {
                      handleResponseChange(question.id, [...checkboxValues, option])
                    } else {
                      handleResponseChange(question.id, checkboxValues.filter((v: string) => v !== option))
                    }
                  }}
                />
                <Label htmlFor={`${question.id}-${index}`}>{option}</Label>
              </div>
            ))}
          </div>
        )

      default:
        return <div>Tipo de pergunta n├úo suportado</div>
    }
  }

  const completedQuestions = session.questions.filter(q => 
    responses[q.id] !== undefined && responses[q.id] !== '' && responses[q.id] !== null
  ).length

  const progressPercentage = (completedQuestions / session.questions.length) * 100

  return (
    <div className="space-y-6">
      {/* Header */}
      <Card>
        <CardHeader>
          <CardTitle>{session.template_name || 'Question├írio'}</CardTitle>
          <CardDescription>
            Responda todas as perguntas para completar o question├írio
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-2">
            <div className="flex items-center justify-between text-sm">
              <span>Progresso</span>
              <span>{completedQuestions} de {session.questions.length} perguntas</span>
            </div>
            <div className="w-full bg-gray-200 rounded-full h-2">
              <div 
                className="bg-blue-600 h-2 rounded-full transition-all duration-300"
                style={{ width: `${progressPercentage}%` }}
              />
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Questions */}
      <div className="space-y-6">
        {session.questions.map((question, index) => {
          const isAnswered = responses[question.id] !== undefined && 
                            responses[question.id] !== '' && 
                            responses[question.id] !== null

          return (
            <Card key={question.id} className={isAnswered ? 'border-green-200 bg-green-50' : ''}>
              <CardHeader>
                <div className="flex items-start space-x-3">
                  <div className="flex items-center justify-center w-8 h-8 rounded-full bg-blue-100 text-blue-600 font-medium text-sm">
                    {isAnswered ? (
                      <CheckCircle className="w-5 h-5 text-green-600" />
                    ) : (
                      <span>{index + 1}</span>
                    )}
                  </div>
                  <div className="flex-1">
                    <CardTitle className="text-lg">
                      {question.question}
                      {question.required && (
                        <span className="text-red-500 ml-1">*</span>
                      )}
                    </CardTitle>
                  </div>
                </div>
              </CardHeader>
              <CardContent>
                {renderQuestion(question)}
              </CardContent>
            </Card>
          )
        })}
      </div>

      {/* Submit Button */}
      <Card>
        <CardContent className="pt-6">
          <div className="flex items-center justify-between">
            <div className="text-sm text-gray-600">
              {completedQuestions === session.questions.length ? (
                <span className="text-green-600 font-medium">
                  Ô£ô Todas as perguntas foram respondidas
                </span>
              ) : (
                <span>
                  {session.questions.length - completedQuestions} perguntas restantes
                </span>
              )}
            </div>
            
            <Button
              onClick={handleSubmit}
              disabled={submitResponseMutation.isPending}
              size="lg"
            >
              {submitResponseMutation.isPending ? (
                <>
                  <LoadingSpinner size="sm" className="mr-2" />
                  Enviando...
                </>
              ) : (
                <>
                  <CheckCircle className="mr-2 h-4 w-4" />
                  Enviar Question├írio
                </>
              )}
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}

import React from 'react'
import { Badge } from '@/components/ui/badge'
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from '@/components/ui/tooltip'
import { CircleCheck as CheckCircle2, Clock, Circle as XCircle, Send } from 'lucide-react'
import { formatDistanceToNow } from 'date-fns'
import { ptBR } from 'date-fns/locale'
import { mapBackendStatus, getStatusLabel } from '@/utils/monthlyQuizStatusMapper'

export interface QuizLinkStatusProps {
  patientId: string
  lastSent?: Date
  lastResponse?: Date
  linkStatus: 'active' | 'expired' | 'completed' | 'pending' | string // Allow backend status values
  expiresAt?: Date
}

export function QuizLinkStatus({
  patientId,
  lastSent,
  lastResponse,
  linkStatus,
  expiresAt
}: QuizLinkStatusProps) {
  // Map backend status to UI status
  const mappedStatus = mapBackendStatus(linkStatus)

  const getStatusConfig = () => {
    switch (mappedStatus) {
      case 'active':
        return {
          icon: Clock,
          label: 'Ativo',
          className: 'bg-blue-100 text-blue-800 border-blue-200',
          iconClassName: 'text-blue-600'
        }
      case 'expired':
        return {
          icon: XCircle,
          label: 'Expirado',
          className: 'bg-red-100 text-red-800 border-red-200',
          iconClassName: 'text-red-600'
        }
      case 'completed':
        return {
          icon: CheckCircle2,
          label: 'Completado',
          className: 'bg-green-100 text-green-800 border-green-200',
          iconClassName: 'text-green-600'
        }
      case 'pending':
        return {
          icon: Send,
          label: 'Pendente',
          className: 'bg-gray-100 text-gray-800 border-gray-200',
          iconClassName: 'text-gray-600'
        }
      default:
        return {
          icon: Clock,
          label: getStatusLabel(linkStatus),
          className: 'bg-gray-100 text-gray-800 border-gray-200',
          iconClassName: 'text-gray-600'
        }
    }
  }

  const config = getStatusConfig()
  const Icon = config.icon

  const formatTimeRemaining = () => {
    if (!expiresAt) return null

    try {
      const now = new Date()
      const expires = new Date(expiresAt)

      if (expires <= now) {
        return 'Expirado'
      }

      return `Expira ${formatDistanceToNow(expires, {
        addSuffix: true,
        locale: ptBR
      })}`
    } catch {
      return 'Data inv├ílida'
    }
  }

  const formatDate = (date?: Date) => {
    if (!date) return 'Nunca'

    try {
      return formatDistanceToNow(new Date(date), {
        addSuffix: true,
        locale: ptBR
      })
    } catch {
      return 'Data inv├ílida'
    }
  }

  const tooltipContent = (
    <div className="space-y-1 text-xs">
      <div>
        <span className="font-semibold">Status:</span> {config.label}
      </div>
      {lastSent && (
        <div>
          <span className="font-semibold">Enviado:</span> {formatDate(lastSent)}
        </div>
      )}
      {lastResponse && (
        <div>
          <span className="font-semibold">Respondido:</span> {formatDate(lastResponse)}
        </div>
      )}
      {mappedStatus === 'active' && expiresAt && (
        <div>
          <span className="font-semibold">Validade:</span> {formatTimeRemaining()}
        </div>
      )}
    </div>
  )

  return (
    <TooltipProvider>
      <Tooltip>
        <TooltipTrigger asChild>
          <Badge className={`${config.className} border cursor-help text-xs`}>
            <Icon className={`h-3 w-3 mr-1 flex-shrink-0 ${config.iconClassName}`} />
            <span className="hidden sm:inline">{config.label}</span>
            <span className="sm:hidden">{config.label.substring(0, 4)}</span>
          </Badge>
        </TooltipTrigger>
        <TooltipContent side="top" className="max-w-[200px] sm:max-w-xs">
          {tooltipContent}
        </TooltipContent>
      </Tooltip>
    </TooltipProvider>
  )
}

import React, { useState } from 'react'
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { Send, Loader as Loader2 } from 'lucide-react'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Label } from '@/components/ui/label'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { useToast } from '@/components/ui/use-toast'
import { apiClient } from '@/lib/api-client'
import type { QuizLinkCreate } from '@/lib/api-client/monthly-quiz'

interface SendQuizLinkModalProps {
  open: boolean
  onOpenChange: (open: boolean) => void
  patientId: string
  patientName: string
  onSuccess?: () => void
}

export function SendQuizLinkModal({
  open,
  onOpenChange,
  patientId,
  patientName,
  onSuccess
}: SendQuizLinkModalProps) {
  const { toast } = useToast()
  const queryClient = useQueryClient()
  const [templateId, setTemplateId] = useState('')
  const [deliveryMethod, setDeliveryMethod] = useState<'whatsapp' | 'email' | 'sms'>('whatsapp')
  const [validityHours, setValidityHours] = useState('72')
  const [customMessage, setCustomMessage] = useState('')

  // Fetch quiz templates
  const { data: templatesData, isLoading: isLoadingTemplates } = useQuery({
    queryKey: ['quiz-templates'],
    queryFn: () => apiClient.quiz.templates(),
    enabled: open
  })

  const templates = templatesData?.items || []

  const sendLinkMutation = useMutation({
    mutationFn: (data: QuizLinkCreate & { send_immediately?: boolean }) => {
      const { send_immediately, ...payload } = data
      return apiClient.monthlyQuiz.createLink(payload)
    },
    onSuccess: (response: any) => {
      const attempts = response?.delivery_attempts as Array<{ status?: string }> | undefined
      const lastAttempt = attempts?.[attempts.length - 1]
      const deliveryStatus = lastAttempt?.status || response?.last_delivery_status || 'pending'

      if (deliveryStatus === 'sent') {
        toast({
          title: 'Link enviado via WhatsApp',
          description: `O quiz foi enviado para ${patientName} no WhatsApp.`,
        })
      } else if (deliveryStatus === 'failed') {
        toast({
          title: 'Link gerado, envio pendente',
          description: 'N├úo foi poss├¡vel entregar via WhatsApp agora; o sistema tentar├í novamente.',
          variant: 'destructive'
        })
      } else {
        toast({
          title: 'Link gerado',
          description: `Link criado para ${patientName}. O envio via WhatsApp ocorrer├í em breve.`,
        })
      }

      queryClient.invalidateQueries({ queryKey: ['monthly-quiz-status', patientId] })
      queryClient.invalidateQueries({ queryKey: ['patients'] })
      onSuccess?.()
      handleClose()
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao enviar link',
        description: error.data?.message || 'Ocorreu um erro ao enviar o link do quiz',
        variant: 'destructive'
      })
    }
  })

  const handleClose = () => {
    setTemplateId('')
    setDeliveryMethod('whatsapp')
    setValidityHours('72')
    setCustomMessage('')
    onOpenChange(false)
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()

    if (!templateId) {
      toast({
        title: 'Template obrigat├│rio',
        description: 'Por favor, selecione um template de quiz',
        variant: 'destructive'
      })
      return
    }

    sendLinkMutation.mutate({
      patient_id: patientId,
      quiz_template_id: templateId,
      delivery_method: deliveryMethod,
      expiry_hours: parseInt(validityHours, 10),
      ...(customMessage ? { custom_message: customMessage } : {}),
      send_immediately: true
    })
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-[95vw] sm:max-w-[500px] max-h-[90vh] overflow-y-auto">
        <DialogHeader className="px-4 sm:px-6">
          <DialogTitle className="text-lg sm:text-xl">Enviar Link do Quiz Mensal</DialogTitle>
          <DialogDescription className="text-sm">
            Enviar link do quiz mensal para {patientName}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-3 sm:space-y-4 py-4 px-4 sm:px-6">
          <div className="space-y-2">
            <Label htmlFor="template">Template do Quiz *</Label>
            <Select value={templateId} onValueChange={setTemplateId} disabled={isLoadingTemplates}>
              <SelectTrigger id="template">
                <SelectValue placeholder="Selecione um template" />
              </SelectTrigger>
              <SelectContent>
                {isLoadingTemplates ? (
                  <SelectItem value="loading" disabled>
                    Carregando...
                  </SelectItem>
                ) : templates.length === 0 ? (
                  <SelectItem value="empty" disabled>
                    Nenhum template dispon├¡vel
                  </SelectItem>
                ) : (
                  templates.map((template: any) => (
                    <SelectItem key={template.id} value={template.id}>
                      {template.name} (v{template.version})
                    </SelectItem>
                  ))
                )}
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-2">
            <Label htmlFor="delivery">M├®todo de Entrega *</Label>
            <Select value={deliveryMethod} onValueChange={(value: any) => setDeliveryMethod(value)}>
              <SelectTrigger id="delivery">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="whatsapp">WhatsApp</SelectItem>
                <SelectItem value="email">Email</SelectItem>
                <SelectItem value="sms">SMS</SelectItem>
