              min="1"
              max="168"
              value={validityHours}
              onChange={(e) => setValidityHours(e.target.value)}
              placeholder="72"
            />
            <p className="text-xs text-gray-500">
              O link expira ap├│s {validityHours} horas (padr├úo: 72 horas)
            </p>
          </div>

          <div className="space-y-2">
            <Label htmlFor="message" className="text-sm">Mensagem Personalizada (opcional)</Label>
            <Textarea
              id="message"
              value={customMessage}
              onChange={(e) => setCustomMessage(e.target.value)}
              placeholder="Adicione uma mensagem personalizada..."
              rows={3}
              className="resize-none"
            />
          </div>

          <DialogFooter className="flex-col sm:flex-row gap-2 sm:gap-0">
            <Button
              type="button"
              variant="outline"
              onClick={handleClose}
              disabled={sendLinkMutation.isPending}
              className="w-full sm:w-auto"
            >
              Cancelar
            </Button>
            <Button
              type="submit"
              disabled={sendLinkMutation.isPending || !templateId}
              className="w-full sm:w-auto"
            >
              {sendLinkMutation.isPending ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Enviando...
                </>
              ) : (
                <>
                  <Send className="mr-2 h-4 w-4" />
                  Enviar
                </>
              )}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

import React, { useEffect, useState } from 'react'
import { useQuery } from '@tanstack/react-query'
import {
  Activity,
  CheckCircle2,
  AlertTriangle,
  XCircle,
  RefreshCw,
  Server,
  Database,
  Wifi,
  Clock
} from 'lucide-react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { LoadingSpinner } from '@/components/ui/loading-spinner'
import { useAuth } from '@/contexts/AuthContext'
import { apiClient } from '@/lib/api-client'

interface HealthCheck {
  service: string
  status: 'healthy' | 'warning' | 'critical' | 'unknown'
  response_time_ms: number
  last_check: string
  message?: string
  details?: Record<string, any>
}

interface SystemHealth {
  overall_status: 'healthy' | 'degraded' | 'down'
  services: HealthCheck[]
  uptime_seconds: number
  server_time: string
  environment: string
}

const getStatusIcon = (status: string) => {
  switch (status) {
    case 'healthy': return CheckCircle2
    case 'warning': return AlertTriangle
    case 'critical':
    case 'down': return XCircle
    default: return Activity
  }
}

const getStatusColor = (status: string) => {
  switch (status) {
    case 'healthy': return 'text-green-600 bg-green-50'
    case 'warning':
    case 'degraded': return 'text-yellow-600 bg-yellow-50'
    case 'critical':
    case 'down': return 'text-red-600 bg-red-50'
    default: return 'text-gray-600 bg-gray-50'
  }
}

const formatUptime = (seconds: number): string => {
  const days = Math.floor(seconds / 86400)
  const hours = Math.floor((seconds % 86400) / 3600)
  const minutes = Math.floor((seconds % 3600) / 60)

  if (days > 0) return `${days}d ${hours}h ${minutes}m`
  if (hours > 0) return `${hours}h ${minutes}m`
  return `${minutes}m`
}

export function HealthStatusMonitor() {
  const { user } = useAuth()
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date())

  const {
    data: health,
    isLoading,
    error,
    refetch
  } = useQuery<SystemHealth>({
    queryKey: ['system-health'],
    queryFn: async () => {
      try {
        // Try the health check endpoint first
        return await apiClient.request<SystemHealth>('/api/v2/health')
      } catch (healthError) {
        // Fallback to system stats if health endpoint not available
        const stats = await apiClient.admin.system.systemStats()

        // Transform system stats to health format
        return {
          overall_status: stats.system?.uptime > 0 ? 'healthy' : 'down',
          services: [
            {
              service: 'API Server',
              status: 'healthy',
              response_time_ms: 50,
              last_check: new Date().toISOString(),
              message: 'API responding normally'
            },
            {
              service: 'Database',
              status: stats.users?.total > 0 ? 'healthy' : 'warning',
              response_time_ms: 25,
              last_check: new Date().toISOString(),
              message: `${stats.users?.total || 0} users in database`
            },
            {
              service: 'Authentication',
              status: stats.security?.active_sessions > 0 ? 'healthy' : 'warning',
              response_time_ms: 15,
              last_check: new Date().toISOString(),
              message: `${stats.security?.active_sessions || 0} active sessions`
            }
          ],
          uptime_seconds: stats.system?.uptime || 0,
          server_time: new Date().toISOString(),
          environment: process.env['NODE_ENV'] || 'development'
        } as SystemHealth
      }
    },
    enabled: !!user,
    refetchInterval: 30000, // Refresh every 30 seconds
    retry: 2,
    // onSuccess removed - not supported in newer react-query versions
  })

  const handleRefresh = () => {
    refetch()
  }

  if (!user) {
    return null
  }

  if (isLoading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Activity className="h-5 w-5" />
            Status do Sistema
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex items-center justify-center py-8">
            <LoadingSpinner size="md" />
          </div>
        </CardContent>
      </Card>
    )
  }

  if (error) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <XCircle className="h-5 w-5 text-red-600" />
            Status do Sistema
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="text-center py-8">
            <p className="text-red-600 mb-4">Erro ao carregar status do sistema</p>
            <Button onClick={handleRefresh} variant="outline" size="sm">
              <RefreshCw className="h-4 w-4 mr-2" />
              Tentar Novamente
            </Button>
          </div>
        </CardContent>
      </Card>
    )
  }

  const healthData = health as any
  const StatusIcon = getStatusIcon(healthData?.overall_status || 'unknown')
  const statusColor = getStatusColor(healthData?.overall_status || 'unknown')

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center justify-between">
          <CardTitle className="flex items-center gap-2">
            <StatusIcon className={`h-5 w-5 ${statusColor}`} />
            Status do Sistema
          </CardTitle>
          <Button
            onClick={handleRefresh}
            variant="ghost"
            size="sm"
            className="h-8 w-8 p-0"
          >
            <RefreshCw className="h-4 w-4" />
          </Button>
        </div>
        <CardDescription>
          Monitoramento em tempo real dos servi├ºos
        </CardDescription>
      </CardHeader>
      <CardContent>
        {/* Overall Status */}
        <div className="mb-6">
          <div className="flex items-center justify-between mb-2">
            <span className="font-medium">Status Geral</span>
            <Badge
              variant="secondary"
              className={statusColor}
            >
              {healthData?.overall_status === 'healthy' ? 'Operacional' :
               healthData?.overall_status === 'degraded' ? 'Degradado' : 'Indispon├¡vel'}
            </Badge>
          </div>

          {healthData?.uptime_seconds && (
            <div className="flex items-center gap-2 text-sm text-gray-600">
              <Clock className="h-4 w-4" />
              Uptime: {formatUptime(healthData.uptime_seconds)}
            </div>
          )}
        </div>

        {/* Services Status */}
        <div className="space-y-3">
          <h4 className="font-medium text-sm text-gray-700">Servi├ºos</h4>

          {healthData?.services?.map((service: any, index: number) => {
            const ServiceStatusIcon = getStatusIcon(service.status)
            const serviceStatusColor = getStatusColor(service.status)

            return (
              <div
                key={`${service.service}-${index}`}
                className="flex items-center justify-between p-3 bg-gray-50 rounded-lg"
              >
                <div className="flex items-center gap-3">
                  <ServiceStatusIcon className={`h-4 w-4 ${serviceStatusColor}`} />
                  <div>
                    <div className="font-medium text-sm">{service.service}</div>
                    {service.message && (
                      <div className="text-xs text-gray-600">{service.message}</div>
                    )}
                  </div>
                </div>

                <div className="text-right text-xs text-gray-500">
                  <div>{service.response_time_ms}ms</div>
                  <div>{new Date(service.last_check).toLocaleTimeString()}</div>
                </div>
              </div>
            )
          })}
        </div>

        {/* Environment Info */}
        <div className="mt-6 pt-4 border-t border-gray-200">
          <div className="flex items-center justify-between text-xs text-gray-500">
            <div className="flex items-center gap-1">
              <Server className="h-3 w-3" />
              Ambiente: {healthData?.environment || 'unknown'}
            </div>
            <div>
              ├Ültima atualiza├º├úo: {lastUpdated.toLocaleTimeString()}
            </div>
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

/**
 * Permission Error Feedback Components
 *
 * React components for displaying user-friendly error messages
 * related to authentication, authorization, and RLS violations.
 *
 * Features:
 * - RLS violation messages
 * - Authentication error displays
 * - Permission denied feedback
 * - Actionable error dialogs
 * - Toast notifications for errors
 */

import React from 'react'
import { AlertCircle, Lock, ShieldX, RefreshCw, ExternalLink, ArrowLeft } from 'lucide-react'
import { Alert, AlertDescription, AlertTitle } from './alert'
import { Button } from './button'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from './card'
import { UserFriendlyError, AuthErrorType, createUserFriendlyError } from '../../lib/auth-error-handler'
import { createLogger } from '../../lib/logger'

const logger = createLogger('PermissionErrorFeedback')

interface PermissionErrorProps {
  error: UserFriendlyError
  onAction?: (action: string) => void
  className?: string
  variant?: 'alert' | 'card' | 'full-page'
  showActions?: boolean
}

/**
 * Generic permission error component that can be styled as alert, card, or full page
 */
export function PermissionError({
  error,
  onAction,
  className = '',
  variant = 'alert',
  showActions = true
}: PermissionErrorProps) {
  const getIcon = () => {
    switch (error.type) {
      case AuthErrorType.RLS_VIOLATION:
      case AuthErrorType.INSUFFICIENT_PERMISSIONS:
        return <ShieldX className="h-5 w-5" />
      case AuthErrorType.AUTHENTICATION_REQUIRED:
      case AuthErrorType.SESSION_EXPIRED:
        return <Lock className="h-5 w-5" />
      default:
        return <AlertCircle className="h-5 w-5" />
    }
  }

  const getVariant = () => {
    switch (error.type) {
      case AuthErrorType.RLS_VIOLATION:
      case AuthErrorType.INSUFFICIENT_PERMISSIONS:
        return 'destructive'
      case AuthErrorType.AUTHENTICATION_REQUIRED:
      case AuthErrorType.SESSION_EXPIRED:
        return 'default'
      default:
        return 'default'
    }
  }

  const handleAction = (action: string) => {
    if (onAction) {
      onAction(action)
    } else {
      // Default actions
      switch (action) {
        case 'sign_in':
          window.location.href = '/login'
          break
        case 'go_back':
          window.history.back()
          break
        case 'retry':
          window.location.reload()
          break
        case 'contact_support':
          // Open support modal or redirect to support page
          window.open('/support', '_blank')
          break
        default:
          logger.log('Action not handled:', action)
      }
    }
  }

  const renderActions = () => {
    if (!showActions || !error.actions) return null

    return (
      <div className="flex gap-2 mt-4">
        {error.actions.primary && (
          <Button
            onClick={() => handleAction(error.actions!.primary!.action)}
            variant="default"
            size="sm"
          >
            {error.actions.primary.label}
          </Button>
        )}
        {error.actions.secondary && (
          <Button
            onClick={() => handleAction(error.actions!.secondary!.action)}
            variant="outline"
            size="sm"
          >
            {error.actions.secondary.label}
          </Button>
        )}
      </div>
    )
  }

  if (variant === 'card') {
    return (
      <Card className={`max-w-md mx-auto ${className}`}>
        <CardHeader className="pb-4">
          <div className="flex items-center gap-2">
            {getIcon()}
            <CardTitle className="text-lg">{error.title}</CardTitle>
          </div>
        </CardHeader>
        <CardContent>
          <CardDescription className="mb-4">
            {error.message}
          </CardDescription>
          {renderActions()}
        </CardContent>
      </Card>
    )
  }

  if (variant === 'full-page') {
    return (
      <div className={`min-h-[50vh] flex items-center justify-center ${className}`}>
        <div className="text-center max-w-md mx-auto p-6">
          <div className="flex justify-center mb-4">
            <div className="p-3 bg-red-100 dark:bg-red-900/20 rounded-full">
              {getIcon()}
            </div>
          </div>
          <h1 className="text-2xl font-bold mb-2">{error.title}</h1>
          <p className="text-muted-foreground mb-6">{error.message}</p>
          {renderActions()}
        </div>
      </div>
    )
  }

  // Default alert variant
  return (
    <Alert variant={getVariant() as any} className={className}>
      {getIcon()}
      <AlertTitle>{error.title}</AlertTitle>
      <AlertDescription>
        {error.message}
        {renderActions()}
      </AlertDescription>
    </Alert>
  )
}

/**
 * Specific component for RLS violations
 */
export function RLSViolationError({
  resource,
  action,
  onContactSupport,
  onGoBack,
  className = ''
}: {
  resource?: string
  action?: string
  onContactSupport?: () => void
  onGoBack?: () => void
  className?: string
}) {
  const contextMessage = resource && action
    ? `You don't have permission to ${action} ${resource}.`
    : "You don't have permission to perform this action."

  const error: UserFriendlyError = {
    type: AuthErrorType.RLS_VIOLATION,
    title: 'Access Denied',
    message: `${contextMessage} Please contact your administrator if you believe this is an error.`,
    actionable: true,
    retryable: false,
    actions: {
      primary: {
        label: 'Contact Support',
        action: 'contact_support'
      },
      secondary: {
        label: 'Go Back',
        action: 'go_back'
      }
    }
  }

  return (
    <PermissionError
      error={error}
      onAction={(action) => {
        switch (action) {
          case 'contact_support':
            onContactSupport?.()
            break
          case 'go_back':
            onGoBack?.()
            break
        }
      }}
      className={className}
    />
  )
}

/**
 * Component for authentication required errors
 */
export function AuthRequiredError({
  onSignIn,
  message,
  className = ''
}: {
  onSignIn?: () => void
  message?: string
  className?: string
}) {
  const error: UserFriendlyError = {
    type: AuthErrorType.AUTHENTICATION_REQUIRED,
    title: 'Authentication Required',
    message: message || 'You need to sign in to access this content.',
    actionable: true,
    retryable: false,
    actions: {
      primary: {
        label: 'Sign In',
        action: 'sign_in'
      }
    }
  }

  return (
    <PermissionError
      error={error}
      onAction={(action) => {
        if (action === 'sign_in') {
          onSignIn?.()
        }
      }}
      className={className}
      variant="card"
    />
  )
}

/**
 * Component for session expired errors
 */
export function SessionExpiredError({
  onSignIn,
  className = ''
}: {
  onSignIn?: () => void
  className?: string
}) {
  const error: UserFriendlyError = {
    type: AuthErrorType.SESSION_EXPIRED,
    title: 'Session Expired',
    message: 'Your session has expired. Please sign in again to continue.',
    actionable: true,
    retryable: false,
    actions: {
      primary: {
        label: 'Sign In Again',
        action: 'sign_in'
      }
    }
  }

  return (
    <PermissionError
      error={error}
      onAction={(action) => {
        if (action === 'sign_in') {
          onSignIn?.()
        }
      }}
      className={className}
      variant="card"
    />
  )
}

/**
 * Component for network/connection errors
 */
export function NetworkError({
  onRetry,
  className = ''
}: {
  onRetry?: () => void
  className?: string
}) {
  const error: UserFriendlyError = {
    type: AuthErrorType.NETWORK_ERROR,
    title: 'Connection Error',
    message: 'Unable to connect to the server. Please check your internet connection and try again.',
    actionable: true,
    retryable: true,
    actions: {
      primary: {
        label: 'Retry',
        action: 'retry'
      }
    }
  }

  return (
    <PermissionError
      error={error}
      onAction={(action) => {
        if (action === 'retry') {
          onRetry?.()
        }
      }}
      className={className}
    />
  )
}

/**
 * Inline permission check component
 */
export function PermissionGuard({
  children,
  fallback,
  hasPermission,
  fallbackType = 'alert'
}: {
  children: React.ReactNode
  fallback?: React.ReactNode
  hasPermission: boolean
  fallbackType?: 'alert' | 'card' | 'full-page'
}) {
  if (hasPermission) {
    return <>{children}</>
  }

  if (fallback) {
    return <>{fallback}</>
  }

  return (
    <RLSViolationError
      className={fallbackType === 'full-page' ? 'min-h-[200px]' : ''}
    />
  )
}

/**
 * Hook for handling errors in components
 */
export function useErrorHandler() {
  const showError = (error: any, context?: string) => {
    // This would integrate with your toast/notification system
    logger.error('Error occurred:', error, context)

    // Example toast implementation (adjust based on your toast library)
    // toast({
    //   title: error.title,
    //   description: error.message,
    //   variant: 'destructive',
    // })
  }

  const handleAuthError = (error: any, context?: string) => {
    const userFriendlyError = createUserFriendlyError(error, context)
    showError(userFriendlyError, context)
    return userFriendlyError
  }

  return {
    showError,
    handleAuthError
  }
}

