// Inspired by react-hot-toast library
import * as React from "react"

import type {
  ToastActionElement,
  ToastProps,
} from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: 'ADD_TOAST'
      toast: ToasterToast
    }
  | {
      type: 'UPDATE_TOAST'
      toast: Partial<ToasterToast>
    }
  | {
      type: 'DISMISS_TOAST'
      toastId?: string | undefined
    }
  | {
      type: 'REMOVE_TOAST'
      toastId?: string | undefined
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, "id">

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id as string })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => {
      if (toastId !== undefined) {
        dispatch({ type: "DISMISS_TOAST", toastId: toastId as string })
      } else {
        dispatch({ type: "DISMISS_TOAST" })
      }
    },
  }
}

export { useToast, toast }

/**
 * WhatsApp Integration Dashboard
 * Main component that combines instance management, messaging, and statistics
 */
import React, { useState, useEffect } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Badge } from '@/components/ui/badge';
import {
  MessageSquare,
  Users,
  Activity,
  TrendingUp,
  AlertCircle,
  CheckCircle,
  Clock,
  Phone,
  BarChart3
} from 'lucide-react';
import { WhatsAppInstanceManager } from './WhatsAppInstanceManager';
import { WhatsAppMessageSender } from './WhatsAppMessageSender';
import { whatsAppService } from '../../services/whatsapp/WhatsAppService';
import { useConfig } from '@/lib/config-initializer';
import { createLogger } from '@/lib/logger';

export interface WhatsAppInstance {
  name: string;
  isConnected: boolean;
  phoneNumber?: string;
  profileName?: string;
  status: string;
  createdAt: string;
}

export interface QueueStats {
  pending: number;
  scheduled: number;
  retryScheduled: number;
  deadLetter: number;
}

interface StatCard {
  title: string;
  value: string | number;
  icon: React.ReactNode;
  description?: string;
  trend?: {
    value: number;
    isPositive: boolean;
  };
}

const logger = createLogger('WhatsAppDashboard');

export const WhatsAppDashboard: React.FC = () => {
  const { config } = useConfig()
  const [selectedInstance, setSelectedInstance] = useState<WhatsAppInstance | null>(null);
  const [queueStats, setQueueStats] = useState<QueueStats | null>(null);
  const [messageStats, setMessageStats] = useState<Record<string, number> | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isEvolutionEnabled, setIsEvolutionEnabled] = useState(false);

  useEffect(() => {
    // Check if Evolution API is enabled
    setIsEvolutionEnabled(config?.VITE_ENABLE_EVOLUTION === 'true');

    if (config?.VITE_ENABLE_EVOLUTION === 'true') {
      loadDashboardData();

      // Refresh data every 30 seconds
      const interval = setInterval(loadDashboardData, 30000);
      return () => clearInterval(interval);
    }

    // Return undefined if Evolution API is disabled
    return undefined;
  }, [config]);

  const loadDashboardData = async () => {
    try {
      setLoading(true);
      setError(null);

      // Load queue statistics
      const queueResponse = await whatsAppService.getQueueStats();
      setQueueStats(queueResponse.queueStatistics);

      // Load message statistics for selected instance
      if (selectedInstance) {
        const statsResponse = await whatsAppService.getMessageStatistics(selectedInstance.name);
        setMessageStats(statsResponse.statistics);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const handleInstanceSelected = (instance: WhatsAppInstance) => {
    setSelectedInstance(instance);
    // Load statistics for the selected instance
    if (instance.isConnected) {
      loadMessageStatistics(instance.name);
    }
  };

  const loadMessageStatistics = async (instanceName: string) => {
    try {
      const response = await whatsAppService.getMessageStatistics(instanceName);
      setMessageStats(response.statistics);
    } catch (err) {
      logger.error('Failed to load message statistics:', err);
    }
  };

  const getStatCards = (): StatCard[] => {
    const cards: StatCard[] = [];

    if (selectedInstance) {
      cards.push({
        title: 'Instance Status',
        value: selectedInstance.isConnected ? 'Connected' : 'Disconnected',
        icon: selectedInstance.isConnected ?
          <CheckCircle className="w-5 h-5 text-green-500" /> :
          <AlertCircle className="w-5 h-5 text-red-500" />,
        description: selectedInstance.phoneNumber || 'No phone number'
      });
    }

    if (queueStats) {
      cards.push(
        {
          title: 'Pending Messages',
          value: queueStats.pending,
          icon: <Clock className="w-5 h-5 text-orange-500" />,
          description: 'Messages in queue'
        },
        {
          title: 'Scheduled Messages',
          value: queueStats.scheduled,
          icon: <TrendingUp className="w-5 h-5 text-blue-500" />,
          description: 'Future deliveries'
        },
        {
          title: 'Failed Messages',
          value: queueStats.deadLetter,
          icon: <AlertCircle className="w-5 h-5 text-red-500" />,
          description: 'Requires attention'
        }
      );
    }

    if (messageStats) {
      cards.push(
        {
          title: 'Total Messages',
          value: messageStats['total'] || 0,
          icon: <MessageSquare className="w-5 h-5 text-blue-500" />,
          description: 'All time'
        },
        {
          title: 'Delivered Today',
          value: messageStats['delivered'] || 0,
          icon: <CheckCircle className="w-5 h-5 text-green-500" />,
          description: 'Successfully delivered'
        },
        {
          title: 'Read Rate',
          value: messageStats && messageStats['total'] && messageStats['total'] > 0 ?
            `${Math.round(((messageStats['read'] || 0) / messageStats['total']) * 100)}%` : '0%',
          icon: <Activity className="w-5 h-5 text-purple-500" />,
          description: 'Message engagement'
        }
      );
    }

    return cards;
  };

  if (!isEvolutionEnabled) {
    return (
      <Card>
        <CardContent className="p-8 text-center">
          <Phone className="w-16 h-16 mx-auto mb-4 text-gray-400" />
          <h2 className="text-xl font-semibold mb-2">WhatsApp Integration Disabled</h2>
          <p className="text-gray-600 mb-4">
            WhatsApp integration is currently disabled. To enable it, set <code>VITE_ENABLE_EVOLUTION=true</code> in your environment variables.
          </p>
          <Alert>
            <AlertCircle className="w-4 h-4" />
            <AlertDescription>
              Make sure you have Evolution API configured and running before enabling this feature.
            </AlertDescription>
          </Alert>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">WhatsApp Integration</h1>
          <p className="text-gray-600">Manage WhatsApp instances and send messages to patients</p>
        </div>
        {selectedInstance && (
          <Badge variant={selectedInstance.isConnected ? "default" : "secondary"} className="px-3 py-1">
            {selectedInstance.name} - {selectedInstance.isConnected ? 'Connected' : 'Disconnected'}
          </Badge>
        )}
      </div>

      {/* Error Alert */}
      {error && (
        <Alert variant="destructive">
          <AlertCircle className="w-4 h-4" />
          <AlertDescription>{error}</AlertDescription>
        </Alert>
      )}

      {/* Statistics Cards */}
      {getStatCards().length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          {getStatCards().map((stat, index) => (
            <Card key={index}>
              <CardContent className="p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">{stat.title}</p>
                    <p className="text-2xl font-bold">{stat.value}</p>
                    {stat.description && (
                      <p className="text-xs text-gray-500">{stat.description}</p>
                    )}
                  </div>
                  {stat.icon}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Main Content */}
      <Tabs defaultValue="instances" className="space-y-4">
        <TabsList className="grid w-full grid-cols-3">
          <TabsTrigger value="instances" className="flex items-center gap-2">
            <Phone className="w-4 h-4" />
            Instances
          </TabsTrigger>
          <TabsTrigger value="messaging" className="flex items-center gap-2">
            <MessageSquare className="w-4 h-4" />
            Send Messages
          </TabsTrigger>
          <TabsTrigger value="analytics" className="flex items-center gap-2">
            <BarChart3 className="w-4 h-4" />
            Analytics
          </TabsTrigger>
        </TabsList>

        <TabsContent value="instances">
          <WhatsAppInstanceManager onInstanceSelected={handleInstanceSelected} />
        </TabsContent>

        <TabsContent value="messaging">
          {selectedInstance?.isConnected ? (
            <WhatsAppMessageSender
              instanceName={selectedInstance.name}
              onMessageSent={(response) => {
                // Refresh statistics after sending a message
                loadMessageStatistics(selectedInstance.name);
              }}
              onError={setError}
            />
          ) : (
            <Card>
              <CardContent className="p-8 text-center">
                <MessageSquare className="w-16 h-16 mx-auto mb-4 text-gray-400" />
                <h3 className="text-lg font-semibold mb-2">No Connected Instance</h3>
                <p className="text-gray-600">
                  Please select and connect a WhatsApp instance to send messages.
                </p>
              </CardContent>
            </Card>
          )}
        </TabsContent>

        <TabsContent value="analytics">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Message Statistics */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <BarChart3 className="w-5 h-5" />
                  Message Statistics
                </CardTitle>
              </CardHeader>
              <CardContent>
                {messageStats ? (
                  <div className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                      <div className="text-center p-3 bg-blue-50 rounded">
                        <p className="text-2xl font-bold text-blue-600">{messageStats['total'] || 0}</p>
                        <p className="text-sm text-blue-600">Total Messages</p>
                      </div>
                      <div className="text-center p-3 bg-green-50 rounded">
                        <p className="text-2xl font-bold text-green-600">{messageStats['sent'] || 0}</p>
                        <p className="text-sm text-green-600">Sent</p>
                      </div>
                      <div className="text-center p-3 bg-orange-50 rounded">
                        <p className="text-2xl font-bold text-orange-600">{messageStats['delivered'] || 0}</p>
                        <p className="text-sm text-orange-600">Delivered</p>
                      </div>
                      <div className="text-center p-3 bg-purple-50 rounded">
                        <p className="text-2xl font-bold text-purple-600">{messageStats['read'] || 0}</p>
                        <p className="text-sm text-purple-600">Read</p>
                      </div>
                    </div>

                    {messageStats && messageStats['failed'] && messageStats['failed'] > 0 && (
                      <div className="text-center p-3 bg-red-50 rounded">
                        <p className="text-2xl font-bold text-red-600">{messageStats['failed']}</p>
                        <p className="text-sm text-red-600">Failed Messages</p>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="text-center py-8 text-gray-500">
                    <BarChart3 className="w-12 h-12 mx-auto mb-4 opacity-50" />
                    <p>No statistics available</p>
                    <p className="text-sm">Send some messages to see analytics</p>
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Queue Status */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Activity className="w-5 h-5" />
                  Queue Status
                </CardTitle>
              </CardHeader>
              <CardContent>
                {queueStats ? (
                  <div className="space-y-4">
                    <div className="flex justify-between items-center p-3 bg-gray-50 rounded">
                      <span className="font-medium">Pending</span>
                      <Badge variant="secondary">{queueStats.pending}</Badge>
                    </div>
                    <div className="flex justify-between items-center p-3 bg-blue-50 rounded">
                      <span className="font-medium">Scheduled</span>
                      <Badge variant="default">{queueStats.scheduled}</Badge>
                    </div>
                    <div className="flex justify-between items-center p-3 bg-orange-50 rounded">
                      <span className="font-medium">Retry Queue</span>
                      <Badge variant="outline">{queueStats.retryScheduled}</Badge>
                    </div>
                    {queueStats.deadLetter > 0 && (
                      <div className="flex justify-between items-center p-3 bg-red-50 rounded">
                        <span className="font-medium">Failed</span>
                        <Badge variant="destructive">{queueStats.deadLetter}</Badge>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="text-center py-8 text-gray-500">
                    <Activity className="w-12 h-12 mx-auto mb-4 opacity-50" />
                    <p>Queue statistics unavailable</p>
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
};

export default WhatsAppDashboard;

/**
 * WhatsApp Instance Manager Component
 * Manages WhatsApp instances, QR codes, and connection status
 */
import React, { useState, useEffect, useCallback } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Alert, AlertDescription } from '@/components/ui/alert';
import {
  Phone,
  QrCode,
  RefreshCw,
  Trash2,
  Plus,
  CheckCircle,
  XCircle,
  Clock,
  User,
  Activity
} from 'lucide-react';
import { whatsAppService, WhatsAppInstance } from '../../services/whatsapp/WhatsAppService';
import { createLogger } from '@/lib/logger';
import { useToast } from '@/components/ui/use-toast';

interface WhatsAppInstanceManagerProps {
  onInstanceSelected?: (instance: WhatsAppInstance) => void;
}

const logger = createLogger('WhatsAppInstanceManager');

export const WhatsAppInstanceManager: React.FC<WhatsAppInstanceManagerProps> = ({
  onInstanceSelected
}) => {
  const { toast } = useToast()
  const [instances, setInstances] = useState<WhatsAppInstance[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [newInstanceName, setNewInstanceName] = useState('');
  const [creatingInstance, setCreatingInstance] = useState(false);
  const [qrCodes, setQrCodes] = useState<Record<string, string>>({});
  const [selectedInstance, setSelectedInstance] = useState<string | null>(null);
  const [confirmDeleteName, setConfirmDeleteName] = useState<string | null>(null);

  const loadInstances = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const response = await whatsAppService.listInstances();
      setInstances(response.instances);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load instances');
    } finally {
      setLoading(false);
    }
  }, []);

  const createInstance = async () => {
    if (!newInstanceName.trim()) {
      setError('Instance name is required');
      return;
    }

    try {
      setCreatingInstance(true);
      setError(null);

      await whatsAppService.createInstance(newInstanceName.trim());
      setNewInstanceName('');
      await loadInstances();

      // Auto-load QR code for new instance
      setTimeout(() => loadQrCode(newInstanceName.trim()), 1000);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to create instance');
    } finally {
      setCreatingInstance(false);
    }
  };

  const deleteInstance = async (instanceName: string) => {
    if (confirmDeleteName === instanceName) {
      setConfirmDeleteName(null)
      try {
        setError(null);
        await whatsAppService.deleteInstance(instanceName);
        await loadInstances();
        setQrCodes(prev => {
          const updated = { ...prev };
          delete updated[instanceName];
          return updated;
        });
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to delete instance');
      }
      return
    }
    setConfirmDeleteName(instanceName)
    toast({
      title: 'Confirm deletion',
      description: `Click delete again to remove instance "${instanceName}"`,
      variant: 'destructive'
    })
    setTimeout(() => {
      setConfirmDeleteName((prev) => (prev === instanceName ? null : prev))
    }, 3000)
  };

  const restartInstance = async (instanceName: string) => {
    try {
      setError(null);
      await whatsAppService.restartInstance(instanceName);
      await loadInstances();

      // Load QR code after restart
      setTimeout(() => loadQrCode(instanceName), 2000);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to restart instance');
    }
  };

  const loadQrCode = async (instanceName: string) => {
    try {
      const response = await whatsAppService.getQrCode(instanceName);
      setQrCodes(prev => ({
        ...prev,
        [instanceName]: response.qr_code
      }));
    } catch (err) {
      // QR code might not be available if already connected
      logger.log(`QR code not available for ${instanceName}:`, err);
    }
  };

  const refreshInstanceStatus = async (instanceName: string) => {
    try {
      const instance = await whatsAppService.getInstanceStatus(instanceName);
      setInstances(prev =>
        prev.map(inst =>
          inst.name === instanceName
            ? { ...inst, ...instance }
            : inst
        )
      );

      if (!instance.isConnected) {
        await loadQrCode(instanceName);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to refresh status');
    }
  };

  const handleInstanceSelect = (instance: WhatsAppInstance) => {
    setSelectedInstance(instance.name);
    onInstanceSelected?.(instance);
  };

  const getStatusBadge = (instance: WhatsAppInstance) => {
    if (instance.isConnected) {
      return <Badge variant="default" className="bg-green-500"><CheckCircle className="w-3 h-3 mr-1" />Connected</Badge>;
    } else if (instance.status === 'created' || instance.status === 'disconnected') {
      return <Badge variant="secondary"><Clock className="w-3 h-3 mr-1" />Waiting</Badge>;
    } else {
      return <Badge variant="destructive"><XCircle className="w-3 h-3 mr-1" />Disconnected</Badge>;
    }
  };

  useEffect(() => {
    loadInstances();

    // Refresh instances every 30 seconds
    const interval = setInterval(loadInstances, 30000);
    return () => clearInterval(interval);
  }, [loadInstances]);

  return (
    <div className="space-y-6">
      {/* Create New Instance */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Plus className="w-5 h-5" />
            Create WhatsApp Instance
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          {error && (
            <Alert variant="destructive">
              <AlertDescription>{error}</AlertDescription>
            </Alert>
          )}

          <div className="flex gap-2">
            <div className="flex-1">
              <Label htmlFor="instanceName">Instance Name</Label>
              <Input
                id="instanceName"
                value={newInstanceName}
                onChange={(e) => setNewInstanceName(e.target.value)}
                placeholder="e.g., clinic-main, reception-desk"
                disabled={creatingInstance}
              />
            </div>
            <div className="flex items-end">
              <Button
                onClick={createInstance}
                disabled={creatingInstance || !newInstanceName.trim()}
              >
                {creatingInstance ? <RefreshCw className="w-4 h-4 animate-spin" /> : <Plus className="w-4 h-4" />}
                Create
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Instances List */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center justify-between">
            <span className="flex items-center gap-2">
              <Phone className="w-5 h-5" />
              WhatsApp Instances ({instances.length})
            </span>
            <Button variant="outline" size="sm" onClick={loadInstances} disabled={loading}>
              <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
              Refresh
            </Button>
          </CardTitle>
        </CardHeader>
        <CardContent>
          {loading && instances.length === 0 ? (
            <div className="text-center py-8">
              <RefreshCw className="w-8 h-8 animate-spin mx-auto mb-2" />
              <p>Loading instances...</p>
            </div>
          ) : instances.length === 0 ? (
            <div className="text-center py-8 text-gray-500">
              <Phone className="w-12 h-12 mx-auto mb-4 opacity-50" />
              <p>No WhatsApp instances found</p>
              <p className="text-sm">Create your first instance to get started</p>
            </div>
          ) : (
            <div className="space-y-4">
              {instances.map((instance) => (
                <Card
                  key={instance.name}
                  className={`cursor-pointer transition-all hover:shadow-md ${
                    selectedInstance === instance.name ? 'ring-2 ring-blue-500' : ''
                  }`}
                  onClick={() => handleInstanceSelect(instance)}
                >
                  <CardContent className="p-4">
                    <div className="flex items-center justify-between mb-3">
                      <div className="flex items-center gap-3">
                        <div className="flex flex-col">
                          <h3 className="font-medium">{instance.name}</h3>
                          <p className="text-sm text-gray-500">
                            Created {new Date(instance.createdAt).toLocaleDateString()}
                          </p>
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                        {getStatusBadge(instance)}
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={(e) => {
                            e.stopPropagation();
                            refreshInstanceStatus(instance.name);
                          }}
                        >
                          <Activity className="w-3 h-3" />
                        </Button>
                      </div>
                    </div>

                    {instance.isConnected && (
                      <div className="flex items-center gap-4 mb-3 p-2 bg-green-50 rounded">
                        <User className="w-4 h-4 text-green-600" />
                        <div className="text-sm">
                          <p className="font-medium">{instance.profileName || 'WhatsApp User'}</p>
                          <p className="text-gray-600">{instance.phoneNumber}</p>
                        </div>
                      </div>
                    )}

                    {!instance.isConnected && qrCodes[instance.name] && (
                      <div className="mb-3 p-4 bg-gray-50 rounded text-center">
                        <QrCode className="w-6 h-6 mx-auto mb-2" />
                        <p className="text-sm font-medium mb-2">Scan QR Code with WhatsApp</p>
                        <div className="bg-white p-2 rounded inline-block">
                          <img
                            src={`data:image/png;base64,${qrCodes[instance.name]}`}
                            alt="QR Code"
                            className="w-32 h-32"
                          />
                        </div>
                        <p className="text-xs text-gray-500 mt-2">
                          Open WhatsApp ÔåÆ Settings ÔåÆ Linked Devices ÔåÆ Link a Device
                        </p>
                      </div>
                    )}

                    <div className="flex gap-2 justify-end">
                      {!instance.isConnected && (
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={(e) => {
                            e.stopPropagation();
                            loadQrCode(instance.name);
                          }}
                        >
                          <QrCode className="w-3 h-3 mr-1" />
                          Show QR
                        </Button>
                      )}

                      <Button
                        variant="outline"
                        size="sm"
                        onClick={(e) => {
                          e.stopPropagation();
                          restartInstance(instance.name);
                        }}
                      >
                        <RefreshCw className="w-3 h-3 mr-1" />
                        Restart
                      </Button>

                      <Button
                        variant="outline"
                        size="sm"
                        onClick={(e) => {
                          e.stopPropagation();
                          deleteInstance(instance.name);
                        }}
                        className="text-red-600 hover:text-red-700"
                      >
                        <Trash2 className="w-3 h-3 mr-1" />
                        Delete
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

export default WhatsAppInstanceManager;

