            Obrigado por completar o question├írio mensal. Suas respostas foram registradas com sucesso.
          </p>
        </div>
      </div>
    );
  }

  if (!quizData) {
    return null;
  }

  const currentQuestion = quizData.questions[currentQuestionIndex];
  const progress = ((currentQuestionIndex + 1) / quizData.total_questions) * 100;

  return (
    <div className="min-h-screen bg-gray-100 py-8 px-4">
      <div className="max-w-2xl mx-auto">
        {/* Header */}
        <div className="bg-white p-6 rounded-lg shadow-md mb-6">
          <h1 className="text-2xl font-bold mb-2">{quizData.template_name}</h1>
          <p className="text-gray-600">Ol├í, {quizData.patient_name}</p>

          {/* Progress Bar */}
          <div className="mt-4">
            <div className="flex justify-between text-sm text-gray-600 mb-2">
              <span>Pergunta {currentQuestionIndex + 1} de {quizData.total_questions}</span>
              <span>{Math.round(progress)}%</span>
            </div>
            <div className="w-full bg-gray-200 rounded-full h-2">
              <div
                className="bg-blue-600 h-2 rounded-full transition-all duration-300"
                style={{ width: `${progress}%` }}
              ></div>
            </div>
          </div>
        </div>

        {/* Question */}
        <div className="bg-white p-6 rounded-lg shadow-md">
          <h2 className="text-lg font-semibold mb-4">{currentQuestion.text}</h2>

          {currentQuestion.description && (
            <p className="text-gray-600 mb-4">{currentQuestion.description}</p>
          )}

          {/* Answer Input based on question type */}
          {currentQuestion.type === 'multiple_choice' && (
            <div className="space-y-2">
              {currentQuestion.options?.map((option: any) => (
                <label key={option.id} className="flex items-center p-3 border rounded hover:bg-gray-50 cursor-pointer">
                  <input
                    type="radio"
                    name={currentQuestion.id}
                    value={option.id}
                    checked={answers[currentQuestion.id] === option.id}
                    onChange={(e) => handleAnswer(currentQuestion.id, e.target.value)}
                    className="mr-3"
                  />
                  <span>{option.text}</span>
                </label>
              ))}
            </div>
          )}

          {currentQuestion.type === 'open_text' && (
            <textarea
              value={answers[currentQuestion.id] || ''}
              onChange={(e) => handleAnswer(currentQuestion.id, e.target.value)}
              className="w-full p-3 border rounded"
              rows={4}
              placeholder="Digite sua resposta aqui..."
            />
          )}

          {currentQuestion.type === 'scale' && (
            <div>
              <input
                type="range"
                min={currentQuestion.validation_rules?.[0]?.min || 0}
                max={currentQuestion.validation_rules?.[0]?.max || 10}
                value={answers[currentQuestion.id] || 5}
                onChange={(e) => handleAnswer(currentQuestion.id, e.target.value)}
                className="w-full"
              />
              <div className="text-center text-2xl font-bold mt-2">
                {answers[currentQuestion.id] || 5}
              </div>
            </div>
          )}

          {submissionError && (
            <p className="mt-4 text-sm text-red-600">{submissionError}</p>
          )}

          {/* Submit Button */}
          <button
            onClick={handleSubmit}
            disabled={!answers[currentQuestion.id] || loading}
            className="w-full mt-6 py-3 px-4 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:bg-gray-400 disabled:cursor-not-allowed"
          >
            {currentQuestionIndex < quizData.total_questions - 1 ? 'Pr├│xima' : 'Finalizar'}
          </button>
        </div>
      </div>
    </div>
  );
};

/**
 * Quiz Link Generator Component
 *
 * Component for creating monthly quiz links in the admin interface.
 */
import React, { useState } from 'react';
import { useMonthlyQuiz } from '../hooks/useMonthlyQuiz';
import type { DeliveryMethod } from '../types';
import { MonthlyQuizLinkCreate } from '../types';

interface QuizLinkGeneratorProps {
  patientId: string;
  quizTemplateId: string;
  onLinkCreated?: (link: any) => void;
}

export const QuizLinkGenerator: React.FC<QuizLinkGeneratorProps> = ({
  patientId,
  quizTemplateId,
  onLinkCreated
}) => {
  const { createQuizLink, loading, error } = useMonthlyQuiz();
  const [deliveryMethod, setDeliveryMethod] = useState<DeliveryMethod>('whatsapp');
  const [expiryHours, setExpiryHours] = useState<number>(72);
  const [customMessage, setCustomMessage] = useState<string>('');
  const [generatedLink, setGeneratedLink] = useState<string | null>(null);

  const handleGenerateLink = async () => {
    const linkData: MonthlyQuizLinkCreate = {
      patient_id: patientId,
      quiz_template_id: quizTemplateId,
      delivery_method: deliveryMethod,
      expiry_hours: expiryHours,
      ...(customMessage && { custom_message: customMessage })
    };

    const link = await createQuizLink(linkData);

    if (link) {
      setGeneratedLink(link.link_url ?? link.link ?? null);
      onLinkCreated?.(link);
    }
  };

  const copyToClipboard = () => {
    if (generatedLink) {
      navigator.clipboard.writeText(generatedLink);
      alert('Link copiado para ├írea de transfer├¬ncia!');
    }
  };

  return (
    <div className="quiz-link-generator p-4 border rounded-lg">
      <h3 className="text-lg font-semibold mb-4">Gerar Link de Quiz Mensal</h3>

      <div className="space-y-4">
        {/* Delivery Method */}
        <div>
          <label className="block text-sm font-medium mb-2">M├®todo de Entrega</label>
          <select
            value={deliveryMethod}
            onChange={(e) => setDeliveryMethod(e.target.value as DeliveryMethod)}
            className="w-full p-2 border rounded"
          >
            <option value={'whatsapp'}>WhatsApp</option>
            <option value={'email'}>Email</option>
            <option value={'sms'}>SMS</option>
            <option value={'manual'}>Manual</option>
          </select>
        </div>

        {/* Expiry Hours */}
        <div>
          <label className="block text-sm font-medium mb-2">Validade (horas)</label>
          <input
            type="number"
            value={expiryHours}
            onChange={(e) => setExpiryHours(parseInt(e.target.value))}
            className="w-full p-2 border rounded"
            min="1"
            max="720"
          />
        </div>

        {/* Custom Message */}
        <div>
          <label className="block text-sm font-medium mb-2">Mensagem Personalizada (Opcional)</label>
          <textarea
            value={customMessage}
            onChange={(e) => setCustomMessage(e.target.value)}
            className="w-full p-2 border rounded"
            rows={3}
            placeholder="Digite uma mensagem personalizada para o paciente..."
          />
        </div>

        {/* Error Display */}
        {error && (
          <div className="p-3 bg-red-100 text-red-700 rounded">
            {error}
          </div>
        )}

        {/* Generated Link Display */}
        {generatedLink && (
          <div className="p-3 bg-green-100 rounded">
            <p className="text-sm font-medium mb-2">Link Gerado:</p>
            <div className="flex items-center space-x-2">
              <input
                type="text"
                value={generatedLink}
                readOnly
                className="flex-1 p-2 border rounded bg-white"
              />
              <button
                onClick={copyToClipboard}
                className="px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600"
              >
                Copiar
              </button>
            </div>
          </div>
        )}

        {/* Generate Button */}
        <button
          onClick={handleGenerateLink}
          disabled={loading}
          className="w-full py-2 px-4 bg-blue-600 text-white rounded hover:bg-blue-700 disabled:bg-gray-400"
        >
          {loading ? 'Gerando...' : 'Gerar Link'}
        </button>
      </div>
    </div>
  );
};

/**
 * Monthly Quiz Hook for Frontend
 *
 * React hook for managing monthly quiz via link functionality.
 */
import { useState, useCallback } from 'react';
import { apiClient } from '@/lib/api-client';
import type { QuizLinkStatus as ApiQuizLinkStatus } from '@/lib/api-client/monthly-quiz';

// Define types inline since ../types doesn't exist
interface MonthlyQuizLinkCreate {
  patient_id: string
  quiz_template_id: string
  expires_in_days?: number
}

interface MonthlyQuizLink {
  session_id?: string
  quiz_session_id?: string
  patient_id: string
  quiz_template_id: string
  link_url?: string
  link?: string
  expires_at: string
  created_at: string
}

interface MonthlyQuizAccessRequest {
  token: string
}

// Import types from centralized location
import type { MonthlyQuizAccess, MonthlyQuizSubmit } from '../types'

interface MonthlyQuizStats {
  total_sent: number
  total_accessed?: number
  total_active?: number
  total_completed: number
  total_expired?: number
  completion_rate: number
  average_score?: number
  expiration_rate?: number
}

// Import bulk types from centralized location
import type { BulkQuizLinkCreate, BulkQuizLinkResponse } from '../types'

export interface UseMonthlyQuizReturn {
  loading: boolean
  error: string | null
  createQuizLink: (linkData: MonthlyQuizLinkCreate) => Promise<MonthlyQuizLink | null>
  createBulkQuizLinks: (bulkData: BulkQuizLinkCreate) => Promise<BulkQuizLinkResponse | null>
  getQuizLinkStatus: (sessionId: string) => Promise<ApiQuizLinkStatus | null>
  getQuizStats: (startDate?: string, endDate?: string) => Promise<MonthlyQuizStats | null>
  accessQuiz: (token: string) => Promise<MonthlyQuizAccess | null>
  submitQuizResponse: (submitData: MonthlyQuizSubmit) => Promise<{ success: boolean; message: string } | null>
}

export function useMonthlyQuiz(): UseMonthlyQuizReturn {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  /**
   * Create a monthly quiz link for a patient
   */
  const createQuizLink = useCallback(async (
    linkData: MonthlyQuizLinkCreate
  ): Promise<MonthlyQuizLink | null> => {
    setLoading(true);
    setError(null);

    try {
      const response = await apiClient.monthlyQuiz.createLink(linkData);
      return response;
    } catch (err: any) {
      setError(err.message || 'Failed to create quiz link');
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  /**
   * Create quiz links for multiple patients
   */
  const createBulkQuizLinks = useCallback(async (
    bulkData: BulkQuizLinkCreate
  ): Promise<BulkQuizLinkResponse | null> => {
    setLoading(true);
    setError(null);

    try {
      const response = await apiClient.monthlyQuiz.bulkCreate(bulkData);
      return response;
    } catch (err: any) {
      setError(err.message || 'Failed to create bulk quiz links');
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  /**
   * Get quiz link status
   */
  const getQuizLinkStatus = useCallback(async (
    sessionId: string
  ): Promise<ApiQuizLinkStatus | null> => {
    setLoading(true);
    setError(null);

    try {
      const response = await apiClient.monthlyQuiz.getStatus(sessionId);
      return response;
    } catch (err: any) {
      setError(err.message || 'Failed to get quiz link status');
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  /**
   * Get monthly quiz statistics
   */
  const getQuizStats = useCallback(async (
    startDate?: string,
    endDate?: string
  ): Promise<MonthlyQuizStats | null> => {
    setLoading(true);
    setError(null);

    try {
      const params = new URLSearchParams();
      if (startDate) params.append('start_date', startDate);
      if (endDate) params.append('end_date', endDate);

      const statsParams: { start_date?: string; end_date?: string } = {}
      if (startDate) statsParams.start_date = startDate
      if (endDate) statsParams.end_date = endDate

      const response = await apiClient.monthlyQuiz.getStats(statsParams);
      return response;
    } catch (err: any) {
      setError(err.message || 'Failed to get quiz statistics');
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  /**
   * Access quiz via token (public endpoint)
   */
  const accessQuiz = useCallback(async (
    token: string
  ): Promise<MonthlyQuizAccess | null> => {
    setLoading(true);
    setError(null);

    try {
      const response = await apiClient.request<MonthlyQuizAccess>(
        '/api/v2/monthly-quiz-public/access',
        {
          method: 'POST',
          body: JSON.stringify({ token })
        }
      );
      return response;
    } catch (err: any) {
      setError(err.message || 'Failed to access quiz');
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  /**
   * Submit quiz response via token (public endpoint)
   */
  const submitQuizResponse = useCallback(async (
    submitData: MonthlyQuizSubmit
  ): Promise<{ success: boolean; message: string } | null> => {
    setLoading(true);
    setError(null);

    try {
      const response = await apiClient.request<{ success: boolean; message: string }>(
        '/api/v2/monthly-quiz-public/submit',
        {
          method: 'POST',
          body: JSON.stringify(submitData)
        }
      );
      return response;
    } catch (err: any) {
      setError(err.message || 'Failed to submit quiz response');
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  return {
    loading,
    error,
    createQuizLink,
    createBulkQuizLinks,
    getQuizLinkStatus,
    getQuizStats,
    accessQuiz,
    submitQuizResponse
  };
}

