import type { User as ApiUser, AuthTokens as ApiAuthTokens, LoginResponse as ApiLoginResponse } from '@/types/api'

export type User = ApiUser
export type AuthTokens = ApiAuthTokens
export type LoginResponse = ApiLoginResponse

export interface SupabaseAuthData {
  user: any | null  // Removed Supabase dependency
  session: any | null  // Removed Supabase dependency
  loading: boolean
}

export interface SessionData {
  expiry: number | null
  isExpiring: boolean
  timeToExpiry: number
}

export interface PermissionConfig {
  permissions: string[]
  role: string
}

export interface AuthState {
  user: ApiUser | null
  token: string | null
  refreshToken: string | null
  isAuthenticated: boolean
  isLoading: boolean
  sessionExpiry: number | null
}

export interface AuthRetryConfig {
  maxRetries: number
  retryDelay: number
  exponentialBackoff: boolean
}

export interface AuthError extends Error {
  code?: string
  retryable?: boolean
  retryAfter?: number
}

export type AuthEventType = 'SIGNED_IN' | 'SIGNED_OUT' | 'TOKEN_REFRESHED' | 'SESSION_EXPIRED' | 'RETRY_FAILED'

export interface AuthEvent {
  type: AuthEventType
  data?: any
  error?: AuthError
}

export type AuthEventListener = (event: AuthEvent) => void

import { useState, useCallback, useRef } from 'react'
import { AuthError, AuthRetryConfig } from './types'
import { createLogger } from '../../lib/logger'

const logger = createLogger('useAuthRetry')

const DEFAULT_RETRY_CONFIG: AuthRetryConfig = {
  maxRetries: 3,
  retryDelay: 1000,
  exponentialBackoff: true
}

interface UseAuthRetryOptions {
  config?: Partial<AuthRetryConfig>
  onRetryFailed?: (error: AuthError, attempts: number) => void
}

export function useAuthRetry({
  config = {},
  onRetryFailed
}: UseAuthRetryOptions = {}) {
  const retryConfig = { ...DEFAULT_RETRY_CONFIG, ...config }
  const [isRetrying, setIsRetrying] = useState(false)
  const [retryCount, setRetryCount] = useState(0)
  const retryTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  const isRetryableError = useCallback((error: AuthError): boolean => {
    // Don't retry certain errors
    const nonRetryableCodes = [
      'invalid_credentials',
      'user_not_found',
      'invalid_email',
      'weak_password',
      'email_already_exists',
      'unauthorized'
    ]

    if (error.code && nonRetryableCodes.includes(error.code)) {
      return false
    }

    // Explicit retryable flag
    if (error.retryable !== undefined) {
      return error.retryable
    }

    // Network errors are generally retryable
    if (error.message?.includes('network') || error.message?.includes('timeout')) {
      return true
    }

    // Server errors (5xx) are retryable
    if (error.message?.includes('500') || error.message?.includes('502') || error.message?.includes('503')) {
      return true
    }

    return false
  }, [])

  const calculateDelay = useCallback((attempt: number): number => {
    if (!retryConfig.exponentialBackoff) {
      return retryConfig.retryDelay
    }

    // Exponential backoff with jitter
    const exponentialDelay = retryConfig.retryDelay * Math.pow(2, attempt - 1)
    const jitter = Math.random() * 0.1 * exponentialDelay
    return Math.min(exponentialDelay + jitter, 30000) // Max 30 seconds
  }, [retryConfig])

  const executeWithRetry = useCallback(async <T>(
    operation: () => Promise<T>,
    operationName: string = 'auth operation'
  ): Promise<T> => {
    let lastError: AuthError
    let attempt = 0

    while (attempt <= retryConfig.maxRetries) {
      try {
        if (attempt > 0) {
          setIsRetrying(true)
          setRetryCount(attempt)
        }

        const result = await operation()

        // Success - reset retry state
        setIsRetrying(false)
        setRetryCount(0)
        if (retryTimeoutRef.current) {
          clearTimeout(retryTimeoutRef.current)
          retryTimeoutRef.current = null
        }

        return result
      } catch (error) {
        lastError = error as AuthError
        attempt++

        logger.warn(`${operationName} attempt ${attempt} failed:`, lastError.message)

        // Check if we should retry
        if (attempt > retryConfig.maxRetries || !isRetryableError(lastError)) {
          break
        }

        // Wait before retry
        const delay = lastError.retryAfter
          ? Math.max(lastError.retryAfter * 1000, calculateDelay(attempt))
          : calculateDelay(attempt)

        logger.debug(`Retrying ${operationName} in ${delay}ms...`)

        await new Promise(resolve => {
          retryTimeoutRef.current = setTimeout(resolve, delay)
        })
      }
    }

    // All retries exhausted
    setIsRetrying(false)
    setRetryCount(0)

    if (onRetryFailed) {
      onRetryFailed(lastError!, attempt)
    }

    throw lastError!
  }, [retryConfig, isRetryableError, calculateDelay, onRetryFailed])

  const resetRetryState = useCallback(() => {
    setIsRetrying(false)
    setRetryCount(0)
    if (retryTimeoutRef.current) {
      clearTimeout(retryTimeoutRef.current)
      retryTimeoutRef.current = null
    }
  }, [])

  const createAuthError = useCallback((
    message: string,
    code?: string,
    retryable?: boolean,
    retryAfter?: number
  ): AuthError => {
    const error = new Error(message) as AuthError
    if (code) error.code = code
    if (retryable !== undefined) error.retryable = retryable
    if (retryAfter !== undefined) error.retryAfter = retryAfter
    return error
  }, [])

  return {
    executeWithRetry,
    isRetrying,
    retryCount,
    resetRetryState,
    createAuthError,
    isRetryableError,
    config: retryConfig
  }
}

import { useCallback, useMemo } from 'react'
import { User, PermissionConfig } from './types'

interface UsePermissionsOptions {
  user: User | null
  strictMode?: boolean // If true, requires exact permission match
}

export function usePermissions({ user, strictMode = false }: UsePermissionsOptions) {
  const permissions = useMemo(() => user?.permissions ?? [], [user])
  const role = user?.role ?? 'guest'
  const isActive = Boolean(user?.is_active)

  const hasPermission = useCallback((permission: string): boolean => {
    if (permissions.length === 0) return false

    if (strictMode) {
      return permissions.includes(permission)
    }

    // Support wildcard permissions (e.g., "admin.*" grants "admin.users", "admin.settings")
    return permissions.some(userPerm => {
      if (userPerm === permission) return true
      if (userPerm.endsWith('.*')) {
        const basePermission = userPerm.slice(0, -2)
        return permission.startsWith(basePermission + '.')
      }
      return false
    })
  }, [permissions, strictMode])

  const hasRole = useCallback((roleToCheck: string): boolean => {
    return role === roleToCheck
  }, [role])

  const hasAnyRole = useCallback((roles: string[]): boolean => {
    return roles.some(role => hasRole(role))
  }, [hasRole])

  const hasAllPermissions = useCallback((permissions: string[]): boolean => {
    return permissions.every(permission => hasPermission(permission))
  }, [hasPermission])

  const hasAnyPermission = useCallback((permissions: string[]): boolean => {
    return permissions.some(permission => hasPermission(permission))
  }, [hasPermission])

  const isAdmin = useCallback((): boolean => {
    return hasRole('admin') || hasPermission('admin.*')
  }, [hasRole, hasPermission])

  const isSuperAdmin = useCallback((): boolean => {
    return hasRole('superadmin') || hasPermission('superadmin.*')
  }, [hasRole, hasPermission])

  const canAccessResource = useCallback((resource: string, action: string = 'read'): boolean => {
    const permission = `${resource}.${action}`
    return hasPermission(permission) || isAdmin()
  }, [hasPermission, isAdmin])

  const getPermissionLevel = useCallback((basePermission: string): 'none' | 'read' | 'write' | 'admin' => {
    if (hasPermission(`${basePermission}.admin`) || isAdmin()) return 'admin'
    if (hasPermission(`${basePermission}.write`)) return 'write'
    if (hasPermission(`${basePermission}.read`)) return 'read'
    return 'none'
  }, [hasPermission, isAdmin])

  const permissionConfig: PermissionConfig = useMemo(() => ({
    permissions,
    role
  }), [permissions, role])

  const totalPermissions = permissions.length

  const permissionSummary = useMemo(() => ({
    isAdmin: isAdmin(),
    isSuperAdmin: isSuperAdmin(),
    totalPermissions,
    role,
    isActive
  }), [totalPermissions, role, isActive, isAdmin, isSuperAdmin])

  return {
    // Basic permission checks
    hasPermission,
    hasRole,
    hasAnyRole,
    hasAllPermissions,
    hasAnyPermission,

    // Convenience checks
    isAdmin,
    isSuperAdmin,
    canAccessResource,
    getPermissionLevel,

    // Data
    permissionConfig,
    permissionSummary,

    // Raw user data for advanced use cases
    user
  }
}

import { useState, useCallback, useRef, useEffect } from 'react'
import { SessionData, AuthTokens } from './types'
import { TOKEN_REFRESH_THRESHOLD, SESSION_TIMEOUT } from '../../config'
import { createLogger } from '../../lib/logger'

const logger = createLogger('useSessionManagement')

interface UseSessionManagementOptions {
  onRefreshNeeded: () => Promise<void>
  onSessionExpired: () => void
  autoRefresh?: boolean
}

export function useSessionManagement({
  onRefreshNeeded,
  onSessionExpired,
  autoRefresh = true
}: UseSessionManagementOptions) {
  const [sessionExpiry, setSessionExpiry] = useState<number | null>(null)
  const refreshTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const sessionTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  const clearTimeouts = useCallback(() => {
    if (refreshTimeoutRef.current) {
      clearTimeout(refreshTimeoutRef.current)
      refreshTimeoutRef.current = null
    }
    if (sessionTimeoutRef.current) {
      clearTimeout(sessionTimeoutRef.current)
      sessionTimeoutRef.current = null
    }
  }, [])

  const isSessionExpiring = useCallback((): boolean => {
    if (!sessionExpiry) return false
    const now = Date.now()
    return (sessionExpiry - now) <= TOKEN_REFRESH_THRESHOLD
  }, [sessionExpiry])

  const getTimeToExpiry = useCallback((): number => {
    if (!sessionExpiry) return 0
    const now = Date.now()
    return Math.max(0, sessionExpiry - now)
  }, [sessionExpiry])

  const setupSession = useCallback((expiresIn: number) => {
    const now = Date.now()
    const expiry = now + (expiresIn * 1000)
    setSessionExpiry(expiry)

    clearTimeouts()

    if (autoRefresh) {
      // Setup refresh token timer (5 minutes before expiry)
      const refreshTime = Math.max(0, (expiresIn * 1000) - TOKEN_REFRESH_THRESHOLD)
      refreshTimeoutRef.current = setTimeout(() => {
        onRefreshNeeded().catch((error) => {
          logger.error('Auto refresh failed:', error)
        })
      }, refreshTime)
    }

    // Setup session timeout (logout when session expires)
    const timeoutDuration = Math.min(expiresIn * 1000, SESSION_TIMEOUT)
    sessionTimeoutRef.current = setTimeout(() => {
      onSessionExpired()
    }, timeoutDuration)
  }, [autoRefresh, onRefreshNeeded, onSessionExpired, clearTimeouts])

  const updateSessionFromTokens = useCallback((tokens: AuthTokens) => {
    if (tokens.expires_in) {
      setupSession(tokens.expires_in)
      // SECURITY: Session managed by httpOnly cookies (backend)
      // No localStorage storage needed - cookies are automatic
    }
  }, [setupSession])

  const clearSession = useCallback(() => {
    clearTimeouts()
    setSessionExpiry(null)
  }, [clearTimeouts])

  const restoreSessionFromStorage = useCallback((): boolean => {
    // SECURITY: Session restoration handled by httpOnly cookies (backend)
    // Firebase Auth SDK manages token refresh automatically
    // No localStorage restoration needed
    logger.debug('Session restore: delegated to backend cookies + Firebase SDK')
    return false // Always return false - let backend/Firebase handle it
  }, [setupSession])

  const sessionData: SessionData = {
    expiry: sessionExpiry,
    isExpiring: isSessionExpiring(),
    timeToExpiry: getTimeToExpiry()
  }

  // Cleanup on unmount
  useEffect(() => {
    return () => clearTimeouts()
  }, [clearTimeouts])

  return {
    sessionData,
    setupSession,
    updateSessionFromTokens,
    clearSession,
    restoreSessionFromStorage,
    isSessionExpiring,
    getTimeToExpiry
  }
}

import { useState, useCallback } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { createLogger } from '@/lib/logger';

const logger = createLogger('useAuthSubmit');

interface AuthSubmitOptions<T> {
  onSubmit: (data: T) => Promise<void>;
  onSuccess?: () => void;
  onError?: (error: Error) => void;
}

export function useAuthSubmit<T>({
  onSubmit,
  onSuccess,
  onError,
}: AuthSubmitOptions<T>) {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = useCallback(
    async (data: T) => {
      setIsSubmitting(true);
      setError(null);
      try {
        await onSubmit(data);
        if (onSuccess) {
          onSuccess();
        }
      } catch (err: any) {
        logger.error('Authentication error', { error: err });
        const errorMessage =
          err.message || 'An unexpected error occurred. Please try again.';
        setError(errorMessage);
        if (onError) {
          onError(err);
        }
      } finally {
        setIsSubmitting(false);
      }
    },
    [onSubmit, onSuccess, onError]
  );

  return {
    isSubmitting,
    error,
    handleSubmit,
  };
}

/**
 * Custom hook for CSRF token management
 *
 * Handles fetching and caching CSRF tokens for secure API requests.
 * Integrates with apiClient to automatically include tokens in state-changing requests.
 */
import { useEffect, useState } from 'react'
import { apiClient } from '../lib/api-client'
import { createLogger } from '../lib/logger'

const logger = createLogger('useCsrfToken')

export function useCsrfToken() {
  const [csrfToken, setCsrfToken] = useState<string | null>(null)
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState<Error | null>(null)

  useEffect(() => {
    let mounted = true

    const fetchToken = async () => {
      try {
        setIsLoading(true)
        setError(null)

        await apiClient.fetchCsrfToken()

        if (mounted) {
          const token = apiClient.getCsrfToken()
          setCsrfToken(token)
          logger.debug('CSRF token fetched and cached')
        }
      } catch (err) {
        if (mounted) {
          const error = err instanceof Error ? err : new Error('Failed to fetch CSRF token')
          setError(error)
          logger.error('Failed to fetch CSRF token:', error)
        }
      } finally {
        if (mounted) {
          setIsLoading(false)
        }
      }
    }

    fetchToken()

    return () => {
      mounted = false
    }
  }, [])

  /**
   * Manually refresh CSRF token
   * Call this after session creation or when token expires
   */
  const refreshToken = async () => {
    try {
      setIsLoading(true)
      setError(null)

      await apiClient.fetchCsrfToken()
      const token = apiClient.getCsrfToken()
      setCsrfToken(token)
      logger.debug('CSRF token refreshed')
    } catch (err) {
      const error = err instanceof Error ? err : new Error('Failed to refresh CSRF token')
      setError(error)
      logger.error('Failed to refresh CSRF token:', error)
      throw error
    } finally {
      setIsLoading(false)
    }
  }

  return {
    csrfToken,
    isLoading,
    error,
    refreshToken
  }
}

import { useState, useEffect } from 'react'
import { toast as sonnerToast } from 'sonner'

export interface ToastOptions {
  title?: string
  description?: string
  variant?: 'default' | 'destructive' | 'success'
  duration?: number
  action?: {
    label: string
    onClick: () => void
  }
}

export interface Toast extends ToastOptions {
  id: string
}

let toastCount = 0

export function useToast() {
  const [toasts, setToasts] = useState<Toast[]>([])

  const toast = (options: ToastOptions) => {
    const id = `toast-${++toastCount}`
    const { variant = 'default', duration = 5000, ...rest } = options

    // Map to sonner toast based on variant
    if (variant === 'destructive') {
      sonnerToast.error(options.title || options.description, {
        description: options.title ? options.description : undefined,
        duration,
        action: options.action
      })
    } else if (variant === 'success') {
      sonnerToast.success(options.title || options.description, {
        description: options.title ? options.description : undefined,
        duration,
        action: options.action
      })
    } else {
      sonnerToast(options.title || options.description, {
        description: options.title ? options.description : undefined,
        duration,
        action: options.action
      })
    }

    const newToast: Toast = { id, variant, duration, ...rest }
    setToasts((prev) => [...prev, newToast])

    // Auto-remove toast after duration
    setTimeout(() => {
      setToasts((prev) => prev.filter((t) => t.id !== id))
    }, duration)

    return id
  }

  const dismiss = (id?: string) => {
    if (id) {
      sonnerToast.dismiss(id)
      setToasts((prev) => prev.filter((t) => t.id !== id))
    } else {
      sonnerToast.dismiss()
      setToasts([])
    }
  }

  return {
    toast,
    dismiss,
    toasts
  }
}

// Standalone toast function for direct import
export const toast = (options: ToastOptions) => {
  const { variant = 'default', duration = 5000 } = options

  // Map to sonner toast based on variant
  if (variant === 'destructive') {
    sonnerToast.error(options.title || options.description, {
      description: options.title ? options.description : undefined,
      duration,
      action: options.action
    })
  } else if (variant === 'success') {
    sonnerToast.success(options.title || options.description, {
      description: options.title ? options.description : undefined,
      duration,
      action: options.action
    })
  } else {
    sonnerToast(options.title || options.description, {
      description: options.title ? options.description : undefined,
      duration,
      action: options.action
    })
  }
}

