    const newSession: ChatSession = {
      id: `session-${Date.now()}`,
      ...(patient_id ? { patient_id } : {}),
      user_id: 'current-user',
      title: patient_id ? `Chat - Paciente ${patient_id}` : 'Chat com IA',
      messages: [],
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
      status: 'active'
