import { useContext } from 'react'
import { AuthContext } from '@/contexts/AuthContext'
import { usePermissions } from './auth/usePermissions'
import { useAuthRetry } from './auth/useAuthRetry'

interface UseAuthOptions {
  onAuthEvent?: (event: any) => void
  autoConnectWebSocket?: boolean
  persistTokens?: boolean
  retryConfig?: {
    maxRetries?: number
    retryDelay?: number
    exponentialBackoff?: boolean
  }
}

/**
 * Main authentication hook that provides a unified interface
 * combining Firebase auth (via AuthContext) and permissions
 *
 * This hook uses Firebase exclusively for authentication.
 * Session management is handled internally by Firebase and AuthContext.
 */
export function useAuth(options: UseAuthOptions = {}) {
  // Get Firebase auth from AuthContext
  const auth = useContext(AuthContext)

  if (!auth) {
    throw new Error('useAuth must be used within an AuthProvider')
  }

  // Initialize auth retry with config
  const { executeWithRetry, isRetrying, retryCount, resetRetryState } = useAuthRetry(
    options.retryConfig ? { config: options.retryConfig } : {}
  )

  // Initialize permissions based on current user
  const permissions = usePermissions({ user: auth.user })

  return {
    // User and auth state from AuthContext
    user: auth.user,
    token: auth.session?.access_token || null,
    refreshToken: null, // Firebase handles refresh internally
    isAuthenticated: auth.isAuthenticated,
    isLoading: auth.isLoading,
    error: null,

    // Session state (derived from auth state)
    sessionData: null, // Firebase session is managed internally
    isSessionExpiring: false, // Firebase handles expiration automatically

    // Auth methods from AuthContext
    login: async (email: string, password: string) => {
      resetRetryState()
      return await auth.login(email, password)
    },
    logout: auth.logout,
    refreshAuth: async () => {
      // Firebase handles refresh automatically via AuthContext
      return null
    },
    signUp: async (_email: string, _password: string) => {
      throw new Error('Sign up must be handled through the backend API')
    },
    resetPassword: async (_email: string) => {
      throw new Error('Password reset must be handled through Firebase directly')
    },
    updatePassword: async (_newPassword: string) => {
      throw new Error('Password update must be handled through Firebase directly')
    },
    restoreSession: async () => {
      // Firebase/AuthContext handles session restoration automatically
      return auth.isAuthenticated
    },

    // Permission methods from usePermissions
    hasPermission: permissions.hasPermission,
    hasRole: permissions.hasRole,
    hasAnyRole: permissions.hasAnyRole,
    hasAllPermissions: permissions.hasAllPermissions,
    hasAnyPermission: permissions.hasAnyPermission,
    isAdmin: permissions.isAdmin,
    isSuperAdmin: permissions.isSuperAdmin,
    canAccessResource: permissions.canAccessResource,
    getPermissionLevel: permissions.getPermissionLevel,

    // Permission data
    permissionConfig: permissions.permissionConfig,
    permissionSummary: permissions.permissionSummary,

    // Retry state
    isRetrying,
    retryCount,
    resetRetryState
  }
}

import { useState, useEffect, useCallback } from 'react'
import { createLogger } from '../lib/logger'

const logger = createLogger('ConnectionStatus')

export interface ConnectionStatus {
  isOnline: boolean
  isSlowConnection: boolean
  lastOnlineAt: Date | null
  connectionType: string
  estimatedBandwidth: number | null
}

export function useConnectionStatus() {
  const [status, setStatus] = useState<ConnectionStatus>({
    isOnline: navigator.onLine,
    isSlowConnection: false,
    lastOnlineAt: navigator.onLine ? new Date() : null,
    connectionType: 'unknown',
    estimatedBandwidth: null
  })

  const updateConnectionInfo = useCallback(() => {
    if ('connection' in navigator) {
      const connection = (navigator as any).connection

      setStatus(prev => ({
        ...prev,
        connectionType: connection.effectiveType || 'unknown',
        estimatedBandwidth: connection.downlink || null,
        isSlowConnection: connection.effectiveType === '2g' || connection.effectiveType === 'slow-2g'
      }))
    }
  }, [])

  const handleOnline = useCallback(() => {
    logger.info('Connection restored')
    setStatus(prev => ({
      ...prev,
      isOnline: true,
      lastOnlineAt: new Date()
    }))
    updateConnectionInfo()
  }, [updateConnectionInfo])

  const handleOffline = useCallback(() => {
    logger.warn('Connection lost')
    setStatus(prev => ({
      ...prev,
      isOnline: false
    }))
  }, [])

  useEffect(() => {
    window.addEventListener('online', handleOnline)
    window.addEventListener('offline', handleOffline)

    // Listen for connection changes
    if ('connection' in navigator) {
      const connection = (navigator as any).connection
      const handleConnectionChange = () => updateConnectionInfo()

      connection.addEventListener('change', handleConnectionChange)

      // Initial connection info
      updateConnectionInfo()

      return () => {
        window.removeEventListener('online', handleOnline)
        window.removeEventListener('offline', handleOffline)
        connection.removeEventListener('change', handleConnectionChange)
      }
    }

    return () => {
      window.removeEventListener('online', handleOnline)
      window.removeEventListener('offline', handleOffline)
    }
  }, [handleOnline, handleOffline, updateConnectionInfo])

  return status
}

import { useState, useEffect } from 'react'

/**
 * Custom hook that debounces a value
 * @param value - The value to debounce
 * @param delay - The debounce delay in milliseconds
 * @returns The debounced value
 */
export function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value)

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value)
    }, delay)

    return () => {
      clearTimeout(handler)
    }
  }, [value, delay])

  return debouncedValue
}

/**
 * Custom hook that debounces a callback function
 * @param callback - The callback function to debounce
 * @param delay - The debounce delay in milliseconds
 * @returns The debounced callback function
 */
export function useDebouncedCallback<T extends (...args: any[]) => any>(
  callback: T,
  delay: number
): T {
  const [debouncedCallback, setDebouncedCallback] = useState<T>(callback)

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedCallback(() => callback)
    }, delay)

    return () => {
      clearTimeout(handler)
    }
  }, [callback, delay])

  return debouncedCallback
}

import { useState, useEffect, useCallback } from 'react'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { createLogger } from '../lib/logger'
import { flowEngine } from '../lib/flow-engine/FlowEngine'
import { templateManager } from '../lib/flow-engine/TemplateManager'
import {
  FlowType,
  type FlowState,
  type FlowTemplate,
  type MessageTemplate,
  type InboundMessage,
  type ResponseResult,
  type FlowEvent
} from '../lib/types/flow'

const logger = createLogger('useFlowEngine')

export function useFlowEngine() {
  const queryClient = useQueryClient()
  const [isInitialized, setIsInitialized] = useState(false)

  // Initialize flow engine
  useEffect(() => {
    const initialize = async () => {
      try {
        await flowEngine.loadTemplates()
        await templateManager.loadTemplates()
        setIsInitialized(true)
        logger.info('Flow engine initialized successfully')
      } catch (error) {
        logger.error('Failed to initialize flow engine', { error })
      }
    }

    initialize()
  }, [])

  // Listen to flow events
  useEffect(() => {
    const handleFlowEvent = (event: FlowEvent) => {
      // Invalidate relevant queries when flow events occur
      queryClient.invalidateQueries({ queryKey: ['flows'] })
      queryClient.invalidateQueries({ queryKey: ['flow-state', event.patient_id] })
      queryClient.invalidateQueries({ queryKey: ['flow-analytics'] })
    }

    flowEngine.on('flow_started', handleFlowEvent)
    flowEngine.on('flow_paused', handleFlowEvent)
    flowEngine.on('flow_resumed', handleFlowEvent)
    flowEngine.on('flow_advanced', handleFlowEvent)
    flowEngine.on('response_received', handleFlowEvent)

    return () => {
      flowEngine.removeAllListeners()
    }
  }, [queryClient])

  return {
    isInitialized,
    flowEngine,
    templateManager
  }
}

