/**
 * WebSocket Hook for Real-time Metrics - Fixed Version
 *
 * [P0 FIX] Uses correct Firebase token from AuthContext
 * - Integrates with AuthContext for automatic token refresh
 * - Uses VITE_WS_BASE_URL environment variable
 * - Implements heartbeat/ping-pong mechanism
 * - Handles reconnection with exponential backoff
 *
 * Usage:
 * ```tsx
 * const { isConnected, lastMessage, error } = useMetricsWebSocket({
 *   onMessage: (data) => console.log('Metrics:', data)
 * })
 * ```
 */
import { useState, useEffect, useCallback, useRef } from 'react'
import { useAuth } from '../contexts/AuthContext'
import { createLogger } from '../lib/logger'

const logger = createLogger('metrics:websocket')

interface UseMetricsWebSocketOptions {
  onMessage?: (data: any) => void
  onError?: (error: Event) => void
  onConnect?: () => void
  onDisconnect?: () => void
  reconnectInterval?: number
  maxReconnectAttempts?: number
  heartbeatInterval?: number
}

interface UseMetricsWebSocketReturn {
  isConnected: boolean
  isConnecting: boolean
  error: string | null
  lastMessage: any
  reconnectAttempts: number
  send: (data: any) => void
  connect: () => void
  disconnect: () => void
}

/**
 * Get WebSocket base URL from environment or fallback to current host
 */
function getWebSocketBaseUrl(): string {
  // Priority 1: VITE_WS_BASE_URL (e.g., wss://backend.railway.app)
  if (import.meta.env.VITE_WS_BASE_URL) {
    return import.meta.env.VITE_WS_BASE_URL
  }

  // Priority 2: VITE_WS_URL (legacy, e.g., wss://backend.railway.app/ws)
  if (import.meta.env.VITE_WS_URL) {
    return import.meta.env.VITE_WS_URL.replace('/ws', '')
  }

  // Fallback: construct from window.location
  const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:'
  const host = window.location.host
  return `${protocol}//${host}`
}

export function useMetricsWebSocket({
  onMessage,
  onError,
  onConnect,
  onDisconnect,
  reconnectInterval = 5000,
  maxReconnectAttempts = 10,
  heartbeatInterval = 30000 // 30 seconds
}: UseMetricsWebSocketOptions = {}): UseMetricsWebSocketReturn {
  const { user, session, getFirebaseToken } = useAuth()

  const [isConnected, setIsConnected] = useState(false)
  const [isConnecting, setIsConnecting] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [lastMessage, setLastMessage] = useState<any>(null)
  const [reconnectAttempts, setReconnectAttempts] = useState(0)

  const ws = useRef<WebSocket | null>(null)
  const reconnectTimer = useRef<NodeJS.Timeout | null>(null)
  const heartbeatTimer = useRef<NodeJS.Timeout | null>(null)
  const isManualDisconnect = useRef(false)

  /**
   * Send heartbeat ping to keep connection alive
   */
  const sendHeartbeat = useCallback(() => {
    if (ws.current?.readyState === WebSocket.OPEN) {
      try {
        ws.current.send(JSON.stringify({ type: 'ping' }))
        logger.debug('Heartbeat ping sent')
      } catch (err) {
        logger.error('Failed to send heartbeat', { error: err })
      }
    }
  }, [])

  /**
   * Start heartbeat interval
   */
  const startHeartbeat = useCallback(() => {
    if (heartbeatTimer.current) {
      clearInterval(heartbeatTimer.current)
    }

    heartbeatTimer.current = setInterval(sendHeartbeat, heartbeatInterval)
    logger.debug('Heartbeat started', { interval: heartbeatInterval })
  }, [sendHeartbeat, heartbeatInterval])

  /**
   * Stop heartbeat interval
   */
  const stopHeartbeat = useCallback(() => {
    if (heartbeatTimer.current) {
      clearInterval(heartbeatTimer.current)
      heartbeatTimer.current = null
      logger.debug('Heartbeat stopped')
    }
  }, [])

  /**
   * Handle WebSocket open event
   */
  const handleOpen = useCallback(() => {
    logger.info('Metrics WebSocket connected')
    setIsConnected(true)
    setIsConnecting(false)
    setError(null)
    setReconnectAttempts(0)

    // Start heartbeat to keep connection alive
    startHeartbeat()

    onConnect?.()
  }, [onConnect, startHeartbeat])

  /**
   * Handle WebSocket message event
   */
  const handleMessage = useCallback((event: MessageEvent) => {
    try {
      const data = JSON.parse(event.data)

      // Handle pong response from server
      if (data.type === 'pong') {
        logger.debug('Heartbeat pong received')
        return
      }

      setLastMessage(data)
      onMessage?.(data)
    } catch (err) {
      logger.error('Error parsing WebSocket message', { error: err })
      setError('Erro ao processar dados recebidos')
    }
  }, [onMessage])

  /**
   * Handle WebSocket error event
   */
  const handleError = useCallback((event: Event) => {
    logger.error('Metrics WebSocket error', { event })
    setError('Erro de conex├úo WebSocket')
    onError?.(event)
  }, [onError])

  /**
   * Handle WebSocket close event
   */
  const handleClose = useCallback(() => {
    logger.info('Metrics WebSocket disconnected', {
      manual: isManualDisconnect.current,
      attempts: reconnectAttempts
    })

    setIsConnected(false)
    setIsConnecting(false)
    stopHeartbeat()

    onDisconnect?.()

    // Attempt reconnection if not manually disconnected
    if (!isManualDisconnect.current && reconnectAttempts < maxReconnectAttempts) {
      const delay = Math.min(reconnectInterval * Math.pow(2, reconnectAttempts), 60000)
      logger.info('Scheduling reconnection', { delay, attempt: reconnectAttempts + 1 })

      reconnectTimer.current = setTimeout(() => {
        setReconnectAttempts(prev => prev + 1)
        connect()
      }, delay)
    } else if (reconnectAttempts >= maxReconnectAttempts) {
      setError('M├íximo de tentativas de reconex├úo atingido')
      logger.error('Max reconnection attempts reached')
    }
  }, [reconnectAttempts, maxReconnectAttempts, reconnectInterval, onDisconnect, stopHeartbeat])

  /**
   * Connect to WebSocket server
   */
  const connect = useCallback(async () => {
    // Don't connect if already connected or connecting
    if (ws.current?.readyState === WebSocket.OPEN || isConnecting) {
      return
    }

    // [P0 FIX] Use Firebase token from AuthContext (in-memory via Firebase SDK)
    const firebaseToken = await getFirebaseToken()

    if (!firebaseToken) {
      logger.error('Cannot connect: No Firebase token available')
      setError('Autentica├º├úo necess├íria')
      return
    }

    // Cleanup existing connection
    if (ws.current) {
      ws.current.close()
      ws.current = null
    }

    try {
      setIsConnecting(true)
      setError(null)
      isManualDisconnect.current = false

      // Build WebSocket URL with Firebase token
      const baseUrl = getWebSocketBaseUrl()
      const wsUrl = `${baseUrl}/api/v2/metrics/live?token=${firebaseToken}`

      logger.info('Connecting to metrics WebSocket', { url: baseUrl })

      // Create WebSocket connection
      const socket = new WebSocket(wsUrl)

      socket.addEventListener('open', handleOpen)
      socket.addEventListener('message', handleMessage)
      socket.addEventListener('error', handleError)
      socket.addEventListener('close', handleClose)

      ws.current = socket

    } catch (err) {
      logger.error('Failed to create WebSocket connection', { error: err })
      setError('Falha ao conectar ao servidor')
      setIsConnecting(false)
    }
  }, [isConnecting, getFirebaseToken, handleOpen, handleMessage, handleError, handleClose])

  /**
   * Disconnect from WebSocket server
   */
  const disconnect = useCallback(() => {
    logger.info('Manual disconnect requested')
    isManualDisconnect.current = true

    // Clear reconnection timer
    if (reconnectTimer.current) {
      clearTimeout(reconnectTimer.current)
      reconnectTimer.current = null
    }

    // Stop heartbeat
    stopHeartbeat()

    // Close WebSocket connection
    if (ws.current) {
      ws.current.close()
      ws.current = null
    }

    setIsConnected(false)
    setIsConnecting(false)
    setReconnectAttempts(0)
  }, [stopHeartbeat])

  /**
   * Send data through WebSocket
   */
  const send = useCallback((data: any) => {
    if (ws.current?.readyState === WebSocket.OPEN) {
      try {
        ws.current.send(JSON.stringify(data))
        logger.debug('Message sent', { data })
      } catch (err) {
        logger.error('Failed to send message', { error: err })
        setError('Falha ao enviar mensagem')
      }
    } else {
      logger.warn('Cannot send message: WebSocket not connected')
      setError('WebSocket n├úo conectado')
    }
  }, [])

  /**
   * Auto-connect when user is authenticated
   */
  useEffect(() => {
    if (user && session) {
      logger.info('User authenticated, auto-connecting WebSocket')
      connect()
    } else {
      logger.info('User not authenticated, disconnecting WebSocket')
      disconnect()
    }

    // Cleanup on unmount
    return () => {
      disconnect()
    }
  }, [user, session])

  /**
   * React to token refresh - reconnect with new token
   */
  useEffect(() => {
    (async () => {
      const firebaseToken = await getFirebaseToken()

      if (firebaseToken && isConnected) {
        logger.info('Token refreshed, reconnecting WebSocket')
        disconnect()
        setTimeout(() => connect(), 1000) // Reconnect after 1 second
      }
    })()
  }, [session?.access_token, getFirebaseToken, isConnected, disconnect, connect])

  return {
    isConnected,
    isConnecting,
    error,
    lastMessage,
    reconnectAttempts,
    send,
    connect,
    disconnect
  }
}

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { useToast } from '@/components/ui/use-toast'
import { apiClient } from '@/lib/api-client'
import type { QuizHistoryEntry, QuizLinkStatus } from '@/lib/api-client/monthly-quiz'

type DeliveryMethod = 'whatsapp' | 'email' | 'sms' | 'manual'

interface CreateQuizLinkData {
  patient_id: string
  quiz_template_id: string
  delivery_method?: DeliveryMethod
  expiry_hours?: number
  custom_message?: string
  send_immediately?: boolean
}

interface BulkCreateQuizLinkData {
  patient_ids: string[]
  quiz_template_id: string
  delivery_method?: DeliveryMethod
  expiry_hours?: number
  custom_message?: string
  send_immediately?: boolean
}

export function useMonthlyQuizAdmin() {
  const { toast } = useToast()
  const queryClient = useQueryClient()

  // Send quiz link to a single patient
  const sendQuizLink = async (data: CreateQuizLinkData) => {
    return await apiClient.monthlyQuiz.createLink(data)
  }

  // Send quiz link to multiple patients (bulk)
  const sendBulkQuizLinks = async (data: BulkCreateQuizLinkData) => {
    return await apiClient.monthlyQuiz.bulkCreate(data)
  }

  // Resend quiz link
  const resendQuizLink = async (sessionId: string) => {
    try {
      const result = await apiClient.monthlyQuiz.resend(sessionId)

      toast({
        title: 'Link reenviado',
        description: 'O link do quiz foi reenviado com sucesso'
      })

      // Invalidate queries to refresh data
      queryClient.invalidateQueries({ queryKey: ['monthly-quiz-active-links'] })
      queryClient.invalidateQueries({ queryKey: ['monthly-quiz-stats'] })

      return result
    } catch (error: any) {
      toast({
        title: 'Erro ao reenviar link',
        description: error.data?.message || 'Ocorreu um erro ao reenviar o link',
        variant: 'destructive'
      })
      throw error
    }
  }

  // Get quiz link status for a patient
  const getQuizLinkStatus = async (patientId: string) => {
    return await apiClient.monthlyQuiz.getPatientStatus(patientId)
  }

  // Use query to get quiz link status with caching
  const useQuizLinkStatus = (patientId: string) => {
    return useQuery<any>({
      queryKey: ['monthly-quiz-status', patientId],
      queryFn: async () => {
        const list = await getQuizLinkStatus(patientId)
        if (!Array.isArray(list) || list.length === 0) return null
        const first = list[0] as QuizLinkStatus
        const expired = first.expires_at ? (new Date(first.expires_at) < new Date()) : false
        const uiStatus = !expired && !['completed', 'cancelled', 'expired'].includes(first.status) ? 'active' : first.status
        return { ...first, status: uiStatus }
      },
      enabled: !!patientId,
      staleTime: 30000 // 30 seconds
    })
  }

  // Get quiz link history for a patient
  const getQuizLinkHistory = async (patientId: string) => {
    return await apiClient.monthlyQuiz.getHistory(patientId)
  }

  // Use query to get quiz link history with caching
  const useQuizLinkHistory = (patientId: string) => {
    return useQuery<QuizHistoryEntry[]>({
      queryKey: ['monthly-quiz-history', patientId],
      queryFn: () => getQuizLinkHistory(patientId),
      enabled: !!patientId
    })
  }

  // Cancel quiz link
  const cancelQuizLink = async (sessionId: string) => {
    try {
      const result = await apiClient.monthlyQuiz.cancel(sessionId)

      toast({
        title: 'Link cancelado',
        description: 'O link do quiz foi cancelado com sucesso'
      })

      // Invalidate queries to refresh data
      queryClient.invalidateQueries({ queryKey: ['monthly-quiz-active-links'] })
      queryClient.invalidateQueries({ queryKey: ['monthly-quiz-stats'] })

      return result
    } catch (error: any) {
      toast({
        title: 'Erro ao cancelar link',
        description: error.data?.message || 'Ocorreu um erro ao cancelar o link',
        variant: 'destructive'
      })
      throw error
    }
  }

  // Get quiz statistics
  const getQuizStats = async (dateFrom?: string, dateTo?: string) => {
    const statsParams: { start_date?: string; end_date?: string } = {}
    if (dateFrom) statsParams.start_date = dateFrom
    if (dateTo) statsParams.end_date = dateTo

    return await apiClient.monthlyQuiz.getStats(statsParams)
  }

  // Use query to get quiz stats with caching
  const useQuizStats = (dateFrom?: string, dateTo?: string) => {
    return useQuery({
      queryKey: ['monthly-quiz-stats', dateFrom, dateTo],
      queryFn: () => getQuizStats(dateFrom, dateTo),
      staleTime: 60000 // 1 minute
    })
  }

  // Mutation for sending quiz link
  const useSendQuizLinkMutation = () => {
    return useMutation({
      mutationFn: sendQuizLink,
      onSuccess: () => {
        toast({
          title: 'Link enviado',
          description: 'O link do quiz foi enviado com sucesso'
        })
        queryClient.invalidateQueries({ queryKey: ['monthly-quiz-stats'] })
        queryClient.invalidateQueries({ queryKey: ['patients'] })
      },
      onError: (error: any) => {
        toast({
          title: 'Erro ao enviar link',
          description: error.data?.message || 'Ocorreu um erro ao enviar o link',
          variant: 'destructive'
        })
      }
    })
  }

  // Mutation for bulk sending quiz links
  const useBulkSendQuizLinksMutation = () => {
    return useMutation({
      mutationFn: sendBulkQuizLinks,
      onSuccess: () => {
        toast({
          title: 'Links enviados',
          description: 'Os links do quiz foram enviados com sucesso'
        })
        queryClient.invalidateQueries({ queryKey: ['monthly-quiz-stats'] })
        queryClient.invalidateQueries({ queryKey: ['patients'] })
      },
      onError: (error: any) => {
        toast({
          title: 'Erro ao enviar links',
          description: error.data?.message || 'Ocorreu um erro ao enviar os links',
          variant: 'destructive'
        })
      }
    })
  }

  return {
    sendQuizLink,
    sendBulkQuizLinks,
    resendQuizLink,
    getQuizLinkStatus,
    useQuizLinkStatus,
    getQuizLinkHistory,
    useQuizLinkHistory,
    cancelQuizLink,
    getQuizStats,
    useQuizStats,
    useSendQuizLinkMutation,
    useBulkSendQuizLinksMutation
  }
}

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { useToast } from '@/components/ui/use-toast'
import { apiClient } from '@/lib/api-client'
import { useAuth } from '@/contexts/AuthContext'
import { quizPermissions, getPermissionErrorMessage } from '@/utils/quizPermissions'

interface CreateQuizLinkData {
  patient_id: string
  quiz_template_id: string
  delivery_method: 'whatsapp' | 'email' | 'sms' | 'manual'
  expiry_hours: number
  custom_message?: string
  send_immediately?: boolean
}

interface BulkCreateQuizLinkData {
  patient_ids: string[]
  quiz_template_id: string
  delivery_method: 'whatsapp' | 'email' | 'sms' | 'manual'
  expiry_hours: number
  custom_message?: string
  send_immediately?: boolean
}

export function useMonthlyQuizAdminSecure() {
  const { toast } = useToast()
  const queryClient = useQueryClient()
  const { user } = useAuth()

  // Permission-aware functions
  const canCreateLink = quizPermissions.canCreateQuizLink(user)
  const canViewStats = quizPermissions.canViewQuizStats(user)
  const canResendLinks = quizPermissions.canResendLink(user)
  const canCancelLinks = quizPermissions.canCancelQuizLink(user)
  const canPerformBulk = quizPermissions.canPerformBulkOperations(user)

  // Send quiz link to a single patient
  const sendQuizLink = async (data: CreateQuizLinkData) => {
    if (!canCreateLink) {
      throw new Error(getPermissionErrorMessage('create_quiz_link', user?.role))
    }
    return await apiClient.monthlyQuiz.createLink(data)
  }

  // Send quiz link to multiple patients (bulk)
  const sendBulkQuizLinks = async (data: BulkCreateQuizLinkData) => {
    if (!canPerformBulk) {
      throw new Error(getPermissionErrorMessage('bulk_operations', user?.role))
    }
    return await apiClient.monthlyQuiz.bulkCreate(data)
  }

  // Resend quiz link with permission check
  const resendQuizLink = async (sessionId: string) => {
    if (!canResendLinks) {
      toast({
        title: 'Acesso negado',
        description: getPermissionErrorMessage('resend_link', user?.role),
        variant: 'destructive'
      })
      throw new Error(getPermissionErrorMessage('resend_link', user?.role))
    }

    try {
      const result = await apiClient.monthlyQuiz.resend(sessionId)

      toast({
        title: 'Link reenviado',
        description: 'O link do quiz foi reenviado com sucesso'
      })

      // Invalidate queries to refresh data
      queryClient.invalidateQueries({ queryKey: ['monthly-quiz-active-links'] })
      queryClient.invalidateQueries({ queryKey: ['monthly-quiz-stats'] })

      return result
    } catch (error: any) {
      toast({
        title: 'Erro ao reenviar link',
        description: error.message || 'Ocorreu um erro ao reenviar o link',
        variant: 'destructive'
      })
      throw error
    }
  }

  // Cancel quiz link with permission check
  const cancelQuizLink = async (sessionId: string) => {
    if (!canCancelLinks) {
      toast({
        title: 'Acesso negado',
        description: getPermissionErrorMessage('cancel_link', user?.role),
        variant: 'destructive'
      })
      throw new Error(getPermissionErrorMessage('cancel_link', user?.role))
    }

    try {
      const result = await apiClient.monthlyQuiz.cancel(sessionId)

      toast({
        title: 'Link cancelado',
        description: 'O link do quiz foi cancelado com sucesso'
      })

      // Invalidate queries to refresh data
      queryClient.invalidateQueries({ queryKey: ['monthly-quiz-active-links'] })
      queryClient.invalidateQueries({ queryKey: ['monthly-quiz-stats'] })

      return result
    } catch (error: any) {
      toast({
        title: 'Erro ao cancelar link',
        description: error.message || 'Ocorreu um erro ao cancelar o link',
        variant: 'destructive'
      })
      throw error
    }
  }

  // Get quiz link status for a patient
  const getQuizLinkStatus = async (patientId: string) => {
    if (!canViewStats) {
      throw new Error(getPermissionErrorMessage('view_quiz_stats', user?.role))
    }
    return await apiClient.monthlyQuiz.getPatientStatus(patientId)
  }

  // Use query to get quiz link status with caching and permission check
  const useQuizLinkStatus = (patientId: string) => {
    return useQuery({
      queryKey: ['monthly-quiz-status', patientId],
      queryFn: () => getQuizLinkStatus(patientId),
      enabled: !!patientId && canViewStats,
      staleTime: 30000 // 30 seconds
    })
  }

  // Get quiz statistics with permission filtering
  const getQuizStats = async (dateFrom?: string, dateTo?: string) => {
    if (!canViewStats) {
      throw new Error(getPermissionErrorMessage('view_quiz_stats', user?.role))
    }
    
    const scope = quizPermissions.getQuizStatsScope(user)
    const params: any = { start_date: dateFrom, end_date: dateTo }
    
    // Add scope filtering for doctors
    if (scope === 'own_patients' && user?.id) {
      params.doctor_id = user['id']
    }
    
    return await apiClient.monthlyQuiz.getStats(params)
  }

  // Use query to get quiz stats with caching and permission filtering
  const useQuizStats = (dateFrom?: string, dateTo?: string) => {
    return useQuery({
      queryKey: ['monthly-quiz-stats', dateFrom, dateTo, user?.id],
      queryFn: () => getQuizStats(dateFrom, dateTo),
      enabled: canViewStats,
      staleTime: 60000 // 1 minute
    })
  }

  // Mutation for sending quiz link with permission check
  const useSendQuizLinkMutation = () => {
    return useMutation({
      mutationFn: sendQuizLink,
      onSuccess: () => {
        toast({
          title: 'Link enviado',
          description: 'O link do quiz foi enviado com sucesso'
        })
        queryClient.invalidateQueries({ queryKey: ['monthly-quiz-stats'] })
        queryClient.invalidateQueries({ queryKey: ['patients'] })
      },
      onError: (error: any) => {
        toast({
          title: 'Erro ao enviar link',
          description: error.message || 'Ocorreu um erro ao enviar o link',
          variant: 'destructive'
        })
      }
    })
  }

  // Mutation for bulk sending quiz links with permission check
  const useBulkSendQuizLinksMutation = () => {
    return useMutation({
      mutationFn: sendBulkQuizLinks,
      onSuccess: () => {
        toast({
          title: 'Links enviados',
          description: 'Os links do quiz foram enviados com sucesso'
        })
        queryClient.invalidateQueries({ queryKey: ['monthly-quiz-stats'] })
        queryClient.invalidateQueries({ queryKey: ['patients'] })
      },
      onError: (error: any) => {
        toast({
          title: 'Erro ao enviar links',
          description: error.message || 'Ocorreu um erro ao enviar os links',
          variant: 'destructive'
        })
      }
    })
  }

  return {
    // Permission flags
    canCreateLink,
    canViewStats,
    canResendLinks,
    canCancelLinks,
    canPerformBulk,
    
    // Functions
    sendQuizLink,
    sendBulkQuizLinks,
    resendQuizLink,
    cancelQuizLink,
    getQuizLinkStatus,
    useQuizLinkStatus,
    getQuizStats,
    useQuizStats,
    useSendQuizLinkMutation,
    useBulkSendQuizLinksMutation,
    
    // User info for permission checks
    user,
    userScope: quizPermissions.getQuizStatsScope(user)
  }
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { apiClient } from '@/lib/api-client'
import { useToast } from '@/components/ui/use-toast'
import type { QuizLinkStatusValue, MonthlyQuizStatusData } from '@/types/api'

export interface MonthlyQuizHistoryItem {
  id: string
  patient_id: string
  patient_name: string
  template_name: string
  template_id: string
  status: QuizLinkStatusValue
  sent_at: string
  accessed_at?: string
  completed_at?: string
  expires_at: string
  delivery_method: 'whatsapp' | 'email' | 'sms'
}

export interface MonthlyQuizBulkStatus {
  [patientId: string]: MonthlyQuizStatusData
}

/**
 * Hook to fetch quiz link status for a single patient
 */
export function useMonthlyQuizStatus(patientId: string) {
  return useQuery<MonthlyQuizStatusData>({
    queryKey: ['monthly-quiz-status', patientId],
    queryFn: async () => {
      try {
        const response = await apiClient.monthlyQuiz.getPatientStatus(patientId)
        const s: any = Array.isArray(response) ? response[0] : response

        if (!s) {
          return {
            patient_id: patientId,
            status: 'not_sent' as QuizLinkStatusValue,
          }
        }

        return {
          patient_id: patientId,
          session_id: s.session_id ?? s.quiz_session_id,
          status: mapBackendStatus(String(s.status ?? 'not_sent')),
          last_sent: s.last_sent ?? s.sent_at,
          access_date: s.last_response ?? s.accessed_at,
          completion_date: (s.status === 'completed' ? (s.last_response ?? s.completed_at) : undefined),
          expires_at: s.expires_at,
        }
      } catch (error: any) {
        // If patient has no quiz link, return not_sent status
        if (error.status === 404) {
          return {
            patient_id: patientId,
            status: 'not_sent' as QuizLinkStatusValue,
          }
        }
        throw error
      }
    },
    enabled: !!patientId,
    staleTime: 30000, // 30 seconds
    retry: 1
  })
}

/**
 * Hook to fetch quiz link statuses for multiple patients (bulk)
 */
export function useBulkMonthlyQuizStatus(patientIds: string[]) {
  return useQuery<MonthlyQuizBulkStatus>({
    queryKey: ['monthly-quiz-bulk-status', patientIds],
    queryFn: async () => {
      const statuses: MonthlyQuizBulkStatus = {}

      // Fetch statuses in parallel
      const results = await Promise.allSettled(
        patientIds.map(id => apiClient.monthlyQuiz.getPatientStatus(id))
      )

      results.forEach((result, index) => {
        const patientId = patientIds[index]

        if (result.status === 'fulfilled') {
          const data = result.value as any
          const s = Array.isArray(data) ? data[0] : data
          const patientIdSafe = patientIds[index]
          if (patientIdSafe) {
            statuses[patientIdSafe] = {
              patient_id: patientIdSafe,
              session_id: s?.session_id ?? s?.quiz_session_id,
              status: mapBackendStatus(String(s?.status ?? 'not_sent')),
              last_sent: s?.last_sent ?? s?.sent_at,
              access_date: s?.last_response ?? s?.accessed_at,
              completion_date: s?.status === 'completed' ? (s?.last_response ?? s?.completed_at) : undefined,
              expires_at: s?.expires_at,
            }
          }
        } else {
          // Patient has no quiz link
          const patientIdSafe = patientIds[index]
          if (patientIdSafe) {
            statuses[patientIdSafe] = {
              patient_id: patientIdSafe,
              status: 'not_sent' as QuizLinkStatusValue
            }
          }
        }
      })

      return statuses
    },
    enabled: patientIds.length > 0,
    staleTime: 30000, // 30 seconds
  })
}

/**
 * Hook to fetch quiz link history for a patient
 */
export function useMonthlyQuizHistory(patientId: string) {
  return useQuery<MonthlyQuizHistoryItem[]>({
    queryKey: ['monthly-quiz-history', patientId],
    queryFn: async () => {
      const response = await apiClient.monthlyQuiz.getHistory(patientId)
      return response.map((item: any) => ({
        id: item.session_id || item['id'],
        patient_id: item.patient_id,
        patient_name: item.patient_name,
        template_name: item.template_name,
        template_id: item.quiz_template_id || item.template_id,
        status: mapBackendStatus(item.status),
        sent_at: item.sent_at,
        accessed_at: item.accessed_at,
        completed_at: item.completed_at,
        expires_at: item.expires_at,
        delivery_method: item.delivery_method || 'whatsapp'
      }))
    },
    enabled: !!patientId,
    staleTime: 60000 // 1 minute
  })
}

/**
 * Hook to resend quiz link mutation
 */
export function useResendQuizLink() {
  const { toast } = useToast()
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async (sessionId: string) => {
      return await apiClient.monthlyQuiz.resend(sessionId)
    },
    onSuccess: (_, sessionId) => {
      toast({
        title: 'Link reenviado',
        description: 'O link do quiz foi reenviado com sucesso'
      })

      // Invalidate all related queries
      queryClient.invalidateQueries({ queryKey: ['monthly-quiz-status'] })
      queryClient.invalidateQueries({ queryKey: ['monthly-quiz-history'] })
      queryClient.invalidateQueries({ queryKey: ['monthly-quiz-stats'] })
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao reenviar link',
        description: error.data?.message || 'N├úo foi poss├¡vel reenviar o link do quiz',
        variant: 'destructive'
      })
    }
  })
}

/**
 * Map backend status to frontend QuizLinkStatusValue
 */
function mapBackendStatus(backendStatus: string): QuizLinkStatusValue {
  switch (backendStatus) {
    case 'active':
    case 'pending':
      return 'sent'
    case 'accessed':
      return 'accessed'
    case 'completed':
      return 'completed'
    case 'expired':
      return 'expired'
    case 'not_sent':
    default:
      return 'not_sent'
  }
}

import { useState } from 'react'
import { getAuth, reauthenticateWithCredential, EmailAuthProvider, updatePassword } from 'firebase/auth'
import { toast } from '@/hooks/use-toast'
import { apiClient } from '@/lib/api-client'

export interface PasswordChangeData {
  current_password: string
  new_password: string
  confirm_password?: string
}

export interface UsePasswordChangeReturn {
  changePassword: (data: PasswordChangeData) => Promise<void>
  isChangingPassword: boolean
  error: string | null
  clearError: () => void
}

/**
 * Hook for changing user password with Firebase re-authentication
 *
 * Security flow:
 * 1. Re-authenticate user with current password (Firebase client-side)
 * 2. Send password change request to backend with current password
 * 3. Backend validates current password via Firebase Auth API
 * 4. Backend updates password via Firebase Admin SDK
 * 5. Backend invalidates all sessions (force re-login)
 *
 * This double validation (client + server) provides defense in depth.
 *
 * @returns Password change functions and state
 */
export function usePasswordChange(): UsePasswordChangeReturn {
  const [isChangingPassword, setIsChangingPassword] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const clearError = () => setError(null)

  const changePassword = async (data: PasswordChangeData): Promise<void> => {
    setIsChangingPassword(true)
    setError(null)

    try {
      const auth = getAuth()
      const user = auth.currentUser

      if (!user || !user.email) {
        throw new Error('Usu├írio n├úo autenticado')
      }

      // Step 1: Re-authenticate with current password (client-side validation)
      const credential = EmailAuthProvider.credential(user.email, data.current_password)

      try {
        await reauthenticateWithCredential(user, credential)
      } catch (reAuthError: any) {
        console.error('Re-authentication failed:', reAuthError)

        // User-friendly error messages
        let errorMessage = 'Senha atual incorreta'
        if (reAuthError.code === 'auth/wrong-password') {
          errorMessage = 'Senha atual incorreta. Por favor, verifique e tente novamente.'
        } else if (reAuthError.code === 'auth/too-many-requests') {
          errorMessage = 'Muitas tentativas falhadas. Por favor, aguarde alguns minutos.'
        } else if (reAuthError.code === 'auth/network-request-failed') {
          errorMessage = 'Erro de conex├úo. Verifique sua internet e tente novamente.'
        }

        setError(errorMessage)
        throw new Error(errorMessage)
      }

      // Step 2: Send password change request to backend (server-side validation + update)
      try {
        const response: any = await apiClient.put('/auth/password', {
          current_password: data.current_password,
          new_password: data.new_password,
        })

        if (
          response?.data &&
          typeof response.data === 'object' &&
          'success' in response.data &&
          response.data.success
        ) {
          toast({
            title: 'Senha alterada com sucesso',
            description: 'Por seguran├ºa, voc├¬ ser├í desconectado em breve. Fa├ºa login novamente com sua nova senha.',
          })

          // Force logout after 3 seconds
          setTimeout(() => {
            window.location.href = '/login?reason=password-changed'
          }, 3000)
        }
      } catch (apiError: any) {
        console.error('Backend password change failed:', apiError)

        const errorMessage = apiError.response?.data?.detail ||
                            'Erro ao alterar senha. Por favor, tente novamente.'

        setError(errorMessage)
        toast({
          title: 'Erro ao alterar senha',
          description: errorMessage,
          variant: 'destructive',
        })
        throw new Error(errorMessage)
      }
    } catch (err: any) {
      // Error already handled and set above
      console.error('Password change error:', err)
      throw err
    } finally {
      setIsChangingPassword(false)
    }
  }

  return {
    changePassword,
    isChangingPassword,
    error,
    clearError,
  }
}

import { useQuery, useQueryClient } from '@tanstack/react-query'
import { useState, useCallback, useMemo, useEffect } from 'react'

import { useDebounce } from './useDebounce'
import { apiClient } from '../lib/api-client'
import type { Patient } from '../lib/types/api'

export interface PatientFilters {
  search?: string
  status?: 'active' | 'paused' | 'completed' | 'inactive'
  treatment_type?: string
  start_date_from?: string
  start_date_to?: string
  page?: number
  size?: number
}

export interface UsePatientFiltersOptions {
  initialFilters?: Partial<PatientFilters>
  debounceMs?: number
  pageSize?: number
}

export function usePatientFilters(options: UsePatientFiltersOptions = {}) {
  const {
    initialFilters = {},
    debounceMs = 300,
    pageSize = 20
  } = options

  const [filters, setFilters] = useState<PatientFilters>(() => ({
    search: '',
    treatment_type: '',
    start_date_from: '',
    start_date_to: '',
    page: 1,
    size: pageSize,
    ...initialFilters
  }))

  // Debounce search to avoid excessive API calls
  const debouncedSearch = useDebounce(filters['search'] || '', debounceMs)

  // Create query parameters for API call
  const queryParams = useMemo(() => {
    const params: Record<string, any> = {
      page: filters['page'] || 1,
      size: filters.size || pageSize
    }

    if (debouncedSearch) {
      params['search'] = debouncedSearch
    }

    if (filters['status']) {
      params['status'] = filters['status']
    }

    if (filters['treatment_type'] && filters['treatment_type'] !== '') {
      params['treatment_type'] = filters['treatment_type']
    }

    // Date range filters would need backend support
    if (filters['start_date_from']) {
      params['start_date_from'] = filters['start_date_from']
    }

    if (filters['start_date_to']) {
      params['start_date_to'] = filters['start_date_to']
    }

    return params
  }, [debouncedSearch, filters['status'], filters['treatment_type'], filters['start_date_from'], filters['start_date_to'], filters['page'], filters.size, pageSize])

  // Update specific filter
  const updateFilter = useCallback(<K extends keyof PatientFilters>(
    key: K,
    value: PatientFilters[K]
  ) => {
    setFilters(prev => ({
      ...prev,
      [key]: value,
      // Reset to page 1 when filter changes (except for page)
      ...(key !== 'page' ? { page: 1 } : {})
    }))
  }, [])

  // Update multiple filters at once
  const updateFilters = useCallback((newFilters: Partial<PatientFilters>) => {
    setFilters(prev => ({
      ...prev,
      ...newFilters,
      // Reset to page 1 when filters change
      page: 1
    }))
  }, [])

  // Reset all filters
  const resetFilters = useCallback(() => {
    setFilters({
      search: '',
      treatment_type: '',
      start_date_from: '',
      start_date_to: '',
      page: 1,
      size: pageSize
    })
  }, [pageSize])

  // Check if any filters are active
  const hasActiveFilters = useMemo(() => {
    return Boolean(
      filters['search'] ||
      filters['status'] ||
      filters['treatment_type'] ||
      filters['start_date_from'] ||
      filters['start_date_to']
    )
  }, [filters])

  // Get active filter count
  const activeFilterCount = useMemo(() => {
    let count = 0
    if (filters['search']) count++
    if (filters['status']) count++
    if (filters['treatment_type']) count++
    if (filters['start_date_from'] || filters['start_date_to']) count++
    return count
  }, [filters])

  return {
    filters,
    queryParams,
    updateFilter,
    updateFilters,
    resetFilters,
    hasActiveFilters,
    activeFilterCount
  }
}

export function usePatients(filterOptions?: UsePatientFiltersOptions) {
  const queryClient = useQueryClient()
  // Maintain cursor map per page and persistent total across pages
  const [cursorsByPage, setCursorsByPage] = useState<Record<number, string | undefined>>({ 1: undefined })
  const [persistedTotal, setPersistedTotal] = useState<number>(0)
  const {
    filters,
    queryParams,
    updateFilter,
    updateFilters,
    resetFilters,
    hasActiveFilters,
    activeFilterCount
  } = usePatientFilters(filterOptions)

  // Reset cursors when non-page filters change
  const filtersKey = useMemo(() => {
    const { page: _p, size: _s, ...rest } = filters || ({} as any)
    return JSON.stringify(rest)
  }, [filters])

  useEffect(() => {
    // When filters (except page/size) change, reset to page 1 and clear cursors
    setCursorsByPage({ 1: undefined })
    setPersistedTotal(0)
  }, [filtersKey])

  // Compute effective API params using cursor-based pagination
  const effectiveParams = useMemo(() => {
    const limit = queryParams['size'] || filterOptions?.pageSize || 20
    const cursor = cursorsByPage[filters.page || 1]
    const { page: _page, size: _size, ...rest } = queryParams as any
    return { limit, ...(cursor ? { cursor } : {}), ...rest }
  }, [queryParams, filters.page, cursorsByPage, filterOptions?.pageSize])

  // Fetch patients with current filters
  const {
    data,
    isLoading,
    error,
    refetch,
    isFetching
  } = useQuery({
    queryKey: ['patients', effectiveParams, filters.page],
    queryFn: async () => {
      const response: any = await apiClient.patients.list({ ...effectiveParams })
      // Prefer has_more from API; fallback to pages computation only if absent
      const has_more = (typeof response?.has_more === 'boolean')
        ? response.has_more
        : (typeof response?.pages === 'number' && (response?.page ?? 1) < response.pages)

      const normalized = {
        data: (response?.data ?? response?.items) || [],
        total: response?.total ?? 0,
        page: filters.page || 1,
        size: effectiveParams['limit'] || 20,
        has_more,
        next_cursor: response?.next_cursor
      } as any

      return normalized as any
    },
    staleTime: 30000, // 30 seconds
    retry: 2,
    retryDelay: (attemptIndex) => Math.min(1000 * 2 ** attemptIndex, 30000)
  })

  // Handle success effects since we removed onSuccess for typing compatibility
  useEffect(() => {
    const resp: any = data as any
    if (!resp) return
    if (typeof resp?.total === 'number' && resp.total > 0) {
      setPersistedTotal(resp.total)
    }
    const currentPage = filters.page || 1
    if (resp?.next_cursor) {
      setCursorsByPage(prev => ({ ...prev, [currentPage + 1]: resp.next_cursor }))
    }
  }, [data, filters.page])

  // Invalidate patients query to force refresh
  const invalidatePatients = useCallback(() => {
    queryClient.invalidateQueries({ queryKey: ['patients'] })
  }, [queryClient])

  // Pre-fetch next page
  const prefetchNextPage = useCallback(() => {
    if ((data as any)?.has_more) {
      const nextPage = (filters.page || 1) + 1
      const nextCursor = (data as any)?.next_cursor || cursorsByPage[nextPage]
      const limit = queryParams['size'] || filterOptions?.pageSize || 20
      const nextParams = { ...effectiveParams, cursor: nextCursor, limit }

      queryClient.prefetchQuery({
        queryKey: ['patients', nextParams, nextPage],
        queryFn: async () => {
          const response: any = await apiClient.patients.list(nextParams as any)
          const has_more = (typeof response?.has_more === 'boolean')
            ? response.has_more
            : (typeof response?.pages === 'number' && (response?.page ?? 1) < response.pages)

          return {
            data: (response?.data ?? response?.items) || [],
            total: response?.total ?? 0,
            page: nextPage,
            size: limit,
            has_more,
            next_cursor: response?.next_cursor
          } as any
        },
        staleTime: 30000
      })
    }
  }, [data, filters.page, queryParams, filterOptions?.pageSize, effectiveParams, cursorsByPage, queryClient])

  return {
    // Data
    patients: (data as any)?.data || [],
    total: (persistedTotal || (data as any)?.total || 0),
    page: filters.page || 1,
    limit: (data as any)?.size || (queryParams['size'] || 20),
    hasMore: (data as any)?.has_more || false,

    // Loading states
    isLoading,
    isFetching,

    error,

    // Filters
    filters,
    hasActiveFilters,
    activeFilterCount,

    
    // Actions
    updateFilter,
    updateFilters,
    resetFilters,
    refetch,
    invalidatePatients,
    prefetchNextPage
  }
}

