/**
 * Authentication API Module
 *
 * Handles all authentication-related API calls:
 * - Login/Logout
 * - Registration
 * - Password management
 * - User profile
 * - Session management
 */

import type { ApiClientCore } from './core'

export interface LoginCredentials {
  email: string
  password: string
}

export interface RegisterData {
  email: string
  password: string
  name: string
  role?: string
}

export interface User {
  id: string
  email: string
  full_name: string
  role: string
  is_active: boolean
  permissions: string[]
  created_at: string
  name?: string
  updated_at?: string
  firebase_uid?: string
  session_id?: string
  token?: string
  avatar_url?: string
}

export interface SessionValidationResponse {
  valid: boolean
  user?: {
    id: string
    email: string
    full_name?: string
    name?: string
    role?: string
    permissions?: string[]
    is_active?: boolean
    created_at?: string
    updated_at?: string
  }
  session_data?: Record<string, any>
}

interface LogoutResponse {
  success: boolean
  sessions_deleted: number
  message: string
}

export interface AuthResponse {
  user: User
  access_token: string
  refresh_token?: string
  expires_in?: number
}

export interface PasswordResetRequest {
  email: string
}

export interface PasswordResetConfirm {
  token: string
  new_password: string
}

export interface PasswordChange {
  old_password: string
  new_password: string
}

/**
 * Authentication API methods
 */
export function createAuthApi(client: ApiClientCore) {
  const mapSessionUser = (sessionUser?: SessionValidationResponse['user']): User => {
    if (!sessionUser || !sessionUser.id || !sessionUser.email) {
      throw new Error('Invalid session user payload')
    }

    const displayName = sessionUser.full_name ?? sessionUser.name ?? sessionUser.email

    const user: User = {
      id: sessionUser.id,
      email: sessionUser.email,
      name: displayName,
      full_name: sessionUser.full_name ?? sessionUser.name ?? displayName,
      role: sessionUser.role ?? 'doctor',
      permissions: sessionUser.permissions ?? [],
      is_active: sessionUser.is_active ?? true,
      created_at: sessionUser.created_at ?? new Date().toISOString(),
    }
    if (sessionUser.updated_at) user.updated_at = sessionUser.updated_at
    return user
  }

  const fetchSession = async (): Promise<SessionValidationResponse> => {
    return client.get<SessionValidationResponse>('/session/validate')
  }

  const unsupported = (method: string): never => {
    throw new Error(`${method} is not supported in the Firebase-based authentication flow`)
  }

  return {
    login: async (_credentials: LoginCredentials): Promise<AuthResponse> =>
      unsupported('login'),
    register: async (_data: RegisterData): Promise<AuthResponse> =>
      unsupported('register'),
    requestPasswordReset: async (_data: PasswordResetRequest): Promise<{ message: string }> =>
      unsupported('requestPasswordReset'),
    confirmPasswordReset: async (_data: PasswordResetConfirm): Promise<{ message: string }> =>
      unsupported('confirmPasswordReset'),
    changePassword: async (_data: PasswordChange): Promise<{ message: string }> =>
      unsupported('changePassword'),
    refreshToken: async (_refreshToken: string): Promise<AuthResponse> =>
      unsupported('refreshToken'),
    verifyEmail: async (_token: string): Promise<{ message: string }> =>
      unsupported('verifyEmail'),
    resendVerificationEmail: async (): Promise<{ message: string }> =>
      unsupported('resendVerificationEmail'),

    logout: async (): Promise<LogoutResponse> => {
      const response = await client.delete<LogoutResponse>('/session/logout')
      client.setAuthToken(null)
      return response
    },

    getCurrentUser: async (): Promise<User> => {
      const session = await fetchSession()
      if (!session.valid || !session.user) {
        throw new Error('Not authenticated')
      }
      return mapSessionUser(session.user)
    },

    updateProfile: async (_data: Partial<User>): Promise<User> =>
      unsupported('updateProfile'),

    checkAuth: async (): Promise<{ authenticated: boolean; user?: User }> => {
      const session = await fetchSession()
      if (session.valid && session.user) {
        return { authenticated: true, user: mapSessionUser(session.user) }
      }
      return { authenticated: false }
    },

    getSession: async (): Promise<SessionValidationResponse> => {
      return fetchSession()
    },

    invalidateAllSessions: async (): Promise<LogoutResponse> => {
      const response = await client.delete<LogoutResponse>('/session/logout-all')
      client.setAuthToken(null)
      return response
    },

    createSession: async (
      firebaseToken: string,
      deviceInfo?: { user_agent?: string; timestamp?: string }
    ): Promise<{
      status: string
      expires_at: string
      user: {
        id: string
        email: string
        full_name: string
        role: string
        is_active: boolean
      }
    }> => {
      return client.post('/session', {
        firebase_token: firebaseToken,
        device_info: deviceInfo
      })
    },

    me: async (): Promise<{ data: User | null; session?: Record<string, any> | undefined }> => {
      const session = await fetchSession()
      if (!session.valid || !session.user) {
        return { data: null, session: session.session_data }
      }
      return {
        data: mapSessionUser(session.user),
        session: session.session_data
      }
    },
  }
}

// Export types
export type AuthApi = ReturnType<typeof createAuthApi>

/**
 * Core API Client - Base class for HTTP requests
 *
 * This module provides the foundational HTTP client with:
 * - Request/response handling
 * - Error handling with retry logic
 * - CSRF token management
 * - Authentication token management
 * - Rate limiting and timeout handling
 */

import { createLogger } from "../logger";
import { environment } from "../environment";

const logger = createLogger("ApiClient");

/**
 * API Response interface
 */
export interface ApiResponse<T> {
  data: T;
  message?: string;
  timestamp: string;
}

/**
 * Paginated response interface
 */
export interface PaginatedResponse<T> {
  items: T[];
  total: number;
  page: number;
  size: number;
  pages: number;
}

/**
 * API Error class with enhanced user messaging
 */
export class ApiError extends Error {
  public userFriendlyMessage: string;
  public retryable: boolean;
  public timestamp: string;

  constructor(
    public status: number,
    public data: unknown,
    message?: string,
    userFriendlyMessage?: string,
  ) {
    super(message || `API Error: ${status}`);
    this.name = "ApiError";
    this.userFriendlyMessage = userFriendlyMessage || this.getDefaultUserMessage(status);
    this.retryable = this.isRetryableError(status);
    this.timestamp = new Date().toISOString();
  }

  private getDefaultUserMessage(status: number): string {
    switch (status) {
      case 0:
        return "N├úo foi poss├¡vel conectar ao servidor. Verifique sua conex├úo com a internet.";
      case 400:
        return "Os dados enviados est├úo incorretos. Verifique as informa├º├Áes e tente novamente.";
      case 401:
        return "Sua sess├úo expirou. Por favor, fa├ºa login novamente.";
      case 403:
        return "Voc├¬ n├úo tem permiss├úo para realizar esta a├º├úo.";
      case 404:
        return "O recurso solicitado n├úo foi encontrado.";
      case 408:
        return "A requisi├º├úo demorou muito para responder. Tente novamente.";
      case 409:
        return "Conflito nos dados. Verifique se outro usu├írio n├úo modificou as informa├º├Áes.";
      case 422:
        return "Os dados fornecidos n├úo puderam ser processados. Verifique os campos obrigat├│rios.";
      case 429:
        return "Muitas tentativas em pouco tempo. Aguarde alguns minutos e tente novamente.";
      case 500:
        return "Erro interno do servidor. Nossa equipe foi notificada.";
      case 502:
      case 503:
      case 504:
        return "O servidor est├í temporariamente indispon├¡vel. Tente novamente em alguns minutos.";
      default:
        if (status >= 500) {
          return "Erro no servidor. Nossa equipe foi notificada.";
        }
        if (status >= 400) {
          return "Erro na requisi├º├úo. Verifique os dados e tente novamente.";
        }
        return "Erro inesperado. Tente novamente ou entre em contato com o suporte.";
    }
  }

  private isRetryableError(status: number): boolean {
    // Network errors (0) and server errors (5xx) are retryable
    // Rate limiting (429) and timeouts (408) are retryable
    return status === 0 || status === 408 || status === 429 || (status >= 500 && status <= 599);
  }

  toJSON() {
    return {
      name: this.name,
      message: this.message,
      userFriendlyMessage: this.userFriendlyMessage,
      status: this.status,
      data: this.data,
      retryable: this.retryable,
      timestamp: this.timestamp,
      stack: environment.isDevelopment ? this.stack : undefined,
    };
  }
}

/**
 * Request options interface
 */
export interface RequestOptions extends RequestInit {
  params?: Record<string, string | number | boolean>;
  retries?: number;
  timeout?: number;
}

/**
 * Core API Client class
 */
export class ApiClientCore {
  private baseURL: string;
  private authToken: string | null = null;
  private initialized: boolean = false;
  private csrfToken: string | null = null;
  private csrfTokenPromise: Promise<void> | null = null;

  constructor(baseURL: string) {
    this.baseURL = baseURL;
  }

  /**
   * Set base URL for API requests
   */
  setBaseURL(url: string): void {
    if (!url) {
      logger.warn("Attempted to set empty base URL");
      return;
    }

    // SECURITY: Block HTTP URLs in production to prevent mixed-content errors
    if (url.startsWith("http://") && typeof window !== "undefined") {
      const isProduction =
        window.location.protocol === "https:" || window.location.hostname !== "localhost";

      if (isProduction) {
        logger.error("­ƒÜ¿ SECURITY: Blocked HTTP URL in production:", url);
        url = url.replace("http://", "https://");
        logger.log("   Corrected URL:", url);
      }
    }

    logger.log("Setting base URL:", url);
    this.baseURL = url;
    this.initialized = true;
  }

  /**
   * Get current base URL
   */
  getBaseURL(): string {
    return this.baseURL;
  }

  /**
   * Check if client is initialized
   */
  isInitialized(): boolean {
    return this.initialized;
  }

  /**
   * Set authentication token
   */
  setAuthToken(token: string | null): void {
    logger.debug("[ApiClient] Setting auth token:", {
      hasToken: !!token,
      tokenLength: token?.length,
    });
    this.authToken = token;
  }

  /**
   * Clear authentication token (alias for setAuthToken(null))
   * Used after establishing cookie-based session
   */
  clearAuthToken(): void {
    logger.debug("[ApiClient] Clearing auth token - switching to cookie-only auth");
    this.setAuthToken(null);
  }

  /**
   * Get current auth token
   */
  getAuthToken(): string | null {
    return this.authToken;
  }

  /**
   * Fetch CSRF token from backend
   * Non-blocking: returns gracefully on failure to prevent app initialization blocking
   */
  async fetchCsrfToken(): Promise<void> {
    if (this.csrfTokenPromise) {
      logger.debug("[ApiClient] CSRF token fetch already in progress, waiting...");
      return this.csrfTokenPromise;
    }

    this.csrfTokenPromise = (async () => {
      // Shorter timeout for CSRF fetch (5s) to prevent blocking
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 5000);

      try {
        logger.debug("[ApiClient] Initiating CSRF token fetch...");
        const response = await fetch(`${this.baseURL}/api/v2/csrf-token`, {
          credentials: "include",
          signal: controller.signal,
        });

        if (response.ok) {
          const data = await response.json();
          let csrfToken = data.csrf_token;

          // Handle array format from backend
          if (Array.isArray(csrfToken) && csrfToken.length >= 2) {
            csrfToken = csrfToken[1];
            logger.debug("[ApiClient] CSRF token extracted from array format");
          } else if (typeof csrfToken !== "string") {
            logger.warn("[ApiClient] Unexpected CSRF token format:", typeof csrfToken);
            // Don't throw - just skip setting token
            return;
          }

          this.csrfToken = csrfToken;
          logger.debug("[ApiClient] CSRF token fetched successfully");
        } else {
          logger.warn("[ApiClient] Failed to fetch CSRF token:", response.status);
          // Don't throw - CSRF token is optional for GET requests
        }
      } catch (error) {
        // Log but don't throw - CSRF failure should not block app initialization
        if (error instanceof Error && error.name === 'AbortError') {
          logger.warn("[ApiClient] CSRF token fetch timed out (5s)");
        } else {
          logger.warn("[ApiClient] Error fetching CSRF token (non-critical):", error);
        }
      } finally {
        clearTimeout(timeoutId);
        this.csrfTokenPromise = null;
      }
    })();

    return this.csrfTokenPromise;
  }

  /**
   * Get current CSRF token
   */
  getCsrfToken(): string | null {
    return this.csrfToken;
  }

  /**
   * Set session token
   */
  setSessionToken(session: { access_token?: string } | null): void {
    if (session?.access_token) {
      this.setAuthToken(session.access_token);
    } else {
      this.setAuthToken(null);
    }
  }

  /**
   * Build URL with query parameters
   */
  private buildUrl(endpoint: string, params?: Record<string, string | number | boolean>): string {
    if (!this.initialized) {
      logger.warn("Making request before initialization. Using fallback URL:", this.baseURL);
    }

    const url = new URL(`${this.baseURL}${endpoint}`);

    if (params) {
      Object.entries(params).forEach(([key, value]) => {
        if (value !== undefined && value !== null) {
          url.searchParams.append(key, String(value));
        }
      });
    }

    return url.toString();
  }

  /**
   * Check if error should be retried
   */
  private shouldRetry(error: any, attempt: number): boolean {
    if (attempt >= 3) return false;

    if (error instanceof ApiError && [401, 403].includes(error.status)) {
      return false;
    }

    if (error instanceof ApiError && error.status >= 400 && error.status < 500) {
      return [408, 429].includes(error.status);
    }

    if (error instanceof TypeError) return true;

    if (error instanceof DOMException && error.name === "AbortError") return true;

    if (error instanceof ApiError) {
      return [408, 429, 500, 502, 503, 504].includes(error.status);
    }

    return false;
  }

  /**
   * Sleep for retry backoff
   */
  private async sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  /**
   * Make HTTP request with retry logic
   */
  async request<T>(endpoint: string, options: RequestOptions = {}): Promise<T> {
    const { params, retries = 0, timeout = 30000, ...fetchOptions } = options;
    const url = this.buildUrl(endpoint, params);

    const headers: Record<string, string> = {
      "Content-Type": "application/json",
      ...((fetchOptions.headers as Record<string, string>) || {}),
    };

    // Add auth token
    if (this.authToken) {
      headers["Authorization"] = `Bearer ${this.authToken}`;
    }

    // Add CSRF token for state-changing methods
    const method = (fetchOptions.method || "GET").toUpperCase();
    if (["POST", "PUT", "DELETE", "PATCH"].includes(method) && this.csrfToken) {
      headers["X-CSRF-Token"] = this.csrfToken;
    }

    // Create abort controller for timeout
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);

    try {
      const response = await fetch(url, {
        ...fetchOptions,
        headers,
        credentials: "include",
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({
          detail: response.statusText,
        }));

        const error = new ApiError(
          response.status,
          errorData,
          errorData.detail || `HTTP ${response.status}`,
          errorData.user_message,
        );

        if (this.shouldRetry(error, retries)) {
          await this.sleep(Math.pow(2, retries) * 1000);
          return this.request(endpoint, { ...options, retries: retries + 1 });
        }

        throw error;
      }

      // Handle empty responses (204 No Content, 205 Reset Content)
      if (response.status === 204 || response.status === 205) {
        return undefined as T;
      }

      // Check if response has content before parsing
      const contentLength = response.headers.get("content-length");
      if (contentLength === "0") {
        return undefined as T;
      }

      const data = await response.json();
      return data as T;
    } catch (error) {
      clearTimeout(timeoutId);

      if (error instanceof ApiError) {
        throw error;
      }

      const apiError = new ApiError(
        0,
        error,
        error instanceof Error ? error.message : "Network error",
      );

      if (this.shouldRetry(apiError, retries)) {
        await this.sleep(Math.pow(2, retries) * 1000);
        return this.request(endpoint, { ...options, retries: retries + 1 });
      }

      throw apiError;
    }
  }

  /**
   * GET request
   */
  async get<T>(endpoint: string, params?: Record<string, string | number | boolean>): Promise<T> {
    const options: RequestOptions = { method: "GET" };
    if (params) {
      (options as any).params = params;
    }
    return this.request<T>(endpoint, options);
  }

  /**
   * POST request
   */
  async post<T>(
    endpoint: string,
    data?: any,
    params?: Record<string, string | number | boolean>,
  ): Promise<T> {
    const options: RequestOptions = { method: "POST" };
    if (data !== undefined) (options as any).body = JSON.stringify(data);
    if (params) (options as any).params = params;
    return this.request<T>(endpoint, options);
  }

  /**
   * PUT request
   */
  async put<T>(
    endpoint: string,
    data?: any,
    params?: Record<string, string | number | boolean>,
  ): Promise<T> {
    const options: RequestOptions = { method: "PUT" };
    if (data !== undefined) (options as any).body = JSON.stringify(data);
    if (params) (options as any).params = params;
    return this.request<T>(endpoint, options);
  }

  /**
   * DELETE request
   */
  async delete<T>(
    endpoint: string,
    params?: Record<string, string | number | boolean>,
  ): Promise<T> {
    const options: RequestOptions = { method: "DELETE" };
    if (params) (options as any).params = params;
    return this.request<T>(endpoint, options);
  }

  /**
   * PATCH request
   */
  async patch<T>(
    endpoint: string,
    data?: any,
    params?: Record<string, string | number | boolean>,
  ): Promise<T> {
    const options: RequestOptions = { method: "PATCH" };
    if (data !== undefined) (options as any).body = JSON.stringify(data);
    if (params) (options as any).params = params;
    return this.request<T>(endpoint, options);
  }
}

// Export types
