/**
 * Authentication Context Helpers
 *
 * This module provides helper functions for managing authentication context,
 * user permissions, and auth-related state throughout the application.
 *
 * Features:
 * - Authentication state management
 * - Permission checking utilities
 * - Role-based access control
 * - Session validation
 * - Auth context providers
 */

import { createContext, useContext } from 'react'

// Removed Supabase imports - using generic types
type User = any
type Session = any
type UserMetadata = Record<string, any>

// Extended user interface with application-specific fields
export interface AppUser {
  id: string
  email: string
  full_name?: string
  role?: string
  is_active: boolean
  permissions?: string[]
  created_at: string
  last_sign_in_at?: string
  metadata?: Record<string, any>
}

// Permission and role definitions
export interface Permission {
  id: string
  name: string
  description: string
  resource: string
  action: string
}

export interface Role {
  id: string
  name: string
  description: string
  permissions: Permission[]
  hierarchy_level: number
}

// Auth context interface
export interface AuthContextValue {
  // User state
  user: AppUser | null
  session: Session | null
  isAuthenticated: boolean
  isLoading: boolean
  error: string | null

  // Auth methods
  signIn: (email: string, password: string) => Promise<void>
  signOut: () => Promise<void>
  signUp: (email: string, password: string, metadata?: Record<string, any>) => Promise<void>
  resetPassword: (email: string) => Promise<void>
  updatePassword: (password: string) => Promise<void>
  refreshSession: () => Promise<void>

  // Permission methods
  hasPermission: (permission: string, resource?: string) => boolean
  hasRole: (role: string) => boolean
  hasAnyRole: (roles: string[]) => boolean
  hasAllPermissions: (permissions: string[]) => boolean
  hasAnyPermission: (permissions: string[]) => boolean
  canAccessResource: (resource: string, action: string) => boolean
  getPermissionLevel: (resource: string) => number

  // Utility methods
  isAdmin: () => boolean
  isSuperAdmin: () => boolean
  getDisplayName: () => string
  getUserInitials: () => string
  isSessionValid: () => boolean
  getSessionTimeLeft: () => number
}

// Create auth context
export const AuthContext = createContext<AuthContextValue | undefined>(undefined)

// Hook to use auth context
export function useAuthContext(): AuthContextValue {
  const context = useContext(AuthContext)
  if (context === undefined) {
    throw new Error('useAuthContext must be used within an AuthProvider')
  }
  return context
}

// Default role hierarchy
const ROLE_HIERARCHY: Record<string, number> = {
