/**
 * Convert Supabase User to AppUser
 */
export function convertSupabaseUser(user: User): AppUser {
  return {
    id: user.id,
    email: user.email || '',
    full_name: user.user_metadata?.['full_name'] || user.user_metadata?.['name'] || '',
    role: user.user_metadata?.['role'] || 'user',
    is_active: true,
    permissions: getUserPermissions(user.user_metadata?.['role'] || 'user'),
    created_at: user.created_at,
    last_sign_in_at: user.last_sign_in_at as string,
    metadata: user.user_metadata
  }
}

/**
 * Get permissions for a role
 */
export function getUserPermissions(role: string): string[] {
  const permissions = DEFAULT_PERMISSIONS[role] || DEFAULT_PERMISSIONS['user']
  return (permissions || []).map(p => p.id)
}

/**
 * Check if user has a specific permission
 */
export function hasPermission(user: AppUser | null, permission: string, resource?: string): boolean {
  if (!user || !user.is_active) return false

  // Super admin has all permissions
  if (user.role === 'super_admin') return true

  // Check if user has the specific permission
  if (user.permissions?.includes(permission)) return true

  // Check if user has wildcard permission for resource
  if (resource && user.permissions?.includes(`${resource}.*`)) return true

  // Check if user has all permissions wildcard
  if (user.permissions?.includes('*') || user.permissions?.includes('all')) return true

  return false
}

/**
 * Check if user has a specific role
 */
export function hasRole(user: AppUser | null, role: string): boolean {
  if (!user || !user.is_active) return false
  return user.role === role
}

/**
 * Check if user has any of the specified roles
 */
export function hasAnyRole(user: AppUser | null, roles: string[]): boolean {
  if (!user || !user.is_active) return false
  return roles.includes(user.role || '')
}

/**
 * Check if user has all specified permissions
 */
export function hasAllPermissions(user: AppUser | null, permissions: string[]): boolean {
  if (!user || !user.is_active) return false
  return permissions.every(permission => hasPermission(user, permission))
}

/**
 * Check if user has any of the specified permissions
 */
export function hasAnyPermission(user: AppUser | null, permissions: string[]): boolean {
  if (!user || !user.is_active) return false
  return permissions.some(permission => hasPermission(user, permission))
}

/**
 * Check if user can access a resource with specific action
 */
export function canAccessResource(user: AppUser | null, resource: string, action: string): boolean {
  if (!user || !user.is_active) return false

  // Check specific permission
  if (hasPermission(user, `${resource}.${action}`, resource)) return true

  // Check manage permission (implies all actions)
  if (hasPermission(user, `${resource}.manage`, resource)) return true

  return false
}

/**
 * Get permission level for a resource (based on role hierarchy)
 */
export function getPermissionLevel(user: AppUser | null, resource: string): number {
  if (!user || !user.is_active) return 0

  const roleLevel = ROLE_HIERARCHY[user.role || 'user'] || 0

  // Check if user has specific permissions for this resource
  const resourcePermissions = user.permissions?.filter(p => p.startsWith(resource)) || []
  if (resourcePermissions.length > 0) {
    return roleLevel + 10 // Bonus for having specific permissions
  }

  return roleLevel
}

/**
 * Check if user is admin (admin or super_admin)
 */
export function isAdmin(user: AppUser | null): boolean {
  return hasAnyRole(user, ['admin', 'super_admin'])
}

/**
 * Check if user is super admin
 */
export function isSuperAdmin(user: AppUser | null): boolean {
  return hasRole(user, 'super_admin')
}

/**
 * Get user display name
 */
export function getDisplayName(user: AppUser | null): string {
  if (!user) return 'Guest'

  if (user.full_name && user.full_name.trim()) {
    return user.full_name
  }

  if (user.email) {
    // @ts-expect-error TODO: fix userId type
    return user.email.split('@')[0]
  }

  return 'User'
}

/**
 * Get user initials for avatar
 */
export function getUserInitials(user: AppUser | null): string {
  if (!user) return 'G'

  const displayName = getDisplayName(user)
  const parts = displayName.split(' ')

  // @ts-expect-error TODO: fix session undefined checks
  if (parts.length >= 2) {
    return (parts[0][0] + parts[1][0]).toUpperCase()
  }

  return displayName.substring(0, 2).toUpperCase()
}

/**
 * Check if session is valid
 */
export function isSessionValid(session: Session | null): boolean {
  if (!session) return false

  const now = Math.floor(Date.now() / 1000)
  const expiresAt = session.expires_at || 0

  return expiresAt > now
}

/**
 * Get time left in session (in seconds)
 */
export function getSessionTimeLeft(session: Session | null): number {
  if (!session) return 0

  const now = Math.floor(Date.now() / 1000)
  const expiresAt = session.expires_at || 0

  return Math.max(0, expiresAt - now)
}

/**
 * Check if session is expiring soon (within 5 minutes)
 */
export function isSessionExpiringSoon(session: Session | null): boolean {
  const timeLeft = getSessionTimeLeft(session)
  return timeLeft > 0 && timeLeft < 300 // 5 minutes
}

/**
 * Format role name for display
 */
export function formatRoleName(role: string): string {
  return role
    .replace(/_/g, ' ')
    .replace(/\b\w/g, l => l.toUpperCase())
}

/**
 * Get role description
 */
export function getRoleDescription(role: string): string {
  const descriptions: Record<string, string> = {
    super_admin: 'Full system access with all permissions',
    admin: 'Administrative access to manage users and system',
    manager: 'Management access to oversee operations',
    doctor: 'Medical professional with patient care access',
    nurse: 'Nursing staff with patient care access',
    staff: 'General staff with limited access',
    reception: 'Reception staff with appointment management',
    user: 'Standard user with basic access',
    patient: 'Patient with access to own information'
  }

  return descriptions[role] || 'Standard user access'
}

/**
 * Get available roles for user management
 */
export function getAvailableRoles(currentUserRole: string): string[] {
  const currentLevel = ROLE_HIERARCHY[currentUserRole] || 0

  return Object.entries(ROLE_HIERARCHY)
    .filter(([_, level]) => level < currentLevel)
    .map(([role, _]) => role)
    .sort((a, b) => (ROLE_HIERARCHY[b] || 0) - (ROLE_HIERARCHY[a] || 0))
}

/**
 * Check if current user can manage target user
 */
export function canManageUser(currentUser: AppUser | null, targetUserRole: string): boolean {
  if (!currentUser || !currentUser.is_active) return false

  const currentLevel = ROLE_HIERARCHY[currentUser.role || 'user'] || 0
  const targetLevel = ROLE_HIERARCHY[targetUserRole] || 0

  return currentLevel > targetLevel
}

/**
 * Validate permission string format
 */
export function isValidPermission(permission: string): boolean {
  // Permission format: resource.action or wildcard patterns
  const permissionRegex = /^(\*|[a-z_]+)\.(\*|[a-z_]+)$|^(\*|all)$/
  return permissionRegex.test(permission)
}

/**
 * Parse permission string
 */
export function parsePermission(permission: string): { resource: string; action: string } | null {
  if (permission === '*' || permission === 'all') {
    return { resource: '*', action: '*' }
  }

    // @ts-expect-error TODO: fix email undefined
  const parts = permission.split('.')
  if (parts.length === 2) {
    return { resource: parts[0], action: parts[1] }
  }

  return null
}

/**
 * Create permission helpers for a specific user
 */
export function createUserPermissionHelpers(user: AppUser | null) {
  return {
    hasPermission: (permission: string, resource?: string) => hasPermission(user, permission, resource),
    hasRole: (role: string) => hasRole(user, role),
    hasAnyRole: (roles: string[]) => hasAnyRole(user, roles),
    hasAllPermissions: (permissions: string[]) => hasAllPermissions(user, permissions),
    hasAnyPermission: (permissions: string[]) => hasAnyPermission(user, permissions),
    canAccessResource: (resource: string, action: string) => canAccessResource(user, resource, action),
    getPermissionLevel: (resource: string) => getPermissionLevel(user, resource),
    isAdmin: () => isAdmin(user),
    isSuperAdmin: () => isSuperAdmin(user),
    getDisplayName: () => getDisplayName(user),
    getUserInitials: () => getUserInitials(user),
    canManageUser: (targetUserRole: string) => canManageUser(user, targetUserRole)
  }
}

/**
 * Authentication and RLS Error Handling Utilities
 *
 * This module provides comprehensive error handling for authentication,
 * authorization, and Row Level Security (RLS) violations in Supabase operations.
 *
 * Features:
 * - RLS violation detection and user-friendly messages
 * - Authentication error categorization
 * - User feedback helpers
 * - Retry logic for transient errors
 * - Permission context helpers
 */

import { createLogger } from './logger'

// Removed Supabase dependency - PostgrestError type replaced with generic error
type PostgrestError = {
  message: string
  code?: string
  details?: string
  hint?: string
}

const logger = createLogger('AuthErrorHandler')

// Error types for better categorization
export enum AuthErrorType {
  AUTHENTICATION_REQUIRED = 'AUTHENTICATION_REQUIRED',
  INVALID_CREDENTIALS = 'INVALID_CREDENTIALS',
  SESSION_EXPIRED = 'SESSION_EXPIRED',
  INSUFFICIENT_PERMISSIONS = 'INSUFFICIENT_PERMISSIONS',
  RLS_VIOLATION = 'RLS_VIOLATION',
  NETWORK_ERROR = 'NETWORK_ERROR',
  RATE_LIMITED = 'RATE_LIMITED',
  SERVER_ERROR = 'SERVER_ERROR',
  UNKNOWN_ERROR = 'UNKNOWN_ERROR'
}

// User-friendly error messages
export interface UserFriendlyError {
  type: AuthErrorType
  title: string
  message: string
  actionable: boolean
  retryable: boolean
  actions?: {
    primary?: {
      label: string
      action: string
    }
    secondary?: {
      label: string
      action: string
    }
  }
}

// RLS error patterns to detect specific violations
const RLS_ERROR_PATTERNS = [
  /new row violates row-level security policy/i,
  /permission denied for table/i,
  /insufficient privilege/i,
  /row-level security policy/i,
  /policy.*violation/i,
  /access denied/i,
  /forbidden/i
]

// Authentication error patterns
const AUTH_ERROR_PATTERNS = {
  INVALID_CREDENTIALS: [
    /invalid login credentials/i,
    /email not confirmed/i,
    /invalid email or password/i,
    /user not found/i
  ],
  SESSION_EXPIRED: [
    /jwt expired/i,
    /token.*expired/i,
    /session.*expired/i,
    /invalid jwt/i
  ],
  RATE_LIMITED: [
    /too many requests/i,
    /rate limit/i,
    /too many attempts/i
  ]
}

/**
 * Analyzes an error and categorizes it for better handling
 */
export function categorizeError(error: any): AuthErrorType {
  if (!error) return AuthErrorType.UNKNOWN_ERROR

  const errorMessage = typeof error === 'string' ? error :
    error.message || error.error_description || error.error || ''

  const statusCode = error.status || error.statusCode || error.code

  // Check for RLS violations first
  if (statusCode === 403 || RLS_ERROR_PATTERNS.some(pattern => pattern.test(errorMessage))) {
    return AuthErrorType.RLS_VIOLATION
  }

  // Check for authentication errors
  if (statusCode === 401) {
    return AuthErrorType.AUTHENTICATION_REQUIRED
  }

  // Check specific authentication patterns
  for (const [type, patterns] of Object.entries(AUTH_ERROR_PATTERNS)) {
    if (patterns.some(pattern => pattern.test(errorMessage))) {
      return type as AuthErrorType
    }
  }

  // Check for network errors
  if (statusCode >= 500 || errorMessage.includes('network') || errorMessage.includes('fetch')) {
    return AuthErrorType.NETWORK_ERROR
  }

  // Check for rate limiting
  if (statusCode === 429) {
    return AuthErrorType.RATE_LIMITED
  }

  return AuthErrorType.UNKNOWN_ERROR
}

/**
 * Converts a technical error into a user-friendly message
 */
export function createUserFriendlyError(error: any, context?: string): UserFriendlyError {
  const errorType = categorizeError(error)
  const contextSuffix = context ? ` when ${context}` : ''

  switch (errorType) {
    case AuthErrorType.RLS_VIOLATION:
      return {
        type: errorType,
        title: 'Access Denied',
        message: `You don't have permission to perform this action${contextSuffix}. Please contact your administrator if you believe this is an error.`,
        actionable: true,
        retryable: false,
        actions: {
          primary: {
            label: 'Contact Support',
            action: 'contact_support'
          },
          secondary: {
            label: 'Go Back',
            action: 'go_back'
          }
        }
      }

    case AuthErrorType.AUTHENTICATION_REQUIRED:
      return {
        type: errorType,
        title: 'Authentication Required',
        message: `You need to sign in${contextSuffix}.`,
        actionable: true,
        retryable: false,
        actions: {
          primary: {
            label: 'Sign In',
            action: 'sign_in'
          }
        }
      }

    case AuthErrorType.INVALID_CREDENTIALS:
      return {
        type: errorType,
        title: 'Invalid Credentials',
        message: 'The email or password you entered is incorrect. Please try again.',
        actionable: true,
        retryable: true,
        actions: {
          primary: {
            label: 'Try Again',
            action: 'retry_login'
          },
          secondary: {
            label: 'Reset Password',
            action: 'reset_password'
          }
        }
      }

    case AuthErrorType.SESSION_EXPIRED:
      return {
        type: errorType,
        title: 'Session Expired',
        message: 'Your session has expired. Please sign in again.',
        actionable: true,
        retryable: false,
        actions: {
          primary: {
            label: 'Sign In',
            action: 'sign_in'
          }
        }
      }

    case AuthErrorType.INSUFFICIENT_PERMISSIONS:
      return {
        type: errorType,
        title: 'Insufficient Permissions',
        message: `You don't have the required permissions${contextSuffix}. Contact your administrator to request access.`,
        actionable: true,
        retryable: false,
        actions: {
          primary: {
            label: 'Request Access',
            action: 'request_access'
          },
          secondary: {
            label: 'Go Back',
            action: 'go_back'
          }
        }
      }

    case AuthErrorType.NETWORK_ERROR:
      return {
        type: errorType,
        title: 'Connection Error',
        message: 'Unable to connect to the server. Please check your internet connection and try again.',
        actionable: true,
        retryable: true,
        actions: {
          primary: {
            label: 'Retry',
            action: 'retry'
          }
        }
      }

    case AuthErrorType.RATE_LIMITED:
      return {
        type: errorType,
        title: 'Too Many Attempts',
        message: 'You\'ve made too many requests. Please wait a moment before trying again.',
        actionable: true,
        retryable: true,
        actions: {
          primary: {
            label: 'Try Again Later',
            action: 'retry_later'
          }
        }
      }

    case AuthErrorType.SERVER_ERROR:
      return {
        type: errorType,
        title: 'Server Error',
        message: 'Something went wrong on our end. Please try again or contact support if the problem persists.',
        actionable: true,
        retryable: true,
        actions: {
          primary: {
            label: 'Retry',
            action: 'retry'
          },
          secondary: {
            label: 'Contact Support',
            action: 'contact_support'
          }
        }
      }

    default:
      return {
        type: AuthErrorType.UNKNOWN_ERROR,
        title: 'Unexpected Error',
        message: 'An unexpected error occurred. Please try again or contact support if the problem persists.',
        actionable: true,
        retryable: true,
        actions: {
          primary: {
            label: 'Retry',
            action: 'retry'
          },
          secondary: {
            label: 'Contact Support',
            action: 'contact_support'
          }
        }
      }
  }
}

/**
 * Checks if an error is related to RLS (Row Level Security)
 */
export function isRLSError(error: any): boolean {
  return categorizeError(error) === AuthErrorType.RLS_VIOLATION
}

/**
 * Checks if an error is retryable
 */
export function isRetryableError(error: any): boolean {
  const errorType = categorizeError(error)
  return [
    AuthErrorType.NETWORK_ERROR,
    AuthErrorType.RATE_LIMITED,
    AuthErrorType.SERVER_ERROR
  ].includes(errorType)
}

/**
 * Checks if an error requires authentication
 */
export function requiresAuthentication(error: any): boolean {
  const errorType = categorizeError(error)
  return [
    AuthErrorType.AUTHENTICATION_REQUIRED,
    AuthErrorType.SESSION_EXPIRED
  ].includes(errorType)
}

/**
 * Enhanced error handler for Supabase operations
 */
export class SupabaseErrorHandler {
  private static instance: SupabaseErrorHandler
  private errorListeners: ((error: UserFriendlyError) => void)[] = []

  static getInstance(): SupabaseErrorHandler {
    if (!SupabaseErrorHandler.instance) {
      SupabaseErrorHandler.instance = new SupabaseErrorHandler()
    }
    return SupabaseErrorHandler.instance
  }

  /**
   * Add a global error listener
   */
  onError(listener: (error: UserFriendlyError) => void): () => void {
    this.errorListeners.push(listener)

    // Return unsubscribe function
    return () => {
      const index = this.errorListeners.indexOf(listener)
      if (index > -1) {
        this.errorListeners.splice(index, 1)
      }
    }
  }

  /**
   * Handle and emit an error
   */
  handleError(error: any, context?: string): UserFriendlyError {
    const userFriendlyError = createUserFriendlyError(error, context)

    // Emit to listeners
    this.errorListeners.forEach(listener => {
      try {
        listener(userFriendlyError)
      } catch (listenerError) {
        logger.error('Error in error listener:', listenerError)
      }
    })

    return userFriendlyError
  }

  /**
   * Wrap a Supabase operation with error handling
   */
  async withErrorHandling<T>(
    operation: () => Promise<{ data: T; error: PostgrestError | null }>,
    context?: string
  ): Promise<T> {
    try {
      const { data, error } = await operation()

      if (error) {
        const userFriendlyError = this.handleError(error, context)
        throw new SupabaseOperationError(userFriendlyError, error)
      }

      return data
    } catch (error) {
      if (error instanceof SupabaseOperationError) {
        throw error
      }

      const userFriendlyError = this.handleError(error, context)
      throw new SupabaseOperationError(userFriendlyError, error)
    }
  }
}

/**
 * Custom error class for Supabase operations
 */
export class SupabaseOperationError extends Error {
  constructor(
    public userFriendlyError: UserFriendlyError,
    public originalError: any
  ) {
    super(userFriendlyError.message)
    this.name = 'SupabaseOperationError'
  }
}

/**
 * Utility function to get permission context for error messages
 */
export function getPermissionContext(tableName: string, operation: string): string {
  const operations: Record<string, string> = {
    select: 'viewing',
    insert: 'creating',
    update: 'updating',
    delete: 'deleting'
  }

  const action = operations[operation.toLowerCase()] || operation.toLowerCase()
  return `${action} ${tableName.replace('_', ' ')}`
}

/**
 * Helper to format table names for user display
 */
export function formatTableName(tableName: string): string {
  return tableName
    .replace(/_/g, ' ')
    .replace(/\b\w/g, l => l.toUpperCase())
}

// Export singleton instance
export const errorHandler = SupabaseErrorHandler.getInstance()

// Simple client types export to avoid import errors
export interface ApiResponse<T = any> {
  data: T
  status: number
  statusText: string
}

export interface ApiError {
  message: string
  status: number
  details?: any
}

// Placeholder for client types that may be needed
export type ClientResponse<T = any> = ApiResponse<T>
export type ClientError = ApiError

/**
 * Configuration Initializer Component for React App
 *
 * This component ensures that runtime configuration is loaded before the app starts.
 * It provides a loading screen while configuration is being fetched and handles
 * configuration errors gracefully.
 */

import React, { createContext, useContext, useEffect, useState, ReactNode } from 'react';
import { getRuntimeConfig, type RuntimeConfig } from './runtime-config';
import { apiClient } from './api-client';
import { createLogger } from './logger';

const logger = createLogger('ConfigInitializer');

// Configuration context
interface ConfigContextType {
  config: RuntimeConfig | null;
  loading: boolean;
  error: string | null;
  reload: () => Promise<void>;
}

const ConfigContext = createContext<ConfigContextType | null>(null);

// Configuration provider component
interface ConfigProviderProps {
  children: ReactNode;
  fallbackComponent?: React.ComponentType<{ error: string; reload: () => void }>;
  loadingComponent?: React.ComponentType;
}

export function ConfigProvider({
  children,
  fallbackComponent: FallbackComponent,
  loadingComponent: LoadingComponent
}: ConfigProviderProps) {
  const [config, setConfig] = useState<RuntimeConfig | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const loadConfiguration = async () => {
    // SAFETY: Force timeout after 15 seconds to prevent infinite loading
    const timeoutId = setTimeout(() => {
      logger.error('ÔÅ▒´©Å [ConfigProvider] Configuration loading timeout after 15s');
      setError('Tempo limite excedido ao carregar configura├º├úo. Verifique sua conex├úo.');
      setLoading(false);
    }, 15000);

    try {
      logger.info('­ƒÜÇ [ConfigProvider] Starting configuration loading...');
      setLoading(true);
      setError(null);

      logger.info('­ƒôï [ConfigProvider] Step 1: Loading runtime configuration...');

      // Load config directly without timeout race condition
      // getRuntimeConfig already has internal timeout handling
      const runtimeConfig = await getRuntimeConfig();
      logger.info('Ô£à [ConfigProvider] Step 1: Configuration loaded successfully', {
        apiUrl: runtimeConfig.VITE_API_URL,
        apiBaseUrl: runtimeConfig.VITE_API_BASE_URL
      });

      // Initialize API client with runtime config
      // Use VITE_API_BASE_URL (sem o sufixo /api) para evitar duplica├º├úo
      // Se apenas VITE_API_URL estiver dispon├¡vel, sanitiza removendo o sufixo /api/v2
      const FALLBACK_PROD_API = 'https://clinica-oncologica-v02-production.up.railway.app';
      const apiBaseUrl = runtimeConfig.VITE_API_BASE_URL ||
                         runtimeConfig.VITE_API_URL?.replace(/\/api\/v2$/, '') ||
                         FALLBACK_PROD_API;
      logger.info('­ƒôí [ConfigProvider] Step 2: Initializing API client...', { apiBaseUrl });
      apiClient.setBaseURL(apiBaseUrl);
      logger.info('Ô£à [ConfigProvider] Step 2: API client initialized');

      // Fetch CSRF token for session security (non-blocking)
      logger.info('­ƒöÉ [ConfigProvider] Step 3: Fetching CSRF token...');
      try {
        await apiClient.fetchCsrfToken();
        logger.info('Ô£à [ConfigProvider] Step 3: CSRF token fetched successfully');
      } catch (csrfError) {
        // CSRF token fetch failure should NOT block app initialization
        logger.warn('ÔÜá´©Å [ConfigProvider] Step 3: Failed to fetch CSRF token (non-critical):', csrfError);
        // App will still work; CSRF token will be fetched on first API call if needed
      }

      // Supabase removed - using Firebase exclusively
      logger.info('­ƒöÑ [ConfigProvider] Step 4: Using Firebase for authentication');

      setConfig(runtimeConfig);
      clearTimeout(timeoutId); // Clear timeout on success
      logger.info('Ô£à [ConfigProvider] Configuration initialization complete!');
    } catch (err) {
      clearTimeout(timeoutId); // Clear timeout on error
      const errorMessage = err instanceof Error ? err.message : 'Failed to load configuration';
      logger.error('ÔØî [ConfigProvider] Configuration loading failed:', err);
      setError(errorMessage);
    } finally {
      // CRITICAL: Always set loading to false, no matter what happens
      logger.info('­ƒÅü [ConfigProvider] Finalizing - setting loading state to false');
      setLoading(false);
      logger.info('Ô£ô [ConfigProvider] Loading state updated, app ready to render');
    }
  };

  useEffect(() => {
    loadConfiguration();
  }, []);

  // Loading state
  if (loading) {
    if (LoadingComponent) {
      return <LoadingComponent />;
    }
    return <DefaultLoadingComponent />;
  }

  // Error state
  if (error) {
    if (FallbackComponent) {
      return <FallbackComponent error={error} reload={loadConfiguration} />;
    }
    return <DefaultErrorComponent error={error} reload={loadConfiguration} />;
  }

  // Success state
  const contextValue: ConfigContextType = {
    config,
    loading,
    error,
    reload: loadConfiguration
  };

  return (
    <ConfigContext.Provider value={contextValue}>
      {children}
    </ConfigContext.Provider>
  );
}

// Hook to access configuration
export function useConfig(): ConfigContextType {
  const context = useContext(ConfigContext);
  if (!context) {
    throw new Error('useConfig must be used within a ConfigProvider');
  }
  return context;
}

// Hook to get configuration values safely
export function useConfigValue<K extends keyof RuntimeConfig>(
  key: K,
  fallback?: RuntimeConfig[K]
): RuntimeConfig[K] | undefined {
  const { config } = useConfig();
  return config?.[key] || fallback;
}

// Default loading component
function DefaultLoadingComponent() {
  return (
    <div className="min-h-screen flex items-center justify-center bg-background">
      <div className="text-center space-y-4">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto"></div>
        <div className="space-y-2">
          <h2 className="text-xl font-semibold">Carregando Configura├º├úo</h2>
          <p className="text-muted-foreground">
            Preparando o sistema Hormonia...
          </p>
        </div>
      </div>
    </div>
  );
}

// Default error component
interface DefaultErrorComponentProps {
  error: string;
  reload: () => void;
}

function DefaultErrorComponent({ error, reload }: DefaultErrorComponentProps) {
  return (
    <div className="min-h-screen flex items-center justify-center bg-background">
      <div className="text-center space-y-6 max-w-md mx-auto p-6">
        <div className="text-destructive">
          <svg
            className="h-16 w-16 mx-auto mb-4"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4.5c-.77-.833-2.694-.833-3.464 0L3.34 16.5c-.77.833.192 2.5 1.732 2.5z"
            />
          </svg>
        </div>

        <div className="space-y-2">
          <h2 className="text-xl font-semibold text-destructive">
            Erro de Configura├º├úo
          </h2>
          <p className="text-muted-foreground">
            N├úo foi poss├¡vel carregar a configura├º├úo do sistema.
          </p>
          <details className="text-sm text-left">
            <summary className="cursor-pointer text-muted-foreground hover:text-foreground">
              Detalhes do erro
            </summary>
            <pre className="mt-2 p-2 bg-muted rounded text-xs overflow-auto">
              {error}
            </pre>
          </details>
        </div>

        <div className="space-y-3">
          <button
            onClick={reload}
            className="px-4 py-2 bg-primary text-primary-foreground rounded-md hover:bg-primary/90 transition-colors"
          >
            Tentar Novamente
          </button>

          <div className="text-xs text-muted-foreground">
            <p>Se o problema persistir:</p>
            <ul className="mt-1 space-y-1">
              <li>ÔÇó Verifique sua conex├úo com a internet</li>
              <li>ÔÇó Recarregue a p├ígina (F5)</li>
              <li>ÔÇó Contate o suporte t├®cnico</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
}

// Utility function to initialize config outside of React
export async function initializeConfiguration(): Promise<RuntimeConfig> {
  try {
    logger.info('Initializing runtime configuration...');
    const config = await getRuntimeConfig();
    logger.info('Configuration initialized successfully');
    return config;
  } catch (error) {
    logger.error('Failed to initialize configuration:', error);
    throw error;
  }
}

// Configuration validation hook
export function useConfigValidation() {
  const { config, error } = useConfig();

  return {
    isValid: !!config && !error,
    hasAPI: !!(config?.VITE_API_BASE_URL || config?.VITE_API_URL),
    hasWebSocket: !!(config?.VITE_WS_BASE_URL || config?.VITE_WS_URL),
    config,
    error
  };
}

