/**
 * Validates a single environment variable
 */
function validateField(key: string, value: any, rule: ValidationRule): {
  errors: ValidationError[]
  warnings: ValidationWarning[]
} {
  const errors: ValidationError[] = []
  const warnings: ValidationWarning[] = []

  // Clean value: remove quotes and trim (Vite preserves quotes from .env)
  if (value && typeof value === 'string') {
    const originalValue = value
    value = value.replace(/^["']|["']$/g, '').trim()

    if (originalValue !== value && import.meta.env.DEV) {
      logger.warn(`${key}: Removed quotes from value (found in .env file)`)
    }
  }

  // Check if required field is missing
  if (rule.required && (!value || value.trim() === '')) {
    errors.push({
      field: key,
      message: `Required environment variable is missing`,
      severity: 'critical',
      suggestion: `Set ${key} in your .env file. ${rule.description}`
    })
    return { errors, warnings }
  }

  // Skip further validation if field is optional and empty
  if (!value || value.trim() === '') {
    return { errors, warnings }
  }

  // Type validation
  if (rule.type) {
    switch (rule.type) {
      case 'number':
        if (isNaN(Number(value))) {
          errors.push({
            field: key,
            message: `Must be a valid number`,
            severity: 'error',
            suggestion: `Provide a numeric value for ${key}`
          })
        }
        break

      case 'boolean':
        if (!['true', 'false'].includes(value.toLowerCase())) {
          errors.push({
            field: key,
            message: `Must be 'true' or 'false'`,
            severity: 'error',
            suggestion: `Set ${key} to either 'true' or 'false'`
          })
        }
        break

      case 'url':
        try {
          const url = new URL(value)
          if (!['http:', 'https:', 'ws:', 'wss:'].includes(url.protocol)) {
            errors.push({
              field: key,
              message: `Must be a valid HTTP/HTTPS/WS/WSS URL`,
              severity: 'error'
            })
          }
        } catch {
          errors.push({
            field: key,
            message: `Must be a valid URL`,
            severity: 'error',
            suggestion: `Provide a valid URL for ${key} (e.g., https://example.com)`
          })
        }
        break

      case 'email':
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
        if (!emailRegex.test(value)) {
          errors.push({
            field: key,
            message: `Must be a valid email address`,
            severity: 'error'
          })
        }
        break
    }
  }

  // Format validation
  if (rule.format && !rule.format.test(value)) {
    errors.push({
      field: key,
      message: `Does not match required format`,
      severity: 'error',
      suggestion: `Check the format requirements for ${key}`
    })
  }

  // Length validation
  if (rule.minLength && value.length < rule.minLength) {
    errors.push({
      field: key,
      message: `Must be at least ${rule.minLength} characters long`,
      severity: 'error'
    })
  }

  if (rule.maxLength && value.length > rule.maxLength) {
    errors.push({
      field: key,
      message: `Must not exceed ${rule.maxLength} characters`,
      severity: 'error'
    })
  }

  // Allowed values validation
  if (rule.allowedValues && !rule.allowedValues.includes(value)) {
    errors.push({
      field: key,
      message: `Must be one of: ${rule.allowedValues.join(', ')}`,
      severity: 'error'
    })
  }

  // Custom validation
  if (rule.validator) {
    const result = rule.validator(value)
    if (result !== true) {
      if (typeof result === 'string') {
        warnings.push({
          field: key,
          message: result,
          suggestion: `Review the configuration for ${key}`
        })
      } else {
        errors.push({
          field: key,
          message: `Custom validation failed`,
          severity: 'error'
        })
      }
    }
  }

  // Security checks
  if (rule.security?.shouldNotBeHardcoded) {
    // Check if this appears to be a hardcoded value (very basic check)
    if (value.length > 20 && !value.includes('$') && !value.includes('{')) {
      warnings.push({
        field: key,
        message: `Appears to be hardcoded. Consider using environment variables.`,
        suggestion: `Move this value to a secure environment variable`
      })
    }
  }

  return { errors, warnings }
}

/**
 * Validates the entire runtime configuration
 */
export function validateRuntimeConfig(config: Partial<RuntimeConfig>): ValidationResult {
  const errors: ValidationError[] = []
  const warnings: ValidationWarning[] = []
  let validated = 0

  // Validate each field
  Object.entries(ENV_VALIDATION_RULES).forEach(([key, rule]) => {
    const value = config[key as keyof RuntimeConfig]
    const { errors: fieldErrors, warnings: fieldWarnings } = validateField(key, value, rule)

    errors.push(...fieldErrors)
    warnings.push(...fieldWarnings)

    if (value !== undefined && value !== null && value !== '') {
      validated++
    }
  })

  // Environment-specific validations
  const environment = config.VITE_ENVIRONMENT || 'development'

  if (environment === 'production') {
    // Production-specific checks
    if (config.VITE_DEBUG_MODE === 'true') {
      warnings.push({
        field: 'VITE_DEBUG_MODE',
        message: 'Debug mode is enabled in production',
        suggestion: 'Set VITE_DEBUG_MODE=false for production'
      })
    }

    if (config.VITE_API_URL?.includes('localhost')) {
      errors.push({
        field: 'VITE_API_URL',
        message: 'Using localhost URL in production',
        severity: 'critical',
        suggestion: 'Use production API URL'
      })
    }
  }

  const summary = {
    total: Object.keys(ENV_VALIDATION_RULES).length,
    validated,
    errors: errors.length,
    warnings: warnings.length,
    missing: Object.keys(ENV_VALIDATION_RULES).filter(key => {
      const rule = ENV_VALIDATION_RULES[key as keyof RuntimeConfig]
      const value = config[key as keyof RuntimeConfig]
      return rule.required && (!value || value.trim() === '')
    }).length
  }

  return {
    isValid: errors.length === 0,
    errors,
    warnings,
    summary
  }
}

/**
 * Validates environment variables and logs results
 */
export function validateAndLogConfig(config: Partial<RuntimeConfig>): boolean {
  const result = validateRuntimeConfig(config)

  if (result.errors.length > 0) {
    logger.group('ÔØî Environment Configuration Errors')
    result.errors.forEach(error => {
      logger.error(`${error.field}: ${error.message}`)
      if (error.suggestion) {
        logger.info(`­ƒÆí Suggestion: ${error.suggestion}`)
      }
    })
    logger.groupEnd()
  }

  if (result.warnings.length > 0) {
    logger.group('ÔÜá´©Å Environment Configuration Warnings')
    result.warnings.forEach(warning => {
      logger.warn(`${warning.field}: ${warning.message}`)
      if (warning.suggestion) {
        logger.info(`­ƒÆí Suggestion: ${warning.suggestion}`)
      }
    })
    logger.groupEnd()
  }

  if (result.isValid && result.warnings.length === 0) {
    logger.log('Ô£à Environment configuration is valid')
  }

  logger.log(`­ƒôè Configuration Summary:`, result.summary)

  return result.isValid
}

/**
 * Gets validation rules for a specific field
 */
export function getValidationRule(field: keyof RuntimeConfig): ValidationRule | undefined {
  return ENV_VALIDATION_RULES[field]
}

/**
 * Gets all required environment variables
 */
export function getRequiredEnvVars(): string[] {
  return Object.entries(ENV_VALIDATION_RULES)
    .filter(([_, rule]) => rule.required)
    .map(([key, _]) => key)
}

/**
 * Gets all sensitive environment variables
 */
export function getSensitiveEnvVars(): string[] {
  return Object.entries(ENV_VALIDATION_RULES)
    .filter(([_, rule]) => rule.security?.sensitive)
    .map(([key, _]) => key)
}

/**
 * Masks sensitive values for logging
 */
export function maskSensitiveConfig(config: Partial<RuntimeConfig>): Partial<RuntimeConfig> {
  const masked = { ...config }
  const sensitiveFields = getSensitiveEnvVars()

  sensitiveFields.forEach(field => {
    const value = masked[field as keyof RuntimeConfig]
    if (value && typeof value === 'string') {
      masked[field as keyof RuntimeConfig] = value.length > 8
        ? `${value.substring(0, 4)}...${value.substring(value.length - 4)}`
        : '***'
    }
  })

  return masked
}

/**
 * Environment Detection and Configuration Utilities
 *
 * Provides safe environment detection for production optimizations
 * and Railway deployment compatibility
 */

import { createLogger } from '@/lib/logger'

interface EnvironmentConfig {
  isDevelopment: boolean
  isProduction: boolean
  isTest: boolean
  isRailway: boolean
  apiUrl: string
  appVersion: string
  buildTime: string
  enableDebugLogs: boolean
  enableMockApi: boolean
  enableErrorReporting: boolean
  enablePerformanceMonitoring: boolean
}

const envLogger = createLogger('EnvironmentConfig')

/**
 * Detect current environment from multiple sources
 */
function detectEnvironment(): string {
  // Vite environment variable
  if (import.meta.env['NODE_ENV']) {
    return import.meta.env['NODE_ENV']
  }

  // Railway environment detection
  if (import.meta.env['VITE_RAILWAY_ENVIRONMENT']) {
    return import.meta.env['VITE_RAILWAY_ENVIRONMENT']
  }

  // Check hostname patterns
  if (typeof window !== 'undefined') {
    const hostname = window.location.hostname

    // Railway production domains
    if (hostname.includes('.railway.app') || hostname.includes('.up.railway.app')) {
      return 'production'
    }

    // Local development
    if (hostname === 'localhost' || hostname === '127.0.0.1' || hostname.startsWith('192.168.')) {
      return 'development'
    }

    // Preview/staging environments
    if (hostname.includes('preview') || hostname.includes('staging')) {
      return 'staging'
    }
  }

  // Default to production for safety
  return 'production'
}

/**
 * Detect Railway deployment
 */
function detectRailway(): boolean {
  // Railway environment variables
  if (import.meta.env['VITE_RAILWAY_PROJECT_ID'] ||
      import.meta.env['VITE_RAILWAY_SERVICE_ID'] ||
      import.meta.env['RAILWAY_PROJECT_ID']) {
    return true
  }

  // Railway URL patterns
  if (typeof window !== 'undefined') {
    const hostname = window.location.hostname
    return hostname.includes('.railway.app') || hostname.includes('.up.railway.app')
  }

  return false
}

/**
 * Get API URL with Railway compatibility
 */
function getApiUrl(): string {
  // Explicit environment variable
  if (import.meta.env.VITE_API_URL) {
    return import.meta.env.VITE_API_URL
  }

  // Railway environment variables
  if (import.meta.env['VITE_RAILWAY_BACKEND_URL']) {
    return import.meta.env['VITE_RAILWAY_BACKEND_URL']
  }

  // Auto-detect based on current URL (for Railway)
  if (typeof window !== 'undefined') {
    const { protocol, hostname } = window.location

    // Railway deployment pattern
    if (hostname.includes('.railway.app') || hostname.includes('.up.railway.app')) {
      // Use the same domain for API (assuming backend is on same Railway project)
      return `${protocol}//${hostname}`
    }

    // Local development
    if (hostname === 'localhost' || hostname === '127.0.0.1') {
      return 'http://localhost:8000'
    }
  }

  // Fallback to production URL
  return 'https://clinica-oncologica-v02-production.up.railway.app'
}

/**
 * Get app version from package.json or build
 */
function getAppVersion(): string {
  return import.meta.env['VITE_APP_VERSION'] ||
         import.meta.env['PACKAGE_VERSION'] ||
         '1.0.0'
}

/**
 * Get build timestamp
 */
function getBuildTime(): string {
  return import.meta.env['VITE_BUILD_TIME'] ||
         import.meta.env['BUILD_TIME'] ||
         new Date().toISOString()
}

/**
 * Create environment configuration
 */
function createEnvironmentConfig(): EnvironmentConfig {
  const env = detectEnvironment()
  const isRailway = detectRailway()

  const isDevelopment = env === 'development'
  const isProduction = env === 'production'
  const isTest = env === 'test'

  return {
    isDevelopment,
    isProduction,
    isTest,
    isRailway,
    apiUrl: getApiUrl(),
    appVersion: getAppVersion(),
    buildTime: getBuildTime(),
    enableDebugLogs: isDevelopment || env === 'staging',
    enableMockApi: isDevelopment && import.meta.env['VITE_ENABLE_MOCK_API'] === 'true',
    enableErrorReporting: isProduction || env === 'staging',
    enablePerformanceMonitoring: isProduction || env === 'staging'
  }
}

// Export singleton instance
export const environment = createEnvironmentConfig()

// Export utilities
export {
  detectEnvironment,
  detectRailway,
  getApiUrl,
  getAppVersion,
  getBuildTime,
  createEnvironmentConfig
}

export type { EnvironmentConfig }

