    total_completed: completed,
    total_expired: expired,
    total_active: active,
    average_score: Math.round(avgScore * 10) / 10,
    completion_rate: Math.round((completed / totalSent) * 100 * 10) / 10,
    expiration_rate: Math.round((expired / totalSent) * 100 * 10) / 10
  }
}

