                          </p>
                        </div>
                      </TableCell>
                      <TableCell>
                        <Badge variant="outline">{message.retry_count}</Badge>
                      </TableCell>
                      <TableCell>
                        <div className="flex flex-col text-sm">
                          <span>
                            {format(new Date(message.created_at), "dd/MM/yyyy", {
                              locale: ptBR,
                            })}
