          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={confirmRetry}>Confirmar</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
