      {/* Discard Confirmation Dialog */}
      <AlertDialog open={!!messageToDiscard} onOpenChange={() => setMessageToDiscard(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Confirmar Descarte</AlertDialogTitle>
