          </Alert>

          {/* User permissions info */}
          {user && (
            <div className="bg-gray-50 dark:bg-gray-800 rounded-lg p-4 space-y-3">
              <h3 className="font-semibold text-sm text-gray-700 dark:text-gray-300">
