              <div className="grid grid-cols-1 gap-2 text-sm">
                <PermissionItem
                  label="Gerenciar Usu├írios"
                  allowed={permissions.canManageUsers}
                />
                <PermissionItem
                  label="Gerenciar Pacientes"
                  allowed={permissions.canManagePatients}
                />
                <PermissionItem
                  label="Visualizar Relat├│rios"
                  allowed={permissions.canViewReports}
                />
                <PermissionItem
                  label="Configurar Flows"
                  allowed={permissions.canManageFlows}
                />
                <PermissionItem
                  label="Painel Administrativo"
                  allowed={permissions.canAccessAdmin}
                />
                <PermissionItem
                  label="Configura├º├Áes do Sistema"
                  allowed={permissions.canManageSettings}
                />
              </div>
            </div>
          )}

          {/* Actions */}
          <div className="flex flex-col sm:flex-row gap-3 pt-4">
            <Button
              variant="outline"
              className="flex-1"
              onClick={handleGoBack}
            >
              <ArrowLeft className="w-4 h-4 mr-2" />
