            : "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400"
        }`}
      >
        {allowed ? "Ô£ô Permitido" : "Ô£ù Negado"}
      </span>
    </div>
  );
}

import React, { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { useMedicoAuth } from '../../contexts/MedicoAuthContext'

export default function MedicoLogin() {
  const navigate = useNavigate()
  const { isAuthenticated, isLoading, error, signIn } = useMedicoAuth()
  const [formData, setFormData] = useState({
    crm: '',
    senha: ''
  })
  const [errors, setErrors] = useState<{ [key: string]: string }>({})

  useEffect(() => {
    if (isAuthenticated) {
      navigate('/medico/dashboard')
    }
  }, [isAuthenticated, navigate])

  const validateForm = () => {
    const newErrors: { [key: string]: string } = {}

    if (!formData.crm.trim()) {
      newErrors['crm'] = 'CRM ├® obrigat├│rio'
    } else if (!/^\d{4,7}$/.test(formData.crm)) {
      newErrors['crm'] = 'CRM deve conter 4-7 d├¡gitos'
    }

    if (!formData.senha) {
      newErrors['senha'] = 'Senha ├® obrigat├│ria'
    } else if (formData.senha.length < 6) {
      newErrors['senha'] = 'Senha deve ter no m├¡nimo 6 caracteres'
    }

    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!validateForm()) {
      return
    }

    try {
      // Use CRM directly; MedicoAuthContext will map to proper email domain in Firebase
      const crmOrEmail = formData.crm

      // Use Firebase signIn from context
      const result = await signIn(crmOrEmail, formData.senha, false)

      if (result.success) {
        // Navigate to dashboard on success
        navigate('/medico/dashboard')
      } else {
        // Show error from context
        setErrors({ submit: result.error || 'Erro ao fazer login' })
      }
    } catch (error) {
      const errorMessage = error instanceof Error
        ? error.message
        : 'Erro ao fazer login'
      setErrors({ submit: errorMessage })
    }
  }

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target
    setFormData(prev => ({
      ...prev,
      [name]: value
    }))
    // Clear error when user starts typing
    if (errors[name as keyof typeof errors]) {
      setErrors(prev => {
        const newErrors = { ...prev }
        delete newErrors[name as keyof typeof newErrors]
        return newErrors
      })
    }
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-50 to-indigo-100 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-md w-full space-y-8 bg-white p-8 rounded-2xl shadow-2xl">
        <div>
          <div className="mx-auto h-16 w-16 flex items-center justify-center rounded-full bg-blue-600">
            <svg className="h-10 w-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
            </svg>
          </div>
          <h2 className="mt-6 text-center text-3xl font-extrabold text-gray-900">
            Portal M├®dico
          </h2>
          <p className="mt-2 text-center text-sm text-gray-600">
            Acesso restrito a profissionais autorizados
          </p>
        </div>

        <form className="mt-8 space-y-6" onSubmit={handleSubmit}>
          <div className="rounded-md shadow-sm space-y-4">
            <div>
              <label htmlFor="crm" className="block text-sm font-medium text-gray-700 mb-1">
                CRM
              </label>
              <input
                id="crm"
                name="crm"
                type="text"
                autoComplete="username"
                required
                value={formData.crm}
                onChange={handleChange}
                className={`appearance-none relative block w-full px-3 py-2 border ${
                  errors['crm'] ? 'border-red-300' : 'border-gray-300'
                } placeholder-gray-500 text-gray-900 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent sm:text-sm`}
                placeholder="Digite seu CRM (somente n├║meros)"
              />
              {errors['crm'] && (
                <p className="mt-1 text-sm text-red-600">{errors['crm']}</p>
              )}
            </div>

            <div>
              <label htmlFor="senha" className="block text-sm font-medium text-gray-700 mb-1">
                Senha
              </label>
              <input
                id="senha"
                name="senha"
                type="password"
                autoComplete="current-password"
                required
                value={formData.senha}
                onChange={handleChange}
                className={`appearance-none relative block w-full px-3 py-2 border ${
                  errors['senha'] ? 'border-red-300' : 'border-gray-300'
                } placeholder-gray-500 text-gray-900 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent sm:text-sm`}
                placeholder="Digite sua senha"
              />
              {errors['senha'] && (
                <p className="mt-1 text-sm text-red-600">{errors['senha']}</p>
              )}
            </div>
          </div>

          {errors['submit'] && (
            <div className="rounded-md bg-red-50 p-4">
              <div className="flex">
                <div className="flex-shrink-0">
                  <svg className="h-5 w-5 text-red-400" fill="currentColor" viewBox="0 0 20 20">
                    <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                  </svg>
                </div>
                <div className="ml-3">
                  <p className="text-sm text-red-800">{errors['submit']}</p>
                </div>
              </div>
            </div>
          )}

          {error && (
            <div className="rounded-md bg-red-50 p-4">
              <div className="flex">
                <div className="flex-shrink-0">
                  <svg className="h-5 w-5 text-red-400" fill="currentColor" viewBox="0 0 20 20">
                    <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                  </svg>
                </div>
                <div className="ml-3">
                  <p className="text-sm text-red-800">{error}</p>
                </div>
              </div>
            </div>
          )}

          <div>
            <button
              type="submit"
              disabled={isLoading}
              className={`group relative w-full flex justify-center py-3 px-4 border border-transparent text-sm font-medium rounded-lg text-white ${
                isLoading
                  ? 'bg-blue-400 cursor-not-allowed'
                  : 'bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500'
              } transition-colors duration-200`}
            >
              {isLoading ? (
                <>
                  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Autenticando...
                </>
              ) : (
                <>
                  <span className="absolute left-0 inset-y-0 flex items-center pl-3">
                    <svg className="h-5 w-5 text-blue-500 group-hover:text-blue-400" fill="currentColor" viewBox="0 0 20 20">
                      <path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" />
                    </svg>
                  </span>
                  Entrar
                </>
              )}
            </button>
          </div>
        </form>

        <div className="text-center">
          <p className="text-xs text-gray-500">
            Problemas de acesso? Entre em contato com a administra├º├úo
          </p>
        </div>
      </div>
    </div>
  )
}

/// <reference types="vite/client" />

import React, { useState, useEffect, useCallback } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { apiClient } from '../../lib/api-client'
import { ChevronDown, Phone, Mail, Calendar, User, FileText } from 'lucide-react'

interface Paciente {
  id: string
  nome: string
  cpf: string
  data_nascimento: string
  telefone: string
  email: string
}

export default function PacientesList() {
  const navigate = useNavigate()
  const [pacientes, setPacientes] = useState<Paciente[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [searchTerm, setSearchTerm] = useState('')
  const [expandedCards, setExpandedCards] = useState<Set<string>>(new Set())

  const fetchPacientes = useCallback(async () => {
    try {
      setLoading(true)
      const params: { size?: number; search?: string } = { size: 50 }
      if (searchTerm) params.search = searchTerm
      const resp = await apiClient.patients.list(params as any)
      const mapped: Paciente[] = (resp.items || []).map((p: any) => ({
        id: p.id,
        nome: p.name,
        cpf: p.cpf || '',
        data_nascimento: p.birth_date || '',
        telefone: p.phone || '',
        email: p.email || ''
      }))
      setPacientes(mapped)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Erro desconhecido')
    } finally {
      setLoading(false)
    }
  }, [searchTerm])

  useEffect(() => {
    fetchPacientes()
  }, [fetchPacientes])

  const filteredPacientes = pacientes.filter(paciente =>
    paciente.nome.toLowerCase().includes(searchTerm.toLowerCase()) ||
    paciente.cpf.includes(searchTerm)
  )

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('pt-BR')
  }

  const calculateAge = (birthDate: string) => {
    const today = new Date()
    const birth = new Date(birthDate)
    let age = today.getFullYear() - birth.getFullYear()
    const monthDiff = today.getMonth() - birth.getMonth()
    if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birth.getDate())) {
      age--
    }
    return age
  }

  const getInitials = (name: string) => {
    const names = name.split(' ').filter(n => n.length > 0)
    if (names.length >= 2) {
      const first = names[0]?.[0] || ''
      const last = names[names.length - 1]?.[0] || ''
      return `${first}${last}`.toUpperCase()
    }
    return name.substring(0, 2).toUpperCase()
  }

  const getAvatarColor = (id: string) => {
    const colors = [
      'bg-blue-500',
      'bg-green-500',
      'bg-yellow-500',
      'bg-red-500',
      'bg-indigo-500',
      'bg-pink-500',
      'bg-teal-500',
      'bg-orange-500'
    ]
    let sum = 0
    for (let i = 0; i < id.length; i++) sum = (sum + id.charCodeAt(i)) % colors.length
    return colors[sum]
  }

  const toggleCard = (id: string) => {
    setExpandedCards(prev => {
      const newSet = new Set(prev)
      if (newSet.has(id)) {
        newSet.delete(id)
      } else {
        newSet.add(id)
      }
      return newSet
    })
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto"></div>
          <p className="mt-4 text-gray-600">Carregando pacientes...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white shadow">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex justify-between items-center">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">Meus Pacientes</h1>
              <p className="text-sm text-gray-600">Lista de pacientes ativos</p>
            </div>
            <button
              onClick={() => navigate('/medico/dashboard')}
              className="px-4 py-2 bg-gray-600 text-white rounded-lg hover:bg-gray-700 transition-colors"
            >
              Voltar
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Search */}
        <div className="mb-6">
          <input
            type="text"
            placeholder="Buscar por nome ou CPF..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>

        {error && (
          <div className="mb-6 bg-red-50 border border-red-200 rounded-lg p-4">
            <p className="text-red-800">{error}</p>
          </div>
        )}

        {/* Pacientes Cards Grid */}
        {filteredPacientes.length === 0 ? (
          <div className="bg-white rounded-lg shadow p-12 text-center">
            <User className="mx-auto h-12 w-12 text-gray-400" />
            <h3 className="mt-4 text-lg font-medium text-gray-900">Nenhum paciente encontrado</h3>
            <p className="mt-2 text-sm text-gray-500">
              {searchTerm ? 'Tente ajustar sua busca' : 'Ainda n├úo h├í pacientes cadastrados'}
            </p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredPacientes.map((paciente) => {
              const isExpanded = expandedCards.has(paciente.id)
              const age = calculateAge(paciente.data_nascimento)

              return (
                <div
                  key={paciente.id}
                  className="bg-white rounded-lg shadow-md hover:shadow-xl transition-all duration-300 overflow-hidden border border-gray-200 hover:border-blue-300"
                >
                  {/* Card Header - Always Visible */}
                  <div
                    className="p-6 cursor-pointer select-none"
                    onClick={() => toggleCard(paciente.id)}
                  >
                    <div className="flex items-start justify-between">
                      <div className="flex items-center space-x-4 flex-1">
                        {/* Avatar */}
                        <div className={`${getAvatarColor(paciente.id)} w-14 h-14 rounded-full flex items-center justify-center text-white font-bold text-lg flex-shrink-0`}>
                          {getInitials(paciente.nome)}
                        </div>

                        {/* Name and Age */}
                        <div className="flex-1 min-w-0">
                          <h3 className="text-lg font-semibold text-gray-900 truncate">
                            {paciente.nome}
                          </h3>
                          <p className="text-sm text-gray-500 flex items-center mt-1">
                            <Calendar className="w-4 h-4 mr-1" />
                            {age} anos
                          </p>
                        </div>
                      </div>

                      {/* Expand/Collapse Icon */}
                      <ChevronDown
                        className={`w-5 h-5 text-gray-400 transition-transform duration-300 flex-shrink-0 ml-2 ${
                          isExpanded ? 'transform rotate-180' : ''
                        }`}
                      />
                    </div>

                    {/* Quick Action Button - Collapsed View */}
                    {!isExpanded && (
                      <div className="mt-4">
                        <Link
                          to={`/medico/prontuario/${paciente.id}`}
                          className="inline-flex items-center text-sm text-blue-600 hover:text-blue-800 font-medium"
                          onClick={(e) => e.stopPropagation()}
                        >
                          <FileText className="w-4 h-4 mr-1" />
                          Ver Prontu├írio
                        </Link>
                      </div>
                    )}
                  </div>

                  {/* Expanded Content */}
                  <div
                    className={`transition-all duration-300 ease-in-out ${
                      isExpanded ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0'
                    } overflow-hidden`}
                  >
                    <div className="px-6 pb-6 space-y-3 border-t border-gray-100 pt-4">
                      {/* Email */}
                      <div className="flex items-start">
                        <Mail className="w-4 h-4 text-gray-400 mr-3 mt-0.5 flex-shrink-0" />
                        <div className="flex-1 min-w-0">
                          <p className="text-xs text-gray-500 uppercase tracking-wide">Email</p>
                          <p className="text-sm text-gray-900 truncate">{paciente.email}</p>
                        </div>
                      </div>

                      {/* Phone */}
                      <div className="flex items-start">
                        <Phone className="w-4 h-4 text-gray-400 mr-3 mt-0.5 flex-shrink-0" />
                        <div className="flex-1">
                          <p className="text-xs text-gray-500 uppercase tracking-wide">Telefone</p>
                          <p className="text-sm text-gray-900">{paciente.telefone}</p>
                        </div>
                      </div>

                      {/* CPF */}
                      <div className="flex items-start">
                        <User className="w-4 h-4 text-gray-400 mr-3 mt-0.5 flex-shrink-0" />
                        <div className="flex-1">
                          <p className="text-xs text-gray-500 uppercase tracking-wide">CPF</p>
                          <p className="text-sm text-gray-900">{paciente.cpf}</p>
                        </div>
                      </div>

                      {/* Birth Date */}
